-- ============================================================
-- SQB Президент дашборди — PostgreSQL backup
-- Generated from JSON data files in assets/data/
-- Encoding: UTF-8 | Schema: public
-- Batch: load_no=1 | final_flag=True | date_modify=2026-04-28 12:00:00+05
-- ============================================================

BEGIN;

-- DROP existing schema (clean slate)
DROP TABLE IF EXISTS indicators CASCADE;
DROP TABLE IF EXISTS hero_kpis CASCADE;
DROP TABLE IF EXISTS districts CASCADE;
DROP TABLE IF EXISTS regions CASCADE;

-- ============================================================
-- DDL: Schema definition
-- ============================================================

CREATE TABLE regions (
    region_id   INT         PRIMARY KEY,
    slug        VARCHAR(64) UNIQUE NOT NULL,
    name_uz     TEXT        NOT NULL,
    name_ru     TEXT,
    name_en     TEXT,
    sort_order  INT         DEFAULT 0,
    load_no     INT         NOT NULL DEFAULT 1,
    final_flag  BOOLEAN     NOT NULL DEFAULT TRUE,
    date_modify TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX idx_regions_slug ON regions(slug);
CREATE INDEX idx_regions_load ON regions(load_no);

COMMENT ON TABLE  regions             IS 'Top-level administrative regions of Uzbekistan covered by the SQB dashboard';
COMMENT ON COLUMN regions.region_id   IS 'Surrogate primary key for the region';
COMMENT ON COLUMN regions.slug        IS 'URL-safe unique identifier (e.g. bukhara, fergana) used in app.js';
COMMENT ON COLUMN regions.name_uz     IS 'Region name in Uzbek (Cyrillic) — primary display language';
COMMENT ON COLUMN regions.name_ru     IS 'Region name in Russian';
COMMENT ON COLUMN regions.name_en     IS 'Region name in English';
COMMENT ON COLUMN regions.sort_order  IS 'Display order in the landing page region grid (alphabetical by Uzbek name)';
COMMENT ON COLUMN regions.load_no     IS 'Batch / load number this row arrived in. 1 = initial dataset migration from JSON';
COMMENT ON COLUMN regions.final_flag  IS 'TRUE when load is closed and data is considered final';
COMMENT ON COLUMN regions.date_modify IS 'Timestamp of the most recent modification (defaults to NOW() on insert/update)';

CREATE TABLE districts (
    district_id   INT         PRIMARY KEY,
    region_id     INT         NOT NULL REFERENCES regions(region_id) ON DELETE CASCADE ON UPDATE CASCADE,
    slug          VARCHAR(64) UNIQUE NOT NULL,
    name_uz       TEXT        NOT NULL,
    name_ru       TEXT,
    name_en       TEXT,
    district_name TEXT,
    json_file     VARCHAR(128),
    has_data      BOOLEAN     NOT NULL DEFAULT FALSE,
    type          VARCHAR(32),
    year          INT,
    total_cards   INT         NOT NULL DEFAULT 0,
    load_no       INT         NOT NULL DEFAULT 1,
    final_flag    BOOLEAN     NOT NULL DEFAULT TRUE,
    date_modify   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX idx_districts_region ON districts(region_id);
CREATE INDEX idx_districts_slug   ON districts(slug);
CREATE INDEX idx_districts_load   ON districts(load_no);

COMMENT ON TABLE  districts               IS 'Districts (tuman), cities (shahar) and republic-level entities under each region';
COMMENT ON COLUMN districts.district_id   IS 'Surrogate primary key for the district';
COMMENT ON COLUMN districts.region_id     IS 'FK -> regions.region_id; cascades on delete/update';
COMMENT ON COLUMN districts.slug          IS 'URL-safe unique identifier used in app.js (e.g. termiz, shahrixon)';
COMMENT ON COLUMN districts.name_uz       IS 'District display name in Uzbek (Cyrillic)';
COMMENT ON COLUMN districts.name_ru       IS 'District display name in Russian';
COMMENT ON COLUMN districts.name_en       IS 'District display name in English';
COMMENT ON COLUMN districts.district_name IS 'Full official name from the source JSON (e.g. "Бойсун тумани")';
COMMENT ON COLUMN districts.json_file     IS 'Source JSON file under assets/data/';
COMMENT ON COLUMN districts.has_data      IS 'TRUE if the district has populated indicators (visible to end users)';
COMMENT ON COLUMN districts.type          IS 'Administrative type: shahar (city), viloyat (region-level), respublika (republic), NULL = ordinary tuman';
COMMENT ON COLUMN districts.year          IS 'Reporting year of the JSON snapshot';
COMMENT ON COLUMN districts.total_cards   IS 'Number of indicator cards loaded for this district';
COMMENT ON COLUMN districts.load_no       IS 'Batch / load number';
COMMENT ON COLUMN districts.final_flag    IS 'TRUE when load is final';
COMMENT ON COLUMN districts.date_modify   IS 'Timestamp of the most recent modification';

CREATE TABLE hero_kpis (
    hero_kpi_id  INT         PRIMARY KEY,
    district_id  INT         NOT NULL REFERENCES districts(district_id) ON DELETE CASCADE ON UPDATE CASCADE,
    metric_name  VARCHAR(64) NOT NULL,
    metric_value NUMERIC(14, 2),
    metric_unit  VARCHAR(32),
    load_no      INT         NOT NULL DEFAULT 1,
    final_flag   BOOLEAN     NOT NULL DEFAULT TRUE,
    date_modify  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (district_id, metric_name)
);
CREATE INDEX idx_hero_kpis_district ON hero_kpis(district_id);
CREATE INDEX idx_hero_kpis_load     ON hero_kpis(load_no);

COMMENT ON TABLE  hero_kpis              IS 'Hero KPI metrics shown on the landing tile of each district (population, mahallas, families, households)';
COMMENT ON COLUMN hero_kpis.hero_kpi_id  IS 'Surrogate primary key';
COMMENT ON COLUMN hero_kpis.district_id  IS 'FK -> districts.district_id; cascades on delete/update';
COMMENT ON COLUMN hero_kpis.metric_name  IS 'Metric label in Uzbek: Аҳоли, Маҳалла, Оила, Хонадон';
COMMENT ON COLUMN hero_kpis.metric_value IS 'Numeric value of the metric';
COMMENT ON COLUMN hero_kpis.metric_unit  IS 'Unit of measurement (e.g. "минг киши", "та")';
COMMENT ON COLUMN hero_kpis.load_no      IS 'Batch / load number';
COMMENT ON COLUMN hero_kpis.final_flag   IS 'TRUE when load is final';
COMMENT ON COLUMN hero_kpis.date_modify  IS 'Timestamp of the most recent modification';

CREATE TABLE indicators (
    indicator_id  INT         PRIMARY KEY,
    district_id   INT         NOT NULL REFERENCES districts(district_id) ON DELETE CASCADE ON UPDATE CASCADE,
    no            INT         NOT NULL,
    slide         INT         NOT NULL,
    slide_no      VARCHAR(8),
    name          TEXT        NOT NULL,
    description   TEXT,
    value         TEXT,
    found         BOOLEAN     NOT NULL DEFAULT TRUE,
    source_org    TEXT,
    ai_insight    TEXT,
    kpi_count     NUMERIC(14, 2),
    kpi_pct       NUMERIC(6, 2),
    load_no       INT         NOT NULL DEFAULT 1,
    final_flag    BOOLEAN     NOT NULL DEFAULT TRUE,
    date_modify   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (district_id, no)
);
CREATE INDEX idx_indicators_district ON indicators(district_id);
CREATE INDEX idx_indicators_slide    ON indicators(district_id, slide);
CREATE INDEX idx_indicators_load     ON indicators(load_no);

COMMENT ON TABLE  indicators              IS 'Card-level economic / social indicators displayed across the 6 dashboard slides for each district';
COMMENT ON COLUMN indicators.indicator_id IS 'Surrogate primary key';
COMMENT ON COLUMN indicators.district_id  IS 'FK -> districts.district_id; cascades on delete/update';
COMMENT ON COLUMN indicators.no           IS 'Card number within the district (1..N), unique per district';
COMMENT ON COLUMN indicators.slide        IS 'Slide section: 1=Iqtisodiy faollik, 2=Infratuzilma, 3=Aholi va bandlik, 4=Mahalla tadbirkorligi va bank, 5=Imkoniyatlar, 6=Xulosa va reja';
COMMENT ON COLUMN indicators.slide_no     IS 'String form of slide number, kept for compatibility with the front-end JSON';
COMMENT ON COLUMN indicators.name         IS 'Card title (e.g. "Ишсизлик кўрсаткичлари")';
COMMENT ON COLUMN indicators.description  IS 'Short description / subtitle shown under the title';
COMMENT ON COLUMN indicators.value        IS 'Pipe-separated raw facts string parsed by app.js (e.g. "Жами: ... | 2021: ... | 2025: ...")';
COMMENT ON COLUMN indicators.found        IS 'TRUE if data is available; FALSE shows "Маълумот мавжуд эмас" (data not yet collected)';
COMMENT ON COLUMN indicators.source_org   IS 'Source organization (e.g. "Бандлик бошқармаси", "Марказий банк")';
COMMENT ON COLUMN indicators.ai_insight   IS 'AI-generated recommendation shown in the "СИ ТАВСИЯСИ" panel';
COMMENT ON COLUMN indicators.kpi_count    IS 'Numeric KPI shown on landing hero (e.g. number of unemployed). Only set on cards mapped to landing KPIs';
COMMENT ON COLUMN indicators.kpi_pct      IS 'Percentage shown next to kpi_count (e.g. unemployment rate)';
COMMENT ON COLUMN indicators.load_no      IS 'Batch / load number';
COMMENT ON COLUMN indicators.final_flag   IS 'TRUE when load is final';
COMMENT ON COLUMN indicators.date_modify  IS 'Timestamp of the most recent modification';

-- ============================================================
-- DATA
-- ============================================================

