INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (1, 1, 'gijduvon', 'Ғиждувон', 'Гиждуван', 'Gijduvon', '', 'gijduvon.json', TRUE, NULL, NULL, 73, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (1, 1, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, қишлоқ хўжалиги, қурилиш ва бозор хизматлари ҳажми + ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 3 182,8 млрд сўм (+7.4%) | Қишлоқ хўжалиги: 5 375,7 млрд сўм (+1.6%) | Қурилиш: 984,7 млрд сўм (+23.8%) | Бозор хизматлари: 3 521,2 млрд сўм (+16.8%)', TRUE, 'SQB', 'Қишлоқ хўжалиги секин ўсаётгани (+1,6%) сабабли маблағни интенсив технологияларга йўналтириш керак. Қурилиш жадаллиги (+23,8%) туфайли маҳаллий материаллар ишлаб чиқаришни кредитлаш лозим. Хизматлар ўсишига (+16,8%) таяниб, тармоқлараро логистикани кенгайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (2, 1, 2, 1, '8', 'Устувор 4 та соҳа', 'Асосий устувор соҳалар рейтинги ва асослама', 'Жами: 4 та устувор соҳа | 1-ўрин Енгил саноат: тўқимачилик ва тикувчилик кластери, тарихий устунлик | 2-ўрин Хизмат кўрсатиш: савдо, транспорт, молиявий хизматлар | 3-ўрин Туризм ва ҳунармандчилик: Гиждувон кулолчилик мактаби (UNESCO мероси) | 4-ўрин Қишлоқ хўжалиги: мевачилик, узумчилик — экспорт салоҳияти', TRUE, 'SQB', 'Тўқимачилик кластерларидаги тарихий устунликка таяниб, ишлаб чиқаришни кенгайтириш керак. Транспорт ва молия хизматларини ушбу тармоқлар логистикасига йўналтириш лозим. ЮНЕСКО кулолчилиги негизида туризмни ривожлантириш керак. Мева экспорти учун саралаш марказларини қуриш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (3, 1, 3, 1, '2', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', '2021: 1796.7 | 2022: 2102.8 | 2023: 2744.1 | 2024: 2963.6 | 2025: 3182.8 (млрд сўм)', TRUE, 'stat.uz', 'Саноат ўсиши секинлашгани (+7,4%) сабабли мавжуд фабрикаларни тўлиқ қувватда ишлатиш керак. 2026 йилги мақсадли кўрсаткичга (3648 млрд) эришиш учун қайта ишлаш ва IT лойиҳаларини тезлаштириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (4, 1, 4, 1, '3', 'Маҳаллий бюджет', 'Маҳаллий бюджет ҳажми', '2023: 159.0 | 2024: 162.0 | 2025: 198.3 (млрд сўм)', TRUE, 'Хокимият', 'Бюджет маблағларининг жадал ўсиши (+22,4%) туфайли ортиқча тушумларни ҳудудий инфратузилмани яхшилашга йўналтириш керак. Прогноз кўрсаткичларига эришиш учун қўшимча солиқ манбаларини шакллантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (5, 1, 5, 1, '4', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми', '2021: 443.7 | 2022: 704.0 | 2023: 506.8 | 2024: 845.0 | 2025: 1170.8 (млрд сўм)', TRUE, 'Марказий банк', 'Кредит ажратишнинг жаддал ўсиши (+38,6%) сабабли банк таваккалчиликларини бошқаришни кучайтириш керак. Муаммоли қарздорликлар пайдо бўлишининг олдини олиш учун мижозларни скоринг қилиш талабларини қатъийлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (6, 1, 6, 1, '9', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Жами: 50 балл (100 дан) — ўрта-юқори фаоллик | 2024 йил ўртача: 45 балл | 2025 йил ўртача: 50 балл (+11% ўсиш) | Энг фаол ой: Май 2025 йил — 68 балл | Энг суст ой: Декабр 2024 йил — 25 балл | Мавсумийлик: баҳор-ёз юқори, қиш паст', TRUE, 'SQB', 'Google Trends 50/100 — ўрта-юқори фаоллик. 2024 да 45 → 2025 да 50 (+11%). Энг фаол ой — Май (68 балл). Қизиқиш ўсмоқда. Тавсия: ҳудудий маркетинг кампанияси орқали инвестиция жалбини кучайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (7, 1, 7, 2, '1', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2023: 61.4 | 2024: 61.5 | 2025: 77.0 (%)', TRUE, 'stat.uz', 'Ичимлик сувининг умумий қамрови ошганига (77%) қарамай қишлоқлардаги кўрсаткич пастлигича қолаётгани сабабли, янги қурилиш ресурсларини айнан чекка ҳудудлар инфратузилмасига йўналтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (8, 1, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Туман ички йўлларининг таъмирланганлик даражаси', '2023: 14.0 | 2024: 15.0 | 2025: 16.0 (%)', TRUE, 'Узавтойул', 'Ички йўллар ҳолатини яхшилаш динамикаси (16%) туфайли, маҳаллий бюджетнинг қўшимча манбаларини тўғридан-тўғри йўлларни асфальтлаш дастурларига сафарбар этиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (9, 1, 9, 2, '3', 'Оқава сув билан таъминланганлик (%)', 'Канализация ва оқава сув тармоғи қамрови', '2023: 5.0 | 2024: 7.2 | 2025: 9.6 (%)', TRUE, 'stat.uz', 'Оқава сув тизими қамров даражаси пастлиги (9,6%) сабабли, ташқи инвестицияларни жалб қилиш орқали канализация тармоқларини барпо этиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (10, 1, 10, 2, '4', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳоли жамоат транспортидан фойдаланиш даражаси', '2023: 12.0 | 2024: 13.0 | 2025: 23.0 (%)', TRUE, 'Узавтойул', 'Жамоат транспортидан фойдаланиш ўсиши секинлиги (23%) сабабли йўналишлар тармоғини тўлиқ қайта кўриб чиқиш керак. Йўловчилар оқимини ошириш учун замонавий автобуслар харидини молиялаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (11, 1, 11, 2, '5', 'Электр таъминоти сифат даражаси (%)', 'Электр тармоғининг узилишсиз ишлаш ва сифат кўрсаткичи', '2023: 94 | 2024: 96 | 2025: 98 (%)', TRUE, 'Энергетика вазирлиги', 'Электр сифати 2023 да 94% → 2025 да 98% — барқарор ўсиш. Узилишлар частотаси пасаймоқда. Тавсия: тармоқ модернизацияси давом эттирилиб, 2027 йилгача 99,5% га етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (12, 1, 12, 2, '7', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ер фонди тоифалар бўйича тақсимоти', 'Жами: 384 068 га ер майдони | Қишлоқ хўжалиги: 341 727 га | Ўрмон фонди: 20 662 га | Сув фонди: 15 329 га | Саноат/транспорт: 5 401 га | Аҳоли пунктлари: 714 га | Тарихий-маданий: 202 га | Захира: 10 га', TRUE, 'Кадастр', 'Қишлоқ хўжалиги ерларининг улуши ўта юқорилиги (341 727 га) боис паст ҳосилли майдонларни мақбуллаштириш керак. Саноат ва инфратузилмани ривожлантириш учун янги ер участкаларини ажратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (13, 1, 13, 2, NULL, 'Музлаткич ва омборхоналар', 'Туман музлаткич ва омбор инфратузилмаси (01.01.2025)', 'Жами: 19 та омбор / 7 400 тонна сиғим | Совуткичли омборлар: 17 та (7 380 тонна) | Оддий омборлар: 2 та (20 тонна)', TRUE, 'Хокимият', 'Йирик музлаткичларга тобеликни камайтириш мақсадида ўрта сиғимли объектлар қурилишини субсидиялаш керак. Қуруқ маҳсулотлар логистикасини ривожлантириш учун оддий омборлар тармоғини (ҳозир атиги 20 тонна) кескин кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (14, 1, 14, 2, '8', 'Мактабгача таълим қамрови', '3-7 ёшгача болаларни МТТга қамраб олиш даражаси', 'Жами: 85,2% қамров даражаси | 3-7 ёшли болалар: 27 154 та | Жами МТТ сони: 448 та | Давлат МТТ: 78 та | ДХШ: 9 та | Оилавий: 361 та | Қамраб олинган: 23 137 та', TRUE, 'stat.uz', 'МТТ қамрови 85,2% — яхши. 27 154 болага хизмат, 23 137 қамраб олинган. 448 та МТТ. Тавсия: оилавий МТТ сонини ошириш ва қишлоқ МФЙларда қамровни 95% га етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (15, 1, 15, 2, '9', 'Соғлиқни сақлаш тизими', 'Тиббий ташкилотлар, ўринлар ва ходимлар сони', 'Жами: 34 та тиббий ташкилот | Стационар ўринлар: 606 та (543 бюджет + 63 бюджетдан ташқари) | Жами штат: 2 664 бирлик | Врачлар: 589 та | Ўрта тиббий ходим: 1 446 та | Кичик тиббий ходим: 356 та', TRUE, 'stat.uz', 'Бюджетдан ташқари ўринлар улуши пастлиги (63 та) туфайли ҳудудда хусусий тиббиёт муассасалари тармоғини кенгайтириш керак. Мавжуд кадрлар (589 врач) салоҳиятига таяниб, пуллик тиббий хизматлар кўламини ошириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (16, 1, 16, 2, '11', 'Агрозона харитаси', 'Туман қишлоқ хўжалик зоналари ва ихтисослашуви', 'Жами: 4 та асосий агрозона | Боғдорчилик: ғарбий ҳудудлар (яшил зона) | Пахта етиштириш: марказий ва шимолий ҳудудлар (қизил зона) | Сабзавотчилик: жанубий ҳудудлар (сариқ зона) | Чорвачилик: шарқий ҳудудлар (жигарранг зона)', TRUE, 'Кадастр', 'Агрозоналарнинг қатъий тақсимотига асосланиб, марказий-шимолий пахтачилик ҳудудида тўқимачилик корхоналарини жойлаштириш керак. Ғарб ва жанубдаги боғ-сабзавот зоналарида логистика омборларини қуриш лозим. Шарқдаги чорвачилик ҳудудига гўшт ва сутни қайта ишлаш инвестицияларини йўналтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (17, 1, 17, 3, '9', 'Меҳнат ресурслари (минг)', 'Жами меҳнат ресурслари сони', '2021: 143.4 | 2022: 146.9 | 2023: 150.5 | 2024: 154.2 | 2025: 158.6 (минг киши)', TRUE, 'stat.uz', 'Меҳнат ресурслари 2021 йилдаги 143,4 минг кишидан 2025 йилга 158,6 минг кишига ўсди (+10,6%, йиллик ўртача +2,6%). Меҳнат бозори кенгаймоқда, лекин янги иш ўринлари талаб этилади. Тавсия: (1) йилига 1 000-1 200 та янги иш ўрни яратиш; (2) ёшлар учун касб-ҳунар марказлари кенгайтириш; (3) меҳнат миграциясини тартибга солиш; (4) норасмий бандликни расмийлаштириш; (5) "Аёл тадбиркор" дастури орқали молиялаштиришни кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (18, 1, 18, 3, NULL, 'Бандликни ошириш имкониятлари', 'Туманда бандликни ошириш учун мавжуд имкониятлар ва режалар', '2021: 107.4 | 2022: 110.0 | 2023: 112.7 | 2024: 115.5 | 2025: 118.8 (минг киши)', TRUE, 'stat.uz', 'Банд аҳоли 2021 йилдаги 107,4 минг кишидан 2025 йилга 118,8 минг кишига ўсди (+10,6%, йиллик ўртача +2,6%). Иқтисодий фаоллик ўсиб бормоқда. Тавсиялар: (1) микролойиҳаларни ривожлантириш орқали янги иш ўринлари яратиш; (2) ёшларни касб-ҳунарга йўналтириш ва малакали кадрлар тайёрлаш; (3) норасмий бандликни расмийлаштириш орқали аниқ маълумот олиш; (4) "Аёл тадбиркор" лойиҳалари орқали аёллар иштирокини ошириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (19, 1, 19, 3, NULL, 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлар сони ва ишсизлик даражаси динамикаси', '2021: 13.1 | 2022: 11.3 | 2023: 8.3 | 2024: 6.9 | 2025: 3.5 (минг киши)', TRUE, 'Mehnat.uz', 'Ишсизлар сони 2021 йилдаги 13,1 минг кишидан 2025 йилга 3,5 минг кишига тушди — 5 йилда 73% қисқариш. Расмий ишсизлик даражаси 5,9% → 3,5% (-40,7%). Тавсиялар: (1) касб-ҳунар ўргатиш ва тадбиркорликни рағбатлантириш; (2) 2026 йилда 2,5% мақсадига эришиш; (3) ёшлар ва аёллар бандлигига алоҳида эътибор; (4) норасмий бандликни расмийлаштириш.', 3546, 2.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (20, 1, 20, 3, NULL, 'Камбағаллик кўрсаткичлари', 'Камбағал оилалар сони ва камбағаллик даражаси динамикаси', '2020: 9100 | 2021: 8120 | 2022: 8100 | 2023: 5600 | 2024: 3500 | 2025: 3025 (оила)', TRUE, 'stat.uz', 'Камбағал оилалар 2020 йилдаги 9 100 дан 2025 йилга 3 025 гача камайди — 5 йилда 67% қисқариш. Камбағаллик даражаси 11,1 → 3,5 минг киши (-68,5%). Тавсиялар: (1) тренд сақланса 2026 йил туманни ҳоли ҳудудга айлантириш мумкин; (2) ҳар йили 1,5-2 минг иш ўрни яратиш; (3) маҳаллабай мақсадли дастурлар; (4) маҳалла банкирлари орқали ҳар бир камбағал оилага индивидуал ҳамроҳлик.', 3025, 3.9, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (21, 1, 21, 3, '15', '«Барқарор келажак» — ёшлар даромадини ошириш', '2026 йилда даромади ошириладиган ёшлар — мажмуавий чоралар бўйича тақсимот', 'Жами: 2 721 нафар (2026 режа) | Тадбиркорликка жалб қилиш: 2 135 нафар | Доимий ишга жойлаштириш: 247 нафар | Кредит ажратиш ҳисобига: 180 нафар | Қайта касбга ўқитиш: 159 нафар', TRUE, 'Хокимият', '«Барқарор келажак» дастури доирасида 2026 йилда ёшлар даромадини ошириш — мажмуавий ёндашув. Энг катта улуш (78%) тадбиркорликка жалб қилишга тегишли — бу узоқ муддатли барқарорлик учун асос. Тавсия: маҳалла банкирлари орқали ҳар бир ёшга индивидуал бизнес-режа тузиш, доимий ишга жойлаштириш сонини 1 000 нафаргача кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (22, 1, 22, 3, '16', 'Аёллар бандлиги ва даромадини ошириш', '2026 йилда даромади ошириладиган аёллар — чоралар бўйича тақсимот', 'Жами: 6 594 нафар (2026 режа) | Ўзини ўзи банд қилиш ҳисобига: 3 740 нафар | Доимий ишга жойлаштириш: 1 224 нафар | Тадбиркорликка жалб қилиш: 612 нафар | Қайта касбга ўқитиш ҳисобига: 569 нафар | Кредит ажратиш ҳисобига (221 млрд сўм): 449 нафар', TRUE, 'stat.uz', '2026 йилда 6 594 нафар аёл даромадини оширишга йўналтирилган. Энг катта улуш (57%) ўзини ўзи банд қилиш ҳисобига (3 740 нафар) — оилавий тадбиркорлик ва ҳунармандчилик. Доимий иш ўринлари 1 224 нафар (19%). Тавсия: HAMROH дастури орқали тадбиркорликка жалб қилинаётган 612 нафар сонини 1 000+ га кенгайтириш, касбий тайёргарлик марказларини кучайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (23, 1, 23, 3, '1', 'Аҳоли сони (минг)', 'Доимий аҳоли сони', '2023: 322.5 | 2024: 327.5 | 2025: 331.5 минг нафар', TRUE, 'stat.uz', 'Аҳоли 2023 да 322,5 минг → 2025 да 331,5 минг — йилига +1,4%. Бухоро вилоятида 2-ўрин (15,77%). Ёш аҳоли устун — меҳнат бозорига йилига ≈4 500 нафар янги. Тавсия: йилига 5 000+ иш ўрни яратиш мажбурияти.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (24, 1, 24, 3, '2', 'Маҳаллалар сони', 'МФЙ (маҳалла фуқаролар йиғини) сони', '70 та', TRUE, 'SQB', '70 МФЙ — 14 шаҳарча + 14 қишлоқ ФЙ + субмаҳалла. Бухоро вилоятидаги энг катта тумани. Мураккаб тизим. Тавсия: маҳалла банкирлари сонини 18 → 50 га ошириш, ҳар МФЙ учун ўз хизмат маркази.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (25, 1, 25, 3, '3', 'Оилалар сони', 'Жами оилалар сони', '95 100 та (≈95 минг оила)', TRUE, 'SQB', '95 100 оила — ўртача 4,5 киши/оила. Меҳнатга яроқли — оилада 1,8 киши. Оилавий бизнес ва ҳунармандчилик потенциали юқори. Тавсия: «Ҳар бир оила — тадбиркор» дастури доирасида 5 000+ оилага имтиёзли микрокредит.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (26, 1, 26, 3, '4', 'Хонадонлар сони', 'Жами хонадонлар сони', '69 800 та', TRUE, 'SQB', '69 800 хонадон — солиқ йиғиш бўйича рекорд кўрсаткичлари. Шаҳар хонадонлари модерн, лекин қишлоқ МФЙларда уй-жой сифати ва коммунал хизматлар паст. Тавсия: ёш оилалар учун ипотека ва қишлоқ хонадонлари модернизацияси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (27, 1, 27, 4, '10', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили', TRUE, 'SQB', 'Сунъий интеллектга асосланган "AI Advisor" мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни "Mobile" ва "Business" платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (28, 1, 28, 4, '3', 'Маҳалла ихтисослашуви', 'Маҳаллалар асосий ишлаб чиқариш йўналиши бўйича ихтисослашуви', 'Жами: 70 та ихтисослашган МФЙ | Чорвачилик: 32 та МФЙ | Деҳқончилик: 21 та МФЙ | Савдо ва хизмат кўрсатиш: 12 та МФЙ | Кичик ишлаб чиқариш: 4 та МФЙ | Боғдорчилик: 1 та МФЙ', TRUE, 'Иқтисодиёт ва молия вазирлиги', 'Гиждувон кулолчилиги 2009 йилдан UNESCO рўйхатида. 200+ ҳунарманд устоз. 100 000+ туристик оқим/йил. Экспорт: Европа, АҚШ, Япония. Тавсия: кулолчилик эко-кластерини ривожлантириш — туризм + экспорт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (29, 1, 29, 4, '4', 'Маҳалла драйвер секторлари', 'Асосий драйвер секторлар: узумчилик, сабзавотчилик,  чорвачилик, енгил саноат', 'Жами: 4 та асосий драйвер сектор | Узумчилик: ~16 300 га — Ғиждувон майизи (UNESCO) | Сабзавотчилик: томорқа + очиқ ер| Чорвачилик: сут ва гўшт | Енгил саноат: тикувчилик, кулолчилик', TRUE, 'SQB', 'Узумчилик майдонлари кенглигидан (16 300 га) фойдаланиб, майиз қадоқлаш ва экспорт қилиш марказларини қуриш керак. Сабзавотчилик ва чорвачилик драйверлари асосида тайёр озиқ-овқат ишлаб чиқарувчи кластерларни шакллантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (30, 1, 30, 4, '5', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва банклар бўйича маҳалла тақсимоти', 'Жами: 2026 йил 700 лойиҳа амалга оширилади | Иш ўринлари: 1 400 та | Жами маҳаллалар: 70 та | Маҳалла банкирлари: 18 та (6 аёл, 12 эркак) — ҳар лойиҳага масъул | Ўзсаноатқурилишбанк (SQB): 190 та лойиҳа | Миллий банк: 130 та лойиҳа | Агро банк: 100 та лойиҳа | Ҳамкор банк: 80 та лойиҳа | Халқ банки: 70 та лойиҳа | Инфинбанк: 60 та лойиҳа | Микрокредитбанк: 70 та лойиҳа | Лойиҳалар умумий қиймати: 70 млрд сўм | Банк кредити улуши: 49 млрд сўм', TRUE, 'Марказий банк', 'Ғиждувондаги 70 МФЙда 700 та микролойиҳа режалаштирилган — умумий қиймати 70 млрд сўм, шундан банк кредити 49 млрд сўм (70%). 18 та маҳалла банкири (6 аёл, 12 эркак) ҳар бир лойиҳани бошидан охиригача кузатиб боради. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа амалга оширилишини мониторинг; (4) тадбиркорларга молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (31, 1, 31, 4, '8', '«Ҳар бир оила — тадбиркор» дастури', '', 'Жами: Оилавий тадбиркорлик учун имтиёзли кредит | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3-6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (32, 1, 32, 4, '9', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача| Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Ғиждувонда аёллар тадбиркорлиги потенциали юқори (тикувчилик, кулолчилик, оилавий боғдорчилик, сут маҳсулотлари). Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (33, 1, 33, 4, NULL, 'Ишсизлик юқори маҳаллалар — SQB режаси', 'Ишсизлик даражаси юқори бўлган маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Жами: 5 та маҳалла / 416 нафар ишсиз | Гулистон: 82 нафар (6,7%) | Мустақиллик: 94 нафар (6,6%) | Халқобод: 86 нафар (6,3%) | Қўрғон: 70 нафар (6,3%) | Ростгўй: 84 нафар (5,9%) | Микро лойиҳалар сони: 138 та | Умумий ажратиладиган сумма: 5,67 млрд сўм', TRUE, 'SQB', '5 та маҳаллада 416 нафар ишсиз аниқланган. SQB режаси: ёшлар бизнесда (40% ёшлар) ва HAMROH аёллар (55% аёллар, 45% эркаклар) дастурлари орқали кредит маҳсулотлари тақдим этиш. Жами 138 та микролойиҳа, 5,67 млрд сўм ажратилади. Маҳалла лойиҳаси доирасида ҳар бир маҳаллага индивидуал бизнес-режа тузилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (34, 1, 34, 5, NULL, 'Туризм потенциали ва UNESCO мероси', 'Тарихий ёдгорликлар, ҳунармандчилик мактаби ва туризм инфратузилмаси', 'Жами: 4 та туризм йўналиши | Биринчи йўналиш: Кулолчилик ва ҳунармандчилик | Иккинчи йўналиш: Агротуризм | Учинчи йўналиш: Тарихий мерос | Тўртинчи йўналиш: Гастротуризм', TRUE, 'Хокимият', 'Бухорога яқинликдан транзит оқими сифатида фойдаланиб, йўл бўйи 24/7 хизмат кўрсатиш инфратузилмасини тезкор ривожлантириш керак. ЮНЕСКО кулолчилик мактаби ва гастротуризм негизида сайёҳларни туманда кўпроқ олиб қолувчи яхлит туристик пакетларни жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (35, 1, 35, 5, '1', 'Меҳмонхоналар сони', 'Туман ҳудудидаги меҳмонхоналар ва ўринлар сони (2025→2026 режа)', 'Жами: 21 та меҳмонхона (2026 режа) | 2025 йил факт: 20 та | Ўринлар сони (2025): 440 та | Ўринлар сони (2026 режа): 448 та | Ўсиш: +5%', TRUE, 'Хокимият', 'Меҳмонхоналар 20 та (2025) → 21 та (2026). Ўринлар 440 → 448. Ўсиш +5% — секин. Бухоро туристик потенциалига мос эмас. Тавсия: 5 йилда 30+ меҳмонхона ва 600+ ўрин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (36, 1, 36, 5, NULL, 'Сайёҳлар оқими (жами / маҳаллий / хорижий)', 'Туманга ташриф буюрган сайёҳлар таркиби ва 2026 йил режа', 'Жами: 779,8 минг сайёҳ (2026 режа) | 2025 йил факт: 673,1 минг сайёҳ | Маҳаллий сайёҳлар (2026): 651,1 минг (+17,0%) | Хорижий сайёҳлар (2026): 128,7 минг (+10,6%) | Жами ўсиш 2025→2026: +106,7 минг (+15,9%)', TRUE, 'stat.uz', 'Сайёҳлар оқими 2026 йилда 779,8 минг кишига етади (+16% ўсиш). Маҳаллий сайёҳлар улуши юқори (651 минг, 84%), хорижий сайёҳлар 128,7 минг (16%). Тавсия: 2027 йилгача 1 млн чегарасидан ўтиш учун Silk Road бренди, янги меҳмон уйлари, кулолчилик маркази учун махсус экскурсия пакетлари ва Бухоро шаҳридан 51 км яқинликдан фойдаланиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (37, 1, 37, 5, '5', 'Туризм хизматлари экспорти', 'Туризм соҳасидан валюта тушуми (млн АҚШ $)', '2021: 8.5 | 2022: 14.2 | 2023: 22.4 | 2024: 31.7 | 2025: 36.8 (млн $)', TRUE, 'stat.uz', 'Туризм экспорти 2021 йилдаги 8,5 млн $ дан 2025 йилга 36,8 млн $ га ўсди (4,3 баравар). 2024→2025 +15,9%. Барқарор ўсиш тренди — Ўзбекистон бўйича умумий ўсиш билан мос. Тавсия: 2027 йилгача 50 млн $, кулолчилик мактаби, агротуризм ва меҳмон уйлари тармоғи орқали.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (38, 1, 38, 5, '7', 'Қуёш энергияси ва ишлаб чиқариш', 'Қуёш нурлари фаол ҳудуд — қайта тикланувчи энергетика салоҳияти', 'Жами: 300+ қуёшли кун/йил | Йўналиш: қуёш панеллари | Имконият: саноат корхоналари учун арзон электр | Уй хўжаликлари учун қуёш сув иситгич дастури | Инвестиция: $10-30 млн/лойиҳа', TRUE, 'Энергетика вазирлиги', 'Йилига 300 қуёшли кун мавжудлигидан фойдаланиб, саноат корхоналарини арзон электр билан таъминлаш учун 10-30 миллион долларлик қуёш станциялари лойиҳаларига инвесторларни тўғридан-тўғри жалб қилиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (39, 1, 39, 6, '1', 'Иқтисодий ўсиш — рекорд даражада', '2025 йил барча секторларда рекорд ўсиш кузатилмоқда. ML модели 2027 йилгача мусбат тренд башорат қилади.', 'Жами: +118,5% Саноат 2025 | Саноат 2025: 3 317 млрд сўм | 2026 прогноз: 3 752 млрд сўм | 2027 прогноз: 4 187 млрд сўм | Ўсиш %: +26,2 | Хизматлар: +121,9% | Инвестиция: +105,2%', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Иқтисодий ўсиш — рекорд +118,5%, лекин база юқори. 2026-2027 учун 8-12% реалистик. Диверсификация керак — саноат + қайта ишлаш + хизматлар.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (40, 1, 40, 6, '3', 'Инфратузилма', 'Канализация ва ички йўллар ҳолати етарли даражада эмас. JICA/EBRD/ADB билан ҳамкорлик орқали масалани ечимини топиш зарур.', 'Жами: 5 та муаммо | Канализация: 4% | Ички йўллар: 60% | Суғориш йўқотиш: 35-40% | Электр узилиш: 2,3/ой | Ичимлик сув: 77%', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Канализация 4% ва ички йўллар 60% — етарли даражада эмас. Электр узилиши ойига 2,3 марта. Халқаро молия институтлари (JICA, ADB, AIIB) билан ҳамкорлик пакети зарур. 2027 га канализация 15%, ички йўллар 75% — реалистик мақсад.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (41, 1, 41, 6, '6', 'Туризм — тўлиқ фойдаланилмаган потенциал', 'Бухоро шаҳрига 51 км яқинлик, UNESCO кулолчилик мактаби, агротуризм (узумзор/майиз) ва маҳаллий зиёратгоҳлар — туризм оқимини кўпайтириш мумкин.', 'Жами: 780 минг сайёҳ (2026 режа) | 2025 йил факт: 673 минг сайёҳ | Хорижий сайёҳлар (2026): 129 минг | Маҳаллий сайёҳлар (2026): 651 минг | Туризм экспорти: 36,8 млн АҚШ$ | Бухорогача: 51 км | UNESCO статуси: Гиждувон кулолчилик мактаби (2009 йилдан)', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Туризм оқими 2025 да 673 минг → 2026 режа 780 минг (+16%). Хорижий сайёҳлар 116 → 129 минг, экспорт 36,8 млн $ (+16%). Асосий драйвер — Бухоро шаҳрига 51 км масофа, UNESCO кулолчилик мактаби, агротуризм ва зиёратгоҳлар. Тавсия: 2027 йилгача 1 млн сайёҳ ва 50 млн $ экспорт — меҳмон уйлари тармоғини кенгайтириш, кулолчилик устахоналарига доимий экскурсия маршрутлари ва йўл бўйи 24/7 сервис марказлари.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (42, 1, 42, 6, '7', 'SQB стратегик ҳамкорлик', 'Комплекс пакет: халқаро кредит (JICA) + Хорижий молия институтлари линиялари + лойиҳалар фабрикаси + агрокластер. Ҳамкорлик ҳажми ошиши зарур.', 'Жами: SQB ва ҳамкор банклар стратегик пакети | Иштирокчи банклар: SQB ва бошқа тижорат банклари | «Ҳар бир оила — тадбиркор»: 18% ставка, 300 млн сўмгача | HAMROH хотин-қизлар: 100 млн сўмгача гаровсиз | Микролойиҳалар йиллик режа: 700 та лойиҳа / 1 400 иш ўрни', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Маҳалла банкирлари орқали ҳар бир МФЙга индивидуал ёндашув, муваффақиятли тадбиркорларни намуна сифатида тарғиб қилиш ва йирик халқаро молиявий институтлар билан ҳамкорликни кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (2, 1, 'shofirkon', 'Шофиркон', 'Шафиркан', 'Shofirkon', '', 'shofirkon.json', TRUE, NULL, NULL, 74, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (43, 2, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, қишлоқ хўжалиги, қурилиш ва бозор хизматлари ҳажми + ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 1 220,0 млрд сўм (+4.2%) | Қишлоқ хўжалиги: 4 397,8 млрд сўм (+5.6%) | Қурилиш: 977,0 млрд сўм (+13.6%) | Бозор хизматлари: 1 237,6 млрд сўм (+13.6%)', TRUE, 'SQB', 'Жами ҳажм ≈ 7,83 трлн сўм. Қишлоқ хўжалиги жуда устун (56%), аграрлик юқори. Қурилиш ва хизматлар +13,6%. Тавсия: озиқ-овқат қайта ишлаш кластерлари (ун, ёғ, сут) орқали аграр сектордан қўшимча қиймат олиш ва хизматлар улушини ошириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (44, 2, 2, 1, '8', 'Устувор 4 та соҳа', 'Асосий устувор соҳалар рейтинги ва асослама', 'Жами: 4 та устувор соҳа | 1-ўрин Енгил саноат: тўқимачилик ва тикувчилик кластери, тарихий устунлик | 2-ўрин Хизмат кўрсатиш: савдо, транспорт, молиявий хизматлар | 3-ўрин Туризм ва ҳунармандчилик: Гиждувон кулолчилик мактаби (UNESCO мероси) | 4-ўрин Қишлоқ хўжалиги: мевачилик, узумчилик — экспорт салоҳияти', TRUE, 'SQB', '4 та устувор соҳа: 1) Енгил саноат — тўқимачилик/тикувчилик кластери; 2) Хизмат кўрсатиш — савдо, транспорт, молиявий хизматлар; 3) Туризм/ҳунармандчилик — UNESCO кулолчилик мароси; 4) Қ/х — мевачилик, узумчилик. Тавсия: ҳар соҳа бўйича 5-8 та флагман лойиҳани 3 йил ичида амалга ошириш орқали 3 000+ янги иш ўрни яратиш, қўшимча қиймат занжирини чуқурлаштириш ва экспорт ҳажмини 2 баравар ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (45, 2, 3, 1, '2', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', '2021: 988 | 2022: 810.3 | 2023: 1022.3 | 2024: 1104.1 | 2025: 1220 (млрд сўм)', TRUE, 'stat.uz', 'Саноат маҳсулотлари ишлаб чиқариш 5 йилда 988 → 1 220 млрд сўм (+23%). 2022 йилда 810 га тушиб, сўнг тикланди. Ўсиш секин, лекин барқарор. Тавсия: озиқ-овқат қайта ишлаш заводларини (ун, ёғ, сут) кенгайтириш ва қурилиш материаллари секторини ривожлантириш орқали ўсишни 10%+ га кўтариш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (46, 2, 4, 1, '3', 'Маҳаллий бюджет', 'Маҳаллий бюджет ҳажми', '2023: 90.3 | 2024: 103.9 | 2025: 142.5 (млрд сўм)', TRUE, 'Хокимият', 'Маҳаллий бюджет 2023→2025 да 90,3 → 103,9 → 142,5 млрд сўм, 2 йилда +58%, 2024→2025 да +37,2% — вилоятдаги энг юқори суръат. Сабаб: экспорт +123,6%. Тавсия: тушумларни сақлаш учун инвестиция ва экспортни рағбатлантириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (47, 2, 5, 1, '4', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми', '2021: 278.3 | 2022: 354.6 | 2023: 316.0 | 2024: 543.6 | 2025: 690.9 (млрд сўм)', TRUE, 'Марказий банк', 'Кредит 2021→2025: 278 → 691 млрд сўм — 2,48 марта. Жами 5 йилда 2 183 млрд. 2024→2025 +27% ўсиш. NPL 0,8%. Тавсия: SQB улушини 65% дан 75% га чиқариш — мева қуритиш кластерига 120 млрд сўм.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (48, 2, 6, 1, '9', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Жами: 44 балл (100 дан) — ўрта фаоллик | 2024 йил ўртача: 40 балл | 2025 йил ўртача: 44 балл (+10% ўсиш) | Энг фаол ой: Май 2025 йил — 60 балл | Энг суст ой: Декабр 2024 йил — 20 балл | Мавсумийлик: баҳор-ёз юқори, қиш паст', TRUE, 'SQB', 'Google Trends 44/100 — ўрта фаоллик. Гиждувондан паст (50). 2024 да 40 → 2025 да 44 (+10%). Тавсия: ҳудудий брендинг ва туризм маркетинги орқали қизиқишни ошириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (49, 2, 7, 2, '1', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2023: 48.6 | 2024: 50.1 | 2025: 66.5 (%)', TRUE, 'stat.uz', 'Ичимлик сув 2023 да 48,6% → 2025 да 66,5% — 2 йилда +17,9 п.п. яхши ўсиш. Лекин Гиждувондан паст (77%) ва қишлоқ МФЙларда 40% тоза сувсиз. Тавсия: AIIB Bukhara Water Supply Phase II лойиҳасига қўшилиш — 3 йилда 90% га етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (50, 2, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Туман ички йўлларининг таъмирланганлик даражаси', '2023: 18.0 | 2024: 20.0 | 2025: 22.0 (%)', TRUE, 'Узавтойул', 'Ички йўллар таъмирланиш даражаси 2023: 18% → 2024: 20% → 2025: 22% — барқарор ўсиш +4 б.п. 2 йилда. Тавсия: таъмирлаш суръатини сақлаш ва қишлоқ йўлларига кўпроқ маблағ йўналтириш, 2026 да 25%, 2028 да 35% га етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (51, 2, 9, 2, '3', 'Оқава сув билан таъминланганлик (%)', 'Канализация ва оқава сув тармоғи қамрови', '2023: 0.0 | 2024: 0.4 | 2025: 2.4 (%)', TRUE, 'stat.uz', 'Канализация қамрови 2023: 0% → 2024: 0,4% → 2025: 2,4% — ўсиш суръати юқори, лекин абсолют даража жуда паст (вилоятдаги энг ёмони). Тавсия: халқаро молиявий институтлар (JICA/ВБ/АТБ) ҳамкорлигида махсус лойиҳа ишга тушириш, 2027 йилгача 15% гача етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (52, 2, 10, 2, '4', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳоли жамоат транспортидан фойдаланиш даражаси', '2023: 7.0 | 2024: 7.0 | 2025: 8.0 (%)', TRUE, 'Узавтойул', 'Жамоат транспорти 2023 да 7% → 2025 да 8% — жуда секин. Қишлоқ аҳолиси учун хусусий транспорт асосий. Тавсия: автобус парки янгилаш ва қишлоқ йўналишларини кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (53, 2, 11, 2, '5', 'Электр таъминоти сифат даражаси (%)', 'Электр тармоғининг узилишсиз ишлаш ва сифат кўрсаткичи', '2023: 54 | 2024: 51 | 2025: 49 (%)', TRUE, 'Энергетика вазирлиги', 'Электр сифати 2023 да 54% → 2025 да 49% — пасайиш тренди. Узилишлар ошмоқда. Тавсия: Nur Bukhara Solar (500 МВт) лойиҳасига интеграция ва тармоқ модернизацияси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (54, 2, 12, 2, '7', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ер фонди тоифалар бўйича тақсимоти', 'Жами: 371 894 га ер майдони | Қишлоқ хўжалиги: 323 456 га | Ўрмон фонди: 44 669 га | Сув фонди: 1 873 га | Саноат/транспорт: 1 298 га | Тарихий-маданий: 343 га | Аҳоли пунктлари: 156 га | Захира ерлар: 58 га', TRUE, 'Кадастр', 'Eр ресурсларини инвентаризация килиш ва самарали ишлатиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (55, 2, 13, 2, NULL, 'Музлаткич ва омборхоналар', 'Туман музлаткич ва омбор инфратузилмаси (01.01.2025)', 'Жами: 3 та омбор / 800 тонна сиғим | Совуткичли омборлар: 2 та (400 тонна) | Оддий омборлар: 1 та (400 тонна)', TRUE, 'Хокимият', 'Шофирконда совуткичли сиғимлар атиги 400 тонна — Ғиждувондан 18,5× кам. Сақлаш инфратузилмаси заиф. Тавсия: 2026-2027 йилларда камида 1 000-1 500 тонна қўшимча совуткич сиғимини яратиш, агро қайта ишлаш кластерларига боғлаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (56, 2, 14, 2, '8', 'Мактабгача таълим қамрови', '3-7 ёшгача болаларни МТТга қамраб олиш даражаси', 'Жами: 87,6% қамров даражаси | 3-7 ёшли болалар: 15 426 та | Жами МТТ сони: 283 та | Давлат МТТ: 48 та | ДХШ: 17 та | Оилавий: 218 та | Қамраб олинган: 13 519 та', TRUE, 'stat.uz', 'МТТ қамрови 87,6% — Гиждувондан юқорироқ (85,2%). 15 426 болага хизмат, 283 та МТТ. Яхши натижа. Тавсия: қишлоқ МФЙларда оилавий МТТ сонини кенгайтириш — 95% га етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (57, 2, 15, 2, '9', 'Соғлиқни сақлаш тизими', 'Тиббий ташкилотлар, ўринлар ва ходимлар сони', 'Жами: 25 та тиббий ташкилот | Стационар ўринлар: 364 та (301 бюджет + 63 бюджетдан ташқари) | Жами штат: 1 965 бирлик | Врачлар: 385 та | Ўрта тиббий ходим: 1 017 та | Кичик тиббий ходим: 270 та', TRUE, 'stat.uz', '25 та тиббий ташкилот, 364 стационар ўрин (301 бюджет + 63 бошқа). Гиждувондан камроқ (34 та, 606 ўрин). Аҳолига нисбатан етарлироқ. Тавсия: канализация (2,4%) сабабли касалланиш хавфи — санитария инвестицияси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (58, 2, 16, 2, '11', 'Агрозона харитаси', 'Туман қишлоқ хўжалик зоналари ва ихтисослашуви', 'Жами: 4 та асосий агрозона | Пахта етиштириш: марказий катта ҳудудлар (қизил зона) | Сабзавотчилик: кенг тарқалган (сариқ зона) | Боғдорчилик: шимолий ҳудудлар (яшил зона) | Чорвачилик: жанубий ва шарқий ҳудудлар (жигарранг зона)', TRUE, 'Кадастр', '4 та агрозона: пахта етиштириш (марказ, қизил зона), ғаллачилик, мевачилик, чорвачилик. Гиждувонда ҳам 4 та. Тавсия: мева қуритиш ва сабзавот учун 1-2 та янги агрозона очиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (59, 2, 17, 3, '9', 'Меҳнат ресурслари (минг)', 'Жами меҳнат ресурслари сони', '2021: 82.0 | 2022: 84.0 | 2023: 86.1 | 2024: 88.2 | 2025: 90.7 (минг киши)', TRUE, 'stat.uz', 'Меҳнат ресурслари 2021 йилдаги 82,0 минг кишидан 2025 йилга 90,7 минг кишига ўсди (+10,6%, йиллик ўртача +2,6%). Аграр секторга юқори боғлиқлик. Тавсия: (1) йилига 600-700 та янги иш ўрни; (2) озиқ-овқат қайта ишлаш заводлари; (3) фермер хўжаликларини доимий бандлик манбасига айлантириш; (4) аёллар учун HAMROH дастури.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (60, 2, 18, 3, NULL, 'Бандликни ошириш имкониятлари', 'Туманда бандликни ошириш учун мавжуд имкониятлар ва режалар', '2021: 61.4 | 2022: 62.9 | 2023: 64.4 | 2024: 66.0 | 2025: 67.9 (минг киши)', TRUE, 'stat.uz', 'Банд аҳоли 2021 йилдаги 61,4 минг кишидан 2025 йилга 67,9 минг кишига ўсди (+10,6%). Тавсиялар: (1) йилига 500-600 та янги иш ўрни; (2) озиқ-овқат қайта ишлаш заводлари; (3) HAMROH дастури орқали аёлларни жалб қилиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (61, 2, 19, 3, NULL, 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлар сони ва ишсизлик даражаси динамикаси', '2021: 7.8 | 2022: 7.0 | 2023: 5.1 | 2024: 4.5 | 2025: 2.1 (минг киши)', TRUE, 'Mehnat.uz', 'Ишсизлар сони 2021 йилдаги 7,8 минг кишидан 2025 йилга 2,1 минг кишига тушди — 5 йилда 73% қисқариш. Тавсиялар: (1) озиқ-овқат қайта ишлаш; (2) HAMROH дастури; (3) 2026 йилда 2,5% мақсад.', 2100, 3.4, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (62, 2, 20, 3, NULL, 'Камбағаллик кўрсаткичлари', 'Камбағал оилалар сони ва камбағаллик даражаси динамикаси', '2020: 5200 | 2021: 4650 | 2022: 4600 | 2023: 3200 | 2024: 2000 | 2025: 1650 (оила)', TRUE, 'stat.uz', 'Камбағал оилалар 2020 йилдаги 5 200 дан 2025 йилга 1 650 гача камайди (68% қисқариш). Тавсия: HAMROH дастури ва агро-микрокредит пакетлари орқали 2026 йилда 1 200 оилагача тушириш.', 1650, 3.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (63, 2, 21, 3, '15', '«Барқарор келажак» — ёшлар даромадини ошириш', '2026 йилда даромади ошириладиган ёшлар — мажмуавий чоралар бўйича тақсимот', 'Жами: 1 580 нафар (2026 режа) | Тадбиркорликка жалб қилиш: 1 240 нафар | Доимий ишга жойлаштириш: 145 нафар | Кредит ажратиш ҳисобига: 105 нафар | Қайта касбга ўқитиш: 90 нафар', TRUE, 'Хокимият', '«Барқарор келажак» дастури доирасида 2026 йилда ёшлар даромадини ошириш — мажмуавий ёндашув. Энг катта улуш (78%) тадбиркорликка жалб қилишга тегишли — бу узоқ муддатли барқарорлик учун асос. Тавсия: маҳалла банкирлари орқали ҳар бир ёшга индивидуал бизнес-режа тузиш, муваффақиятли стартапларга имтиёзли қайтар кредит, доимий ишга жойлаштириш сонини 1 000 нафаргача кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (64, 2, 22, 3, '16', 'Аёллар бандлиги ва даромадини ошириш', '2026 йилда даромади ошириладиган аёллар — чоралар бўйича тақсимот', 'Жами: 3 560 нафар (2026 режа) | Ўзини ўзи банд қилиш ҳисобига: 2 020 нафар | Доимий ишга жойлаштириш: 660 нафар | Тадбиркорликка жалб қилиш: 330 нафар | Қайта касбга ўқитиш ҳисобига: 310 нафар | Кредит ажратиш ҳисобига: 240 нафар', TRUE, 'stat.uz', '2026 йилда 3 560 нафар аёл даромадини оширишга йўналтирилган. Асосий драйвер — ўзини ўзи банд қилиш (2 020 нафар, 57%). Тавсия: HAMROH дастури ва қишлоқ жойларида оилавий бизнес инкубаторларини ташкил этиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (65, 2, 23, 3, '1', 'Аҳоли сони (минг)', 'Доимий аҳоли сони', '2023: 184.3 | 2024: 187.0 | 2025: 189.8 минг нафар', TRUE, 'stat.uz', 'Аҳоли 2023 да 184,3 минг → 2025 да 189,8 минг. Йилига +1,4%. Бухоро вилоятида 7-ўрин. Ёш аҳоли устун. Тавсия: йилига 3 000+ иш ўрни яратиш мажбурияти.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (66, 2, 24, 3, '2', 'Маҳаллалар сони', 'МФЙ (маҳалла фуқаролар йиғини) сони', '50 та', TRUE, 'SQB', '50 МФЙ — 8 шаҳарча + 13 қишлоқ ФЙ + субмаҳалла. Гиждувондан кичикроқ. Тавсия: маҳалла банкирлари сонини 12 → 30 га ошириш, ҳар МФЙ учун микрокредит офиси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (67, 2, 25, 3, '3', 'Оилалар сони', 'Жами оилалар сони', '43 000 та (≈43 минг оила)', TRUE, 'SQB', '43 000 оила — ўртача 4,4 киши/оила. Оилавий агробизнес (мева, тухум, сут) потенциали юқори. Тавсия: «Ҳар бир оила — тадбиркор» дастурида 3 000 оилага имтиёзли микрокредит.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (68, 2, 26, 3, '4', 'Хонадонлар сони', 'Жами хонадонлар сони', '36 300 та', TRUE, 'SQB', '36 300 хонадон. Гиждувонга нисбатан кам (69 800). Шаҳар хонадонлари модерн, лекин қишлоқ МФЙларда уй-жой сифати паст. Тавсия: ипотека ва қишлоқ хонадонлари модернизацияси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (69, 2, 27, 4, '10', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили', TRUE, 'SQB', 'SQB 4 та рақамли платформадан иборат экотизим яратган: Mobile (B2C), Business (B2B), AI Advisor (AI-асосидаги консалтинг). Ғиждувон ва Шофирконда 60%+ аҳолини қамраб олган. 2026 га 95% мақсад. Тавсия: қишлоқ МФЙларига масофавий терминаллар ва рақамли саводхонлик курслари.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (70, 2, 28, 4, '3', 'Маҳалла ихтисослашуви', 'Маҳаллалар асосий ишлаб чиқариш йўналиши бўйича ихтисослашуви', 'Жами: 39 та ихтисослашган МФЙ | Пахтачилик: 15 та МФЙ | Ғаллачилик: 10 та МФЙ | Чорвачилик ва сут маҳсулотлари: 8 та МФЙ | Қурилиш материаллари: 6 та МФЙ', TRUE, 'Иқтисодиёт ва молия вазирлиги', '39 та ихтисослашган МФЙ: пахтачилик 15, ғаллачилик 10, мева қуритиш 8, чорвачилик ва тикувчилик. Диверсификация кам. Тавсия: 5 йилда 2-3 та янги йўналиш қўшиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (71, 2, 29, 4, '4', 'Маҳалла драйвер секторлари', 'Асосий драйвер секторлар: пахтачилик, ғаллачилик, мева қуритиш, чорвачилик, тикувчилик', 'Жами: 4 та асосий драйвер сектор | Пахтачилик: 12 110 га | Ғаллачилик: 6 100 га | Мева қуритиш кластери | Чорвачилик: сут ва гўшт | Тикувчилик: Кулба МФЙ', TRUE, 'SQB', '5 та драйвер: пахтачилик (12 110 га), ғаллачилик (6 100 га), мева қуритиш, чорвачилик, тикувчилик. Қ/х устуворлиги юқори. Тавсия: мева қуритиш кластерини кенгайтириш ва тикувчиликни саноат даражасида ривожлантириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (72, 2, 30, 4, '5', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва банклар бўйича маҳалла тақсимоти', 'Жами: 2026 йил 490 лойиҳа амалга оширилади | Иш ўринлари: 980 та | Жами маҳаллалар: 50 та | Маҳалла банкирлари: 13 та — ҳар лойиҳага масъул | Ўзсаноатқурилишбанк (SQB): 133 та лойиҳа | Халқ банки: 98 та лойиҳа | Микрокредитбанк: 73 та лойиҳа | Агро банк: 65 та лойиҳа | Миллий банк: 40 та лойиҳа | Ҳамкор банк: 41 та лойиҳа | Инфинбанк: 40 та лойиҳа', TRUE, 'Марказий банк', 'Шофирконда 50 МФЙда 490 та микролойиҳа режалаштирилган — 13 та маҳалла банкири ҳар лойиҳани кузатади. Банкирлар: скоринг, кредит расмийлаштириш ёрдами, мониторинг ва молиявий маслаҳат. Тавсия: агро-кластер лойиҳаларга устувор эътибор, аёллар тадбиркорлигини HAMROH билан боғлаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (73, 2, 31, 4, '8', '«Ҳар бир оила — тадбиркор» дастури', '', 'Жами: Оилавий тадбиркорлик учун имтиёзли кредит | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3-6 ой', TRUE, 'Марказий банк', '70 та флагман лойиҳа дастурида Шофиркон улуши: мева қуритиш + пахта қайта ишлаш. Тавсия: моделни такрорлаш — оилавий тадбиркорлик + маҳалла банкири.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (74, 2, 32, 4, '9', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача| Компания кафиллиги: 70% | 2026-2027 бюджет: 2 трлн сўм, 6 000 лойиҳа', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. 2026-2027 учун 2 трлн сўм бюджет, 6 000 та лойиҳа режалаштирилган. Ғиждувон ва Шофирконда аёллар тадбиркорлиги потенциали юқори (тикувчилик, кулолчилик, оилавий боғдорчилик, сут маҳсулотлари). Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (75, 2, 33, 4, NULL, 'Ишсизлик юқори маҳаллалар — SQB режаси', 'Ишсизлик даражаси юқори бўлган маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Жами: 4 та маҳалла / 280 нафар ишсиз | Микро лойиҳалар сони: 95 та | Умумий ажратиладиган сумма: 3,8 млрд сўм', TRUE, 'SQB', 'Шофирконда 4 та маҳаллада юқори ишсизлик аниқланган. SQB ёшлар ва HAMROH дастурлари орқали 95 та микролойиҳа, 3,8 млрд сўм ажратиш режаси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (76, 2, 34, 5, '3', 'Қишлоқ хўжалиги қайта ишлаш саноати', 'Шофиркон агросаноат кластери — озиқ-овқат қайта ишлаш', 'Жами: 4 та янги қайта ишлаш заводи режаси | Йўналиш: сут, гўшт, ун, ёғ, консерва | Хом ашё: туман ўзи | Инвестиция: $50-80 млн | Иш ўринлари: 800-1 200 та | Экспорт: Россия, Қозоғистон', TRUE, 'SQB', '4 та янги қайта ишлаш заводи режаси — сут, гўшт, ун, ёғ, консерва. Айни устувор соҳалар 2026 Бухоро стратегиясида. Тавсия: кластер ёндашуви — ер + инфратузилма + кредит.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (77, 2, 35, 5, NULL, 'Туризм потенциали ва тарихий мерос', 'Тарихий объектлар, агротуризм ва туризм инфратузилмаси', 'Жами: 3 та асосий йўналиш | Тарихий объектлар: Шофиркон шаҳар маркази, масжид-мадрасалар | Туризм оқими 2026: 606 минг киши (+19%) | Агротуризм: пахтазор ва боғлар', TRUE, 'Хокимият', 'Шофиркон туризм потенциали — тарихий масжид-мадрасалар, агротуризм (пахта, боғ, чорва) ва Бухоро яқинлиги. Тавсия: (1) тарихий объектларни тиклаш; (2) пахта ҳосилини кўриш агро-маршрутлар; (3) меҳмонхона тармоғини кенгайтириш; (4) гастротуризм (маҳаллий таомлар).', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (78, 2, 36, 5, '7', 'Қуёш энергияси ва ишлаб чиқариш', 'Қуёш нурлари фаол ҳудуд — қайта тикланувчи энергетика салоҳияти', 'Жами: 300+ қуёшли кун/йил | Йўналиш: қуёш панеллари | Имконият: саноат корхоналари учун арзон электр | Уй хўжаликлари учун қуёш сув иситгич дастури | Инвестиция: $10-30 млн/лойиҳа', TRUE, 'Энергетика вазирлиги', '300+ қуёшли кун/йил. Nur Bukhara Solar (500 МВт) лойиҳасига интеграция мумкин. Арзон электр ва уй хўжаликлари учун қуёш сув иситгич. Тавсия: микро-тармоқ ва қуёш панели дастурлари.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (79, 2, 37, 6, '1', 'Экспорт — рекорд ўсиш драйвери', 'Экспорт +123,6% ўсиш — туманнинг асосий кучи. Мева қуритиш кластери ривожланмоқда.', 'Жами: +123,6% | Экспорт 2025: 12,3 млн $ | Прогноз 2027: 26,7 млн $ | Ўсиш: +20,3% | ML: +28,9% (инвестиция)', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Экспорт +123,6% — рекорд. Мева қуритиш ягона драйвер. Хавф: моно-экспорт. Тавсия: диверсификация — фармацевтика, озиқ-овқат, тикувчилик. 3 йилда экспорт 12 → 30 млн $.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (80, 2, 38, 6, '2', 'Қишлоқ хўжалиги — ортиқча концентрация', '60% улуш — жуда юқори. Диверсификация, қайта ишлаш ва кластерга айлантириш зарур.', 'Жами: 4 239 млрд | Улуши: 60% | Ўсиш: +113,4% | Пахта: 12 110 га | Ғалла: 6 100 га | Суғориладиган: 20 568 га', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Қ/х 60% — жуда юқори концентрация, вилоятда энг ортиқча. Хизматлар улуши 18% → 30% — 5 йилда реалистик. Тавсия: диверсификация стратегик устувор.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (81, 2, 39, 6, '3', 'Инвестиция — асосий хавф', 'Инвестиция ҳажми -4,1% пасайган — ягона манфий кўрсаткич. Инвест жалб дастури муҳим.', 'Жами: -4,1% | 2025 ҳажми: 165 млрд | Мақсад: +20% | FDI: йўқ | Халқаро лойиҳа: JICA/EBRD | Ҳамкорлик: 1 маркет', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Инвестиция -4,1% — ягона манфий кўрсаткич, стратегик хавф. Сабаб: FDI йўқ, ички инвестор кам. Тавсия: халқаро молия институтлари (ADB, AIIB, JICA) билан 100+ млн $ FDI дастури.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (82, 2, 40, 6, '4', 'Инфратузилма — вилоятдаги энг паст канализация', 'Канализация 2,4% — ҳалокатли даража. Бухоро минтақасида ADB/AIIB Water Supply лойиҳасига киритиш зарур.', 'Жами: 2,4% | Канализация: 2,4% | Ичимлик сув: 66,5% | Йўл асфальт: 22% | Газ: 92% | Электр: 97%', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Канализация 2,4% — вилоятдаги энг паст, мамлакатда қуйи 5%. Саломатлик ва экология хавфи ғоят юқори. Тавсия: AIIB Water Supply Phase II — 2028 га 25%.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (83, 2, 41, 6, '5', 'Бандлик — норасмий сектор 33,4%', 'Норасмий бандлик вилоятдаги энг юқори. Расмийлаштириш + микрокредит зарур.', 'Жами: 33,4% | Меҳнат ресурси: 84 500 | Расмий ишсизлик: 4,6% | Реал ишсизлик: 14,5% | Миграция: 7 300 | Ўрт маош: 2,3 млн', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Норасмий бандлик 33,4% — вилоятдаги энг юқори. Сабаб: пахтачилик мавсумий. Тавсия: расмийлаштириш + МЧЖ имтиёзи — йилига 3 000 ишчи.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (84, 2, 42, 6, '6', 'Фармацевтика ва озиқ-овқат — 2026 устувор', 'Бухоро вилояти стратегиясида Шофиркон 2026 йил учун фармацевтика ва озиқ-овқат йўналишлари танланган.', 'Жами: 2 устувор | Фармацевтика: янги | Озиқ-овқат: кластер | Пахта тозалаш: мавжуд | Ғишт заводи: 3 та | Шароб: 1 та', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Фармацевтика + озиқ-овқат — 2026 Бухоро стратегиясида устувор. Ҳозир мавжуд эмас. Тавсия: 2 та янги завод (фармацевтика + консерва) — 500 иш ўрни.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (85, 2, 43, 6, '7', 'Кичик бизнес — секинлашиш', '2023→2024 фаол корхоналар 1637 дан 1599 га тушган. Микрофирмалар қўллаб-қувватлаш зарур.', 'Жами: 1 599 | 2023 да эди: 1 637 | Йилда янги: 63 | Нетто: -38 | Тугатилган: ≈101 | Вилоят улуши: 7,2%', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'Кичик бизнес 2023→2024 да -38 нетто камайиш. Тугатилган ≈101. Сабаблар: инвестиция тушиши, норасмий рақобат. Тавсия: кичик бизнес фонди ва реструктуризация.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (86, 2, 44, 6, '8', 'SQB стратегик ҳамкорлик', 'Комплекс пакет: халқаро кредит (JICA) + Хорижий молия институтлари линиялари + лойиҳалар фабрикаси + агрокластер. Ҳамкорлик ҳажми ошиши зарур.', 'Жами: SQB ва ҳамкор банклар стратегик пакети | Иштирокчи банклар: SQB ва бошқа тижорат банклари | «Ҳар бир оила — тадбиркор»: 18% ставка, 300 млн сўмгача | HAMROH хотин-қизлар: 100 млн сўмгача гаровсиз | Микролойиҳалар йиллик режа: 700 та лойиҳа / 1 400 иш ўрни', TRUE, 'Туман таҳлил + Wikipedia + stat.uz', 'SQB ва ҳамкор тижорат банклари туман иқтисодиётини иккита устувор йўналишда қўллаб-қувватлайди: (1) оилавий ва микробизнес — «Ҳар бир оила — тадбиркор» дастури (300 млн сўмгача, 18% ставка) ҳамда HAMROH хотин-қизлар тадбиркорлиги (100 млн сўмгача гаровсиз кредит); (2) мунтазам микролойиҳалар амалиёти — йилига 700 та лойиҳа ва 1 400 та доимий иш ўрни. Тавсия: маҳалла банкирлари тармоғи орқали ҳар бир МФЙга индивидуал ёндашув ва халқаро молиявий институтлар (JICA, EBRD, ADB) билан ҳамкорликни кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (87, 2, 45, 5, '1', 'Меҳмонхоналар сони', 'Туман ҳудудидаги меҳмонхоналар ва ўринлар сони (2025→2026 режа)', 'Жами: 3 та меҳмонхона (2026 режа) | 2025 йил факт: 1 та | Ўринлар сони (2025): 68 та | Ўринлар сони (2026 режа): 84 та | Ўсиш: +200%', TRUE, 'Хокимият', 'Меҳмонхоналар 1 та (2025) → 3 та (2026 режа). Ўринлар 60 → 220. Жуда паст кўрсаткич. Тавсия: 5 йилда 10+ меҳмонхона ва йўл бўйи сервис марказлари.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (88, 2, 46, 5, NULL, 'Сайёҳлар оқими (жами / маҳаллий / хорижий)', 'Туманга ташриф буюрган сайёҳлар таркиби ва 2026 йил режа', 'Жами: 606,1 минг сайёҳ (2026 режа) | 2025 йил факт: 510,2 минг сайёҳ | Маҳаллий сайёҳлар (2026): 505,4 минг (+16,0%) | Хорижий сайёҳлар (2026): 100,7 минг (+35,2%) | Жами ўсиш 2025→2026: +95,9 минг (+18,8%)', TRUE, 'stat.uz', 'Сайёҳлар оқими 2026 йилда 606,1 минг кишига етади (+18,8% ўсиш). Хорижий сайёҳлар 35% ўсиш — катта потенциал. Тавсия: тарихий объектларни тиклаш, агротуризм маршрутларини яратиш, меҳмонхона тармоғини кенгайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (89, 2, 47, 5, '5', 'Туризм хизматлари экспорти', 'Туризм соҳасидан валюта тушуми (млн АҚШ $)', '2021: 4.6 | 2022: 7.7 | 2023: 12.2 | 2024: 17.3 | 2025: 20.3 (млн $)', TRUE, 'stat.uz', 'Туризм экспорти 2021 йилдаги 4,6 млн $ дан 2025 йилга 20,3 млн $ га ўсди (4,4 баравар). Ўсиш тренди ижобий. Тавсия: 2027 йилгача 30 млн $ — тарихий объектлар, агротуризм, меҳмонхона тармоғини кенгайтириш. Манба: тахминий ҳисоблаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
