INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (90, 3, 1, 1, '1', 'Шаҳарнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 9 410,4 млрд сўм (+24,2%) | Бозор хизматлари: 6 371 млрд сўм (+18,4%) | Саноат ўсиш суръати: 109,4% | Тармоқлар улуши: Қ/х 9,5%, Саноат 21,5%, Хизматлар 69% | Очилган корхоналар (2025): 619 та | Ёпилган корхоналар (2025): 140 та', TRUE, 'stat.uz', 'Саноатда юқори ўсиш кузатилаётгани сабабли қиймат занжирини чуқурлаштириш (тайёр маҳсулот улушини ошириш) керак. Хизматлар улуши катта бўлгани учун савдо-логистика ва сервис инфратузилмасига инвестицияни кучайтириш мақсадга мувофиқ. Саноат ва хизматлар юқори суръатда ўсаётгани учун кейинги босқичда логистика, кадрлар тайёрлаш ва энергия самарадорлигига йўналтирилган лойиҳаларни кучайтириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (91, 3, 2, 1, '1', 'Шаҳар иқтисодиётининг 4 та драйвери', 'Қўқон шаҳрининг устувор тармоқлари ва ривожланиш йўналишлари', 'Жами: 4 та устувор соҳа | 1-ўрин Савдо: савдо-логистика марказлари ва бозор инфратузилмаси | 2-ўрин Ишлаб чиқариш: енгил саноат, тўқимачилик ва тикувчилик | 3-ўрин Туризм: тарихий обидалар ва маданий туризм салоҳияти | 4-ўрин Хизматлар: молиявий, транспорт ва сервис хизматлари', TRUE, 'SQB', 'Устувор тармоқларни «бир-бирига боғланган кластер» шаклида ривожлантириш керак: ишлаб чиқариш + савдо + логистика + туризм сервиси. Ҳар бир тармоқ учун 1–2 та «тез натижа» берувчи лойиҳани молиялаштириб, бандлик ва тушумга таъсирини KPI орқали ойма-ой баҳолаш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (92, 3, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Шаҳарда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', '2021: 5145 | 2022: 5602.6 | 2023: 5886.6 | 2024: 7577.8 | 2025: 9410.4 (млрд сўм)', TRUE, 'stat.uz', 'Динамика ижобий ва тезлашаётгани учун ишлаб чиқариш қувватларини модернизация қилиш, энергия самарадорлигини ошириш ва экспортбоп маҳсулот улушини кенгайтириш керак. Ўсиш суръати барқарорлигини сақлаш учун хомашё таъминоти ва транспорт логистикасида узилиш хавфларини олдиндан бошқариш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (93, 3, 4, 1, '1', 'Ажратилган кредитлар', 'Шаҳар иқтисодиёти учун ажратилган жами кредитлар ҳажми', '{''type'': ''yearly_credits'', ''years'': [2021, 2022, 2023, 2024, 2025], ''values'': [1107, 637, 1062, 1149, 3169], ''total'': 7124, ''unit'': ''млрд сўм''}', TRUE, 'Марказий банк', 'Кредитлар ҳажми кескин ошгани учун уларни ишлаб чиқариш, экспорт ва юқори қўшимча қиймат берувчи лойиҳаларга мақсадли тақсимлаш керак. Эрта огоҳлантириш тизимини кучайтириш ва кредитларни тармоқлар бўйича мунтазам таҳлил қилиб бориш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (94, 3, 5, 1, '1', 'Google Trends иқтисодий фаоллик', 'Шаҳар иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Жами: 65 балл (100 дан) — юқори фаоллик | 2024 йил ўртача: 58 балл | 2025 йил ўртача: 65 балл (+12% ўсиш) | Энг фаол ой: Апрел 2025 йил — 82 балл | Энг суст ой: Январ 2024 йил — 31 балл | Мавсумийлик: баҳор-ёз юқори, қиш паст', TRUE, 'SQB', 'Google Trends 65/100 — юқори фаоллик. 2024 да 58 → 2025 да 65 (+12%). Қўқон Ўзбекистоннинг 4-йирик шаҳри сифатида барқарор қизиқиш ўсишини кўрсатмоқда. Тавсия: туризм ва инвестиция контентини рақамли каналларда кучайтириш, шаҳар брендини ривожлантириш орқали қидирув фаоллигини янада оширш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (95, 3, 6, 1, '1', '«Қўқон ЭИЗ» махсус саноат зонаси', 'Қўқон шаҳри балансидаги саноат зоналари мавжуд эмас — Учкўприк туманда Қўқон эркин иқтисодий зона ташкил этилган', 'Жами: Қўқон ЭИЗ Қўқон эркин иқтисодий зона | ВМ қарори: 23.12.2024 йил №846-сон | Жами тадбиркорлик субъектлари: 117 нафар | Қўқондан кўчиб ўтган корхоналар: 80+ та | Асосий корхоналар: Great Kokand, Beton Plita, Euro Cable Industry, Quantity Glass, Glorius Business | Муаммо: кўрсаткичлар Учкўприк статистикасида акс этмоқда | Таклиф: Махсус саноат зонасини Қўқон шаҳар заҳирасига ўтказиш | Кутилаётган натижа: 2,5 млрд $ хорижий инвестиция, 10 000+ иш ўрни', TRUE, 'Хокимият', 'Учкўприк туман ҳудудидаги «Қўқон ЭИЗ» Қўқон эркин иқтисодий зонада фаолият кўрсатувчи 117 та тадбиркорлик субъектининг 80 тадан ортиғи Қўқон шаҳридан кўчиб ўтган корхоналар. Уларнинг иқтисодий кўрсаткичлари ва солиқ тушумлари ҳозирда Учкўприк туман ҳисоботларида акс этмоқда. Ерни Қўқон шаҳар заҳирасига ўтказиш ва юридик манзилни Қўқон номидан аукционга чиқариш орқали 2,5 млрд долларлик хорижий инвестиция ва 10 минг нафардан зиёд иш ўрни шаҳар тасарруфида қолишига эришилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (96, 3, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2021: 98.5 | 2022: 99.0 | 2023: 99.2 | 2024: 95.5 | 2025: 99.3 (%)', TRUE, 'Сув хўжалиги', 'Ичимлик суви қамрови 99,3% — юқори. Энди сув сифатини назорат қилиш ва тармоқ йўқотишларини камайтириш устувор. Эски қувурларни босқичма-босқич алмаштириш ва сув ҳисоблагичларини 100% жорий этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (97, 3, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Қўқон шаҳри ички йўлларининг таъмирланганлик даражаси', '2023: 62.6 | 2024: 69.9 | 2025: 100.0 (%)', TRUE, 'Йўл хўжалиги', 'Йўллар 100% таъмирланган — муҳим натижа. Энди сифатни сақлаш учун йиллик профилактик таъмир режасини тузиш ва оғир транспорт учун алоҳида маршрутлар белгилаш керак. Янги қурилиш ҳудудларида йўл тармоғини олдиндан режалаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (98, 3, 9, 2, '2', 'Электр таъминоти сифат даражаси (%)', 'Электр узилишлари ва тармоқ модернизация ҳолати', 'Жами: 1–1,1 марта/ой (ўртача узилиш) | Трансформаторлар: 35% эскирган | Линиялар: 25% алмаштириш керак', TRUE, 'Электр тармоқлари', 'Электр таъминоти сифатини ошириш учун биринчи босқичда эски трансформатор ва линияларни мақсадли янгилаш керак. Саноат ва хизмат нуқталари жойлашган ҳудудларда модернизацияга устуворлик бериш барқарор электр таъминотини таъминлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (99, 3, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Шаҳар ер фонди тузилмаси', 'Жами: Ер фонди тузилмаси | Тарихий-маданий аҳамиятга молик ерлар: 76 га | Ўрмон фонди: 27 га | Қишлоқ хўжалигига мўлжалланган ерлар: 1 095 га', TRUE, 'Кадастр', 'Ер тоифалари бўйича балансдан келиб чиқиб, туризм ва сервис лойиҳаларини тарихий ҳудудларга мос режалаштириш, қишлоқ хўжалиги ерларида эса юқори қўшимча қийматли йўналишларни ривожлантириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (100, 3, 11, 2, '2', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳолини жамоат транспорти билан қамраб олинганлик даражаси', '2023: 79 | 2024: 88 | 2025: 100 (%)', TRUE, 'Хокимият', '100% қамровга эришилгани муҳим натижа. Энди сифатни ошириш босқичига ўтиш керак: электр автобуслар паркини кенгайтириш, маршрутлар оптималлаштириш ва ҳафтада 1–2 кун «машинасиз кун» акциясини жорий этиб, экологик транспорт маданиятини шакллантириш тавсия этилади. GPS мониторинг ва электрон тўлов тизимини жорий қилиш орқали йўловчилар қулайлигини янада ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (101, 3, 12, 2, '2', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик', '2021: 83.9 | 2022: 84.6 | 2023: 86.0 | 2024: 87.1 | 2025: 87.9 (%)', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', 'Қамров барқарор ўсмоқда, энди эътиборни сифат ва ҳудудий тенгликка қаратиш керак. Қамров паст ҳудудларда қўшимча қувват яратиш ва давлат-хусусий шериклик асосида янги МТМ лойиҳаларини қўллаб-қувватлаш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (102, 3, 13, 3, '3', 'Меҳнат ресурслари', 'Жами меҳнат ресурслари сони — йиллик динамика', '2021: 143.7 | 2022: 148.3 | 2023: 154.6 | 2024: 160.5 | 2025: 165.8 (минг киши)', TRUE, 'stat.uz', 'Бандликни ошириш учун маҳалла даражасида талаб юқори бўлган касблар рўйхатини шакллантириб, шу йўналишларда қисқа муддатли ўқув ва амалиёт дастурларини кенгайтириш керак. Айниқса, кичик хизматлар, савдо ва ишлаб чиқаришда тез иш ўрни яратадиган лойиҳаларни қўллаб-қувватлаш самарали бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (103, 3, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Иш ўрни яратиш ва меҳнат бозори резервлари', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 108,5 минг киши (+3,1%) | Қайтган мигрантлар (2025): 2 570 киши (+33,3%) | Норасмий секторда бандлик (2021): 41 183 киши', TRUE, 'Mehnat.uz', 'Бандликни ошириш учун маҳалла даражасида талаб юқори бўлган касблар рўйхатини шакллантириб, шу йўналишларда қисқа муддатли ўқув ва амалиёт дастурларини кенгайтириш керак. Айниқса, кичик хизматлар, савдо ва ишлаб чиқаришда тез иш ўрни яратадиган лойиҳаларни қўллаб-қувватлаш самарали бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (104, 3, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси ва ишсизлар сони', 'Жами: Ишсизлик кўрсаткичлари | Расмий ишсизлик (2025): 4,5% | Ишсизлар сони (2025): 5 165 киши | Ишсизлик тренди: 7,3% → 6,9% → 6,1% → 5,6% → 4,5% | Мақсад: 2026 йил охиригача 2,9% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни йил охиригача 2,9% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим. Ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш зарур.', 5165, 4.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (105, 3, 16, 3, '3', 'Камбағаллик даражаси динамикаси', 'Камбағаллик даражаси (%) — 5 йиллик динамика; 2025: 2 978 камбағал оила; 2026 мақсад — 1%', '2021: 10,1 | 2022: 8,7 | 2023: 7,2 | 2024: 6,6 | 2025: 4,2 (%)', TRUE, 'stat.uz', 'Камбағаллик 2021 йилдаги 10,1% дан 2025 йилда 4,2% га тушди (2 978 камбағал оила) — 4 йилда 2,4 баробар камайди. Мақсад: 2026 йил охиригача 1% га тушириш. Бунинг учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. Ижтимоий ёрдамни иш билан ва микролойиҳалар билан боғлаш, барқарор даромад манбаини яратишга эътиборни қаратиш зарур.', 2978, 4.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (106, 3, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '«Барқарор келажак» дастури — 2026 йилда ёшлар даромадини ошириш режаси', 'Жами: 1 489 нафар ёшлар даромади ошириладиган (2026 режа) | Доимий ишга жойлаштириш: 596 нафар | Тадбиркор жалб қилиш: 205 нафар | Кредит ажратиш ҳисобига: 102 нафар | Қайта касбга ўқитиш: 586 нафар', TRUE, 'stat.uz', 'Ёшлар даромадини ошириш учун дуал таълим, биринчи иш ўрнига субсидия ва талаб юқори касблар бўйича тезкор қайта тайёрлаш дастурларини кучайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (107, 3, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар бандлиги ва даромадини ошириш — 2026 йил режаси', 'Жами: 2026 йил режаси | Иш жойларига жойлаштириш: 4 500 нафар (доимий ва мавсумий) | Хотин-қизлар ўқитиш: 850 нафар (касб-ҳунар ва тадбиркорлик) | Раҳбар аёллар улуши: 38% | Олий таълимда қизлар улуши: 55% | Контракт тўланадиган қизлар: 15 нафар', TRUE, 'Mehnat.uz', 'Аёллар бандлигини ошириш учун имтиёзли молиялаштириш, мос иш режими (масофавий/ярим ставка) ва маҳалла кесимида касбга йўналтириш дастурларини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (108, 3, 19, 3, '3', 'Қўқон шаҳридаги олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', 'Жами: 2 та ОТМ, 29 499 та талаба | Қўқон давлат университети: қуввати 9 360 ўрин, талаба сони 16 918 | Қўқон университети: қуввати 6 000 ўрин, талаба сони 12 581 | Жами ўрин: 15 360 та, жами талаба: 29 499 та | Талабалар сони ўрин сонидан 14 139 тага кўп', TRUE, 'Хокимият', 'Иккала университетда қувватдан 1,9 баробар кўп талаба таҳсил олмоқда (15 360 ўринга 29 499 талаба). Бу инфратузилмага жиддий босим. Тавсия: (1) масофавий таълим улушини 30% гача ошириш; (2) хусусий секторда янги кампуслар қуришга инвесторларни жалб қилиш; (3) университетларни шаҳар иқтисодиётига интеграция қилиш — талабаларни маҳаллий корхоналарда амалиётга жалб этиш ва стартап инкубаторлар очиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (109, 3, 20, 3, '3', 'Қўқон шаҳридаги техникумлар', 'Касб-ҳунар таълим муассасалари, ўқувчилар ва қувватлар', 'Жами: 8 та техникум, 8 202 та ўқувчи | Абу Али ибн Сино жамоат саломатлиги: 2 505 (қувват 2 520) | Рақамли технологиялар: 311 (қувват 575) | Педагогика: 923 (қувват 1 000) | 1-сон техникум: 713 (қувват 400, 178%) | 2-сон техникум: 828 (қувват 585, 142%) | 3-сон техникум: 281 (қувват 240) | 4-сон техникум: 1 692 (қувват 800, 212%) | 5-сон техникум: 949 (қувват 1 000) | Умумий қувват: 7 120, умумий ўқувчи: 8 202 (115%)', TRUE, 'Хокимият', '8 та техникумда 8 202 ўқувчи таълим олмоқда. 4-сон техникум қувватидан 2 баробар кўп юкланган (800 га 1 692). Рақамли технологиялар техникуми эса атиги 54% банд — бу йўналишга талабни ошириш зарур. Тавсия: (1) рақамли технологиялар техникумини СИ ва IT йўналишида кенгайтириш; (2) қувват ортиқча юкланган техникумларда кечки ва ҳафта охири смена очиш; (3) битирувчиларни маҳаллий корхоналарга мақсадли жойлаштириш тизимини жорий этиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (110, 3, 21, 4, '4', 'Сунъий интеллект куни ва СИ ўқитиш дастури', 'Ҳафталик СИ куни ва 4 босқичли ўқитиш тизими', 'Жами: СИ малака ошириш дастури | «Сунъий интеллект куни» — ҳар чоршанба СИ ўқитишга бағишланади |  1-босқич: Ўқув маркази очиш | 2-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 3-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 4-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 5-босқич: МФЙ раислари ва ҳоким ёрдамчилари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', '4 босқичли СИ ўқитиш дастури «юқоридан пастга» тамойилида: ҳар чоршанба СИ куни, ҳоким даражасида стратегик СИ қўллаш, банк раҳбарларига скоринг ва риск таҳлили, маҳалла банкирларига мижоз хизмати платформаси, МФЙ раисларига маълумотлар таҳлили. Ҳар босқич 2–4 ҳафта, ҳар бир бўлимга аниқ СИ KPI жорий этилиб, натижалар чоракда баҳоланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (111, 3, 22, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш, тадбиркорлик ва ишга жойлашишга тайёрлаш', 'Жами: 1 350 нафар СИ платформаси орқали ўқитилади (2026 режа) | СИ таҳлили: ҳар бир мурожаатчининг кўникмаси ва қизиқиши аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури тузилади | Тадбиркорлик йўналиши: бизнес-режа + микрокредит таклиф қилинади | Касб йўналиши: тайёр иш ўринларига йўналтирилади', TRUE, 'SQB', 'СИ платформаси орқали ҳар бир фуқаро индивидуал баҳоланади: кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтирилади. Мақсад: 80% иштирокчи 3 ой ичида даромадли фаолиятга ўтади. СИ скоринг натижалари маҳалла банкирларига ҳам тақдим этилиб, кредит ажратишда қўшимча маълумот сифатида фойдаланилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (112, 3, 23, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 68 маҳаллада жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (113, 3, 24, 4, '4', 'Маҳалла драйвер ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари', 'Жами: 68 та маҳалла | Савдо ва хизмат: 37 та МФЙ (55%) | Ишлаб чиқариш: 20 та МФЙ (30%) | Чорвачилик/паррандачилик: 4 та МФЙ (5%) | Туризм ва ҳунармандчилик: 7 та МФЙ (10%) ', TRUE, 'Хокимият', 'Маҳалла ихтисослашуви таркибида савдо ва хизмат улуши юқори (41/68), шунинг учун шу сегментда самарадорликни ошириш учун рақамли савдо, логистика ва сервис сифат стандартларини жорий этиш керак. Ишлаб чиқаришга ихтисослашган 23 та МФЙда эса кичик кооперация ва қиймат занжири асосида даромадни ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (114, 3, 25, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва банклар бўйича маҳалла тақсимоти', 'Жами: 2026 йил 680 та лойиҳа амалга оширилади | Иш ўринлари: 2 350 та | Жами маҳаллалар: 68 та | Ўзсаноатқурилишбанк (SQB): 180 та лойиҳа | Миллий банк: 120 та лойиҳа | Агро банк: 90 та лойиҳа | Ҳамкор банк: 80 та лойиҳа | Халқ банки: 70 та лойиҳа | Инфинбанк: 60 та лойиҳа | Микрокредитбанк: 80 та лойиҳа | Лойиҳалар умумий қиймати: 58 млрд сўм | Банк кредити улуши: 29,4 млрд сўм', TRUE, 'Марказий банк', 'Қўқондаги 68 МФЙда 680 та микролойиҳа режалаштирилган — умумий қиймати 58 млрд сўм, шундан банк кредити 29,4 млрд сўм (51%). Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа амалга оширилишини мониторинг; (4) тадбиркорларга молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (115, 3, 26, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 2 та оғир тоифадаги маҳалла | 1-маҳалла: Янги чорсу | 2-маҳалла: Мўйимуборак | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 2 та маҳаллада бандликни ихтисослашув асосида ҳал этиш мақсадга мувофиқ: Янги Чорсуда гастротуризмни ривожлантириб, миллий таомлар, сервис ва кичик туризм хизматлари орқали тезкор иш ўринлари яратиш; Мўйимуборакда эса саноат-ишлаб чиқариш йўналишида кичик цехлар, кооперация ва қайта ишлаш лойиҳаларини йўлга қўйиш зарур. Шу асосда аҳолини қисқа муддатли ўқитиш, микролойиҳаларга улаш ва доимий мониторинг орқали барқарор бандликка эришиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (116, 3, 27, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили', TRUE, 'SQB', 'Сунъий интеллектга асосланган «AI Advisor» мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (117, 3, 28, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (118, 3, 29, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Қўқонда аёллар тадбиркорлиги потенциали юқори (тикувчилик, чарм-пойабзал, савдо-хизмат, ҳунармандчилик). Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (119, 3, 30, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'SQB томонидан 2 та маҳаллада 145 нафар ишсизни бандликка жалб қилиш режаси', 'Жами: 2 та маҳалла, 145 нафар ишсиз | Янги чорсу: 60 нафар (6,5%) — аёллар 15, эркаклар 40, ёшлар 5 | Мўйимуборак: 85 нафар (6,2%) — аёллар 70, эркаклар 12, ёшлар 3 | Таркиб: ёшлар 5%, аёллар 59%, эркаклар 36% | Кредит маҳсулотлари: Ёшлар бизнесда, Ҳамроҳ (аёллар), Маҳалла лойиҳаси | Микролойиҳалар: 71 та, умумий сумма 2,4 млрд сўм', TRUE, 'SQB', 'Аниқланган 2 та маҳаллада ишсизлик даражаси ўртача 6–6,5% атрофида бўлиб, асосий улушни аёллар ва ёшлар ташкил қилади. Шу асосда «бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (120, 3, 31, 5, '5', 'Қуёш энергияси ва ишлаб чиқариш', 'Қуёш энергетикаси орқали саноат таннархини пасайтириш салоҳияти', 'Жами: 280–300 кунга яқин қуёшли давр/йил (баҳолаш) | Йўналиш: қуёш панеллари ва кичик СЭС лойиҳалари | Имконият: саноат корхоналари ва сервис объектлари учун электр харажатини пасайтириш | Инвестиция: $8–25 млн/лойиҳа (лойиҳа қувватига қараб)', TRUE, 'Хокимият', 'Қўқонда саноат ва хизмат кўрсатиш тармоқлари фаоллиги юқори бўлгани учун қуёш энергетикаси лойиҳаларини ишлаб чиқариш зоналарига босқичма-босқич жойлаштириш керак. Аввало 1–2 та пилот лойиҳа орқали иқтисодий самара (электр таннархи, қайтиш муддати) тасдиқланиб, кейин хусусий инвесторлар учун тайёр лойиҳа пакетлари (ер, тармоққа уланиш, PPA шартлари) таклиф қилиниши мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (121, 3, 32, 5, '5', 'Туризм ва меҳмонхона инфратузилмаси', 'Сайёҳлар оқими, меҳмонхоналар ва туризм экспорти', 'Жами: Туризм кўрсаткичлари | Сайёҳлар (йиллик): 442 минг киши | Хорижий сайёҳлар: 117 минг киши | Маҳаллий сайёҳлар: 325 минг киши | Меҳмонхоналар: 15 та (386 хона, 804 ўрин) | Туризм экспорти: 40,3 млн $', TRUE, 'Хокимият', 'Сайёҳлар оқими ўсиши натижасида меҳмонхона ўринлари етишмовчилиги юзага келиши мумкин, шу боис янги меҳмонхоналарни жорий этиш ва мавжудларини кенгайтириш муҳим. Бу эса қўшимча иш ўринлари яратишга хизмат қилади. Шу билан бирга, хизмат сифатини ошириш учун меҳмонхона ходимларини доимий ўқитиш ва халқаро стандартларга мос тайёрлаш зарур. Меҳмонхоналарни тоифалаш, рақамли бронлаш тизими ва кўп тилли сервисни жорий этиш билан бирга, хорижий сайёҳлар учун тарихий мерос + ҳунармандчилик + гастро йўналишларини ягона бренд остида сотиш, маҳаллий сайёҳлар учун эса 1–2 кунлик тур-пакетларни ривожлантириш юқори самара беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (122, 3, 33, 5, '5', 'Транспорт-логистика марказ', 'Темир йўл станциясигача масофа бор-йўғи 1,1 км. Қўқон — водийнинг дарвозаси', 'Жами: Логистика қуввати | Йўллар узунлиги: 683 км | Темир йўл станциясигача: 1,1 км | Стратегик транспорт жойлашуви: SWOT кучли томони', TRUE, 'Хокимият', 'Қўқонни нафақат саноат, балки «Қуруқ порт» (Dry Port) сифатида ривожлантириш керак. Темир йўл яқинлигидан фойдаланиб, Фарғона водийси маҳсулотларини экспортга юклаш марказини ташкил этиш, транспорт ва омборхона хизматлари экспортини шаҳар ЯҲМдаги улушини 20% гача ошириш имкони мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (123, 3, 34, 5, '5', 'Демографик зичлик ва урбанизация', 'Аҳоли зичлиги — ҳар 1 км² га 3 733 киши. Республикадаги энг юқори кўрсаткичлардан бири', 'Жами: Демографик ва иқтисодий зичлик | Аҳоли (2025): 320 минг киши | Аҳоли зичлиги: 3 733 киши/км² | Саноат ҳажми (2025): 9,4 трлн сўм | Жон бошига саноат: 29,7 млн сўм | Янги иш ўринлари: 59 та лойиҳа орқали 1 154 та', TRUE, 'stat.uz', 'Ер ресурслари чекланганлиги сабабли, саноатни ривожлантиришда «горизонтал» эмас, «вертикал» урбанизация стратегиясига ўтиш керак. Яъни, кўп қаватли кичик саноат марказлари (Industrial Lofts) қуриш ва хизмат кўрсатиш соҳасида юқори технологик (IT, аутсорсинг) йўналишларни танлаш мақсадга мувофиқ. Юқори зичлик — бу тайёр йирик истеъмол бозори демакдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (124, 3, 35, 5, '5', 'Туризм ва ҳунармандчилик бренди', 'Қўқон — Жаҳон ҳунармандлари шаҳри (World Craft City). Савдо, хизмат ва ҳунармандчиликнинг юқори фаоллиги', 'Жами: 3 та туристик йўналиш (2027–2028 режа) | Йўналиш 1: Тарихий-меъморий мерос (Худоёрхон ўрдаси) | Йўналиш 2: Ҳунармандчилик (ёғоч ўймакорлиги, пичоқчилик) | Йўналиш 3: Ишбилармонлик туризми (MICE)', TRUE, 'Хокимият', 'Қўқоннинг «Жаҳон ҳунармандлари шаҳри» мақомидан фойдаланиб, ҳунармандчилик маҳсулотларини экспорт қилиш бўйича B2B платформасини яратиш керак. 2027–2028 йилларга мўлжалланган 3 та маршрутни ҳозирдан «Digital Guide» тизимига интеграция қилиш ва туристларнинг шаҳарда қолиш вақтини 1,5 кундан 3 кунгача ошириш учун «кечки Қўқон» концепциясини ишлаб чиқиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (125, 3, 36, 5, '5', 'Ер фонди ва табиий ресурслар', 'Тарихий, ўрмон ва қишлоқ хўжалик ерларининг иқтисодий салоҳияти', 'Жами: 1 198 гектар ер фонди (3 та категория) | Тарихий-маданий ерлар: 76 га | Ўрмон фонди: 27 га | Қишлоқ хўжалик ерлари: 1 095 га', TRUE, 'Хокимият', 'Қишлоқ хўжалик ерлари (1 095 га) агротуризм ва органик маҳсулот ишлаб чиқариш учун асосий ресурс сифатида фаоллаштирилиши керак. Тарихий-маданий ерлар (76 га) туризм маршрутлари билан бирлаштирилиб, меросни сақлаш ва даромад олишни уйғунлаштириш мумкин. Ўрмон фонди (27 га) экотуризм йўналишида қўшимча қийматга эга.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (126, 3, 37, 5, '5', 'Стратегик устунликлар ва ички потенциал', 'Транспорт, туризм, савдо ва меҳнат ресурсларининг мажмуавий салоҳияти', 'Жами: 4 та стратегик устунлик | 1-устунлик: Стратегик транспорт жойлашуви | 2-устунлик: Туризм ва ҳунармандчилик бренди кучли | 3-устунлик: Савдо ва хизмат кўрсатиш соҳаси юқори фаол | 4-устунлик: Меҳнат ресурслари ва ёш аҳоли улуши катта', TRUE, 'Хокимият', 'Тўрт устунликни бир-бири билан боғлаш зарур: ёш аҳолини ҳунармандчилик ва туризм хизматларига йўналтириш орқали меҳнат бозорини фаоллаштириш, транспорт устунлигидан фойдаланиб транзит савдо ва логистика марказини ривожлантириш мумкин. Савдо ва хизмат кўрсатиш соҳасида 24/7 иш режимини кенгайтириш — кечки бозорлар, доимий хизмат нуқталари ва рақамли буюртма тизимларини жорий этиш орқали соҳа фаоллигини янада ошириш лозим. Бренд капиталини рақамли маркетинг орқали кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (127, 3, 38, 5, '5', 'Туризм инфратузилмасига давлат инвестицияси', '2027 йилга мўлжалланган маҳаллалар туризм инфратузилмасини ривожлантириш дастури', 'Жами: 42 млрд сўм режалаштирилган инвестиция (2027 йил) | Молиялаштириш: давлат бюджети | Муддат: 2027 йил | Қамров: маҳаллалар туризм инфратузилмаси', TRUE, 'Хокимият', '42 млрд сўмлик инвестициядан максимал фойда олиш учун маблағларни тарихий ерлар ва туризм йўналишлари имкониятлари билан уйғунлаштириш — устувор йўналтириш керак. Хусусий инвесторларни жалб қилиш учун давлат маблағини катализатор сифатида ишлатиш ва ПЧШ (давлат-хусусий шериклик) механизмини қўллаш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (128, 3, 39, 6, '6', 'Маҳалла иқтисодиёти драйверлари', 'Қўқонда маҳалла ихтисослашуви аниқ шаклланган, энди мақсад — юқори самарали маҳаллалар моделини бошқаларига кўчириш', 'Жами: Маҳалла иқтисодиёти хулосаси | Савдо ва хизмат: 37 та МФЙ | Саноат - Ишлаб чиқариш: 20 та МФЙ | Ҳунармандчилик: 7 та МФЙ | Туризм: 4 та МФЙ | Оғир тоифа: 2 та (Янги чорсув, Мўйимуборак)', TRUE, 'SQB', 'Қўқонда маҳалла ихтисослашуви аниқ шакллангани — асосий устунлик. Энди вазифа — бу моделни самарали масштаблаш: 37 та савдо-хизмат маҳаллаларида айланма ва рақамли хизматлар ўсади, 20 та ишлаб чиқариш маҳаллаларида кооперация орқали қўшимча қиймат ошади. Ҳунармандчилик ва туризм маҳаллаларида брендлаш ва экспорт салоҳияти кучаяди. «Оғир тоифа»даги 2 маҳалла учун эса 3 ойлик тезкор бандлик дастури ва манзилли молиялаштириш жорий этилса, қисқа муддатда ижобий динамика кузатилади ва уларни барқарор ўсишга олиб чиқиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (129, 3, 40, 6, '6', 'SQB стратегик ҳамкорлик ва лойиҳалар фабрикаси', 'Комплекс пакет: халқаро кредит (JICA) + Хорижий молия институтлари линиялари + лойиҳалар фабрикаси + СИ таҳлили асосида қўшимча лойиҳалар портфели', 'Жами: SQB ва ҳамкор банклар стратегик пакети | Лойиҳа фабрикаси: Ғоя → Баҳолаш → Бизнес-режа → Молиялаштириш | Иштирокчи банклар: SQB ва бошқа тижорат банклари | СИ таҳлили асосида қўшимча: ~152 та лойиҳа, 127 млрд сўм, 1584 иш ўрни | Йирик қўшимча лойиҳалар: 15 та, 108 млрд сўм, 348 иш ўрни | Микролойиҳалар: ~137 та, 19 млрд сўм, 286 иш ўрни | Саноат йўналиши: 49 та лойиҳа, 82,5 млрд сўм, 415 иш ўрни | Савдо - Хизмат йўналиши: 103 та лойиҳа, 44,5 млрд сўм, 1169 иш ўрни', TRUE, 'SQB', 'Бандлик ва янги лойиҳалар режаси (Қисқача):
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (130, 3, 41, 6, '6', 'Савдо - Сотиқ инфратузилмаси', 'Қўқон шаҳри савдо соҳасига ихтисослашган бўлиб, бозорлар ва дўконлар тармоғи кенг ривожланган ҳамда 2026 йилда янги савдо нуқталарини очиш учун юқори салоҳият мавжуд.', 'Жами: Савдо инфратузилмаси хулосаси | Мавжуд: 10 та бозор, 7 000+ савдо дўкони | Девелоперлар лойиҳаси (2026): (35 ихтисослашган МФЙ)
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (131, 3, 42, 6, '6', 'Жаҳон ҳунармандчилик шаҳри — глобал бренд', 'Қўқон — Марказий Осиёда «Жаҳон ҳунармандлари шаҳри» мақомини олган илк шаҳар', 'Жами: 320 минг аҳоли учун янги имкониятлар | Статус: World Craft City (2019 йилдан) | Маршрутлар: 3 та янги йўналиш (2027–2028) | Логистика: Темир йўл вокзали марказдан 1,1 км масофада | Лойиҳалар: (7 ихтисослашган МФЙ)
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (132, 3, 43, 6, '6', 'Инфратузилма ва ресурс тақчиллиги', 'Аҳоли зичлиги жуда юқори (3 733 киши/км²) — муҳандислик тармоқларига юклама ортган', 'Жами: 4 та асосий чеклов | Энергия: электр ва газ таъминотидаги танқислик | Ер ресурси: янги саноат объектлари учун бўш ер камлиги (0,8% саноат зонаси) | NPL хатари: оилавий тадбиркорликда муаммоли кредитлар — 32% | Кадрлар: юқори малакали мутахассислар етишмаслиги', TRUE, 'Хокимият', 'Инфратузилмавий чекловларни ечиш учун «Ақлли шаҳар» (Smart City) концепциясини жорий этиш ва энергия тежамкор технологияларга имтиёзли кредитлар ажратиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (4, 2, 'qoshtepa', 'Қўштепа', 'Куштепа', 'Qoshtepa', '', 'qoshtepa.json', TRUE, NULL, NULL, 36, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
