INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (133, 4, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва бюджет даромадларининг 5 йиллик динамикаси', 'Жами: 2025 йил кўрсаткичлари | Саноат ҳажми: 3 074,0 млрд сўм (+301,0%) | Бозор хизматлари: 1 494,2 млрд сўм (+237%) | Маҳаллий бюджет: 154,3 млрд сўм (+66,1%) | Тармоқлар улуши: Қ/х 41,2%, Саноат 33,9%, Хизматлар 14,8%', TRUE, 'stat.uz', 'Туман иқтисодиёти сўнгги 5 йилда жуда кескин ўсиш кўрсатган — саноат 3 баробардан кўп (+301%), бозор хизматлари 2,4 баробар (+237%) ўсган. Саноат улуши 33,9% га етгани туман иқтисодиётининг диверсификация қилинаётганини кўрсатади. Қишлоқ хўжалиги улуши (41,2%) ҳамон етакчи, лекин фарқ камайиб бормоқда. Кейинги босқичда саноат ва хизматлар улушини янада ошириш, қишлоқ хўжалигида қайта ишлаш занжирини чуқурлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (134, 4, 2, 1, '1', 'Устувор соҳалар ва саноат индекси', 'Ривожланиш драйверлари ва ўсиш суръатлари', 'Жами: Саноат ривожланиши таҳлили | Саноат ишлаб чиқариш индекси: 128,3 → 168,9 (2021–2025) | 1-устувор: Тўқимачилик (кластер тизими) | 2-устувор: Чарм-пойабзал (локализация) | 3-устувор: Қишлоқ хўжалиги (қайта ишлаш) | Бандлик: Қ/х 8,6 минг, Хизмат 5,2 минг, Саноат 3,4 минг киши', TRUE, 'stat.uz', 'Саноат индекси 168,9 га етгани ишлаб чиқариш қувватлари кенгаяётганини кўрсатади. Тўқимачилик ва чарм-пойабзал тармоқларида тайёр маҳсулот занжирини яратиш орқали қишлоқ хўжалигидаги ортиқча ишчи кучини (8,6 минг киши) юқори даромадли саноат соҳасига трансформация қилиш стратегик вазифа ҳисобланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (135, 4, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Йирик корхоналар ва кичик бизнес таҳлили (млрд сўм)', 'Жами: Саноат ишлаб чиқариш таҳлили | Йирик корхоналар: 2 236,5 млрд сўм (2021: 395,4 → 2025: 2 236,5) | Кичик бизнес: 837,2 млрд сўм (2021: 625,0 → 2025: 837,2) | Кичик бизнес улуши: 38% | Очилган корхоналар (2025): 234 та | Ёпилган корхоналар (2025): 152 та', TRUE, 'stat.uz', 'Саноатнинг 38% қисми кичик бизнес ҳиссасига тўғри келмоқда. Кичик бизнеснинг мослашувчанлиги яхши, лекин ёпилиш кўрсаткичининг юқорилиги (152 та) хавотирли. Саноат барқарорлиги учун кичик корхоналарни йирик корхоналар билан кооперация қилиш ва "саноат ипотекаси" орқали уларга бино-иншоотлар ажратиш самара беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (136, 4, 4, 1, '1', 'Маҳаллий бюджет ва молиявий ҳолат', 'Прогноз ва контингент даромадлар (млрд сўм)', 'Жами: Молиявий таҳлил | Маҳаллий бюджет (2025): 154,3 млрд сўм (+66,1%) | Контингент бюджет (2025): 228,5 млрд сўм (+18,4%) | Бюджет ўсиши: 2021: 37,2 → 2025: 154,3 (4 баробар) | Контингент ўсиши: 2021: 109,4 → 2025: 228,5 | Экспорт (2025): 88,9 минг $ (−16,0%)', TRUE, 'Туман молия бўлими', 'Бюджет даромадларининг 4 баробар ўсиши солиқ йиғилувчанлиги яхшиланганини кўрсатади. Бироқ экспортнинг пасайиши (105,8 дан 88,9 га) маҳаллий ишлаб чиқарувчиларнинг ташқи бозорга чиқишда қийналаётганидан далолат беради. Бюджетнинг ошириб бажарилган қисмини экспортёр корхоналарни транспорт харажатларини қоплаш ёки халқаро кўргазмаларда қатнашишига субсидия беришга йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (137, 4, 5, 1, '1', 'Ажратилган кредитлар ва ижтимоий индикаторлар', 'NPL динамикаси ва аҳоли кутишлари', 'Жами: Кредит ва ижтимоий таҳлил | NPL (2025): 1,5% (2021: 5,4% → 2025: 1,5%) | Юк айланмаси: 1 662 минг тонна | Йўловчи ташиш: 12 807,3 минг киши | Аҳоли кутишлари: Ижобий 71%, Салбий 14%, Нейтрал 15%', TRUE, 'SQB', 'NPL даражасининг 5,4% дан 1,5% гача пасайиши банк секторининг соғломлашганини англатади. 71% тадбиркор ва аҳоли ижобий кутишга эга эканлиги — туманда инвестиция киритиш учун энг қулай пайт келганини билдиради. Юқори юк айланмасини инобатга олиб, туманда "қўруқ" логистика хабларини ташкил этиш ва транспорт хизматларини рақамлаштириш орқали иқтисодий фаолликни янада ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (138, 4, 6, 1, '1', 'Туман иқтисодий фаоллиги Google Trends орқали', 'Аҳоли ва бизнеснинг рақамли қидирув сўровлари асосида 0-100 балл шкаласи бўйича иқтисодий қизиқиш', 'Жами: Google Trends таҳлили | 2025 йил кўрсаткичи: 27,3 балл (100 дан) — ўртачадан паст фаоллик | 2024 йил ўртача: 21,8 балл | 2025 йил ўртача: 27,3 балл (+25% ўсиш) | Тренд: Рақамли фаоллик паст базадан жуда тез суръатда ўсмоқда | Мавсумийлик: Қишлоқ хўжалиги мавсумида (баҳор-куз) энг юқори нуқта', TRUE, 'Google Trends', 'Қўштепа туманида рақамли иқтисодий фаоллик паст базадан (27,3 балл) бошланган бўлса-да, ўсиш суръати жуда юқори (+25%). Бу аҳолининг рақамли хизматларга тез мослашаётганини кўрсатади. Тавсия: туманнинг инвестициявий жозибадорлигини ошириш учун интернетдаги маҳаллий контентни кўпайтириш, тадбиркорларни "E-auksion" ва онлайн платформаларда фаолроқ бўлишга ўргатиш лозим. Ушбу паст индекс туманда рақамли иқтисодиётни ривожлантириш учун ҳали фойдаланилмаган катта имконият борлигидан далолат беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (139, 4, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолининг тоза ичимлик суви билан таъминланиш динамикаси (%)', '2021: 42,5 | 2022: 48,3 | 2023: 51,6 | 2024: 83,1 | 2025: 84,0 (%)', TRUE, 'Сув хўжалиги бошқармаси', 'Туманда охирги икки йилда (2024-2025) сув таъминотида кескин сакраш (42% дан 84% га) кузатилган. Бу йирик давлат дастурлари амалга оширилганидан далолат беради. Эндиги асосий эътиборни мавжуд тармоқларнинг техник ҳолатини сақлаш ва сув йўқотишларини камайтириш учун рақамли ҳисоблагичлар (smart meters) ўрнатишга қаратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (140, 4, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Автомобил йўллари узунлиги ва сифат кўрсаткичлари', 'Жами: Йўл инфратузилмаси | Умумий йўллар узунлиги: 981 км | Асфальтланган йўллар улуши: 82% | Вилоят марказигача масофа: 24,9 км', TRUE, 'Йўл хўжалиги бўлими', 'Йўлларнинг 82 фоизи асфальтлангани ижобий кўрсаткич ва бу вилоят марказига яқинлик билан биргаликда туманнинг логистика жозибадорлигини оширади. Қолган 18 фоиз йўлларни таъмирлашда асосий урғуни саноат зоналарига (КСЗ ва ЭИЗ) олиб борувчи йўналишларга бериш, юк ташиш ҳажми юқори бўлган нуқталарда бетон қопламали йўлларни жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (141, 4, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Тармоқлар ҳолати ва модернизация эҳтиёжи', 'Жами: Электр инфратузилмаси | Электр узилишлари: ойига ўртача 1–1,3 марта | Трансформаторлар: 30% модернизация талаб қилади | Электр линиялари: 21% алмаштирилиши керак', TRUE, 'Электр тармоқлари корхонаси', 'Узилишлар сони кам (1-1,3 марта) бўлса-да, инфратузилманинг 18-21% қисми эскиргани келажакда хавф туғдириши мумкин. Саноат зоналари ва йирик корхоналарнинг узлуксиз ишлашини таъминлаш учун давлат-хусусий шериклик асосида муқобил энергия манбаларини (қуёш панеллари) жорий этишни рағбатлантириш ва тармоқларни босқичма-босқич янгилаш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (142, 4, 10, 2, '2', 'Ер тоифалари ва саноат ерларидан фойдаланиш', 'Ҳудудий тақсимот ва ер ресурсларининг самарадорлиги (га)', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 37 000 гектар | Суғориладиган ерлар: 32 652 гектар (88%) | Саноат зоналарида ердан фойдаланиш: 77% | Аҳоли зичлиги: 586 киши/км²', TRUE, 'Кадастр агентлиги', 'Туман ҳудудининг катта қисми (88%) суғориладиган ерлар бўлгани учун саноатни ривожлантиришда "тик йўналиш" (вертикал) тамойилидан фойдаланиш, яъни мавжуд саноат зоналарида (ердан фойдаланиш 77%) бўш турган биноларда кўп қаватли кичик ишлаб чиқариш мажмуаларини қуриш мақсадга мувофиқ. Бу аҳоли зич жойлашган ҳудудда қишлоқ хўжалиги ерларини сақлаб қолишга ёрдам беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (143, 4, 11, 2, '2', 'Жамоат транспорти ва мобиллик', 'Транспорт инфратузилмаси ва алоқа сифати', 'Жами: Транспорт ва алоқа | Темир йўл станциясига масофа: 16 км | Йўловчи айланмаси: 12 807,3 минг киши | Интернет қоплами: 100% / 128 Мбит/с | Газ билан таъминланганлик: 10,1%', TRUE, 'stat.uz', 'Йўловчи айланмасининг юқорилиги ва аҳоли зичлиги (586 киши/км²) жамоат транспортига бўлган талаб катталигини кўрсатади. Газ таъминоти пастлигини (10,1%) инобатга олиб, жамоат транспорти ва юк ташувчиларни электр қувватида ишловчи транспорт воситаларига (электробуслар) ўтказиш ва ҳудудда қувватлаш станцияларини кўпайтириш иқтисодий ва экологик жиҳатдан энг тўғри йўлдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (144, 4, 12, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурсларининг 5 йиллик динамикаси (минг киши)', '2021: 104,6 | 2022: 105,8 | 2023: 108,7 | 2024: 109,9 | 2025: 111,7 (минг киши)', TRUE, 'stat.uz', '2021 йилдаги 104,6 минг кишидан 2025 йилда 111,7 минг кишигача ўсиш (+6,8%, йиллик ўртача +1,7%) меҳнат бозорининг кенгайишини кўрсатади. Бу ҳолат янги иш ўринлари яратишни талаб қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (145, 4, 13, 3, '3', 'Бандликни ошириш имкониятлари', 'КСЗ, ЭИЗ, инвестиция лойиҳалари ва касб-ҳунар дастурлари', 'Жами: Бандлик имкониятлари | КСЗ ва ЭИЗ: инфратузилмани тўлиқ яратиш | Инвестиция: янги лойиҳаларни жойлаштириш | Экспорт: салоҳиятини ошириш | Ёшлар ва аёллар: касб-ҳунар имкониятларини кенгайтириш', TRUE, 'stat.uz', 'Қўштепа туманида меҳнат ресурслари ўсиши ва саноат зоналари мавжудлиги иш ўринлари яратиш учун асосий имкониятдир. Шунинг учун: инфратузилмани тез яратиш ва газ тармоқларига уланишни таъминлаш; янги саноат ва агрозоналарда йилига камида 1 000–1 200 иш ўрни яратиш; ёшлар ва аёллар учун касб-ҳунар дастурларини кенгайтириш; норасмий секторни расмийлаштириш орқали солиқ базасини кучайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (146, 4, 14, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик 4 341 нафар', '2021: 10,3 | 2022: 9,5 | 2023: 7,2 | 2024: 6,0 | 2025: 5,1 (%)', TRUE, 'stat.uz', 'Қўштепа туманида ишсизлик даражаси пасайиб бормоқда, лекин меҳнат ресурслари ўсиши янги иш ўринларини талаб қилади. Шунинг учун: янги саноат ва агрозоналарда иш ўринлари яратишни тезлаштириш; ёшлар ва аёллар учун касб-ҳунар дастурларини кенгайтириш; норасмий секторни расмийлаштириш орқали ишсизликни янада камайтириш лозим.', 4341, 5.1, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (147, 4, 15, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони', 'Жами: Камбағаллик таҳлили (2025) | Камбағаллик даражаси: 5,2% | Камбағал оилалар сони: 3 319 та | Туман ўртачаси: 6,3% | Оғир тоифа (10%+): 5 та маҳалла | Енгил тоифа (3% ва паст): 6 та маҳалла', TRUE, 'Статистика / МФЙ', 'Қўштепа туманида камбағаллик даражаси 5,2% ни ташкил этади. 5 та маҳаллада камбағаллик 10% дан юқори (Кичик бешкапа 13,3%, Қорақушчи 10,8%) — улар учун алоҳида «интенсив ёрдам» режаси тузилиши керак. Камбағал оилаларни ижтимоий ёрдам ва микрокредитлар билан қўллаб-қувватлаш лозим.', 3319, 5.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (148, 4, 16, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '2026 йил режаси: ёшларни бандликка жалб қилиш йўналишлари', 'Жами: 2 221 нафар ёшлар даромади ошириладиган (2026 режа) | Доимий ишга жойлаштириш: 1 366 нафар | Тадбиркорликка жалб қилиш: 327 нафар | Кредит ажратиш ҳисобига: 297 нафар | Қайта касбга ўқитиш: 231 нафар', TRUE, 'Хокимият', 'Ёшлар даромадини ошириш учун асосий йўналишлар: дуал таълим ва қайта тайёрлаш дастурларини кучайтириш; биринчи иш ўрнига субсидия бериш; ёш тадбиркорларни микрокредит ва грантлар билан қўллаб-қувватлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (149, 4, 17, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', '2026 йил режаси: аёлларни бандликка жалб қилиш йўналишлари', 'Жами: 2 120 нафар аёллар даромади ошириладиган (2026 режа) | Доимий ишга жойлаштириш: 949 нафар | Тадбиркорликка жалб қилиш: 230 нафар | Кредит ажратиш ҳисобига: 350 нафар | Қайта касбга ўқитиш: 591 нафар', TRUE, 'Хокимият', 'Аёллар даромадини ошириш учун: саноат ва хизмат кўрсатиш соҳаларида иш ўринларини яратиш; аёллар тадбиркорлигини микрокредит ва грантлар билан қўллаб-қувватлаш; қайта касбга ўқитиш дастурларини кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (150, 4, 18, 4, '4', 'Маҳаллаларда сунъий интеллект ва таълим орқали бизнесни ривожлантириш', '11 000 нафар аҳоли «Беш миллион сунъий интеллект етакчилари» дастури доирасида сертификат олган', 'Жами: 2026 режалари | «Беш миллион СИ етакчилари» таълими: 25 000 нафар аҳолини қамраб олиш | Маҳалла еттилигини ўқитиш: 350 та / 49 та маҳалла | СИ лойиҳа: SQB AI advisor | AIда тайёрланган бизнес-режалар: 100 та', TRUE, 'SQB', 'Қўштепа туманида 11 000 нафар аҳолининг сунъий интеллект бўйича сертификат олгани юқори натижа бўлиб, 2026 йилгача бу кўрсаткични 25 000 нафарга етказиш режалаштирилган. Шу асосда SQB AI advisor орқали AIда тайёрланган 100 та бизнес-режани ишлаб чиқиш ва молиялаштириш, 350 та маҳалла еттилиги орқали сунъий интеллектни амалиётга кенг жорий этиш натижасида камида 100 та янги бизнесни йўлга қўйиш ва янги иш ўринларини яратиш таъминланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (151, 4, 19, 4, '4', 'Сунъий интеллект куни ва СИ ўқитиш дастури', 'Ҳоким, банк раҳбарлари, маҳалла банкирлари ва аҳолини босқичма-босқич СИ га ўқитиш тизими', 'Жами: 5 босқичли СИ ўқитиш дастури | 1-босқич: Ўқув маркази очиш | 2-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 3-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 4-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 5-босқич: МФЙ раислари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Дастур «юқоридан пастга» тамойилида: ҳоким даражасида стратегик СИ қарорлари, банк раҳбарларига скоринг, маҳалла банкирларига мижоз хизмати, МФЙ раисларига маълумотлар таҳлили ва ниҳоят 49 маҳалладаги аҳолини СИ платформаси орқали ўқитиш. Ҳар босқич 2–4 ҳафта. 5-босқичда ҳар бир фуқаро индивидуал баҳоланади — кўникмалилар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтирилади. Мақсад: 80% иштирокчи 3 ой ичида даромадли фаолиятга ўтади, СИ скоринг натижалари маҳалла банкирларига кредит қарорида қўшимча маълумот сифатида тақдим этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (152, 4, 20, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит мослаштириш: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси Қўштепа туманидаги маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 49 маҳаллада жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (153, 4, 21, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари (2026 режа)', 'Жами: Маҳалла ихтисослашуви | Узумчилик: 38 та МФЙ (78%) | Деҳқончилик: 6 та МФЙ (12%) | Ишлаб чиқариш: 5 та МФЙ (10%)', TRUE, 'Хокимият', 'Қўштепа туманида 49 маҳалланинг 38 таси (78%) узумчиликка ихтисослашган — бу моноконцентрация хавфини туғдиради. Тавсия: узумчиликда қайта ишлаш занжирини (қуритиш, шарбат, экспорт) кучайтириш; деҳқончилик маҳаллаларида сабзавот қайта ишлаш кластерларини ташкил этиш; ишлаб чиқариш маҳаллаларида ёшлар учун касб-ҳунар ўқитиш ва иш ўринлари яратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (154, 4, 22, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳаллаларда ўсишни таъминлайдиган асосий тармоқлар (2026 режа)', 'Жами: Драйвер секторлар | Савдо: маҳаллий бозорлар ва чакана савдо тармоқлари | Енгил саноат: тикиш-бичиш, озиқ-овқат ва маиший маҳсулот ишлаб чиқариш | Чарм-пойабзал: чарм маҳсулотлари ва пойабзал ишлаб чиқариш | Ҳунармандчилик: миллий ҳунарлар, оилавий ишлаб чиқариш ва номланиш', TRUE, 'Хокимият', 'Қўштепа туманида драйвер секторларни самарали ривожлантириш учун: секторларни алоҳида эмас, «ишлаб чиқариш + савдо + хизмат» занжирида боғлаш; чарм-пойабзал ва ҳунармандчиликда тайёр маҳсулотни бозорга чиқариш; маҳаллий номланишларни ривожлантириш ва онлайн сотув каналларини кенгайтириш; савдо ва хизмат соҳасида рақамли ечимларни жорий қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (155, 4, 23, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва банклар бўйича маҳалла тақсимоти (2026 йил)', 'Жами: 490 та лойиҳа / 940 иш ўрни (2026 режа) | Маҳаллалар: 49 та лойиҳа | SQB: 31 та лойиҳа | Агро банк: 9 та лойиҳа | Халқ банки: 9 та лойиҳа | Умумий қиймат: 58,8 млрд сўм | Банк кредити: 17,8 млрд сўм', TRUE, 'SQB', 'Қўштепа туманида микролойиҳаларни самарали амалга ошириш учун: лойиҳаларни танлашда СИ асосида скоринг жорий қилиш; кредит расмийлаштириш жараёнини соддалаштириш; лойиҳаларни амалга оширишни мунтазам мониторинг қилиш; тадбиркорларга молиявий маслаҳат ва бизнес режа тайёрлашда ёрдам бериш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (156, 4, 24, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси (2026 йил)', 'Жами: 3 та оғир тоифадаги маҳалла | 1-маҳалла: Кичик бешкапа | 2-маҳалла: Коракушча | 3-маҳалла: Намуна | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'Хокимият', 'Қўштепа туманида ишсизлик юқори бўлган маҳаллаларда: «Бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга тушириш; ишсиз аҳолини кўникма ва қизиқишлар бўйича сегментация қилиш; 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳаларга улаш механизмларини жорий қилиш; ҳар ой KPI мониторинг (иш ўрни, даромад, қайтмаслик) юритиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (157, 4, 25, 5, '5', 'Кичик саноат зоналари ва инвестиция', 'КСЗ ва ЭИЗ ҳудудларида саноат инфратузилмасини кенгайтириш', 'Жами: 49,9 га саноат учун ажратилган ер | КСЗ майдони: 25,5 га | ЭИЗ майдони: 24,4 га | Фаол лойиҳалар: 11 та (6,1 га) | Яратилган иш ўрни: 1 380 та | Бюджетга қўшимча: 24,0 млрд сўм | Фаолият кўрсатувчи КСЗ/ЁСТЗ: 5 та', TRUE, 'Хокимият', '49,9 гектарлик саноат зоналарида газ тармоқлари уланмагани — бу асосий тўсиқ. «Оқтепа» КСЗда ягона корхона орқали 1 700 та иш ўрни яратилган — бу потенциал модели. Газ инфратузилмасини қуриб, э-аукционга чиқарилмаган ерларни иқтисодий айланмага киритиш ва янги чарм-пойабзал КСЗни ишга тушириш (1–3 йил режасида) тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (158, 4, 26, 5, '5', 'Боғдорчилик ва узумчилик кластери', 'Туманнинг асосий ихтисослашуви — 38 маҳалла боғдорчиликка ихтисослашган', 'Жами: 38 та маҳалла боғдорчиликка ихтисослашган | Узум майдони: 288 га | Узум ҳосили: 461 тонна | Фермер кластерлари: 457 та | Сабзавот қайта ишлаш: 15% | Гўшт қайта ишлаш: 12% | Қ/х ҳажми (2025): 3 736,2 млрд сўм', TRUE, 'МФЙ агентлиги / Қ/х бўлими', '38 маҳалла боғдорчилик, 6 деҳқончилик, 5 кичик ишлаб чиқаришга ихтисослашган. Қайта ишлаш даражаси (15% ва 12%) жуда паст — экспортга йўналтирилган қайта ишлаш заводлари ва совуқ сақлаш иншоотлари қурилиши туманнинг энг устувор имконияти. Россия ва Қозоғистон бозорлари асосий экспорт йўналиши сифатида белгиланган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (159, 4, 27, 5, '5', 'Жаҳон банки ва халқаро молиялаштириш', 'ХМИ маблағлари ҳисобидан молиялаштириладиган лойиҳалар (13.04.2026 ҳолати)', 'Жами: $11 545 минг — 8 лойиҳа тасдиқланган (13.04.2026) | Тасдиқланган лойиҳалар: 8 та | Тасдиқланган сумма: $11 545 минг | Ҳужжат топширилган: 25 та лойиҳа / $20 143 минг | Режа (жами): 36 та лойиҳа, $9 млн (ЖБ) | Ҳужжат кутилаётган: 17 та / $8 598 минг', TRUE, 'SQB / Халқаро молия институтлари', 'Ҳужжат топширилмаган 17 та лойиҳа ($8 598 минг) бўйича ишлар кечикмоқда. Ушбу лойиҳалар бўйича тижорат банкларга ҳужжат топшириш жадаллаштирилиши керак. ХМИ молиялашуви — энг арзон ва узоқ муддатли манба; 2026 йил учун устувор вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (160, 4, 28, 5, '5', 'Иш ўрни яратиш дастури 2026–2027', 'Барча секторлар бўйича янги иш ўринлари яратиш режаси', 'Жами: 2 605 дан ортиқ янги иш ўрни (2026 режа, 33 лойиҳа, $108,8 млн) | Саноат (2026): 2 826 та | Саноат (2027): 3 200 та | Туризм (15 лойиҳа): 241 та | Ишсизлик даражаси (2025): 5,1% | Динамика: 2021: 10,3% (8 708 киши) → 2023: 7,2% (6 279) → 2025: 5,1% (4 341)', TRUE, 'Хокимият', 'Ишсизлик 2021 йилдан буён доимий камаймоқда (10,3% → 5,1%). Ёшлар ишсизлиги 1 302 киши, аёллар 1 519 киши — улар учун маҳалла ихтисослашуви дастурлари (чарм, тикувчилик, боғдорчилик) устувор йўналиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (161, 4, 29, 5, '5', 'Инвестиция жалб қилиш режаси 2026–2031', '6 йиллик инвестиция дастури — ўсувчи динамика', '[2026–2031 инвестиция режаси] 2026: 180 | 2027: 210 | 2028: 235 | 2029: 265 | 2030: 300 | 2031: 340 (млн $)', TRUE, 'Хокимият', 'Инвестиция жалб қилиш 2021–2024 йилларда 72,9%–113% оралиғида бажарилган (2022 йил энг юқори — 111%). Саноат зоналарига газ уланиши ва э-аукционга ер чиқариш — инвесторлар учун энг муҳим шартлар. Халқаро консалтинг баҳоси: «Тўғри бошқарув ва инвестиция билан Фарғона вилоятида етакчи иқтисодий нуқтага айланиши мумкин.»', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (162, 4, 30, 5, '5', 'Газ инфратузилмаси — устувор муаммо', 'Туманнинг энг катта инфратузилма тўсиғи ва инвестиция имконияти', 'Жами: 10,1% ҳозирги газ таъминоти даражаси (критик паст) | Газ таъминоти: 10,1% | Газ уланган саноат зоналари: 0 та (49,9 га) | Асфальтланган йўллар: 82% | Интернет қоплами: 100%, 128 Мбит/с | Ичимлик сув (2025): 84% | Канализация: 2,5%', TRUE, 'Хокимият', '10,1% газ таъминоти — вилоятда энг паст кўрсаткичлардан бири. 49,9 гектарлик саноат зоналарида газ йўқлиги энергия талаб қилувчи ишлаб чиқаришни чеклайди ва инвесторлар учун рақобатбардошликни камайтиради. Газ тармоғини саноат зоналарига улаш — 0–12 ойлик энг устувор вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (163, 4, 31, 5, '5', 'Урбанизация ва туман маркази', 'Туман марказини шакллантириш — узоқ муддатли ўсиш нуқтаси', 'Жами: 3 000+ янги иш ўрни (3–5 йиллик режа) | Туман маркази: мавжуд эмас | Тадбиркорлик субъектлари (режа): 200+ | Аҳоли (2025): 217 800 киши | Маҳаллалар сони: 49 та МФЙ | Мактаб (1 смена): 852 та синф | Мактаб (2 смена): 490 та синф', TRUE, 'Хокимият', 'Туман марказининг мавжуд эмаслиги — узоқ муддатли ривожланиш учун энг катта хавф ва энг катта имконият. Туман марказида урбанизация ишларини амалга ошириш орқали 200 дан ортиқ тадбиркорлик субъектлари ва 3 000+ юқори даромадли иш ўринлари яратиш режаси мавжуд (3–5 йил).', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (164, 4, 32, 6, '6', 'Бандлик — норасмий сектор', 'Расмий ишсизлик 5,1%, лекин 36 746 киши норасмий секторда ҳисобга олинмаган', 'Жами: 36 746 киши норасмий секторда — солиқ йўқотиш 0,7 млрд сўм/йил | Расмий ишсизлик (2025): 5,1% / 4 341 киши | Ёшлар ишсизлиги (16–30): 1 302 киши | Аёллар ишсизлиги: 1 519 киши | Ногиронлар (ишламайди): 3 728 / 4 199 киши | Динамика: 2021: 10,3% → 2023: 7,2% → 2025: 5,1%', TRUE, 'Бандлик маркази', 'Расмийлаштириш орқали йилига 3 000+ киши қамраб олиниши мумкин. Маҳалла ихтисослашуви дастурлари (чарм, тикувчилик, боғдорчилик) ёшлар ва аёллар учун энг аниқ йўналиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (165, 4, 33, 6, '6', 'Инфратузилма — саноатни тўхтатаётган 2 та тўсиқ', 'Газ ва канализация — инвестиция жозибадорлигига энг катта тўсиқ', 'Жами: 10,1% газ таъминоти — Фарғона вилоятида энг паст кўрсаткичлардан | Газ таъминоти: 10,1% (критик) | Канализация: 2,5% (критик) | Ичимлик сув: 84% (ўртача) | Асфальт йўллар: 82% (ўртача) | Интернет: 100%, 128 Мбит/с (яхши) | Саноат зонаси газ уланган: 0 та (49,9 га дан) (критик)', TRUE, 'Газ / Коммунал / Хокимият', 'Ичимлик сув модели — муваффақият намунаси: 42,5% (2021) → 84% (2025). Худди шу ёндашувни газ ва канализацияга қўллаш лозим. Газ улашсиз 49,9 га саноат майдони тўлиқ салоҳиятини бермайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (166, 4, 34, 6, '6', 'SQB стратегик ҳамкорлик ва лойиҳалар фабрикаси', 'Комплекс пакет: халқаро кредит (JICA) + Хорижий молия институтлари линиялари + лойиҳалар фабрикаси + СИ таҳлили асосида қўшимча лойиҳалар портфели', 'Жами: SQB ва ҳамкор банклар стратегик пакети | Лойиҳа фабрикаси: Ғоя → Баҳолаш → Бизнес-режа → Молиялаштириш | Иштирокчи банклар: SQB ва бошқа тижорат банклари | СИ таҳлили асосида қўшимча: 91 та лойиҳа, 100,5 млрд сўм, 425 иш ўрни | Йирик қўшимча лойиҳалар: 13 та, 98 млрд сўм, 290 иш ўрни | Микролойиҳалар: 78 та, 2,5 млрд сўм, 135 иш ўрни | Қишлоқ хўжалиги (узумчилик): 78 та лойиҳа, 7,5 млрд сўм, 135 иш ўрни', TRUE, 'SQB', 'Бандлик ва янги лойиҳалар (қисқача): СИ таҳлил ва маҳалла ихтисослашуви асосида 91 та лойиҳа (100,5 млрд сўм, 425 иш ўрни) шакллантирилди: 13 та йирик (98 млрд, 290 иш ўрни) ва 78 та микролойиҳа (2,5 млрд, 135 иш ўрни). Микролойиҳалар асосан узумчиликка таянади, йириклари эса саноат-хизмат сегментига қаратилган. Уларни амалга ошириш натижасида 425 та янги иш ўрни яратилиб, иқтисодиёт қишлоқ хўжалиги–қайта ишлаш–хизмат занжирида диверсификация қилинади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (167, 4, 35, 6, '6', 'Қ/х — ўсиш бор, лекин қайта ишлаш бўғини йўқ', '3 736 млрд сўмлик Қ/х, лекин қайта ишлаш 12–15% — қўшилган қиймат тумандан чиқиб кетмоқда', 'Жами: 3 736,2 млрд сўм — Қ/х ҳажми (2025), ўсиш +49,5% (2021 дан) | Қ/х ўсиши: 2 499,6 → 3 736,2 млрд (+49,5%) | Сабзавот қайта ишлаш: 15% | Гўшт қайта ишлаш: 12% | Узум: 288 га / 461 тонна | Фермер кластерлари: 457 та | Дон экини майдони: 7 800 га | Дефицит товарлар: гўшт, сут маҳсулотлари, қурилиш материаллари, дори-дармон', TRUE, 'Қ/х бўлими / МФЙ', 'Қ/х +49,5% ўсган, лекин қайта ишлаш атиги 12–15% — хом-ашёнинг 85% и қўшилган қиймат яратмасдан тумандан чиқиб кетмоқда. 457 та фермер кластери базаси бор, аммо қайта ишлаш занжирига боғланмаган. Тавсия: (1) кластерлар ёнида кичик консерва ва гўшт-сут цехларини «саноат ипотекаси» орқали қуриб, қайта ишлашни 3 йилда 35–40% га етказиш; (2) дефицит товарлар (гўшт, сут, қурилиш, дори) — тайёр ички бозор, импорт ўрнини босувчи лойиҳаларга имтиёзли кредит ва ер устувор берилсин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (168, 4, 36, 6, '6', '3 босқичли ҳаракат режаси — 2026–2031', 'Қисқа муддатдан узоқ муддатгача аниқ вазифалар ва инвестиция жадвали', 'Жами: $180 млн — 2026 йили инвестиция режаси, 2031 гача $340 млн | 0–12 ой: Саноат зоналарига газ улаш; 17 ХМИ лойиҳасини расмийлаштириш; 5 оғир маҳаллада тезкор дастур | 1–3 йил: 4 КСЗ тўлиқ қувватда; Чарм-пойабзал КСЗ ишга тушириш; э-аукционга ер чиқариш | 3–5 йил: Туман маркази (200+ корхона, 3 000+ иш ўрни); Қайта ишлаш кластерлари — экспорт', TRUE, 'Хокимият', 'Инвестиция жалб қилиш 2021–2024 йилларида 72,9%–113% оралиғида бажарилган. Газ улаш ва саноат зоналарини тўлиқ ишга тушириш — инвесторлар учун энг муҳим сигнал. Бу икки қарор туманнинг бутун 2026–2031 йиллар режасини белгилайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (5, 3, 'surkhandarya_vil', 'Сурхондарё вилояти', 'Сурхандарьинская область', 'Surkhandarya Region', '', 'boysun.json', TRUE, 'viloyat', NULL, 40, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
