INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (12, 5, 'Хонадон', 549117, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (169, 5, 1, 1, '1', 'Макроиқтисодий кўрсаткичлар', 'Саноат, хизматлар, ЯҲМ ва ташқи савдо (2025 йил)', 'Жами: 2025 йил макроиқтисодий кўрсаткичлар | ЯҲМ ўсиши: 54,6 млрд сўм (106,6%) | Саноат: 18,8 трлн сўм (+36,3%) | Хизматлар: 35,5 трлн сўм (+24,1%) | Тармоқлар улуши: Хизматлар 43,4%, Қ/х 37,4%, Саноат 9,9%, Қурилиш 9,3% | Экспорт: $507,5 млн (+86,2%) | Импорт: $283,4 млн', TRUE, 'Статистика бошқармаси / Молия бошқармаси', 'Саноат улуши пастлиги (9,9%) сабабли қишлоқ хўжалиги маҳсулотларини қайта ишлаш қувватларини ошириш керак. Саноат индустриаллашуви учун маҳаллий хом ашё базасида янги корхоналарни ишга тушириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (170, 5, 2, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '5 йиллик вақт қатори: ҳажм, ўсиш ва тузилма', 'Саноат ҳажми (млрд сўм): 2021: 6675,3 | 2022: 7229,8 | 2023: 10882,3 | 2024: 13819,8 | 2025: 18833,2', TRUE, 'Статистика бошқармаси', 'Йирик корхоналар улуши камайгани сабабли 2026 йилги 93 та йирик саноат лойиҳасини биринчи навбатда молиялаштириш керак. Саноат ерларидан фойдаланиш коэффициентини 90 фоизга етказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (171, 5, 3, 1, '1', 'Маҳаллий бюджет ва солиқ тушумлари динамикаси', 'Бюджет даромади, солиқ тушумлари, иш ҳақи фонди', 'Маҳаллий бюджет (млрд сўм): 2021: 1993,3 | 2022: 2670,6 | 2023: 3043,0 | 2024: 2989,1 | 2025: 3534,7 | Солиқ даромадлари (млрд сўм): 2021: 1934,4 | 2022: 2445,0 | 2023: 2829,5 | 2024: 3188,3 | 2025: 3779,1', TRUE, 'Молия бошқармаси / Давлат солиқ қўмитаси', 'Маҳаллий бюджет тушумлари тебраниши сабабли солиқ базасини диверсификация қилиш керак. Бюджет барқарорлигини таъминлаш учун кичик бизнес улушини янада кенгайтириш чораларини кўриш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (172, 5, 4, 1, '1', 'Ажратилган кредитлар сифати', 'Кредит ҳажми, кичик бизнес ва оилавий тадбиркорлик кредитлари', 'Умумий кредит (трлн сўм): 2021: 5,2 | 2022: 6,0 | 2023: 6,6 | 2024: 8,6 | 2025: 11,3 | Кичик бизнес кредитлари (трлн сўм): 2021: 2,5 | 2022: 3,1 | 2023: 3,2 | 2024: 3,8 | 2025: 6,5 | Оилавий тадбиркорлик кредитлари: 274 млрд сўм | Жон бошига кредит: 7 641 минг сўм | Банк инфратузилмаси: 15 филиал, 786 банкомат, 2 543 ходим', TRUE, 'Марказий банк', 'Кредит ҳажми ва кичик бизнес молиялаштириши жадал ўсгани вилоятда молиявий фаоллик юқори эканини кўрсатади; эндиликда устувор вазифа — ушбу ўсишни сифатли қайтимга айлантириш. Бунинг учун кредитни “скоринг + бизнес-режа + бозорга чиқиш” бирлашган моделида бериш ва маҳалла даражасида кейинги кузатувни кучайтириш энг юқори самара бериши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (173, 5, 5, 1, '1', 'Google Trends иқтисодий фаоллик', 'Вилоят иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Жами: 55 балл (100 дан) — ўрта-юқори фаоллик | 2024 йил ўртача: 48 балл | 2025 йил ўртача: 55 балл (+14,5% ўсиш) | Энг фаол ой: Июнь 2025 — 72 балл | Энг суст ой: Январь 2025 — 30 балл | Интернет қоплами: 99%, тезлик 600 Гбит/с | Аҳоли кутишлари: Ижобий 59%, Нейтрал 15%, Салбий 26%', TRUE, 'Google', 'Интернет қамрови (99%) жуда юқори эканлигини ҳисобга олиб, рақамли иқтисодий фаолликни 55 баллдан 70 баллгача ошириш имконияти мавжуд. Аҳолининг салбий кутишларини (26%) камайтириш учун Сурхондарёнинг туризм ва агро-экспорт салоҳиятини рақамли платформалар (Google, ижтимоий тармоқлар) орқали манзилли тарғиб қилиш, шунингдек, онлайн банк хизматларидан фойдаланиш даражасини ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (174, 5, 6, 2, '2', 'Ичимлик суви таъминоти динамикаси', 'Марказлаштирилган ичимлик суви таъминоти даражаси', 'Таъминланганлик (%): 2021: 42,7 | 2022: 60,8 | 2023: 62,9 | 2024: 64,7 | 2025: 67,5 (%) | Канализация тармоғи қамрови: 26,5% | Ташиш орқали сув истеъмол қилувчилар: 487 765 киши | Энг яхши: Термиз ш. (98,9%), Шўрчи (82,0%), Қумқўрғон (76,6%) | Энг заиф: Шеробод (45,3%), Ангор (47,1%), Бандихон (47,6%), Бойсун (51,8%)', TRUE, '«Сувоқа» ДУК / Коммунал хизмат бошқармаси', 'Ичимлик суви таъминоти паст Шеробод ва Бойсунга инвестициянинг 60 фоизини йўналтириш керак. Ташиб ичиладиган ҳудудларда қуёш насосли модулларни ўрнатиш тизимини жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (175, 5, 7, 2, '2', 'Йўл инфратузилмаси ва таъмирланиш даражаси', 'Қопламасига кўра йўллар тузилиши ва таъмир талаби', 'Жами: 16 526 км йўллар тармоғи | Таъмир талаб: 5 572 км (33,7%) | Асфальтланганлик: 30,8% | Шағал қоплама: 8 030 км (58,9%) | Асфальт-бетон: 4 015,8 км (29,5%) | Тупроқ йўллар: 1 403,7 км (10,3%) | Цемент-бетон: 180,8 км (1,3%) | Энг оғир туманлар: Бандихон (89,5%), Қумқўрғон (81,3%), Қизириқ (74,3%), Олтинсой (62,1%)', TRUE, 'Йўл бошқармаси', 'Асфальтланмаган йўллар улуши (69,2%) юқорилиги сабабли Бандихон ва Қумқўрғонда йўлларни бетонлаштириш керак. Маҳаллий цемент хом ашёсидан фойдаланиб, йўл инфратузилмасини стратегик кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (176, 5, 8, 2, '2', 'Электр таъминоти сифати ва модернизация', 'Узилишлар, модернизация даражаси ва инфратузилма', 'Жами: Электр тизими таҳлили | Электр узилишлари: Ойига ўртача 3,2 марта | Истеъмолчилар: 613 421 (Аҳоли 94,2%, Юридик 5,8%) | Тармоқ узунлиги: 18 970,6 км | ТП: 6 705 тадан 2 030 таси (30,3%) таъмир талаб | Линиялар: 18 970,6 км дан 758,8 км (4,0%) эскирган | Энг оғир туманлар: Денов (305), Жарқўрғон (219), Қумқўрғон (202), Музработ (151)', TRUE, 'Ҳудудий электр тармоқлари корхонаси', 'Электр узилишларини (ойига 3,2 марта) камайтириш учун таъмирталаб 2030 та трансформаторни алмаштириш керак. Саноат зоналарида марказий тармоқ юкламасини пасайтириш учун қуёш панелларини ўрнатиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (177, 5, 9, 2, '2', 'Ер ресурслари ва қазилма бойликлар таҳлили', 'Ер фонди тузилмаси ва ресурслар захиралари', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 2 009 911 га | Суғориладиган ерлар: 326 000 га | Аҳоли зичлиги: 149,8 киши/км² | Яйловлар: 809 557 га (40,3%) | Экин ерлари: 260 056 га (12,9%) | Дон экинлари: 98,3 минг га | Узумзорлар: 17,7 минг га | Фойдали қазилмалар: 104 та кон (ғишт 43, қум-шағал 24, гипс 9, цемент 7, оҳактош 3)', TRUE, 'Қишлоқ хўжалиги бошқармаси / Геология қўмитаси', 'Яйловлар (40%) салоҳиятини ошириш учун чорвачиликни интенсив ривожлантириш керак. 50 минг гектар ғалла майдонини даромадли писта ва анор боғларига айлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (178, 5, 10, 2, '2', 'Жамоат транспорти ва юк ташиш таҳлили', 'Автобус ва микроавтобус инфратузилмаси, йўловчи ва юк ташиш', 'Жами: 84 та йўналиш (66,7% ички) | Йиллик йўловчи ташиш: 318,9 млн киши | Юк айланмаси: 84,3 млн тонна | Дамас: 878 та (77,6%) | Автобуслар: 223 та (19,7%) | Такси ва бошқалар: 31 та (2,7%) | Юқори қамров: Термиз ш., Денов, Термиз тумани | Тизим йўқ: Бандихон, Қизириқ (0 та), Олтинсой (1 та)', TRUE, 'Транспорт бошқармаси / Статистика бошқармаси', 'Жамоат транспортида Дамаслар (77,6%) улушини камайтириб, автобуслар сонини 300 тага етказиш керак. Олтинсой ва Қизириқда ДҲШ асосида электрик микроавтобуслар хизматини ташкил этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (179, 5, 11, 2, '2', 'Мактабгача таълим қамрови ва тармоғи', 'МТТ шакллари, қамраб олинган болалар ва ёш гуруҳлари', 'Қамров (%): 2021: 55,2 | 2022: 60,6 | 2023: 62,7 | 2024: 67,8 | 2025: 68,4 (%) | Жами МТТлар: 3 367 та | Оилавий МТТ: 2 653 та (78,8%) | Давлат МТТ: 506 та (15,0%) | ДХШ асосидаги: 196 та (5,8%) | Хусусий МТТ: 12 та (0,4%) | Энг заиф ҳудудлар: Бандихон, Термиз тумани, Бойсун', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Мактабгача таълим қамровини (68,4%) ошириш учун Бандихон ва Бойсунда янги МТТлар қуриш керак. Оилавий боғчалар учун йиллик мажбурий сертификация тизимини жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (180, 5, 12, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурсларининг 5 йиллик динамикаси (минг киши)', 'Меҳнат ресурслари (минг киши): 2021: 1463,5 | 2022: 1468,9 | 2023: 1489,6 | 2024: 1509,6 | 2025: 1531,4', TRUE, 'Бандлик бошқармаси', 'Меҳнат ресурслари кўпайиши (1,4%) фонида саноат зоналарида иш ўринлари яратишни жадаллаштириш керак. Янги қишлоқ хўжалиги кластерлари орқали аҳоли бандлигини тизимли таъминлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (181, 5, 13, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси: 4,9% (2025 йил)', 'Ишсизлар сони (минг киши): 2021: 113,9 | 2022: 102,7 | 2023: 80,6 | 2024: 64,3 | 2025: 54,6 | Ишсизлик даражаси (2025): 4,9% | Мақсад (2027): 4,0%', TRUE, 'Бандлик бошқармаси', 'Ишсизликни 4 фоизга тушириш учун ёшлар ва аёллар учун қисқа муддатли касбий курсларни кенгайтириш керак. Ҳар бир маҳаллада манзилли ишга жойлаштириш механизмини кучайтириш лозим.', 54641, 4.9, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (182, 5, 14, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси: 6,1% (2025 йил)', 'Камбағал оилалар: 2021: 92214 | 2022: 82462 | 2023: 73612 | 2024: 61764 | 2025: 54142 (оила) | Ижтимоий ҳимояга муҳтож: 98 906 оила', TRUE, 'Бандлик бошқармаси / МФЙ / Ижтимоий ҳимоя', 'Камбағалликни қисқартириш (6,1%) учун ҳар бир оилага мақсадли микрокредит пакетини шакллантириш керак. Ижтимоий ёрдамни барқарор даромад манбаи яратиш лойиҳалари билан боғлаш лозим.', 54142, 6.1, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (183, 5, 15, 3, '3', 'Ёшлар ва аёллар бандлиги', 'Ишсизликнинг ижтимоий таркиби ва манзилли чоралар', 'Жами: 54,6 минг ишсиз (100% ёшлар ва аёллар) | Ёшлар ишсизлиги (16–30 ёш): 28,4 минг киши (52%) | Аёллар ишсизлиги: 26,2 минг киши (48%)', TRUE, 'Бандлик бошқармаси', 'Ишсиз ёшлар ва аёлларни (54,6 минг) маҳаллабай тизим орқали банд қилиш керак. Уларга касаначилик ва микролойиҳалар учун имтиёзли кредитлар ажратишни кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (184, 5, 16, 3, '3', 'Миграция динамикаси', 'Хорижий меҳнат миграцияси ва қайтиш оқими таҳлили', 'Жами: Миграция таҳлили | Хорижга кетганлар (2025): 71,7 минг киши (−29,6%) | Қайтган мигрантлар: 42,8 минг киши | 2023 йилдаги оқим: 129,2 минг киши | Камайиш: 57,5 минг кишига (−44,5%)', TRUE, 'Бандлик бошқармаси / ИИВ миграция', 'Хориждан қайтган мигрантларнинг (42,8 минг) тажрибасидан маҳаллий тадбиркорликда фойдаланиш керак. Уларни касбий мослаштириш ва лойиҳаларини молиялаштириш дастурларини тақдим этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (185, 5, 17, 4, '4', 'Сунъий интеллект куни ва СИ ўқитиш дастури', 'Ҳафталик СИ куни ва 4 босқичли ўқитиш тизими', 'Жами: СИ малака ошириш дастури | «Сунъий интеллект куни» — ҳар ҳафтанинг жума куни СИ ўқитишга бағишланади | 1-босқич: Ҳар ҳафта жума куни СИ ўқитиш куни | 2-босқич: Туман ҳокимлари ва ҳоким ўринбосарлари — СИ ўқитиш ва СИ қўллашни жорий қилиш | 3-босқич: Банк филиал раҳбарлари ва маҳалла банкирлари — СИ скоринг, риск таҳлили ва мижоз хизмати | 4-босқич: Маҳалла раислари ва ҳоким ёрдамчилари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', '4 босқичли СИ ўқитиш дастури: жума куни СИ куни, ҳокимлар стратегик СИ қўллаш, банк ходимлари скоринг ва мижоз хизмати, маҳалла раислари маълумотлар таҳлили. Ҳар бир босқичга аниқ КПИ жорий этиш ва натижаларни ҳар чоракда баҳолаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (186, 5, 18, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Банкнинг сунъий интеллект асосидаги маслаҳат платформаси', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформасини йил якунигача барча 723 маҳаллада тўлиқ ишга тушириш керак. Тадбиркорларга СИ орқали бизнес-режалар тузиш ва молиявай маслаҳат беришни кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (187, 5, 19, 4, '4', 'Маҳалла драйвер секторлари', '723 та маҳалланинг асосий иқтисодий йўналишлари', 'Жами: 723 та маҳалла, 4 та драйвер сектор | 1-сектор Деҳқончилик: асосий меҳнат ресурсларини қамраб олувчи тармоқ | 2-сектор Чорвачилик: озиқ-овқат хавфсизлиги ва аҳоли даромади | 3-сектор Қурилиш: инфратузилма ва янги иш ўринлари драйвери | 4-сектор Хизматлар: турмуш даражасини ошириш ва тадбиркорлик', TRUE, 'Бандлик бошқармаси / SQB', 'Драйвер секторларни (деҳқончилик, чорвачилик, қурилиш, хизматлар) кластер тизимида бирлаштириш керак. Мева-сабзавот ва тоғ-кон захираларини ўзлаштириш даражасини кескин ошириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (188, 5, 20, 4, '4', 'Ишсизлик юқори маҳаллалар', '723 та маҳалланинг тоифалаштириши ва оғир ҳудудлар таҳлили', 'Жами: 723 та маҳалла | Қизил тоифа: 114 та маҳалла | Сариқ тоифа: 217 та маҳалла | Яшил тоифа: 393 та маҳалла | Манзилли режа: 114 та қизил тоифадаги маҳалла бўйича алоҳида бандлик дастури | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'Бандлик бошқармаси / МФЙ агентлиги', 'Қизил тоифадаги 114 та маҳаллада «бир маҳалла — бир драйвер» тамойилини жорий этиш керак. Ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда микролойиҳаларга жалб қилиш ва бандликни таъминлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (189, 5, 21, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Лойиҳалар, иш ўринлари ва банк инфратузилмаси', 'Жами: 7 240 та лойиҳа | Иш ўринлари: 14 480 та | Жами маҳаллалар: 723 та | Банк филиаллари: 15 та', TRUE, 'Марказий банк', 'Микролойиҳалар орқали яратилган иш ўринлари барқарорлигини таъминлаш учун банкирлар мониторингини кучайтириш керак. Кредит скорингида рақамли платформалардан кенг фойдаланиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (190, 5, 22, 4, '4', 'SQB рақамли хизматлари', 'Банкнинг рақамли платформалари ва хизматлари', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: 15 филиал, 786 банкомат, маҳалла банкирлари 2 543 та (941 аёл, 1 602 эркак)', TRUE, 'SQB / Марказий банк', 'Мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш орқали рақамли хизматлар улушини ошириш керак. Банк ходимларининг масофавий хизмат кўрсатиш кўникмаларини такомиллаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (191, 5, 23, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит дастури', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кенгайтириш учун AI Advisor платформасида кредит скоринг тизимини қўллаш керак. Имтиёзли кредитлардан самарали фойдаланиш бўйича маҳаллабай маслаҳатларни кучайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (192, 5, 24, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: HAMROH дастури | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', '«HAMROH» дастури доирасида хотин-қизларни тадбиркорликка жалб қилиш кўламини ошириш керак. Улар учун махсус бизнес тренинглар ва гаровсиз кредитлаш тизимини кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (193, 5, 25, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Оғир тоифадаги маҳаллалар учун манзилли бандлик va кредит дастурлари', 'Жами: 114 та маҳалла, оғир тоифа | Ишсизлар (2025): 54 641 киши | Ёшлар (16–30): 28 413 киши | Аёллар: 26 228 киши | Кредит маҳсулотлари: 1) Микрокредит 2) Оилавий тадбиркорлик 3) Давлат субсидияси 4) Лизинг | Мақсад: 2027 йилгача 4% га тушириш', TRUE, 'SQB / Бандлик бошқармаси', 'Оғир маҳаллаларда ипакчилик ва мева қайта ишлаш бўйича кичик лойиҳаларни молиялаштириш керак. 2027 йилгача ишсизликни 4 фоизга тушириш учун манзилли кредитлар ажратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (194, 5, 26, 5, '5', 'Қуёш энергетикаси ва субтропик иқлим', 'Арзон электр манбаи ва қайта тикланувчи энергия салоҳияти', 'Жами: 300+ қуёшли кун/йил | Йўналиш: Қуёш электр станциялари (СЭС) ва гибрид панеллар | Имконият: 52 та саноат зонасини арзон энергия билан таъминлаш | Инвестиция: $10–40 млн/лойиҳа', TRUE, 'Энергетика вазирлиги', 'Сурхондарёнинг юқори қуёш радиациясидан фойдаланиб, нафақат йирик СЭСлар, балки тоғли ҳудудлардаги (Бойсун, Сариосиё) тадбиркорлар учун кичик мобил қуёш агрегатларини жорий этиш керак. Бу маҳсулот таннархини 15-20% га тушириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (195, 5, 27, 5, '5', 'Жанубий «Қуруқ порт» ва логистика маркази', 'Афғонистон ва Тожикистон билан чегарадош стратегик нуқта', 'Жами: Жанубий логистика маркази | Темир йўл станциясигача: 1 км | Умумий йўллар тармоғи: 16 526 км | Реконструкция: М-41 (159 км) ва А-164 (4,5 км) халқаро йўллар', TRUE, 'Транспорт бошқармаси', 'Сурхондарёни Ўзбекистоннинг жанубий дарвозаси сифатида «Dry Port» (Қуруқ порт) концепцияси асосида ривожлантириш лозим. Термиз эркин иқтисодий зонасини Жанубий Осиё (Покистон, Ҳиндистон) бозорларига чиқувчи асосий дистрибьюторлик марказига айлантириш имконияти мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (196, 5, 28, 5, '5', 'Тоғ-кон ва қурилиш материаллари кластери', 'Хомашё захираларининг атиги 34 фоизи ўзлаштирилган', 'Жами: 103 та фойдали қазилма кони (12 хил хомашё) | Оҳактош: 308 млн тонна | Гилла (Керамика хомашёси): 133 млн тонна | Гипс ва цемент конлари | Кластер: 31 та корхона, 1,5 трлн сўм/йил | Ўзлаштирилган: атиги 34%', TRUE, 'Геология қўмитаси', 'Захираларнинг 66% ҳали фойдаланилмасдан ётибди. Вилоятда қурилиш материаллари (айниқса пардозлаш тошлари ва тайёр гипс маҳсулотлари) бўйича экспорт хабини яратиш ва Термиз орқали Афғонистон қайта қурилиши бозорига кириш стратегик аҳамиятга эга.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (197, 5, 29, 5, '5', 'Туризм ва курорт шаҳар — Бойсун ҳамда Сангардак', 'UNESCO мероси «Boysun Bahori», Сангардак табиий зонаси — халқаро туризм салоҳияти', 'Жами: Туризм потенциали | 265 000 йиллик сайёҳлар (Сангардак, 2025) — режа x2 ошади | Бойсун курорт шаҳри: 172 млрд сўм инвестиция (2026–2028) | Туризм иш ўринлари: 2026: 750 → 2027: 835 | Йўналишлар: экотуризм, этнография (Бойсун), археологик мерос (Далварзинтепа, Фаёзтепа)', TRUE, 'Туризм бошқармаси / Инвестиция бошқармаси', 'Бойсун ва Сангардакнинг туризм салоҳиятини ошириш учун «Жанубий йўналиш» ягона брендини яратиш керак. Инфратузилмага киритиладиган инвестицияларни бутик меҳмонхоналар ва сервисга йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (198, 5, 30, 5, '5', 'Писта, узум ва юқори маржали боғдорчилик', 'Интенсив боғлар ва субтропик мевалар — экспорт потенциали $500+ млн', 'Жами: Боғдорчилик потенциали | 8 000 гектар янги писта боғлари (2026–2028 режа) | Узум майдони: 17 700 га, ҳосил 94 400 т, қайта ишлаш 11% (GAP 89%) | Қ/х ҳажми: 42,2 млрд сўм (2025) — 2021 га нисбатан х1,8 | Ер фонди: 260 056 га экин ери, 326 000 га суғориладиган', TRUE, 'Қ/х бошқармаси / Инвестиция бошқармаси', 'Субтропик иқлимдан фойдаланиб, 8 минг гектарда янги писта боғларини ташкил этиш керак. Узумчиликда қайта ишлаш даражасини ошириш орқали экспорт тушумини кўпайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (199, 5, 31, 5, '5', 'Қишлоқ хўжалик маҳсулотларини қайта ишлаш', 'Хомашёнинг 87% хом ҳолда сотилмоқда — қўшимча қиймат имконияти', 'Жами: 87% хомашё ҳолда сотилмоқда | Гўшт қайта ишлаш: атиги 1,1% (республикадан ~20× паст) | Сабзавот қайта ишлаш: 13,1% | Узум қайта ишлаш: 11%', TRUE, 'Қ/х бошқармаси / Статистика бошқармаси', 'Қишлоқ хўжалиги маҳсулотларининг 87% хом ҳолда сотилмоқда — бу катта йўқотиш. Янги консерва, гўшт ва сут заводларини қуриш орқали қайта ишлаш занжирини яратиб, қўшимча қийматни ошириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (200, 5, 32, 5, '5', 'Демографик дивиденд ва меҳнат ресурслари', '3 млн аҳоли, ёш ва ўсаётган меҳнат бозори — Ўзбекистон ўртачасидан устун динамика', 'Жами: Демографик таҳлил | 3 011 минг киши (2025) — 2021 дан +268 минг ўсиш | Меҳнат ресурслари: 1 531 минг киши | Ишсизлик: 10,2% → 4,9% (2021→2025) | Камбағаллик: 13,3% → 6,1% — 4 йилда 2 баравар пасайди | Қайтган мигрантлар: 2025: 42 893 киши (ички меҳнат бозорига импулс)', TRUE, 'Статистика бошқармаси / Бандлик бошқармаси', 'Ёш меҳнат ресурсларини (1,5 млн) замонавий тармоқларга жалб қилиш учун IT-Park филиалларини кенгайтириш керак. Қайтган мигрантлар тажрибасидан маҳаллий лойиҳаларда фойдаланиш тизимини яратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (201, 5, 33, 5, '5', 'Бойсун ва Сангардак: Халқаро Эко-Этно туризм', 'UNESCO мероси ва табиий шаршаралар салоҳияти', 'Жами: 265 000 йиллик сайёҳ (Сангардак, 2025) | Бойсун курорт шаҳри инвестициялари: 172 млрд сўм | UNESCO мероси: «Бойсун баҳори» фестивали | Археологик обидалар: Далварзинтепа, Фаёзтепа | Зиёрат: Ал-Ҳаким ат-Термизий', TRUE, 'Туризм бошқармаси', 'Бойсун ва Сангардакни «Жанубий Швейцария» бренди остида дунёга танитиш керак. Фақат мавсумий фестиваллар билан чекланмай, йил бўйи ишловчи бутик-меҳмонхоналар ва Глампинг тизимини ривожлантириш орқали туристларнинг қолиш вақтини 3-4 кунгача узайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (202, 5, 34, 5, '5', 'Экспортбоп боғдорчилик ва пистачилик', 'Юқори маржали мевалар ва субтропик экинлар', 'Жами: $500 млн+ экспорт потенциали | Писта боғлари режаси (2026–2028): 8 000 га | Узумзорлар майдони: 17 700 га | Узум қайта ишлаш: атиги 11% | Субтропик мевалар: лимон, анор, хурмо', TRUE, 'Қишлоқ хўжалиги бошқармаси', 'Вилоятнинг иқлими Ўзбекистонда ягона бўлиб, лимон, анор ва хурмо етиштиришда рақобатсиз. Бироқ қайта ишлаш даражаси жуда паст (узумда атиги 11%). Тавсия: маҳсулотни хом ҳолда эмас, балки сублимация (музлатиб қуритиш) технологияси орқали экспорт қилиш занжирини яратиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (203, 5, 35, 5, '5', 'Аҳоли бандлигини таъминлаш ва даромадини ошириш', '2026 йил режаси: доимий иш ўрни яратиш ва аҳоли даромадини ошириш', 'Жами: 67 327 нафар (2026 йил режаси) | Инвестиция лойиҳалари: 7 832 нафар | Ёшлар ва битирувчилар: 8 705 нафар | Қишлоқ хўжалиги соҳаси: 5 192 нафар | Қайтган мигрантлар: 27 812 нафар | Хизмат кўрсатиш ва сервис лойиҳалари: 17 786 нафар', TRUE, 'Бандлик бошқармаси / Ҳокимият / SQB', '67 327 нафар ишсизларни банд қилиш учун асосий эътиборни хизмат кўрсатиш (17 786) ва инвестиция лойиҳалари (7 832) орқали тез ва барқарор иш ўринлари яратишга қаратиш, 27 812 нафар қайтган мигрантларни тадбиркорликка йўналтириш, 8 705 нафар ёшларни касбга ўқитиш ва 5 192 нафарни қишлоқ хўжалигида банд қилиш зарур. Бу ёндашув даромадларни барқарор оширишга хизмат қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (204, 5, 36, 6, '6', 'Стратегик устунликлар — 4 та таянч нуқта', 'SWOT асосида шакллантирилган вилоятнинг ички потенциали', 'Жами: 4 та стратегик устунлик | 1-устунлик: Субтропик иқлим ва 300+ қуёшли кун/йил (қайта тикланувчи энергетика) | 2-устунлик: Табиий ресурсларга бойлик — 103 та кон, 12 хил хомашё | 3-устунлик: Жанубий транспорт дарвозаси — темир йўлга 1 км, Афғонистон чегараси | 4-устунлик: Демографик дивиденд — 3 011 минг аҳоли, 1 531 минг меҳнат ресурси', TRUE, 'Вилоят ҳокимияти', 'Вилоятнинг 4 та стратегик устунлигини бирлаштирган саноат хабларини ташкил этиш керак. Саноатда рақобатдош маҳсулотлар ишлаб чиқариш учун инвестицион ТТИ оқимини кўпайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (205, 5, 37, 6, '6', 'Лойиҳа фабрикаси — 402 лойиҳалик портфель', 'Тармоқлар бўйича диверсификацияланган инвестицион қамров', 'Жами: 402 та лойиҳа — 131 млрд сўм — 15 163 иш ўрни | Хизмат кўрсатиш: 219 та лойиҳа, 2026: 3 703 млрд сўм | Саноат: 110 та лойиҳа, 2026: 5 000 млрд сўм, 93 та катта саноат лойиҳаси | Қишлоқ хўжалиги: 73 та лойиҳа, писта 8 000 га, узум қайта ишлаш', TRUE, 'Инвестиция бошқармаси / Вилоят ҳокимияти', 'Инвестиция портфелидаги саноат ва хизмат кўрсатиш лойиҳаларини ўз вақтида ишга тушириш керак. 15 минг янги иш ўрни яратиш учун молиялаштириш занжирини узлуксиз таъминлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (206, 5, 38, 6, '6', 'Молиялаштириш архитектураси (0–5 йил)', 'Қисқа, ўрта ва узоқ муддатли маблағ манбалари — мувозанатли капитал оқими', 'Жами: Молиялаштириш режаси | 7,2 трлн сўм — 2026 йил кредитлаш режаси | Қисқа (0–12 ой): Кредит 7,2 трлн + Оғир тоифа маҳаллалар 892 млрд | Ўрта (1–3 йил): Саноат кредитлари 2,2 млрд + ЭИЗ 328 млрд + КСЗ 70 млрд | Узоқ (3–5 йил): Кредит 14,2 трлн + ЭИЗ 716 млрд + КСЗ 150 млрд | Халқаро: ЕБРР 6 лойиҳа ($7,5 млн) + АБР 19 лойиҳа ($16,5 млн) + Жаҳон банки 23 лойиҳа ($14,5 млн)', TRUE, 'Марказий банк / SQB / Инвестиция бошқармаси', 'Банк тизимини соғломлаштириш учун саноат инфратузилмасини ривожлантириш ва янги молиявий инструментларни қўллаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (207, 5, 39, 6, '6', 'Инвестиция жалб қилиш йўл харитаси 2026–2031', '6 йиллик ўсиш траекторияси — режа х1,5 бажарилиш тренди', 'Инвестиция режаси (млрд сўм): 2026: 640 | 2027: 705 | 2028: 780 | 2029: 830 | 2030: 890 | 2031: 950 | Бажарилиш тарихи: 2021: 103% → 2025: 114%', TRUE, 'Инвестиция бошқармаси', 'Инвестиция режасини бажариш учун юқори технологияли саноат улушини 15 фоизгача етказиш керак. Давлат-хусусий шериклик асосида йирик инфратузилма лойиҳаларини молиялаштиришни жадаллаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (208, 5, 40, 6, '6', '2030 йил мақсадлари — 9 та стратегик КПИ', 'Сурхондарёни ТОП-5 вилоятга олиб чиқадиган маёқлар', 'Жами: 9 та стратегик КПИ (2030 мақсад) | Янги иш ўринлари: 67 327 та/йил | Янги тадбиркорлар: 5 250 та/йил | Аҳоли даромади ўсиши: +12%/йил | Импорт ўрнини босиш: 60% | Кредит қайтариш: 87,7% → 97%+ | Камбағаллик: 6,1% → 2% | Ишсизлик: 4,9% → 2,5% | Туризм экспорти: $20+ млн | Рейтинг: 10-ўрин → ТОП-5', TRUE, 'Вилоят ҳокимияти / Статистика бошқармаси', '2030 йил стратегик мақсадларига эришиш учун ҳар бир КПИ бўйича чораклик мониторинг тизимини жорий этиш керак. Сурхондарёни республика рейтингида ТОП-5 вилоят қаторига олиб чиқиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (6, 3, 'boysun', 'Бойсун', 'Байсун', 'Boysun', '', 'boysun_tuman.json', TRUE, NULL, NULL, 40, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
