INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (209, 6, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва экспортнинг ўсиш динамикаси', 'Саноат ҳажми (млрд сўм): 2021: 100,6 | 2022: 108,7 | 2023: 150,7 | 2024: 223,7 | 2025: 300,6 | Хизматлар ҳажми (млрд сўм): 2021: 330,0 | 2022: 403,4 | 2023: 483,2 | 2024: 580,8 | 2025: 761,5 | Экспорт ҳажми (минг $): 2021: 5 611 | 2022: 8 981 | 2023: 7 059 | 2024: 9 175 | 2025: 16 339 | Маҳаллий бюджет (млрд сўм): 2021: 58,1 | 2022: 76,0 | 2023: 52,8 | 2024: 60,7 | 2025: 86,8', TRUE, 'Статистика бўлими', 'Туман иқтисодиётида саноат ҳажми 5 йилда 3 баробар, хизматлар эса 2,3 баробар ўсган. Энг катта ютуқ экспортнинг 16 млн доллардан ошишидир. Стратегия: ЯҲМ республика ўртачасининг 23% ни ташкил этиши ҳудудда ҳали ишга солинмаган улкан имкониятлар борлигини англатади. Саноатда кичик бизнес улуши юқорилигини (92%) инобатга олиб, кластер тизимини ривожлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (210, 6, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Туман иқтисодиётининг асосий ҳаракатлантирувчи кучлари', 'Қишлоқ хўжалиги (64,9%): 2025 йилда 21,6 трлн сўм прогноз | Хизматлар ва савдо (25,1%): Юк айланмаси йилига 3,3 млн тоннадан ошган | Саноат ва қурилиш материаллари (10%): Кичик тадбиркорлик маҳсулоти 277,5 млрд сўм | Капитал қўйилмалар: 107 та янги корхона очилган', TRUE, 'Туман ҳокимияти / Статистика', 'Иқтисодиётнинг 65%и қишлоқ хўжалигига боғлиқлиги "моно-драйвер" хавфини туғдиради. Стратегия: Хизмат кўрсатиш ва саноат драйверларини СИ технологиялари (ақлли агро-сервис) ва қурилиш материаллари кластери орқали кучайтириш, драйверлар мувозанатини таъминлаш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (211, 6, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Саноат ишлаб чиқариш индекси ва ҳажми', '2021: 100,6 млрд сўм (109,6%) | 2022: 108,7 млрд сўм (103,3%) | 2023: 150,7 млрд сўм (110,3%) | 2024: 223,7 млрд сўм (108,3%) | 2025: 300,6 млрд сўм (110,2%)', TRUE, 'Статистика бўлими', 'Саноатда ўсиш суръати барқарор (ўртача 108-110%). Диққатга сазовор жиҳати — йирик корхоналар ишлаб чиқариши 2024 йилда 5,5 млрддан 20,1 млрдга (4 баробар) сакраган. Стратегия: Ушбу "йирик саноат драйвери"ни қўллаб-қувватлаш ва кичик корхоналарни (95 млрддан 277 млрдга ўсган) уларга кооперация асосида боғлаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (212, 6, 4, 1, '1', 'Маҳаллий бюджет', 'Маҳаллий бюджет даромадлари динамикаси', 'Даромадлар (млрд сўм): 2021: 58,1 | 2022: 76,0 | 2023: 72,4 | 2024: 60,7 | 2025: 86,8', TRUE, 'Туман молия бўлими', 'Маҳаллий бюджет даромадлари 2025 йилда 86,8 млрд сўмга етиб, 2023 йилга нисбатан 64% га ўсиши прогноз қилинмоқда. Контингент бюджет режасининг 30,3 млрдгача оширилиши туманда солиқ базаси кенгаётганини кўрсатади. Тавсия: бюджет тушумларининг ошишини ижтимоий инфратузилма ва бизнес учун "soft power" лойиҳаларига йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (213, 6, 5, 1, '1', 'Ажратилган кредитлар', 'Кичик тадбиркорликка ажратилган кредитлар динамикаси (млрд сўм)', '2021: 67,4 | 2022: 92,6 | 2023: 117,9 | 2024: 135,3 | 2025: 163,7 (млрд сўм)', TRUE, 'Марказий банк', 'Кредитлаш ҳажмининг 67,4 млрддан 163,7 млрдгача ошиши ҳудудда тадбиркорлик субъектларининг молиявий ресурсларга бўлган талаби ортаётганини кўрсатади. Раҳбарият учун таклиф: кредитларнинг асосий қисмини тумандаги «драйвер» соҳалар — чорвачилик ва мева-сабзавотни қайта ишлаш лойиҳаларига йўналтириш орқали янги иш ўринлари сонини кўпайтириш ва бюджет тушумларини 2025 йилги прогноз (27,8 млрд сўм) даражасига чиқариш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (214, 6, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Аҳоли ва бизнеснинг рақамли қизиқиши (0-100 шкаласи)', 'Умумий балл: 48/100 (ўртача фаоллик) | 2024 йил ўртача: 42 балл | 2025 йил ўртача: 48 балл (+14% ўсиш) | Энг фаол ой: Май 2025 — 72 балл | Энг суст ой: Декабр 2024 — 28 балл | Мавсумийлик: Баҳор-Ёз юқори, Қиш суст', TRUE, 'Google Trends таҳлили', 'Google Trends 48/100 балл — Бойсун учун ўсиш салоҳияти мавжудлигини англатади. Туманнинг 42% аҳоли ва бизнесида ижобий кутишлар мавжудлиги рақамли фаолликни оширишга замин яратади. Тавсия: "Бойсун — экотуризм маркази" брендини рақамли маконда тарғиб қилиш ва инвестиция лойиҳалари ҳақида интернетда маълумотларни кўпайтириш орқали индексни 60+ баллга чиқариш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (215, 6, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Ичимлик суви таъминоти динамикаси (%)', '2021: 62.3 | 2022: 62.8 | 2023: 63.5 | 2024: 64.2 | 2025: 72.1 (%)', TRUE, 'Сув хўжалиги бўлими', 'Сув таъминотида барқарор ўсиш кузатилмоқда (5 йилда +4,8%). Бироқ, аҳолининг 32% дан ортиғи ҳали ҳам тоза ичимлик суви билан таъминланмаган. Стратегия: Қурилиш материаллари саноатидан тушадиган маҳаллий бюджет даромадларини сув қувурларини ётқизиш лойиҳаларига йўналтириш орқали қамровни тезлаштириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (216, 6, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Йўл инфратузилмаси ҳолати', 'Умумий йўллар узунлиги: 1 224 км | Асфальтланган йўллар улуши: 71,1% | Вилоят марказигача масофа: 145 км | Темир йўл станциясигача масофа: 12 км', TRUE, 'Йўл хўжалиги бўлими', 'Туман йўлларининг 71 фоизи асфальтлангани логистика учун ижобий кўрсаткич. Лекин Бойсуннинг тоғли ҳудуд эканини инобатга олсак, йўлларнинг сифати юк ташиш ҳажмига (йилига 3,3 млн тонна) тўғри келиши керак. Тавсия: "Мустақиллик" КСЗ атрофидаги йўлларни биринчи навбатда модернизация қилиш юк айланмаси ва инвестиция жозибадорлигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (217, 6, 9, 2, '2', 'Электр таъминоти сифат даражаси (%)', 'Электр тармоқлари ҳолати ва муаммолар', 'Электр узилишлари: Ойига ўртача 4,2 марта | Трансформаторлар ҳолати: 38% модернизацияга муҳтож (эскирган) | Линиялар ҳолати: 35% қисмини алмаштириш зарур', TRUE, 'Электр тармоқлари корхонаси', 'Трансформаторларнинг деярли учдан бир қисми эскиргани саноат ўсиши (йиллик 110%) учун асосий тўсиқдир. Тавсия: Саноат зонасида ердан фойдаланиш 79% га етганини ҳисобга олиб, ушбу ҳудудда алоҳида "Ақлли тармоқ" (Smart Grid) тизимини жорий этиш ва трансформаторларни янгилаш бўйича мақсадли дастур ишлаб чиқиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (218, 6, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Ҳудудий тақсимот ва ер ресурслари', 'Туман умумий майдони: 320 577 гектар | Суғориладиган ер майдони: 4558 гектар (умумий майдоннинг 2%) | Каналларнинг бетонлашиш даражаси: 17% | Аҳоли зичлиги: 40,3 киши/км²', TRUE, 'Кадастр агентлиги', 'Суғориладиган ерлар ҳажми жуда камлиги Бойсун иқтисодиётида нега чорвачилик ва тоғ-кон саноати муҳимлигини тушунтиради. Тавсия: Каналларнинг бетонлашиш даражаси (17%) жуда паст. Сув исрофини камайтириш учун бетонлаштириш даражасини камида 40-50% га чиқариш лозим, бу мавжуд 6,5 минг гектар ернинг маҳсулдорлигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (219, 6, 11, 2, '2', 'Жамоат транспортидан фойдаланиш (%)', 'Мобиллик кўрсаткичлари ва динамика', 'Йўловчи ташиш ҳажми (2025 прогноз): 5 782,4 минг киши/йил | Юк ташиш ҳажми: 3 357 минг тонна | Динамика: 2021 йилга (4,6 млн) нисбатан 25% га ошган', TRUE, 'Туман статистика бўлими', 'Йўловчи оқимининг йиллик 5,7 млн кишига етиши жамоат транспортига бўлган талаб юқорилигини кўрсатади. Тавсия: Вилоят марказигача бўлган 145 км масофани инобатга олиб, шаҳарлараро транспорт йўналишларини кўпайтириш ва рақамли йўналиш хариталарини (GPS мониторинг) жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (220, 6, 12, 2, '2', 'Мактабгача таълим қамрови', 'Болаларни боғчаларга қамраб олиш ҳолати ва инфратузилма', 'Жами: МТТ таҳлили (2025) | 3–7 ёшли болалар: 12 050 нафар | Қамраб олинган: 8 375 нафар (69,5%) | Жами МТТ сони: 116 та | Давлат МТТ: 25 та | Давлат-хусусий шерикчилик: 12 та | Оилавий нодавлат МТТ: 79 та', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Бойсун туманида мактабгача таълим қамрови 69,5% ни ташкил этмоқда. Бу кўрсаткич шуни англатадики, тумандаги 3 675 нафар (30,5%) бола ҳали таълим билан қамраб олинмаган. Диққатга сазовор жиҳати — инфратузилманинг асосий қисми (68%) оилавий боғчалар ҳисобига тўғри келмоқда.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (221, 6, 13, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурсларининг 5 йиллик динамикаси', '2021: 61432 | 2022: 62712 | 2023: 63645 | 2024: 64825 | 2025: 65596 (киши)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор ўсиб бормоқда. Аммо ўсиш суръати секин (йилига ~1,2%). Янги иш ўринлари яратишни, айниқса ёшлар ва аёлларни расмий бандликка жалб қилишни кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (222, 6, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва миграция таҳлили', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 44 365 киши (+1,9%) | Норасмий секторда банд: 19 241 киши | Хорижга кетганлар (2025): 2 618 киши | Қайтган мигрантлар (2025): 4 952 киши', TRUE, 'Бандлик маркази / ИИВ миграция', '2025 йилда 4 952 та мигрант қайтиши кескин ошган. Қайтган кадрларнинг кўникмаларини маҳаллий иқтисодиётга йўналтириш ва норасмий секторни (19 241 киши) расмийлаштириш орқали бандликни сезиларли ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (223, 6, 15, 3, '3', 'Ишсизлик кўрсаткичлари', '2 607 нафар ишсиз (2025 йил)', '2021: 6741 | 2022: 5923 | 2023: 4584 | 2024: 3892 | 2025: 2607 (киши)', TRUE, 'Бандлик маркази', 'Ишсизлик 9,7% дан 5,6% га тушган, ишсизлар сони 6 741 дан 2 607 га камайган — 5 йилда 2,6 баробар қисқарган. 2027 йилгача 3% мақсадига эришиш учун ёшлар ва аёлларга йўналтирилган касб-ҳунар курслари ва микролойиҳалар учун имтиёзли кредитларни кучайтириш зарур.', 2607, 5.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (224, 6, 16, 3, '3', 'Камбағаллик кўрсаткичлари', '3 024 нафар камбағал оила (2025 йил)', '2021: 16,4 | 2022: 15,7 | 2023: 14,5 | 2024: 12,8 | 2025: 5,7 (%)', TRUE, 'Бандлик, МФЙ, Статистика бўлими', 'Камбағаллик 5 йилда 16,4% дан 5,7% га тушган — жуда кучли натижа. 2026 йил охиригача 3% гача тушириш учун 23 851 та хонадон кесимида ҳар бир камбағал оилага (жами 954 нафар) мақсадли микрокредит ва субсидия пакети шакллантирилиши лозим. Ижтимоий ёрдамни нафақа билан эмас, иш ўрни яратиш ва микрокредит пакетлари билан боғлаш орқали доимий даромад манбаи шакллантириш тавсия этилади.', 3024, 5.7, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (225, 6, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар ишсизлиги, маош динамикаси ва миграция', 'Жами: Ёшлар бандлиги | Ёшлар ишсизлиги (16-30): 437 киши | Ўртача маош (2025): 4 351 минг сўм (+29,2%) | Хорижга кетганлар (2025): 2 618 киши | Қайтган мигрантлар (2025): 4 952 киши', TRUE, 'Бандлик маркази / ИИВ миграция', '2025 йилда қайтган мигрантлар (4 952) кетганлардан (2 618) икки баробар кўп. Бу кадрларни ёшларга мўлжалланган дуал таълим ва касбий қайта тайёрлаш дастурлари орқали маҳаллий иқтисодиётга жалб қилиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (226, 6, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий ҳимоя', 'Жами: Аёллар бандлиги | Аёллар ишсизлиги: 1 342 киши | Маҳалла банкирлари (аёл): 1 нафар | Ўртача маош (2025): 4 351 минг сўм (+29,2%)', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя', '1 342 ишсиз аёлга қарши атиги 1 та аёл маҳалла банкири мавжуд. Аёл банкирлар сонини кўпайтириш, маҳалла кесимида касбга йўналтириш дастурлари ва имтиёзли молиялаштиришни кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (227, 6, 19, 3, '3', 'Бойсун туманидаги техникумлар', 'Профессионал таълим муассасалари ва қувватдан фойдаланиш', 'Жами: 3 та техникум, 1 338 нафар ўқувчи | Умумий қувват: 2 085 ўрин | Бўш ўринлар: 747 та | 1-сон: 488 ўқувчи (қувват 600, 81% банд) | 2-сон: 409 ўқувчи (қувват 900, 45% банд) | 3-сон: 441 ўқувчи (қувват 585, 75% банд)', TRUE, 'Олий таълим, фан ва инновациялар бўлими', 'Бойсун туманидаги техникумлар ҳозирда 64% қувват билан ишламоқда, бу эса мавжуд таълим инфратузилмасининг 36% (747 та ўрин) бекор турганини англатади. Айниқса, 2-сон техникумнинг потенциалидан фойдаланиш даражаси жуда паст (45%). Бу ҳолат туманнинг ишсизлик кўрсаткичлари ва миграция оқими билан мутаносиб эмас.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (228, 6, 20, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | СҚБ Бойсун филиали ходимлари учун | «Сунъий интеллект куни»: Ҳар чоршанба — амалий кейслар таҳлили | Онлайн таълим: Ходимларнинг 90% дан ортиғи СИ модулларини якунлади | Маҳалла банкирлари: СИ асбобларидан (chatbot, data analysis) фойдаланиш кўникмаси шакллантирилди', TRUE, 'SQB', 'Бойсун каби тоғли ва чекка ҳудудларда банк хизматларини тезлаштиришда СИ муҳим рол ўйнайди. Ходимларнинг СИ саводхонлиги мижозларга хизмат кўрсатиш вақтини 30% га қисқартириш имконини беради. Тавсия: СҚБ мобил иловаси орқали масофавий хизматларни кенгайтиришда ходимларнинг СИ бўйича эгаллаган билимларини амалиётда қўллаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (229, 6, 21, 4, '4', 'Раҳбарлар, МФЙ раислари ва банкирларни СИ га ўқитиш', 'Ҳоким ёрдамчилари, МФЙ раислари ва банкирлар учун 4 босқичли СИ ўқитиш дастури', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Туман ҳокими ва ёрдамчилари — Бойсунни ривожлантиришда СИ ва Big Data (туризм ва чорвачилик таҳлили) | 2-босқич: Банк филиал раҳбарлари — Кредит скоринги ва иқлим рискларини прогноз қилиш | 3-босқич: Маҳалла банкирлари — СИ платформаси орқали маҳаллабай хизмат кўрсатиш | 4-босқич: МФЙ раислари — Маҳалланинг «рақамли паспорти», аҳоли эҳтиёжлари таҳлили ва маҳалла ривожланиш режасини СИ ёрдамида тузиш', TRUE, 'SQB', 'Ҳоким ёрдамчилари туман стратегиясини СИ асосида шакллантиради, МФЙ раислари эса маҳалла даражасида амалий қарорлар қабул қилишда СИ дан фойдаланади. Тавсия: МФЙ раисларига «рақамли паспорт» тизимини ўргатиш — ҳар бир маҳалланинг кучли ва заиф томонларини аниқлаб, мақсадли лойиҳалар режалаштиришга имкон беради. Ҳоким ёрдамчилари эса ушбу маълумотларни туман миқёсида умумлаштириб, ресурсларни тўғри тақсимлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (230, 6, 22, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'Жами: 2026 йил режаси | Қамров: 1 450 нафар Бойсунлик ёшлар ва аёллар СИ платформасида ўқитилади | СИ таҳлили: Аҳолининг ҳунармандчилик (каштачилик) ва тоғ туризми бўйича кўникмаларини баҳолаш | Индивидуал дастур: СИ-ментор ёрдамида шахсий бизнес-трек яратиш | Натижа: Тайёр бизнес-режа ва банкдан имтиёзли кредит таклифи', TRUE, 'SQB', 'Бойсуннинг «Бойсун баҳори» каби туризм салоҳиятидан фойдаланган ҳолда аҳолини хизмат кўрсатиш соҳасига СИ орқали ўқитиш самаралидир. Тавсия: Платформа иштирокчиларининг камида 75% ини туризм ва қўшимча қийматли қишлоқ хўжалиги маҳсулотлари етиштиришга йўналтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (231, 6, 23, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва Бойсун тадбиркорларига СИ ёрдами берувчи тизим', 'Жами: SQB AI Advisor функциялари | СИ Маслаҳатчи: Бойсунда туризм ва чорвачиликни ривожлантириш бўйича ҳуқуқий-молиявий маслаҳатлар | Бизнес-режа генератори: Меҳмон уйлари ва иссиқхоналар учун автоматик бизнес-лойиҳалар | KPI мониторинг: Бойсундаги 40 та маҳалла банкирларининг фаоллигини онлайн кузатиш | Прогноз: Мавсумий туризм оқими ва яйловлар ҳолати бўйича тавсиялар', TRUE, 'SQB', '«SQB AI Advisor» Бойсундаги тадбиркорлар учун 24/7 маслаҳатчи бўла олади. Тавсия: Платформани маҳаллий лаҳжа ва атамаларни тушунадиган даражада соддалаштириш ва 2026 йил якунига қадар барча маҳаллаларда тўлиқ жорий этиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (232, 6, 24, 4, '4', 'Маҳалла драйвер секторлари', 'Ўсиш нуқталари ва иқтисодий локомотивлар', 'Жами: 3 та асосий драйвер | Чорвачилик: яйлов ресурсларидан (18 300 га) фойдаланиш | Боғдорчилик: олма стратегияси (600 га янги боғлар) | Туризм: экотуризм, тоғ туризми ва маданий мерос йўналишлари', TRUE, 'SQB / МФЙ агентлиги', 'Драйвер секторларга «Тоғ туризми»ни тўртинчи элемент сифатида қўшиш керак. Йиллик сайёҳлар сонини 300 мингга етказиш режаси чорвачилик ва ҳунармандчилик маҳсулотларига ички талабни автоматик оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (233, 6, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллалар тоифаси ва ихтисослашув йўналишлари', 'Жами: 39 та маҳалла | Ихтисослашув: Чорвачилик, Томорқа деҳқончилиги, Сабзавот ва боғдорчилик | Ипакчилик маҳаллалари: 6 та | Картошка/карам маҳаллалари: 4 та | Оғир тоифа: 19 та | Ўрта тоифа: 16 та | Енгил тоифа: 4 та', TRUE, 'МФЙ агентлиги / Бандлик маркази', '39 та МФЙдан 19 таси оғир тоифада — бу умумий МФЙларнинг 49%. Оғир маҳаллаларга манзилли бандлик дастурлари ва микролойиҳаларни йўналтириш устувор бўлиши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (234, 6, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳаллаларда ўсишни таъминлайдиган асосий тармоқлар', 'Жами: 3 та драйвер сектор | 1-сектор: Чорвачилик | 2-сектор: Боғдорчилик | 3-сектор: Туризм', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни «чорвачилик + боғдорчилик + хизмат» занжирида боғлаш керак. Тайёр маҳсулотни бозорга чиқариш ва брендлаш орқали маҳалла даражасида қўшимча қиймат яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (235, 6, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Лойиҳалар ҳажми ва яратилган иш ўринлари', 'Жами: Микролойиҳалар таҳлили | Лойиҳалар сони: 390 та | Иш ўринлари: 980 та | Лойиҳалар умумий қиймати: 13,6 млрд сўм', TRUE, 'Туман бандлик / Марказий банк', '390 та микролойиҳа орқали 780 та иш ўрни яратилган. Лойиҳалар сонини ошириш, айниқса 19 та оғир тоифали маҳаллага мақсадли молиялаштиришни йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (236, 6, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Қизил тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 39 та МФЙ | Қизил тоифа: 19 та МФЙ | Сариқ тоифа: 16 та МФЙ | Яшил тоифа: 4 та МФЙ', TRUE, 'МФЙ агентлиги / Бандлик маркази', 'Қизил тоифадаги 19 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳаларга улаш механизмлари қўлланиши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (237, 6, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили', TRUE, 'SQB', 'Сунъий интеллектга асосланган «AI Advisor» мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (238, 6, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: SQB ва бошқа тижорат банклари (Халқ банки, Микрокредит банк, Агро банк, Ҳамкор банк) | Фоиз ставкаси: 12% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Дастурда SQB етакчи банк сифатида кредит скоринги ва СИ платформасини таъминлайди. Халқ банки ва Микрокредит банк оилавий тадбиркорлик кредитларини ажратади, Агро банк қишлоқ хўжалиги йўналишидаги лойиҳаларни молиялаштиради, Ҳамкор банк эса кичик бизнес сегментида иштирок этади. Маҳалла банкирлари ҳар бир оилани мос банк ва кредит маҳсулотига йўналтириш вазифасини бажаради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (239, 6, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Бойсунда аёллар тадбиркорлиги потенциали юқори (каштачилик, зардўзлик, меҳмон уйлари, боғдорчилик). Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (240, 6, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Оғир тоифадаги маҳаллалар учун манзилли бандлик ва кредит дастурлари', 'Жами: 19 та маҳалла, оғир тоифа | Ишсизлар (2025): 2 607 киши | Ёшлар (16-30): 437 киши | Аёллар: 1 342 киши | Кредит маҳсулотлари: Ёшлар бизнесда, Ҳамроҳ (аёллар), Маҳалла лойиҳаси | Мақсад: 2027 йилгача 3% га тушириш', TRUE, 'SQB / МФЙ агентлиги / Бандлик маркази', '19 та оғир маҳаллада «бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2-3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва 2027 йилгача ишсизликни 3% га тушириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (241, 6, 33, 5, '5', 'Тоғ-кон ва қурилиш материаллари кластери', 'Гипс, цемент ва шиша хомашёсининг улкан захиралари', 'Жами: Тоғ-кон захиралари | Цемент хомашёси: 158 973 минг тонна | Гипс ва ангидрит: 22 912 минг тонна | Шиша хомашёси: 109 162 минг тонна | Инвестиция салоҳияти: $50–100 млн', TRUE, 'Геология қўмитаси', 'Бойсунда хомашёни шунчаки қазиб олиш эмас, балки тайёр қурилиш материаллари (қуруқ қоришмалар, гипсокартон, шиша буюмлар) ишлаб чиқаришни йўлга қўйиш керак. Тумандаги дефицит товарлар рўйхатида қурилиш материаллари борлигини ҳисобга олсак, бу лойиҳалар ҳам ички, ҳам ташқи бозор (Афғонистон) учун истиқболлидир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (242, 6, 34, 5, '5', 'Этно-туризм ва «Бойсун курорт шаҳри»', 'ЮНЕСКО маданий мероси ва тоғли ҳудуднинг туристик жозибадорлиги', 'Жами: Туризм таҳлили | Сайёҳлар оқими: 180 минг (жорий) → 300 минг (режа) | Инвестиция (2026-2028): 350 млрд сўм | Машҳур масканлар: Омонхона, Хўжамайхона, Завбоши | Йўналиш: эко-туризм ва соғломлаштириш', TRUE, 'Ҳокимият / UNESCO', '«Омонхона» шифобахш суви ва «Бойсун баҳори» брендидан фойдаланиб, туманни йил давомида ишлайдиган туристик марказга айлантириш лозим. Оилавий меҳмон уйларини рақамлаштириш ва хорижий сайёҳлар учун махсус «Ethno-Village» тур-пакетларини яратиш орқали сайёҳларнинг қолиш вақтини 3 кунгача узайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (243, 6, 35, 5, '5', 'Транзит ва логистика устунлиги', 'М-39 халқаро йўли ва темир йўл тизимининг мавжудлиги', 'Жами: Логистика қуввати | М-39 ва 4Р-105 йўллари: туман ҳудудидан ўтган | Темир йўл станциясигача: 12 км | Юк айланмаси (2024): 3 109,7 минг тонна', TRUE, 'Транспорт вазирлиги', 'Бойсунни Сурхондарёнинг шимолий «логистика дарвозаси» сифатида ривожлантириш лозим. М-39 йўли бўйида замонавий сервис марказлари (кемпинг, хизмат кўрсатиш) ташкил этиш ва темир йўл яқинлигидан фойдаланиб, тоғ-кон маҳсулотларини экспорт қилиш учун йирик юк терминалини қуриш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (244, 6, 36, 5, '5', 'Чорвачилик ва гўштни қайта ишлаш', 'Тоғли яйловлар ва аҳоли ихтисослашуви', 'Жами: Чорвачилик салоҳияти | Ихтисослашув: қорамолчилик ва қоракўлчилик | Дефицит товар №1: гўшт маҳсулотлари | Имконият: табиий тоғ гўшти бренди', TRUE, 'Қишлоқ хўжалиги бўлими', 'Туманда гўшт маҳсулотлари дефицит эканлиги аниқланган. Бу имкониятдан фойдаланиб, «Бойсун тоғ гўшти» бренди остида ярим тайёр маҳсулотлар ва консерва ишлаб чиқаришни ташкил этиш керак. Бу нафақат туман эҳтиёжини қоплайди, балки Термиз ва Тошкент бозорларига юқори қийматли маҳсулот чиқариш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (245, 6, 37, 5, '5', 'Муқобил энергия ва саноат харажатлари', 'Тоғли ҳудудларда қуёш ва шамол энергиясидан фойдаланиш', 'Жами: Энергия салоҳияти | Қуёшли кунлар: 280–300 кун | Талаб: саноат ҳажми 223 млрд (2024) → 300 млрд (2025) | Тўсиқ: электр таннархининг юқорилиги', TRUE, 'Минерал ресурслар / Энергетика', 'Янги ташкил этилаётган қурилиш материаллари корхоналарига қуёш панеллари ўрнатиш мажбуриятини юклаш ва давлат субсидияларини шу йўналишга қаратиш керак. Бу саноат маҳсулотлари таннархини 15-20% гача камайтиришга ёрдам беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (246, 6, 38, 6, '6', 'Стратегик мақсад — 2027', 'Саноат ва туризм драйверига айланиш', 'Жами: 2027 йил мақсадлари | Саноат ҳажми: 400+ млрд сўм | Янги иш ўринлари: 5 000+ (лойиҳалар ҳисобига) | Камбағалликни қисқартириш: оилалар сонини 1 950 тадан (2025) 1 000 тагача камайтириш', TRUE, 'Туман ҳокимияти', 'Бойсун иқтисодиётини «Тоғ-кон + Туризм + Чорвачилик» триадаси асосида ривожлантириш лозим. 2025 йилда асосий эътиборни инфратузилмани (сув ва йўл) яхшилашга қаратиш, бу эса йирик инвесторларнинг туманга келиши учун кафолат бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (247, 6, 39, 6, '6', 'Инвестиция портфели ва «Лойиҳа фабрикаси»', 'Устувор йўналишлар ва молиявий воситалар', 'Жами: Инвестиция режаси | Микролойиҳалар: 390 та (780 иш ўрни) | Банк кредитлари: 219,5 млрд сўм (умумий портфел 2025) | Фокус: экспорт (30%) ва импорт ўрнини босиш (50%)', TRUE, 'SQB / Туман ҳокимияти', '«Лойиҳа фабрикаси» механизми орқали тумандаги дефицит 5 та товар (гўшт, қурилиш моллари, мебел, пластик, сут) бўйича тайёр бизнес-пакетларни тадбиркорларга таклиф қилиш лозим. Айниқса, хотин-қизлар ва ёшлар бандлиги учун кичик тикувчилик ва ҳунармандчилик цехларига имтиёзли лизинг бериш тизимини кучайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (248, 6, 40, 6, '6', 'Инфратузилма ва ижтимоий ривожланиш', 'Яшаш шароитини яхшилаш — иқтисодий фаоллик гарови', 'Жами: Инфратузилма чора-тадбирлари | Сув ва электр: тоғли қишлоқларни барқарор энергия билан таъминлаш | Йўллар: М-39 дан туристик зоналаргача 1 224 км йўлни босқичма-босқич таъмирлаш | Таълим: чорвачилик ва туризм хизматлари бўйича касб-ҳунарга ўқитиш марказларини кўпайтириш', TRUE, 'Туман ҳокимияти', 'Аҳоли зичлиги паст (40 киши/км²) бўлган тоғли ҳудудларда «ихчам сервис марказлари»ни ташкил этиш лозим. Бунда маҳаллабай ишлаш тизими орқали ҳар бир оиланинг томорқасидан самарали фойдаланиш (ёнғоқ, доривор ўсимликлар етиштириш) бўйича консультациялар бериш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (7, 3, 'sariosiyo', 'Сариосиё', 'Сариасия', 'Sariosiyo', 'Сариосиё тумани', 'sariosiyo.json', TRUE, NULL, 2026, 45, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
