INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (249, 7, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва экспорт ҳажми динамикаси', 'Саноат ҳажми (млрд сўм): 2021: 266,2 | 2022: 783,2 | 2023: 460,1 | 2024: 953,9 | 2025: 1208,2 (%) | Хизматлар ҳажми (млрд сўм): 2021: 554,4 | 2022: 771,7 | 2023: 930,6 | 2024: 1104,3 | 2025: 1441,4 (%) | Экспорт ҳажми (минг $): 2021: 18,2 | 2022: 17278,9 | 2023: 11959,1 | 2024: 10262,0 | 2025: 13826,5 (%)', TRUE, 'Туман статистика бўлими', 'Саноат ҳажми 5 йил ичида 4,5 баробарга ўсиши прогноз қилинмоқда. Бироқ, 2023 йилда пасайиш кузатилган. Барқарор ўсишни таъминлаш учун экспорт таркибини фақат хомашё эмас, балки тайёр маҳсулотлар ҳисобига диверсификация қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (250, 7, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Иқтисодиёт таркиби ва йўналишлари', 'Жами: Тармоқлар улуши | Қишлоқ хўжалиги: 43,6% | Хизматлар: 22,5% | Саноат: 18,6% | Пудрат ишлари: 15,4%', TRUE, 'Туман статистика бўлими / Ҳокимият', 'Қишлоқ хўжалиги асосий драйвер бўлиб қолмоқда (43,6%). Иқтисодий самарадорликни ошириш учун қишлоқ хўжалиги маҳсулотларини қайта ишлайдиган кичик саноат зоналарини ёқилғи-энергетика имкониятлари билан интеграция қилиш зарур. Юк айланмасининг юқорилигидан (14,9 млн тонна) фойдаланиб, туманни «Агро-логистика маркази»га айлантириш қўшимча қиймат яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (251, 7, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Ўсиш суръатлари ва ишлаб чиқариш таркиби', '2021: 117.8 | 2022: 98.5 | 2023: 106.6 | 2024: 112.1 | 2025: 109.3 (%)', TRUE, 'Туман статистика бўлими', 'Йирик корхоналар улуши юқори, лекин кичик бизнеснинг ўсиш динамикаси барқарор. Корхоналарнинг ёпилиш кўрсаткичи (356 та) хавотирли. Сабабларни таҳлил қилиб, янги очилган корхоналарга «инкубация» даврида солиқ ва ресурс имтиёзлари бериш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (252, 7, 4, 1, '1', 'Маҳаллий бюджет ва молия', 'Бюджет даромадлари динамикаси', 'Маҳаллий бюджет даромади (млрд сўм): 2021: 92,0 | 2022: 107,7 | 2023: 109,5 | 2024: 103,3 | 2025: 137,0 (%) | Контингент бюджет (млрд сўм): 2024: 48,4 | 2025: 59,2 | ЯҲМдаги улуши: Вилоят ўртача кўрсаткичига нисбатан 8%', TRUE, 'Туман молия бўлими', '2025 йилда бюджет даромадларининг 137 млрд сўм булган. Бюджет барқарорлигини ошириш учун хизматлар соҳасини (2025 йил прогнози 1441,4 млрд) рақамлаштириш орқали солиқ базасини кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (253, 7, 5, 1, '1', 'Ажратилган кредитлар', 'Кичик бизнесни молиявий қўллаб-қувватлаш динамикаси', 'Кредитлаш ҳажми (млрд сўм): 2021: 102,4 | 2022: 125,6 | 2023: 147,9 | 2024: 175,3 | 2025: 250,7 (%) | Ўсиш: 5 йилда 2,4 баробар | NPL: 2025 йилга 4,2% (2022 йилдаги 6,2% дан)', TRUE, 'Марказий банк', 'Кредитлаш ҳажмининг кескин ўсиши туманда тадбиркорлик фаоллиги ошаётганидан далолат беради. Молиявий ресурсларнинг самарадорлигини ошириш учун кредитларни асосан туманнинг драйвер соҳалари бўлган қурилиш материаллари ишлаб чиқариш ва қишлоқ хўжалиги маҳсулотларини қайта ишлаш лойиҳаларига йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (254, 7, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали (0-100 балл)', 'Жами: 62 балл (100 дан) — Барқарор ўсиш фаоллиги | 2024 йил ўртача: 54 балл | 2025 йил ўртача: 62 балл (+15% ўсиш) | Энг фаол давр: Март-Апрель 2025 — 78 балл | Мавсумийлик: Баҳор ва куз ойларида юқори', TRUE, 'Google Trends таҳлили', 'Google Trends индексининг 62 баллга кўтарилиши аҳолининг тадбиркорлик ва қишлоқ хўжалиги хизматларига бўлган рақамли қизиқиши ортиб бораётганини кўрсатади. «Сариосиё бренди» остида маҳсулотларни рақамли платформаларда тарғиб қилиш ва инвестициявий жозибадорликни оширувчи онлайн контентни кўпайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (255, 7, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолини тоза ичимлик суви билан таъминлаш динамикаси (%)', 'Таъминланганлик (%): 2021: 61,0 | 2022: 61,8 | 2023: 61,9 | 2024: 64,4 | 2025: 66,7 (%)', TRUE, 'Сув хўжалиги', '5 йил ичида таъминланганлик даражаси 4,1% га ошган. Бироқ, ўсиш суръати паст. Инфратузилмани яхшилаш учун сув тармоқларини тортишда давлат-хусусий шериклик моделларини қўллаш ва сув йўқотишларини камайтириш учун рақамли ҳисоблагичлар ўрнатишни жадаллаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (256, 7, 8, 2, '2', 'Ички йўллар ҳолати ва Логистика', 'Йўллар узунлиги ва таркиби', 'Жами: Йўллар таҳлили | Умумий йўллар узунлиги: 1 252 км | Асфальтланган (қаттиқ қопламали): 58,3% | Темир йўл станциясигача: 8 км | Вилоят марказигача: 170 км', TRUE, 'Йўл хўжалиги / Туман ҳокимияти', 'Йўлларнинг ярмидан кўпи (55,5%) ҳали асфальтланмаган. Темир йўл станциясининг яқинлиги (8 км) туманнинг логистика салоҳиятини оширади. Асосий эътиборни ички йўлларни таъмирлашга ва юк ташиш ҳажмини инобатга олиб, транспорт йўлакларини кенгайтиришга қаратиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (257, 7, 9, 2, '2', 'Электр таъминоти сифати', 'Энергия инфратузилмаси ҳолати', 'Жами: Энергия таъминоти таҳлили | Электр узилишлари: Ўртача 4 марта/ой | Газ билан таъминланганлик 100,0% | Трансформаторлар: 29% алмаштиришга муҳтож | Электр линиялари: 35% модернизацияга муҳтож', TRUE, 'Электр ва Газ тармоқлари', 'Электр тармоқларининг эскирганлиги саноат ўсишига тўсиқ бўлиши мумкин. Тумандаги қуёш энергияси салоҳиятидан фойдаланиб, ижтимоий объектлар ва тадбиркорлик субъектларини муқобил энергияга ўтказиш орқали тармоқдаги юкламани камайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (258, 7, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Ер фонди таркиби ва саноат зоналари', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 384 638 гектар | Суғориладиган ерлар: 13 867 гектар | Аҳоли зичлиги: 62 киши/км² | «Анорзор» КСЗ: 17 та корхона, ердан фойдаланиш 98,2%', TRUE, 'Кадастр агентлиги / Туман ҳокимияти', 'Туман ҳудуди кенг, лекин аҳоли зичлиги паст. «Анорзор» КСЗдаги бўш турган 21,7% ер майдонларига фойдали қазилмаларни (оҳактош, гипс) қайта ишловчи янги инновацион лойиҳаларни жалб қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (259, 7, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Транспорт ва йўловчи айланмаси таҳлили', 'Йиллик йўловчи ташиш: 17,5 млн киши | Йўлларнинг 58,3% асфальтланган | Вилоят марказигача: 170 км | Темир йўл станциясигача: 8 км', TRUE, 'Йўл хўжалиги / Статистика бўлими', 'Туманда йиллик 17,5 млн йўловчи ташиш ҳажми жамоат транспортига бўлган талаб юқорилигини кўрсатади. Темир йўл станцияси билан туман маркази ўртасида мунтазам автобус йўналишларини йўлга қўйиш ва тоғли ҳудудлар учун кичик сиғимли транспорт паркини янгилаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (260, 7, 12, 2, '2', 'Мактабгача таълим қамрови', 'Болаларни мактабгача таълим муассасаларига қамраб олиш кўрсаткичлари', 'Қамров даражаси: 70,3% | 3-7 ёшли болалар: 22 400 нафар | Қамраб олинган: 15 750 нафар | МТТлар сони (жами): 233 та | Давлат МТТ: 37 та | Оилавий МТТ: 186 та | ДХШ: 10 та | Хусусий МТТ: 0 та', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Қамров даражасининг 70,3% га етказилгани ижобий кўрсаткич, асосан оилавий МТТлар (186 та) ҳисобига юқори натижа қайд этилган. Хусусий секторнинг (0 та) мавжуд эмаслиги соҳада фойдаланилмаган имкониятлар борлигини кўрсатади. Тадбиркорларга имтиёзли кредитлар орқали хусусий МТТлар ташкил этиш, ДХШ тармоғини кенгайтириш ва оилавий МТТларда таълим сифатини ошириш учун давлат МТТлари билан «методик ҳамкорлик» тизимини кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (261, 7, 13, 2, '2', 'Соғлиқни сақлаш тизими', 'Туман аҳолисига тиббий хизмат кўрсатиш қуввати ва ресурс базаси', 'Тиббий ташкилотлар: 17 та | Стационар ўринлар (жами): 430 та | Бюджет ҳисобига: 385 та | Бюджетдан ташқари (пуллик): 45 та | Умумий штат бирлиги: 2 027,25 | Врачлар: 267 нафар | Ўрта тиббий ходимлар: 1 382 нафар | Кичик тиббий ходимлар: 454 нафар', TRUE, 'Соғлиқни сақлаш вазирлиги (Туман тиббиёт бирлашмаси)', 'Ўрта тиббий ходимлар ва врачлар нисбати (тахминан 5:1) стандарт талабларига мос. Стационар ўринларнинг атиги 10,4% бюджетдан ташқари (пуллик) — хусусий сектор ва қўшимча хизматларни ривожлантириш зарур. «Рақамли тиббиёт» лойиҳаларини кенгайтириш, тиббий туризм ва пуллик хизмат кўламини ошириш, олис ҳудудлар учун «Қишлоқ шифокори» дастурларини кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (262, 7, 14, 3, '3', 'Меҳнат ресурслари', 'Инсон капитали ва меҳнат салоҳияти динамикаси', 'Меҳнат ресурслари (минг киши): 2021: 111,8 | 2022: 112,9 | 2023: 113,1 | 2024: 113,4 | 2025: 113,6 | Ўртача маош (минг сўм): 2021: 2286 | 2022: 2776 | 2023: 3255 | 2024: 3849 | 2025: 4289', TRUE, 'Статистика бўлими / Бандлик маркази', 'Сўнгги 5 йилда ўртача ойлик иш ҳақининг 87% га ўсиши (2,2 млн дан 4,2 млн гача) аҳолининг сотиб олиш қобилияти ошаётганини кўрсатади. Меҳнат ресурсларининг бироз қисқариши фонида бандликнинг барқарор қолиши — меҳнат самарадорлиги ошаётганидан далолатдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (263, 7, 15, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва инклюзив бандлик', 'Меҳнат ресурслари: 113 100 киши | Норасмий сектордаги бандлик: 28 109 киши | Ногиронлиги бўлган шахслар: 10 024 нафар (ишлайди: 1 952, ишламайди: 8 072) | Расмий рўйхатдаги ишчилар: 79 200 киши', TRUE, 'Бандлик маркази / Давлат солиқ қўмитаси', 'Бандликни оширишнинг асосий нуқтаси — норасмий сектордаги 28 минг нафар аҳолини легаллаштиришдир. Ногиронлиги бўлган 8 072 нафар ишсиз фуқарони ижтимоий тадбиркорлик ва уй меҳнати (касаначилик) орқали банд қилиш туман иқтисодиётига ижобий таъсир кўрсатади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (264, 7, 16, 3, '3', 'Ишсизлик кўрсаткичлари', 'Ишсизлик даражаси ва сонининг пасайиш тренди', 'Ишсизлик (%): 2021: 11,3 | 2022: 9,4 | 2023: 7,7 | 2024: 6,2 | 2025: 5,3 (%) | Ишсизлар сони: 2021: 9217 | 2022: 8853 | 2023: 6522 | 2024: 5224 | 2025: 4389', TRUE, 'Бандлик маркази', 'Ишсизлик даражаси 5 йил ичида 2 баравардан кўпроққа (11,3% дан 5,3% га) камайган. Бу жуда ижобий тренд. 2026-2027 йилларда ушбу кўрсаткични 5% дан пастга тушириш учун асосий эътиборни касбий малакаси бўлмаган 4,3 минг нафар ишсизни қайта ўқитишга қаратиш лозим.', 4389, 5.3, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (265, 7, 17, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағалликни қисқартириш ва оилалар динамикаси', 'Камбағаллик (%): 2021: 18,6 | 2022: 17,1 | 2023: 12,4 | 2024: 10,7 | 2025: 3,9 (%) | Камбағал оилалар: 2021: 4002 | 2022: 8523 | 2023: 6250 | 2024: 5402 | 2025: 1894', TRUE, 'Статистика бўлими', 'Камбағаллик даражаси 18,6% дан 5,6% гача тушиши ижтимоий ислоҳотлар самара бераётганини англатади. Мавжуд 1 894 та камбағал оила билан ишлашда «Камбағалликдан фаровонликка» дастури доирасида манзилли субсидия ва микрокредитлар бериш самарали бўлади.', 1894, 3.9, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (266, 7, 18, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва миграция оқими', 'Ёшлар ишсизлиги (16-30 ёш): 628 нафар (расмий) | Хорижга кетганлар (2025): 8,9 минг киши | Қайтган мигрантлар (2025): 12 745 нафар | Ўртача маош ўсиши: 2,2 дан 4,2 млн сўмгача', TRUE, 'Бандлик маркази / ИИВ', 'Хориждан қайтган 12,7 минг нафар фуқарони маҳаллий меҳнат бозорига интеграция қилиш зарур. Уларнинг хорижда орттирган тажрибасини тадбиркорликка йўналтириш учун махсус «Реинтеграция» кредитларини жорий этиш ва кичик бизнес лойиҳаларига йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (267, 7, 19, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлаш', 'Ишсиз аёллар: 1 875 нафар | Бола нафақаси олувчилар: 2400 оила | Кам таъминланган оилалар: 2420 та | Ижтимоий ёрдам олувчи жами: 4820 оила', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя', '1 075 нафар ишсиз аёлнинг бандлигини таъминлаш учун туманда «Касаначилик марказлари» ва қишлоқ хўжалиги маҳсулотларини қайта ишлаш кичик цехларини ташкил этиш лозим. Ижтимоий нафақа олувчи оилаларни «тадбиркор оила» тоифасига ўтказиш орқали ижтимоий юкламани камайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (268, 7, 20, 3, '3', 'Касб-ҳунар таълими муассасалари', 'Сариосиё туманидаги техникум ва касб-ҳунар мактаблари', 'Жами: 4 та техникум, 1 470 ўқувчи (қуввати 1 365, банд 107,7%) | 1-сон техникум: 670 ўқувчи (қуввати 450, 148,9%) | 2-сон техникум: 800 ўқувчи (қуввати 765, 104,6%) | 3-сон техникум: 174 ўқувчи (қуввати 150, 98%) | Абу Али ибн Сино жамоат саломатлик техникуми: 843 ўқувчи (қуввати 575, 146,6%)', TRUE, 'Ҳокимият', 'Техникумларда қурилиш ва тоғ-кон ишлари бўйича қисқа муддатли курсларни кўпайтириш керак. 3-сон техникум бўш турибди (0 ўқувчи) — уни тоғ-кон ва туризм мутахассисларини тайёрлаш марказига айлантириш лозим. Инфратузилма лойиҳалари кўплиги сабабли, ўқувчиларни «Уста-шогирд» йўналишида йирик пудратчи ташкилотларга бириктириш самарали натижа беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (269, 7, 21, 3, '3', 'Сариосиё туманидаги техникумлар', 'Касб-ҳунар таълими муассасалари ва колледжлар', 'Жами: 4 та техникум, 1 470 та ўқувчи (қуввати 1 365, банд 107,7%) | 1-сон техникум: 670 ўқувчи (қуввати 450, 148,9%) | 2-сон техникум: 800 ўқувчи (қуввати 765, 104,6%) | 3-сон техникум: 147 ўқувчи (қуввати 150, 98%) | Абу Али ибн Сино жамоат саломатлик техникуми: 843 ўқувчи (қуввати 575, 146,6%)', TRUE, 'Ҳокимият', '4 та техникумда 1 470 нафар ўқувчи таҳсил олмоқда, умумий қуввати 1 365 ўринга нисбатан 107,7% банд. 1-сон техникум қувватидан 1,5 баробар кўп юкланган (450 га 670). 3-сон техникум бўш турибди (0 ўқувчи) — уни тоғ-кон ва туризм мутахассисларини тайёрлаш марказига айлантириш лозим. Битирувчиларни маҳаллий корхоналарга мақсадли жойлаштириш тизимини жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (270, 7, 22, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури (Сариосиё филиали қамрови — 100%) | «Сунъий интеллект куни» — ҳар пайшанба | Онлайн ўқитиш тизими жорий (LMS) | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Ходимларнинг СИ саводхонлигини ошириш орқали мижозларга кредит ажратишда скоринг таҳлилларини тезлаштириш мумкин. Ҳафталик «СИ куни» доирасида ходимларга маҳаллабай ишлаш тизимида маълумотларни йиғиш бўйича СИ ботларидан фойдаланишни ўргатиш филиал самарадорлигини 20% га оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (271, 7, 23, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', 'Раҳбарларнинг СИ воситаларидан фойдаланиши маълумотлар асосида қарор қабул қилиш тезлигини 3 баробар оширади. Маҳалла банкирларига мижознинг кредит лаёқатини СИ орқали олдиндан баҳолаш кўникмаларини бериш, банкнинг рискларини камайтириш ва хизмат сифатини янги босқичга олиб чиқади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (272, 7, 24, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', '1 350 нафар СИ орқали ўқитилади (2026 режа) | СИ таҳлили: кўникма ва қизиқиш аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури | Тадбиркорлик: бизнес-режа + микрокредит | Касб: тайёр иш ўринларига йўналтириш', TRUE, 'SQB', 'СИ платформаси орқали фуқароларни индивидуал баҳолаш — «ижтимоий боқимандалик» кайфиятини камайтириб, аниқ йўналиш бўйича бандликни таъминлайди. Тизим тадбиркорлик қобилияти бор фуқарони аниқлаганда, банк томонидан автоматик равишда имтиёзли кредит таклифи шакллантирилиши тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (273, 7, 25, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 68 маҳаллада жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (274, 7, 26, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари ва тоифалари', 'Жами: 61 та маҳалла | Чорвачилик: 26 та МФЙ | Деҳқончилик: 17 та МФЙ | Боғдорчилик: 10 та МФЙ | Савдо ва хизмат кўрсатиш: 7 та МФЙ | Маҳалла тоифалари: Енгил: 31 та, Ўрта: 28 та, Оғир: 1 та', TRUE, 'МФЙ агентлиги', 'Маҳаллаларнинг асосий қисми (43 таси) чорвачилик ва деҳқончиликка ихтисослашган. 7 та хизмат кўрсатиш маҳалласида туризм потенциали (Сангардак) ҳисобига даромадларни тезроқ ошириш имконияти мавжуд. Оғир тоифадаги 1 та маҳаллани «енгил» тоифага ўтказиш учун ихтисослашувни саноат хомашёсини қайта ишлашга йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (275, 7, 27, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида иқтисодий ўсишни бошқарувчи асосий тармоқлар', 'Жами: 4 та драйвер сектор | Энергетика ва Кўмир саноати: «Шарғункўмир» — 160 млн тонна заҳира, йиллик 900 минг тонна қазиб олиш | Қишлоқ хўжалиги: мева-сабзавотчилик ва боғдорчилик — 2 500+ га боғлар, экспорт $13,8 млн | Туризм: Сангардак курорт маскани — йиллик 265 минг сайёҳ, $12 млн салоҳият | Савдо ва хизмат кўрсатиш: Тожикистон чегараси — йиллик 1,5 млн тонна юк айланмаси', TRUE, 'SQB / Туман ҳокимияти', 'Туманнинг асосий «ўсиш нуқтаси» — кўмир саноати ва мева-сабзавотчиликдир. Мева-сабзавотни қайта ишлаш даражаси ҳозирда атиги 10-12% ни ташкил этади. Ушбу кўрсаткични ошириш учун агрозоналарда кичик консервация ва музлатгичли омборхоналар тармоғини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (276, 7, 28, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', '2026 йил учун режалаштирилган кредит режа ва иш ўринлари', 'Жами лойиҳалар: 610 та | Яратиладиган иш ўринлари: 1 210 та | 100 кунлик режа: 83 та лойиҳа ва 4 400 иш ўрни | Йўналиш: Боғдорчилик (105 га янги боғ), Хизматлар ва Саноат', TRUE, 'SQB / Туман ҳокимияти / Марказий банк', '610 та микролойиҳанинг асосий қисмини Сангардак туристик зонасидаги хизмат кўрсатиш шохобчаларига йўналтириш лозим. Янги ташкил этиладиган 105 гектарлик боғлар ва қайта ишлаш лойиҳалари туманнинг экспорт салоҳиятини камида 10% га оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (277, 7, 29, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Иқтисодий аҳволи оғир ва ишсизлик даражаси юқори бўлган ҳудудлар', 'Жами: 13 та маҳалла | А.Навоий, Боғисамарқанд, Дарагитстон, Лочин, Маржона, Ниҳолзор, Нодирабегим, Нурбулоқ, Келажак сари, Боғистон, Чош, Шарафобод, Хуршид', TRUE, 'МФЙ агентлиги / Бандлик маркази', 'Ушбу 13 та маҳаллада ишсизликни камайтириш учун «Маҳаллабай» инвентаризация ўтказиш ва аҳолини ипакчилик (30 та маҳалла) ва картошка/карам етиштиришга (20 та маҳалла) жалб қилиш лозим. Ҳар бир «оғир» маҳаллага алоҳида «Йўл харитаси» тузиб, уларни драйвер соҳаларга бириктириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (278, 7, 30, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк | SQB Business: юридик шахслар учун онлайн бухгалтерия | SQB AI Advisor: СИ асосидаги молиявий маслаҳатчи', TRUE, 'SQB', 'СИ асосидаги «AI Advisor» мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (279, 7, 31, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Иштирокчи банклар: SQB ва бошқа тижорат банклари | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (280, 7, 32, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (281, 7, 33, 4, '4', 'Ишсизлик юқори маҳаллаларни ривожлантириш режаси', '«Сангардак» ва «Хуршид» каби маҳаллаларни ривожлантириш стратегияси', 'Сангардак лойиҳаси: 2025-2028 йилларда 913,3 млрд сўм инвестиция | Сайёҳлар оқими: Йиллик 265 000 нафар (мақсад: 130 000 доимий) | Инфратузилма: Д-170 Б автомагистрали 2 км реконструкция | Режа: 4 400 нафар бандлик (100 кунлик дастур)', TRUE, 'SQB / Туман ҳокимияти', 'Сангардакни курорт масканга айлантириш лойиҳаси туманнинг «ташриф қоғози» бўлиши мумкин. 913,3 млрд сўмлик инвестицияларни ўзлаштиришда маҳаллий аҳолини меҳмонхона хизмати ва гидлик бўйича СИ платформалари орқали ўқитиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (282, 7, 34, 5, '5', 'Гидроэнергетика салоҳияти', 'Тўпаланг сув омбори ва тоғ дарёларининг улкан гидроэнергетик салоҳияти', 'Қувват: 175 МВт (Тўпаланг ГЭС ва кичик ГЭСлар) | Йўналиш: Янги кичик ва микро ГЭСлар қуриш | Имконият: Саноат корхоналарини 100% қайта тикланувчи энергия билан таъминлаш | Инвестиция: $15–40 млн (хусусий шериклик асосида)', TRUE, 'Энергетика вазирлиги', 'Сариосиёни вилоятнинг «яшил энергия» марказига айлантириш керак. ГЭСлар яқинида энергия сиғими юқори бўлган саноат зоналарини ташкил этиш, электр таннархи пастлиги эвазига инвесторларни жалб қилиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (283, 7, 35, 5, '5', 'Эко ва экстремал туризм: Сангардак шаршараси', 'Ўзбекистондаги энг баланд шаршаралардан бири ва тоғли рекреация зонаси', 'Сайёҳлар сиғими: Йиллик 200–250 минг киши | Объектлар: Сангардак, Хондиза тоғлари, Тўпаланг соҳили | Лойиҳа: Канат йўллари ва кемпинг зоналари | Экспорт салоҳияти: $12 млн (йиллик)', TRUE, 'Туризм қўмитаси', 'Сангардак ҳудудини «туризм қишлоғи» мақомига ўтказиш ва Швейцария модели асосида йил бўйи ишловчи курорт марказини яратиш лозим. Бу ерда фақат мавсумий эмас, балки қишки туризмни ҳам ривожлантириш имкони мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (284, 7, 36, 5, '5', 'Субтропик экинлар ва экспорт', 'Сариосиёнинг микроиқлимида ноёб хурмо, анор ва лимон етиштириш', 'Ер майдони: 2 500+ гектар боғлар | Ҳосилдорлик: Вилоятдаги энг юқори кўрсаткичлардан бири | Йўналиш: Қайта ишлаш ва шок усулида музлатиш | Бозор: МДҲ ва Европа давлатлари', TRUE, 'Қишлоқ хўжалиги вазирлиги', 'Шунчаки хом ашё сотишдан «тайёр бренд» босқичига ўтиш керак. Сариосиё хурмосини алоҳида географик бренд сифатида рўйхатдан ўтказиш ва экспорт сифатини таъминловчи агро-логистика марказини қуриш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (285, 7, 37, 5, '5', 'Тоғ-кон саноати ва кўмир қазиб олиш', '«Шарғункўмир» конини модернизация қилиш ва ишлаб чиқариш занжири', 'Заҳира: 160 млн тоннадан ортиқ | Йиллик қазиб олиш: 900 минг тоннадан ортиқ (режа) | Иш ўринлари: 2 000 дан ортиқ янги штатлар | Инновация: Кўмирни бойитиш ва брикетлаш', TRUE, 'Шарғункўмир АЖ / Инвестициялар, саноат ва савдо вазирлиги', 'Кўмир қазиб олиш билан бирга, уни қайта ишлаш кимёвий кластерини яратиш керак. Бу иқтисодий қийматни 3-4 бараварга оширади ва маҳаллий аҳолининг юқори технологик касбларни эгаллашига хизмат қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (286, 7, 38, 5, '5', 'Транзит ва логистика коридори', 'Тожикистон Республикаси билан чегарадошлик ва темир йўл тармоғи', 'Статус: «Сариосиё» халқаро темир йўл ва автомобиль назорат-ўтказиш пункти | Юк айланмаси: Йиллик 1,5 млн тоннадан ортиқ | Имконият: Божхона терминали ва «қуруқ порт»', TRUE, 'Транспорт вазирлиги', 'Сариосиёни Тожикистон ва Афғонистон бозорларига чиқиш учун асосий логистика хабига айлантириш лозим. Чегара яқинида улкан улгуржи савдо мажмуасини барпо этиш транзит даромадларини 20-25% га оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (287, 7, 39, 5, '5', 'Даволаш туризми ва минерал сувлар', 'Ҳудуддаги шифобахш булоқлар ва тоғ ҳавосининг даволаш қуввати', 'Ресурс: Минерал сув манбалари ва тоғ климати | Йўналиш: Санаторий ва соғломлаштириш марказлари | Инвестиция: $5–15 млн', TRUE, 'Соғлиқни сақлаш вазирлиги / Хусусий сектор', 'Сариосиёнинг юқори тоғли ҳудудларида нафас йўлларини даволашга ихтисослашган халқаро рекреация марказларини ташкил этиш керак. Бу нафақат маҳаллий, балки қўшни давлатлардан келувчи тиббий сайёҳлар оқимини таъминлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (288, 7, 40, 6, '6', 'Стратегик мақсад: 2030', 'Сариосиё — Сурхондарёнинг «яшил» индустриал ва эко-туризм маркази', 'S: Саноат ҳажмини 2 баробарга ошириш | W: Инфратузилма (йўл ва сув) сифатини 80% га етказиш | O: Тоғ туризми орқали 5000 та янги иш ўрни | T: Табиий ресурслардан оқилона фойдаланиш', TRUE, '', 'Туманни ривожлантиришда табиий бойликлар (кўмир, сув) ва туристик жозибадорлик мувозанатини сақлаш лозим. Ҳар бир инвестиция лойиҳаси экологик стандартларга жавоб бериши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (289, 7, 41, 6, '6', 'Инвестиция жозибадорлиги', 'Туманга хорижий ва маҳаллий капитални жалб қилиш прогнози', '2025–2027 йиллар: $150 млн тўғридан-тўғри инвестиция | Устуворлик: Энергетика ва агросаноат | Имтиёз: Тоғли ҳудудларда бизнес учун махсус солиқ режимлари', TRUE, '', 'Инвесторлар учун «Бир дарча» тизими асосида тайёр лойиҳавий таклифларни (масалан, кичик ГЭС ёки меҳмонхона учун ер) шакллантириш ва халқаро бизнес-форумларда тақдим этиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (290, 7, 42, 6, '6', 'Инфратузилма ва рақамлаштириш', 'Тоғли қишлоқларда алоқа ва сервис сифатини ошириш', 'Режа: 100% интернет қамрови (тоғли ҳудудларда ҳам) | Рақамли хизматлар: Туристлар учун «Sariosiyo Guide» мобил иловаси | Логистика: Тоғ йўлларини реконструкция қилиш (Сангардак йўли)', TRUE, '', 'Туризм ривожи учун биринчи навбатда транспорт боғланишини яхшилаш ва меҳмонхоналарда юқори тезликдаги интернетни таъминлаш шарт. Бу «рақамли кўчманчилар» (digital nomads) учун ҳам туманни жозибадор қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (291, 7, 43, 6, '6', 'Ижтимоий ривожланиш ва таълим', 'Инсон капиталини янги иқтисодиётга тайёрлаш', 'Касбий таълим: Туризм ва тоғ-кон мутахассисларини тайёрлаш маркази | Аҳоли даромади: Жон бошига даромадни 1.5 бараварга ошириш | Аёллар бандлиги: Ҳунармандчилик ва меҳмон уйлари тизимида', TRUE, '', 'Маҳаллий ёшларни хорижий тилларга (инглиз, тожик, рус) ва меҳмонхона сервисига ўқитиш тизимини йўлга қўйиш зарур. Бу хизмат кўрсатиш сифатини халқаро даражага олиб чиқади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (292, 7, 44, 6, '6', 'Экспорт стратегияси', '«Сариосиё маҳсулотлари» брендини жаҳон бозорига олиб чиқиш', 'Маҳсулотлар: Кўмир, хурмо, анор, минерал сув, асал | География: Хитой, БАА, Европа ва МДҲ | Мақсад: Йиллик экспортни $50 млн дан ошириш', TRUE, '', 'Ҳар бир экспорт маҳсулоти учун сертификатлаштириш ва сифат назорати лабораториясини ташкил этиш лозим. Айниқса, «органик» тоғ асали ва мевалари учун сертификат олиш экспорт нархини 2 бараварга оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (293, 7, 45, 6, '6', 'Якуний хулоса: «Сурхон дурдонаси»', 'Сариосиё — фақат чекка туман эмас, балки стратегик ресурс маркази', 'Хулоса: Туманнинг тоғли иқлими ва табиий бойликлари Ўзбекистон иқтисодиёти учун янги драйвердир | Шиор: «Яшил энергия ва бетакрор табиат уйғунлиги»', TRUE, '', 'Келажакдаги 3 йиллик режани ишлаб чиқишда «Экологик барқарорлик» тамойилини бош мезон қилиб олиш керак. Сариосиёнинг табиати — унинг асосий капитали, уни асраган ҳолда иқтисодий фойда олиш энг тўғри йўлдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (8, 3, 'termiz', 'Термиз', 'Термез', 'Termez', 'Термиз тумани', 'termiz.json', TRUE, NULL, 2026, 42, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
