INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (294, 8, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Саноат: 1 715,0 млрд сўм (+126,4%) | Бозор хизматлари: 1 180,3 млрд сўм (+28,2%) | Саноат ўсиш суръати: 109,3% (реал) | Қишлоқ хўжалиги: 2 198,1 млрд сўм (+16,5%) | Тармоқлар улуши: Қ/х 43,2%, Саноат 33,7%, Хизматлар 23,2% | Экспорт/Импорт: 121,2 / 57,6 млн $ (соф +63,6 млн $)', TRUE, 'Статистика бўлими / stat.uz', 'Термиз тумани иқтисодиётида 2025 йил саноат ҳажми 2024 йилга нисбатан 2,3 бараварга кенгайди. Ўсишни турғунлаштириш учун кичик ва ўрта корхоналар улушини оширишга диққатни қаратиш лозим. Қишлоқ хўжалиги ҳажм жиҳатидан устун (43,2%) бўлса-да, гўшт ва сабзавот қайта ишлаш 0% даражасида — агро-қайта ишлаш кластери ташкил этиш энг устувор вазифа. Экспорт 5,9 мартага ўсгани ташқи бозорга оғирлашаётганини кўрсатади; логистика ва божхона инфратузилмасига инвестицияни тезлаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (295, 8, 2, 1, '1', 'Устувор 4 та соҳа', 'Асосий устувор соҳалар рейтинги ва асослама', 'Жами: 4 та устувор соҳа | 1-ўрин Қишлоқ хўжалиги: 2 198,1 млрд сўм (43,2%), чорвачилик ва деҳқончилик, 3 та агрозона | 2-ўрин Саноат: 1 715,0 млрд сўм (33,7%), йирик корхоналар 73,5% | 3-ўрин Хизматлар: 1 180,3 млрд сўм (23,2%), савдо ва логистика | 4-ўрин Экспорт ва логистика: 121,2 млн $ (+489%), ЭИЗ «Айратом» потенциали', TRUE, 'Статистика бўлими / Туман ҳокимияти', '4 та драйвердан фақат иккиси (саноат ва экспорт) юқори динамика кўрсатмоқда; қишлоқ хўжалиги хомашё сотишга асосланган — ишлов бериш улушини ошириш орқали бир маҳсулотга икки драйверни бирлаштириш мумкин. Хизматлар улуши (23,2%) вилоят марказига яқинлигини ҳисобга олганда паст; туризм ва курорт шаҳри лойиҳаси (50 млрд сўм) орқали хизматлар улушини 30% гача олиб чиқиш тавсия этилади. Экспорт энг тез ўсаётган драйвер — корхоналарни ЭИЗ «Айратом» занжирига қўшиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (296, 8, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '2021-2025 йиллар давомида саноат ҳажми ва индекс ўзгариши', 'Саноат ҳажми (млрд сўм): 2021: 280,3 | 2022: 387,5 | 2023: 491,4 | 2024: 757,6 | 2025: 1715,0 | Йирик корхоналар (2025): 1 260,1 млрд сўм (73,5%) | Кичик бизнес (2025): 454,9 млрд сўм (26,5%)', TRUE, 'Статистика бўлими', '5 йилда саноат 6,1 бараварга ўсди, аммо 73,5% йирик корхоналар улуши туман саноатини ягона субъект қарорига боғлаб қўяди — диверсификация учун кичик бизнес кредит портфелини 650 млрд сўмгача ошириш ва 3-5 та янги ўрта корхонани саноат зонасига киритиш тавсия этилади. Саноат зонаси ер фойдаланиш 69,7% — қолган 30,3% ни тўлдириш орқали 500-700 иш ўрни яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (297, 8, 4, 1, '1', 'Маҳаллий бюджет ва молиявий ҳолат', '2021-2025 йиллар давомида туман маҳаллий бюджет даромадлари', 'Бюджет даромади (млрд сўм): 2021: 41,2 | 2022: 61,3 | 2023: 69,4 | 2024: 67,4 | 2025: 99,1 | Норасмий иқтисодиёт улуши: 27,3% | Солиқ йўқотиш: 15 млрд сўм/йил | Иш ҳақи фонди (2025): 486,9 млрд сўм', TRUE, 'Туман молия бўлими', '2024 йилда бюджет 2,9% га пасайиб, 2025 да 46,9% га кескин ошган — бундай волатиллик якка сектор солиқ тушумига боғлиқликдан келиб чиқади; солиқ базасини диверсификациялаш лозим. Норасмий секторда 15 млрд сўм (бюджетнинг 15,1%) йиллик йўқотиш мавжуд — расмийлаштиришни тезлаштириш орқали бюджетни 5-7 млрд сўм билан кенгайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (298, 8, 5, 1, '1', 'Ажратилган кредитлар', 'Туман бўйича кредит портфели ва кичик бизнес кредитлари', 'Кредит портфели (млрд сўм): 2021: 1123,0 | 2022: 1179,2 | 2023: 1273,5 | 2024: 1337,2 | 2025: 1366,1 | Кичик бизнес (2025): 475,0 млрд (34,8%) | Муаммоли кредитлар (%): 2021: 4,0 | 2022: 4,8 | 2023: 5,8 | 2024: 6,3 | 2025: 6,7 | Банк филиаллари: 6 та / 22 та банкомат', TRUE, 'Марказий банк / SQB', 'Кредит портфели 5 йилда атиги 21,6% га ўсган — саноат 6 бараварга ўсган шароитда мувозанатсизлик. NPL 4,0% дан 6,7% гача ортиши асосий хавф — портфелни тозалаш ва гаров таъминотини мустаҳкамлаш устувор. Оилавий тадбиркорлик портфели атиги 7,9 млрд (0,6%) — микромолия инструментини кенгайтириш учун катта имконият бор.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (299, 8, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Цифровой фаоллик индекси — қидирув трендлари асосидаги иқтисодий сигнал', 'Google Trends индекси: Марказий гуруҳ ҳисоблайди | Сунъий йўлдош тасвири таҳлили: Марказий гуруҳ ҳисоблайди | ML прогноз модели 2025-2027: Марказий гуруҳ ҳисоблайди | Аҳоли ва бизнес кутишлари: Ижобий 55%, Салбий 25%, Нейтрал 20% | Интернет қоплами: 100% | Ўртача тезлик: 40 Мбит/с', TRUE, 'Google Trends таҳлили', 'Интернет қоплами 100% ва 40 Мбит/с тезлик (республика ўртачасидан юқори) — цифровой фаоллик учун техник замин тайёр, аммо маҳаллий трендларни кузатиш учун МФЙ-даражасида сўров механизми зарур. Аҳоли-бизнес сўрови соф баланс +30 — салоҳияти катта, салбий 25% сабабларини аниқлаб мишен-тадбирларни шу сегментга йўналтириш самарали. AI бизнес-режа генерацияси ва қидирув трендлари таҳлилини туман сайтига интеграция қилиш орқали инвесторларга сигнал бериш тизимини яратиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (300, 8, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолининг тоза ичимлик сув билан таъминланганлик даражаси (%)', 'Таъминланганлик (%): 2021: 54,8 | 2022: 57,1 | 2023: 62,4 | 2024: 66,2 | 2025: 69,5 (%) | 5 йиллик ўсиш: +14,7 п.п. | Канализация тармоғи: 1,5% | Суғориш каналлари бетонлаш: 27% | Шошилинч муаммолар рўйхатидаги ўрни: №1', TRUE, 'Сувоқа (Сув таъминоти корхонаси)', 'Термиз тумани 2025 йилда 69,5% ичимлик сув қопламига эга — 5 йилда 14,7 п.п. ўсиш, яхши темп, аммо ҳали ҳам аҳолининг 30,5% (тахминан 27 400 киши) тоза сувдан узоқ. Канализация қамрови 1,5% — кескин паст, санитария хавфи ва ёр остидаги сув манбаини ифлослантириш хатарини туғдиради. 2030 йилгача 95%+ қопламга етиш учун йиллик ўсишни 2,94 п.п. дан 5 п.п. гача ошириш лозим; 2026 инфратузилма қарорлари лойиҳасига қўшимча 30-40 млрд сўм йўналтириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (301, 8, 8, 2, '2', 'Ички йўллар ва логистика инфратузилмаси', 'Қаттиқ қопламали йўллар улуши, темир йўл яқинлиги ва юк айланмаси', 'Жами: Йўл инфратузилмаси | Умумий йўллар узунлиги: 893 км | Асфальтланган: 87% (786 км) | Қопламасиз: 13% (107 км) | Темир йўл станциясигача: 1,2 км | Юк айланмаси: 8 769,7 минг тонна/йил | Транзит артериялар: 4Р-206 ва М-39А', TRUE, 'Йўл хўжалиги бўлими', 'Туман йўлларининг 87% асфальтланган — республика ўртачасидан юқори, темир йўл стансиясига 1,2 км яқинлик Термизни Сурхондарё логистика марказига айлантириш учун кучли замин яратади. Қолган 13% (106,7 км) қаттиқ қопламасиз йўллар чекка МФЙ ва фермер ҳудудида — таъмирлаш агросектор учун меҳнат ҳаражатини 8-12% га камайтиради. 4Р-206 ва М-39А транзит артерия, ички МФЙ-йўллари учун 2026-2028 алоҳида дастур (120-150 млрд сўм) ишлаб чиқиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (302, 8, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Узилишлар сони, модернизация эҳтиёжи ва газ таъминоти', 'Электр узилишлари: 4 марта/ой (йилига ~48) | Трансформаторлар эскирган: 31,7% | Линиялар алмаштириш керак: 31,3% | Газ билан таъминланганлик: 30% | Суюлтирилган газ билан таъминланганлик: 70% | Саноат зонаси ер фойдаланиш: 69,7% (кенгайиш имкони 30,3%) | Аҳоли зичлиги: 108,1 киши/км²', TRUE, 'Электр тармоқлари бошқармаси', 'Ойига 4 марта узилиш саноат учун сезиларли зарар манбаи — йирик корхоналар 73,5% ни ташкил этишини ҳисобга олиб, йиллик 10-15 млрд сўм йўқотишга олиб келиши мумкин. Трансформаторларнинг 31,7% ва линияларнинг 31,3% модернизация талаб қилиши — жами тармоқнинг учдан бири. Ҳажмни 4-5 йилга тақсимлаб, йилига 6-8% модернизация суратини сақлаш тавсия этилади. Газ таъминоти 30% — ичимлик сувдан ҳам паст; қуёш энергияси ва газлаштириш режасини биргаликда ишлаб чиқиш жуда муҳим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (303, 8, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Туман ер фонди тузилмаси ва фойдаланиш', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 83 444 га | Экин ерлари: 83 443 га | Яйлов: 10 977 га | Бошқа (шаҳар, саноат, ўрмон, йўл): 55 186 га | Суғориладиган ер: 9 021,6 га | Дон экин майдони: 2 900 га', TRUE, 'Кадастр агентлиги', 'Ер қўмитаси ва Статистика бўлими рақамларида номутаносиблик мавжуд — стратегик қарорлар учун ягона реестр яратиш биринчи ишдир. Суғориладиган ер улуши атиги 9 021,6 га (экин ерларининг 10,8%) — жуда паст, сув танқислиги SWOT-таҳдидлар ичида №1. Томчилатиб суғориш технологияси учун 500-1 000 га пилот лойиҳа 2026-йилда 20-30% сув тежаш беради. Олма боғларига 529 га қўшимча стратегик тўғри қадам, аммо сабзавот/гўшт қайта ишлаш 0% эканини ҳисобга олиб, олма шираси/қуритма корхонаси биргаликда лойиҳалаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (304, 8, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Йўловчи ва юк ташиш ҳажмлари', 'Йўловчи ташиш: 6 602,7 минг/йил | Юк ташиш: 8 769,7 минг тонна/йил | Аҳоли жон бошига ташиш: ~73,6 йўловчилик/киши/йил (кунига ~0,20) | Юк зичлиги: ~97,8 тонна/км² | Йўллар узунлиги: 821 км | Транспорт инфратузилмаси: Темир йўл 1,2 км, М-39А магистрал, 4Р-206 йўли', TRUE, 'Статистика бўлими', 'Аҳоли жон бошига кунига 0,20 йўловчилик — республика ўртачасидан паст, жамоат транспорти маршрутлари камлиги ёки хусусий транспортга боғлиқлик юқорилигидан далолат. Юк ташиш 8,77 млн тонна (темир йўлга 1,2 км) Термизни Сурхондарё транзит логистика марказига айлантириш имкониятини кўрсатади — экспорт 121 млн $ га ўсгани тасдиқлайди. Очиқ омборхоналар (17 та, 29 090 м²) ҳажмини 2-3 бараварга ошириш, замонавий контейнер майдони ва мультимодал алоқани кучайтириш тавсия этилади. Ички маршрутларга электр-автобуслар киритиш давомли ёқилғи тежайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (305, 8, 12, 3, '3', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик (%)', 'Жами: МТТ таҳлили | Қамраб олиш даражаси: 91,1% | 3-7 ёшли болалар: 8 050 нафар | Қамраб олинган: 7 330 нафар | Жами МТТ: 113 та | Давлат МТТ: 18 та | ДХШ: 10 та | Хусусий: 1 та | Оилавий: 84 та', TRUE, 'Мактабгача ва мактаб таълими бошқармаси', '89,6% мактабгача таълим қоплами — республика бўйича яхши натижа (ўртача 75-80%); 2030 йилгача 95-97% га етиб бориш реал мақсад. Қолган 10,4% одатда қишлоқ ва чекка МФЙ ларда — мобил богча ва оилавий богча модели самарадор ечим. 11 та мактаб 2 сменада ишлаши — 5-7 йилда аҳоли ўсиши (2021→2025: +11,7%) билан кучайиш хавфини кўрсатади; 2026-2031 инвестиция режасида мактаб-богча қурилиши учун алоҳида устунлик бўлимини ажратиш тавсия этилади. Ёшлар ишсизлиги 909 киши атрофида — мактабгача таълим сифат индикаторларини ҳам мониторинг рўйхатига киритиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (306, 8, 13, 3, '3', 'Меҳнат ресурслари', 'Инсон капитали ва меҳнат салоҳияти динамикаси', 'Аҳоли сони (минг киши): 2021: 80,3 | 2022: 82,3 | 2023: 84,7 | 2024: 87,2 | 2025: 89,7 | Меҳнат ресурслари (минг киши): 2021: 59,0 | 2022: 54,1 | 2023: 44,0 | 2024: 44,8 | 2025: 47,2 | Банд аҳоли (минг киши): 2021: 42,0 | 2022: 39,0 | 2023: 30,5 | 2024: 30,7 | 2025: 29,6', TRUE, 'Статистика бўлими / Бандлик маркази', 'Туманда доимий аҳоли сони барқарор ўсиб бормоқда (йилига ўртача 2,3%). Меҳнат ресурсларининг самарадорлигини ошириш учун «драйвер» соҳаларга (хизмат кўрсатиш ва логистика) урғу бериш, демографик ўсишни иқтисодий имкониятга айлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (307, 8, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва норасмий бандлик', 'Қайтган мигрантлар сони (киши): 2021: 642 | 2022: 687 | 2023: 931 | 2024: 767 | 2025: 835 | Норасмий бандлик: 3 384 киши | Норасмий секторда йиллик солиқ йўқотиши: 15 млрд сўм', TRUE, 'Бандлик маркази', 'Миграциядан қайтган фуқароларнинг тажрибасини маҳаллий ишлаб чиқаришга йўналтириш учун «Мигрантдан — тадбиркор» дастурини кенгайтириш лозим. Норасмий сектордаги 3,3 минг нафар аҳолини ўзини-ўзи банд қилиш орқали легаллаштириш солиқ базасини кенгайтиришнинг асосий манбаидир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (308, 8, 15, 3, '3', 'Ишсизлик кўрсаткичлари', '1789 нафар ишсиз (5.6%)', 'Ишсизлик (%): 2021: 10,1 | 2022: 9,1 | 2023: 8,1 | 2024: 6,4 | 2025: 5,6 (%) | Ишсизлар сони: 2021: 4647 | 2022: 3906 | 2023: 2674 | 2024: 2084 | 2025: 1749', TRUE, 'Бандлик маркази', 'Туманда ишсизлик даражаси сўнгги 5 йилда деярли икки баробарга камайган. Эндиги вазифа ишсизликни 5,3% га тушириш учун бўш иш ўринлари ярмаркаларини «маҳаллабай» кесимида ташкил этиш ва ёшларни меҳнат бозори талабларига мослаштиришдир.', 1749, 5.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (309, 8, 16, 3, '3', 'Камбағаллик кўрсаткичлари', '787 нафар камбағал оила (4.6%)', 'Камбағаллик (%): 2021: 9,2 | 2022: 8,4 | 2023: 7,8 | 2024: 7,7 | 2025: 6,4 (%) | Камбағал оилалар: 2021: 1632 | 2022: 1360 | 2023: 1133 | 2024: 944 | 2025: 787', TRUE, 'Статистика бўлими', 'Камбағалликни қисқартиришда оилавий тадбиркорлик дастурлари муҳим роль ўйнамоқда. Қолган 787 та камбағал оилани «Темир дафтар»дан чиқариш учун ҳар бир хонадоннинг ички имкониятларини (томорқа, чорвачилик) тўлиқ ишга солиш бўйича микро-лойиҳалар тавсия этилади.', 787, 6.4, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (310, 8, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва ўртача маош динамикаси', 'Ўртача ойлик маош (минг сўм): 2021: 2185 | 2022: 2833 | 2023: 3282 | 2024: 3594 | 2025: 4775 | Ёшлар ишсизлиги (16-30 ёш): 909,5 киши', TRUE, 'Бандлик маркази', 'Ўртача маошнинг йиллик ўсиши 20% дан юқори бўлаётгани ёшлар учун меҳнат бозорининг жозибадорлигини оширади. Ёшлар даромадини янада кўпайтириш учун уларни юқори қўшимча қийматга эга бўлган IT, замонавий иссиқхона хўжалиги ва логистика соҳаларига йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (311, 8, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлаш', 'Жами: 839,5 нафар аёллар ишсиз | Аёллар ишсизлиги: 839,5 киши | Бола нафақаси олувчи оилалар: 2 237 та | Кам таъминланган оилалар: 2 265 та', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя', 'Аёллар орасидаги ишсизлик ва ижтимоий нафақага боғлиқликни камайтириш учун маҳаллаларда «Аёллар дафтари» орқали ҳунармандчилик ва касаначилик марказларини ташкил этиш, аёлларнинг бизнес ташаббусларини 100% қўллаб-қувватлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (312, 8, 19, 3, '3', 'Термиз туманидаги олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', 'Жами: 1 та ОТМ, 10 840 та талаба | Термиз давлат педагогика институти: қуввати 5 080 ўрин, талаба сони 10 840 | Талабалар сони ўрин сонидан 5 760 тага кўп (213,4%)', TRUE, 'Ҳокимият', 'Термиз давлат педагогика институтида талабалар сони қувватидан 2,1 баробар кўп (5 080 ўринга 10 840 талаба) — бу юкланиш таълим сифатига салбий таъсир кўрсатиши мумкин. Тавсия: (1) институт кампусини кенгайтириш ёки янги бино қуриш; (2) масофавий таълим технологияларини жорий этиш; (3) битирувчиларни туман мактабларига ва маҳаллий корхоналарга мақсадли жойлаштириш тизимини яратиш. Педагогик кадрлар тайёрлаш базаси мавжуд бўлгани учун тумандаги 11 та 2-сменали мактаб муаммосини ҳал қилишда ушбу институтдан фойдаланиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (313, 8, 20, 3, '3', 'Термиз туманидаги техникумлар', 'Касб-ҳунар таълим муассасалари, ўқувчилар ва қувватлар', 'Жами: 1 та техникум, 554 та ўқувчи | Сурхондарё илғор касбий махорат техникуми: қуввати 554 ўрин, ўқувчилар сони 554 (100%)', TRUE, 'Ҳокимият', 'Туманда атиги 1 та техникум мавжуд бўлиб, у тўлиқ банд (100%). Ёшлар ишсизлиги 909,5 кишини ташкил этишини ва қайтган мигрантлар 835 кишига етганини ҳисобга олсак, касб-ҳунар таълими қуввати етарли эмас. Тавсия: (1) 2-чи техникум очиш ёки мавжудини кенгайтириш (қувватни 1 000 ўринга етказиш); (2) тоғ-кон, логистика ва қурилиш материаллари ишлаб чиқариш бўйича қисқа муддатли курслар йўлга қўйиш; (3) «Айратом» ЭИЗ корхоналари билан дуал таълим шартномалари тузиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (314, 8, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури (Термиз филиали қамрови — 100%) | «Сунъий интеллект куни» — ҳар пайшанба | Онлайн ўқитиш тизими жорий (LMS) | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Термиз филиали ходимларининг СИ саводхонлигини ошириш орқали мижозларга (айниқса, тадбиркорларга) кредит ажратишда скоринг таҳлилларини тезлаштириш мумкин. Ҳафталик «СИ куни» доирасида ходимларга маҳаллабай ишлаш тизимида маълумотларни йиғиш ва қайта ишлаш бўйича СИ ботларидан фойдаланишни ўргатиш филиал самарадорлигини 20% га оширади. Кейинги босқичда мижозлар билан ишлашда СИ асосидаги «виртуал ёрдамчи»ларни жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (315, 8, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари ва ҳоким ёрдамчилари — маълумотлар таҳлили', TRUE, 'SQB', 'Термиз тумани стратегик ривожланиш режасини тузишда раҳбарларнинг СИ воситаларидан фойдаланиши маълумотлар асосида (data-driven) қарор қабул қилиш тезлигини 3 баробар оширади. Маҳалла банкирларига мижознинг кредит лаёқатини СИ орқали олдиндан баҳолаш (pre-scoring) кўникмаларини бериш, банкнинг рискларини камайтириш ва аҳолига хизмат кўрсатиш сифатини янги босқичга олиб чиқади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (316, 8, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'СИ таҳлили: кўникма ва қизиқиш аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури | Тадбиркорлик: бизнес-режа + микрокредит | Касб: тайёр иш ўринларига йўналтириш', TRUE, 'SQB', 'СИ платформаси орқали ҳар бир фуқаро индивидуал баҳоланади: кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтирилади. Мақсад: 80% иштирокчи 3 ой ичида даромадли фаолиятга ўтади. СИ скоринг натижалари маҳалла банкирларига ҳам тақдим этилиб, кредит ажратишда қўшимча маълумот сифатида фойдаланилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (317, 8, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (318, 8, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари ва тоифаланиши', 'Жами: 30 та маҳалла | Маҳалла тоифалари: Енгил: 18 та | Ўрта: 12 та | Оғир: 0 та | Сабзавотчилик (картошка/карам): 8 та МФЙ | Асосий йўналишлар: Боғдорчилик, Деҳқончилик, Паррандачилик, Чорвачилик', TRUE, 'МФЙ агентлиги', 'Термиз туманида «оғир» тоифадаги маҳаллаларнинг мавжуд эмаслиги (0 та) ижобий кўрсаткич. Бироқ, маҳаллаларнинг 40% (12 та) ҳали «ўрта» тоифада қолмоқда. Уларни «енгил» тоифага ўтказиш учун ипакчилик (30 та МФЙ) ва боғдорчиликдаги хомашёни қайта ишлаш даражасини ошириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (319, 8, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Иқтисодий ўсишни таъминловчи асосий тармоқлар (SWOT таҳлил асосида)', 'Қишлоқ хўжалиги: Мева-сабзавот ва олма (529 га янги боғ) | Туризм ва хизмат: Учқизил сув омбори туристик зонаси | Транспорт ва логистика: Халқаро магистрал йўллар тугуни | Саноат: Саноат зоналарини кенгайтириш ва қурилиш материаллари (оҳактош, қум-шағал)', TRUE, 'Туман ҳокимияти / SQB', 'Туманнинг кучли томони транспорт логистикаси ва экспорт салоҳиятидир. Аммо гўшт ва сабзавотни қайта ишлаш кўрсаткичи ҳозирда 0% ни ташкил этмоқда. Асосий драйвер сифатида агросервис ва саноат зоналарида тайёр маҳсулот ишлаб чиқаришни йўлга қўйиш, шу орқали норасмий иқтисодиёт улушини (27,3%) камайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (320, 8, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва банклар бўйича маҳалла тақсимоти', 'Жами: 300 та микролойиҳа амалга оширилади | Иш ўринлари: 700 та | Жами маҳаллалар: 30 та | Трастбанк: 140 та лойиҳа | Агробанк: 90 та лойиҳа | Саноатқурилишбанк (SQB): 40 та лойиҳа | Бизнесни ривожлантириш банк: 20 та лойиҳа | Халқбанк: 10 та лойиҳа', TRUE, 'Бандлик бўлими / Туман ҳокимияти', 'Термиз туманидаги 30 та МФЙда 300 та микролойиҳа режалаштирилган. 6 та маҳалла банкири ҳар бир лойиҳани бошидан охиригача кузатиб боради. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа амалга оширилишини мониторинг; (4) тадбиркорларга молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (321, 8, 28, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк | SQB Business: юридик шахслар учун онлайн бухгалтерия | SQB AI Advisor: СИ асосидаги молиявий маслаҳатчи', TRUE, 'SQB', 'СИ асосидаги «AI Advisor» мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (322, 8, 29, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: SQB ва бошқа тижорат банклари | Фоиз ставкаси: 1% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (323, 8, 30, 4, '4', 'Ишсизлик юқори маҳаллаларни ривожлантириш режаси', 'SQB томонидан 3 та маҳаллада 240 нафар ишсизни бандликка жалб қилиш режаси', 'Жами: 3 та маҳалла, 240 нафар ишсиз | Гулбаҳор: 83 нафар (5,5%) — аёллар 35, эркаклар 30, ёшлар 18 | Халқобод: 80 нафар (5,7%) — аёллар 32, эркаклар 33, ёшлар 15 | Янгиҳаёт: 77 нафар (5,6%) — аёллар 30, эркаклар 28, ёшлар 19 | Таркиб: ёшлар 22%, аёллар 40%, эркаклар 38% | Кредит маҳсулотлари: Ёшлар бизнесда, Ҳамроҳ (аёллар), Маҳалла лойиҳаси | Микролойиҳалар: 30 та, 240 та иш ўрни, 0,6 млрд сўм', TRUE, 'SQB', 'Аниқланган 3 та маҳаллада ишсизлик даражаси 5,5–5,7% атрофида бўлиб, асосий улушни аёллар (40%) ташкил қилади. «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (324, 8, 31, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк, Агробанк | Фоиз ставкаси: 1% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (325, 8, 32, 5, '5', 'Транспорт-логистика маркази: Жанубий дарвоза', 'Темир йўл ва халқаро йўллар кесишувидаги стратегик нуқта', 'Темир йўл станциясигача: 1,2 км | Автомобиль йўллари: 821 км | Вилоят марказигача: 12 км | Асосий устунлик: Транспорт логистикаси ва экспорт салоҳияти', TRUE, 'Ҳокимият / Статистика', 'Термиз туманининг Афғонистон билан чегарадошлиги ва темир йўлнинг яқинлиги (1,2 км) уни халқаро логистика марказига айлантириш учун катта имконият беради. «Қуруқ порт» (Dry Port) ва божхона терминалларини кенгайтириш, экспортга йўналтирилган маҳсулотларни шу ернинг ўзида қадоқлаш ва жўнатиш тизимини яратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (326, 8, 33, 5, '5', 'Учқизил сув омбори ва экотуризм', 'Сув бўйида дам олиш ва рекреацион зона яратиш имконияти', 'Жорий сайёҳлар: 5 000 киши/йил | Режа: 8 000 киши | Инвестиция лойиҳаси: Термиз курорт шаҳри (2026-2028) | Бюджет: 50 млрд сўм', TRUE, 'Туризм бошқармаси', 'Учқизил сув омбори негизида замонавий дам олиш зоналари ва сув спорти объектларини ташкил этиш керак. 50 млрд сўмлик инвестиция дастури доирасида ҳудудни «Термиз курорт шаҳри» бренди остида тарғиб қилиш ва сайёҳлар сонини 1,5 бараварга ошириш учун меҳмон уйлари ва эко-кемпинглар сонини кўпайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (327, 8, 34, 5, '5', 'Эркин иқтисодий ва кичик саноат зоналари', '«Айратом» ЭИЗ ва «Нурафшон» КСЗ салоҳияти', 'ЭИЗ «Айратом»: 4 корхона, 182 иш ўрни | КСЗ «Нурафшон ва Бунёдкор»: 9 корхона, 122 иш ўрни | Ихтисослашув: Саноат ва ишлаб чиқариш', TRUE, 'Инвестиция бўлими', 'Мавжуд саноат зоналарида бўш турган майдонларга юқори технологик корхоналарни жалб қилиш лозим. Айниқса, Афғонистон бозори учун зарур бўлган қурилиш материаллари ва тайёр озиқ-овқат маҳсулотлари ишлаб чиқаришни йўлга қўйиш орқали саноат ҳажмини 2025 йилдаги 1 715 млрд сўмлик кўрсаткичдан янада ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (328, 8, 35, 5, '5', 'Тоғ-кон хомашёси захиралари', 'Табиий ресурслардан саноатда фойдаланиш', 'Оҳактош: 7 313,9 минг м³ | Қум-шағал: 25,1 минг тонна | Янги иш ўринлари режаси: 2027 йилгача 265 та', TRUE, 'Геология қўмитаси', 'Тумандаги улкан оҳактош захиралари қурилиш кластерларини ташкил этиш учун тайёр хомашё базасидир. Хомашёни шунчаки қазиб олиш эмас, балки уни қайта ишлаб, юқори қўшилган қийматли қурилиш қоришмалари ва пардозлаш материаллари ишлаб чиқаришни йўлга қўйиш, бу орқали экспорт тушумини ошириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (329, 8, 36, 5, '5', 'Жануб қуёши — арзон энергия манбаи', 'Муқобил энергия орқали таннархни пасайтириш', 'Жами: Қуёш энергияси салоҳияти | Қуёшли кунлар: 310+ кун/йил | Имконият: Саноат зоналари ва сув омбори атрофида кичик СЭСлар | Инвестиция: ПЧШ асосидаги лойиҳалар | Самара: Таннархни 15-20% камайтириш', TRUE, 'Энергетика вазирлиги', 'Сурхондарё вилоятининг қуёш радиацияси юқорилигидан фойдаланиб, «Айратом» ЭИЗ корхоналарининг томига қуёш панелларини ўрнатиш ва «Green Industrial Zone» концепциясини жорий этиш лозим. Бу маҳсулот таннархини 15-20% гача камайтиришга ва экспортда рақобатбардошликни оширишга хизмат қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (330, 8, 37, 6, '6', 'Молиявий калибрлаш ва кредитлаш стратегияси', 'Кредит портфелини самарали йўналтириш', 'Умумий кредит ҳажми (2025): 1 366,1 млрд сўм | Кичик бизнес кредитлари: 475 млрд сўм | Микрокредит режаси: 467 млрд сўм', TRUE, 'SQB / Марказий банк', 'Кредитлашда асосий урғуни оилавий тадбиркорликдан кичик ва ўрта саноат лойиҳаларига ўтказиш лозим. 467 млрд сўмлик микрокредитларни тарқоқ эмас, балки маҳаллалар ихтисослашувидан келиб чиқиб, занжирли лойиҳаларга (масалан, бир маҳаллада фақат иссиқхона, бошқасида ҳунармандчилик) йўналтириш самарадорликни оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (331, 8, 38, 6, '6', 'Инфратузилмавий ривожланиш 2026', '2026 йилда қабул қилинадиган муҳим қарорлар', 'Устувор йўналишлар: Сув тармоғини кенгайтириш | Янги трансформаторлар ўрнатиш | Ички йўлларни таъмирлаш', TRUE, 'Ҳокимият', 'Инфратузилма лойиҳаларини бевосита «Лойиҳа фабрикаси»даги истиқболли бизнес лойиҳалари билан мувофиқлаштириш керак. Яъни, янги трансформатор ва сув тармоғи аввало ишлаб чиқариш ва туризм объекти қурилаётган нуқталарга етиб бориши лозим. Бу давлат маблағларининг иқтисодий қайтимини тезлаштиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (332, 8, 39, 6, '6', 'Инсон капитали ва бандликни таъминлаш', 'Кадрлар етишмовчилиги муаммосини ҳал қилиш', 'Камбағал оилалар: 787 та (2025 режа) | Муаммо (SWOT): Малакали кадрлар етишмаслиги | Режа: Тоғ-кон секторида 2026 йилда 110 та иш ўрни', TRUE, 'Бандлик бошқармаси', 'Тумандаги кадрлар тақчиллигини бартараф этиш учун «Бандлик маркази» қошида тоғ-кон ва логистика соҳалари учун қисқа муддатли қайта тайёрлаш курсларини очиш зарур. «Айратом» ЭИЗдаги бўш иш ўринларига маҳаллий ёшларни тизимли равишда йўналтириш орқали камбағаллик даражасини кескин камайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (333, 8, 40, 6, '6', 'Лойиҳалар портфели ва экспорт', 'Янги қиймат занжирларини яратиш', 'Лойиҳалар сони: 17 та | Жами қиймати: 1 703 млрд сўм | Яратиладиган иш ўрни: 1 709 та', TRUE, 'Лойиҳа фабрикаси', '17 та йирик лойиҳанинг ҳар бири учун «Лойиҳа фабрикаси» механизми асосида индивидуал «йўл харитаси» ишлаб чиқиш керак. Мақсад — импорт ўрнини босувчи маҳсулотлар чиқариш ва Термиз туманининг экспорт улушини вилоятда 6-ўриндан (ҳозирги ҳолат) кучли 3-ликка олиб чиқиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (334, 8, 41, 6, '6', 'Минтақавий рейтинг ва ЯҲМ ўсиши', 'Туманнинг иқтисодий мавқеини мустаҳкамлаш', 'Жами: Минтақавий рейтинг таҳлили | Вилоятдаги ўрни: 6-ўрин (14 тадан) | Саноат ўсиш суръати (2025): 159,3% | Мақсад: Рейтингни 3-ўринга кўтариш', TRUE, 'Статистика бўлими', 'Туманнинг 6-ўринда эканлиги унинг потенциали ҳали тўлиқ ишга солинмаганини англатади. Саноат ўсиш суръатини (159%) сақлаб қолган ҳолда, хизмат кўрсатиш соҳасини (айниқса транзит хизматлар ва туризм) жадаллаштириш орқали рейтингни кўтариш мумкин. Хизматлар соҳасидаги статистик ҳисоб-китобларни шаффофлаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (335, 8, 42, 6, '6', 'Стратегик якун: 2026-2027 мақсадлари', 'Термизни ривожлантиришнинг 3 та асосий устуни', 'Логистика ва Транзит (Афғонистон билан савдо) | Рекреацион Туризм (Учқизил ва Курорт шаҳар) | Саноат Кластерлари (Оҳактош ва Саноат зоналари)', TRUE, 'Ҳокимият / СИ таҳлили', 'Термиз тумани учун «24/7 фаол иқтисодий ҳудуд» моделини таклиф этамиз. Бунда кундузи саноат ва қишлоқ хўжалиги, кечаси эса логистика ва хизмат кўрсатиш объектлари тўлиқ қувватда ишлаши таъминланади. 2027 йилгача туманни «Жанубий иқтисодий драйвер»га айлантириш учун барча ресурс ва имкониятлар мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (9, 4, 'karakalpakstan_resp', 'Қорақалпоғистон Республикаси', 'Республика Каракалпакстан', 'Republic of Karakalpakstan', '', 'karakalpakstan.json', TRUE, 'respublika', NULL, 42, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
