INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (28, 9, 'Хонадон', 363147, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (336, 9, 1, 1, '1', 'Макроиқтисодий кўрсаткичлар', 'Саноат, хизматлар ва ташқи савдо (2025 йил)', 'Жами: 2025 йил макроиқтисодий кўрсаткичлар | Саноат ҳажми: 29,1 трлн сўм | Хизматлар ҳажми: 35,2 трлн сўм | Экспорт ҳажми: 435,2 млн $ | Импорт ҳажми: 375,6 млн $ | Савдо сальдоси: +59,5 млн $', TRUE, 'Статистика ва Молия бўлимлари', 'Хизматлар соҳаси 5 йил ичида 4 баробар ўсган. Саноат ўсишини сақлаб қолиш учун маҳаллий хомашёни қайта ишлаш ва экспортни диверсификация қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (337, 9, 2, 1, '1', 'Иқтисодиётнинг драйвер тармоқлари', 'Тармоқлар улуши ва ихтисослашув йўналишлари', 'Жами: Устувор тармоқлар таҳлили | Қишлоқ хўжалиги: 87,6% | Хизматлар: 74% | Саноат: 41,3%', TRUE, 'Ҳокимият ва Статистика бўлими', 'Қишлоқ хўжалигининг улуши юқори, бироқ саноат паст. Агро-саноат кластерлари орқали қишлоқ хўжалиги маҳсулотларини тайёр маҳсулотгача қайта ишлашни йўлга қўйиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (338, 9, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш', 'Йирик ва кичик бизнеснинг ишлаб чиқариш ҳажми', 'Жами: Саноат ишлаб чиқариш таҳлили | Йирик корхоналар: 22,6 трлн сўм | Кичик бизнес: 31,5 трлн сўм | Очилган корхоналар: 3 602 та | Ёпилган корхоналар: 6 194 та', TRUE, 'Статистика бўлими', 'Ёпилган корхоналар сони очилганларидан юқори. Кичик саноат зоналари инфратузилмасини яхшилаш ва бизнес-инкубаторларни кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (339, 9, 4, 1, '1', 'Маҳаллий бюджет', 'Бюджет даромадлари ва контингент бюджет', 'Жами: 3,3 трлн сўм маҳаллий бюджет (2025) | Контингент бюджет (2025): 3,4 трлн сўм', TRUE, 'Молия бўлими', 'Бюджет даромадлари прогнозида пасайиш кузатилмоқда. Солиқ базасини инвентаризация қилиш ва яширин иқтисодиётни қисқартирувчи рақамли ечимларни жорий этиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (340, 9, 5, 1, '1', 'Ажратилган кредитлар', 'Банк кредитлари ҳажми динамикаси (трлн сўм)', 'Жами: 11,1 трлн сўм (2025 йил) | Кредитлар динамикаси (трлн сўм): 2021: 4,8 | 2022: 5,3 | 2023: 7,9 | 2024: 8,5 | 2025: 11,1', TRUE, 'Марказий банк', 'Кредитлар ҳажми кескин ошган. Уларни экспорт ва юқори қийматли лойиҳаларга мақсадли тақсимлаш ҳамда эрта огоҳлантириш тизимини кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (341, 9, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Google Trends индекси (балл): 2021: 18,5 | 2022: 20,1 | 2023: 22,8 | 2024: 26,5 | 2025: 32,4', TRUE, 'Google', 'Инвестициявий жозибадорлик рақамли маконда ўсмоқда, лекин фаоллик ҳали паст. Тарғиботни инвестиция форумлари ва экспорт мавсумида кучайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (342, 9, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолини тоза ичимлик суви билан таъминлаш даражаси', 'Жами: 70,9% таъминланганлик (2025) | Таъминланганлик динамикаси (%): 2023: 66,4 | 2024: 68,6 | 2025: 70,9', TRUE, 'Сув хўжалиги', 'Аҳолининг 30% қисми ҳали ҳам тоза ичимлик сувисиз. Локал сув тозалаш иншоотлари қуриш ва Smart Water тизими орқали исрофгарчиликни камайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (343, 9, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Йўл инфратузилмаси кўрсаткичлари', 'Жами: 4 172 км йўллар тармоғи | Асфальтланган улуш: 98,1% | Аҳоли зичлиги: 12,3 киши/км²', TRUE, 'Йўл хўжалиги', 'Асфальтланиш даражаси юқори бўлса-да, паст аҳоли зичлиги йўлларни сақлаш харажатларини оширади. Юк транспортлари вазнини назорат қилувчи автоматик тизимлар ўрнатиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (344, 9, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Тармоқларнинг техник ҳолати ва модернизацияси', 'Жами: Электр тармоғи таҳлили | Трансформаторлар эскириши: 42% | Линиялар эскириши: 62% | Узилишлар: ойига 13 марта (2 баробар камайган)', TRUE, 'Электр тармоқлари корхонаси', 'Тармоқларнинг эскириш даражаси критик. Модернизацияни тезлаштириш учун қайта тикланувчи энергия манбаларини маҳаллий тармоқларга интеграция қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (345, 9, 10, 2, '2', 'Ер ресурслари ва коммуникация', 'Ҳудуднинг умумий майдони ва рақамли инфратузилма', 'Жами: 6,2 млн гектар ер фонди | Интернет қоплами: 97,4% | Газ билан таъминланганлик: 75%', TRUE, 'Кадастр агентлиги', 'Бўш ер майдонларини ГИС орқали инвесторларга тайёр пакет сифатида таклиф қилиш ва Ақлли қишлоқ хўжалиги лойиҳаларини ривожлантириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (346, 9, 11, 2, '2', 'Жамоат транспорти ва юк ташиш таҳлили', 'Автобус ва микроавтобус инфратузилмаси, йўловчи ва юк ташиш', 'Жами: 582 та транспорт воситаси | Дамас: 189 та (32,5%) | Автобуслар: 105 та (18,0%) | Такси ва бошқалар: 288 та (49,5%) | Йиллик йўловчи ташиш: 170,4 млн киши | Юқори қамров: Нукус ш. | Аҳоли зичлиги: 12,3 киши/км²', TRUE, 'Транспорт бошқармаси / Статистика бошқармаси', 'Жамоат транспортида такси ва бошқалар (49,5%) устунлик қилади, Дамаслар 32,5% ташкил этади. Автобуслар сонини 105 тадан камида 200 тага ошириш ва Нукус шаҳридан ташқари туманларда маршрутлар тармоғини кенгайтириш лозим. 170,4 млн йўловчи ташиш ҳажмини ошириш учун электрик автобуслар киритиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (347, 9, 12, 2, '2', 'Мактабгача таълим қамрови', 'МТТ қоплами динамикаси', 'МТТ қамрови (%): 2021: 76,1 | 2022: 78,5 | 2023: 80,2 | 2024: 82,1 | 2025: 84,0', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Қолган 16% қамровни таъминлаш учун хусусий сектор ва оилавий боғчалар моделини рағбатлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (348, 9, 13, 2, '2', 'Мактаблар юкламаси', 'Мактаб сменалари ва инфратузилмаси', 'Жами: 735 та мактаб | 1 сменали: 126 та | 2 сменали: 609 та (82,9%)', TRUE, 'Мактабгача ва мактаб таълими бўлими', '2-сменали мактаблар улуши (83%) критик. Янги мактаб қурилишини юкламаси энг юқори бўлган маҳаллаларга йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (349, 9, 14, 3, '3', 'Меҳнат ресурслари', 'Инсон капитали ва меҳнат салоҳияти', 'Жами: 1,14 млн меҳнат ресурслари | Банд аҳоли: 805,8 минг киши | Ўртача ойлик маош: 5,0 млн сўм', TRUE, 'Бандлик маркази ва Статистика бўлими', 'Расмий бандликни таъминлаш учун йилига камида 50 мингта янги иш ўрни яратиш ва ўсиб бораётган харид қобилиятини қўллаб-қувватлаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (350, 9, 15, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва инклюзив бандлик', 'Жами: 229,5 минг киши норасмий секторда | Ногиронлиги бўлган шахслар: 59,3 минг нафар (фақат 14% иш билан таъминланган)', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя агентлиги', 'Норасмий секторни ўзини-ўзи банд қилиш орқали легаллаштириш ва ногиронлиги бўлган шахслар учун масофавий иш ўринларини кўпайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (351, 9, 16, 3, '3', 'Ишсизлик кўрсаткичлари', '42 400 нафар ишсиз — 5,0% (2025)', 'Ишсизлик даражаси (%): 2021: 10,1 | 2022: 9,1 | 2023: 7,1 | 2024: 5,8 | 2025: 5,0', TRUE, 'Бандлик маркази', 'Ишсизлик даражаси 2 баробарга камайган. Эндиги эътиборни иш ўринларининг сифати ва юқори маошли соҳаларга қаратиш, меҳнат бозорини рақамлаштириш лозим.', 42400, 5.0, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (352, 9, 17, 3, '3', 'Камбағаллик кўрсаткичлари', '43 079 оила', 'Камбағаллик даражаси (%): 2021: 21,2 | 2023: 19,9 | 2024: 13,6 | 2025: 6,6 | Мақсад: 3,0% | Камбағал оилалар: 1 574 та', TRUE, 'Статистика бўлими', 'Қолган 1 574 та оилага мақсадли микрокредитлар ва субсидиялар ажратиш, шунингдек ҳар бир хонадоннинг иқтисодий паспортини юритиш зарур.', 43079, 6.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (353, 9, 18, 3, '3', 'Ёшлар бандлиги ва даромади', 'Ёшлар ишсизлиги ва миграция', 'Жами: 23,0 минг ишсиз ёшлар (16–30 ёш) | Хорижга кетганлар: 15,5 минг нафар', TRUE, 'Бандлик маркази / Статистика бўлими', 'Ишсиз ёшларни юқори технологик соҳаларга ўқитиш орқали миграцияни камайтириш ва Рақамли маҳалла лойиҳасини ишга тушириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (354, 9, 19, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва бандлик режаси', 'Жами: 19,7 минг ишсиз аёллар | Бандлик режаси: 12,5 минг нафар', TRUE, 'Mehnat.uz', 'Аёллар даромадини ошириш учун фриланс ва ГИГ-иқтисодиётни ривожлантириш, HAMROH дастурини IT ва молиявий хизматларга ҳам йўналтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (355, 9, 20, 3, '3', 'Олий таълим муассасалари', 'ОТМ сони ва талабалар', 'Жами: 9 та ОТМ | Талабалар: 73,5 минг нафар', TRUE, 'Ҳокимият', 'Талабаларни маҳаллий корхоналарга амалиётга жалб этиш ва ОТМлар қошида стартап инкубаторлар очиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (356, 9, 21, 3, '3', 'Касб-ҳунар таълими муассасалари', 'Техникумлар сони ва ўқувчилар', 'Жами: 49 та техникум | Ўқувчилар: 90,6 минг нафар', TRUE, 'Ҳокимият', 'Битирувчиларни ҳудудий корхоналар эҳтиёжига мос равишда мақсадли ишга жойлаштириш тизимини жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (357, 9, 22, 4, '4', 'Сунъий интеллект куни ва СИ ўқитиш дастури', 'Ҳафталик СИ куни ва 4 босқичли ўқитиш тизими', 'Жами: СИ малака ошириш дастури | «Сунъий интеллект куни» — ҳар ҳафтанинг жума куни СИ ўқитишга бағишланади | 1-босқич: Ҳар ҳафта жума куни СИ ўқитиш куни | 2-босқич: Туман ҳокимлари ва ҳоким ўринбосарлари — СИ ўқитиш ва СИ қўллашни жорий қилиш | 3-босқич: Банк филиал раҳбарлари ва маҳалла банкирлари — СИ скоринг, риск таҳлили ва мижоз хизмати | 4-босқич: Маҳалла раислари ва ҳоким ёрдамчилари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Таълим тизимини амалиётга боғлаш учун ҳар бир бўлим ва банк филиалларида СИ бўйича KPI кўрсаткичларини жорий этиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (358, 9, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'Жами: 1 350 нафар СИ орқали ўқитиш (2026 режа) | СИ таҳлили: кўникмаларни аниқлаш | СИ-ментор: индивидуал ўқув дастури', TRUE, 'SQB', 'СИ орқали баҳоланган фуқароларнинг натижаларини маҳалла банкирларига кредит ажратишда қўшимча скоринг маълумоти сифатида узатиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (359, 9, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами', 'Жами: 5 та СИ хизмати (SQB AI Advisor) | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит мослаштириш: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти KPI мониторинги | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', 'Маҳалла банкирлари ва тадбиркорлар ишини енгиллаштирувчи ушбу платформани 2026 йил якунигача барча 452 та маҳаллада тўлиқ жорий этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (360, 9, 25, 4, '4', 'Маҳалла драйвер секторлари', '452 та маҳалланинг асосий иқтисодий йўналишлари', 'Жами: 452 та маҳалла, 6 та драйвер сектор | 1 - Деҳқончилик: 188 та маҳалла (сабзавотчилик — 120, полизчилик — 23, сабзичилик — 16, дуккакли — 16, картошкачилик — 8, карамчилик — 2, кўкатчилик — 1, мошчилик — 1, супурги — 1) | 2 - Савдо ва хизмат кўрсатиш: 130 та маҳалла (озиқ-овқат/ноозиқ-овқат — 41, маиший хизмат — 24, хизмат кўрсатиш — 63, сартарошлик — 2) | 3 - Чорвачилик: 94 та маҳалла (қорамолчилик — 76, қўй ва эчкичилик — 18) | 4 - Кичик ишлаб чиқариш: 8 та маҳалла (тикувчилик — 4, қандолат — 3, қурилиш материаллари — 1) | 5 - Паррандачилик: 28 та маҳалла | 6 - Боғдорчилик: 4 та маҳалла', TRUE, 'Бандлик бошқармаси / Иқтисодиёт бошқармаси', 'Деҳқончилик (188 та) ва чорвачилик (94 та) устунлик қилади. Кичик ишлаб чиқариш атиги 8 та маҳаллада мавжуд — бу сонни камида 30 тага етказиш, айниқса гўшт ва сут қайта ишлаш бўйича кичик цехлар очиш лозим. Паррандачилик (28 та) ва боғдорчилик (4 та) секторларини кенгайтириш имконияти юқори.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (361, 9, 26, 4, '4', 'Ишсизлик юқори маҳаллалар', '452 та маҳалланинг тоифалаштириши ва оғир ҳудудлар таҳлили', 'Жами: 452 та маҳалла | Қизил тоифа (оғир): 90 та маҳалла | Сариқ тоифа (ўрта): 32 та маҳалла | Яшил тоифа (енгил): 330 та маҳалла | Оғир маҳаллалар: 102 та (иқтисодий аҳволи оғир) | Расмий ишсизлик: 5,0% (2025) | Ишсизлар сони: 42 408 киши (2025) | Камбағаллик даражаси: 10,8% (2025) | Кам таъминланган оилалар: 45 997 та | Камбағал оилалар: 43 079 та | Ижтимоий ёрдамга муҳтож: 142 309 оила | Мақсад: 2026 йил якунида 4,2% га тушириш', TRUE, 'Бандлик бошқармаси / МФЙ агентлиги / Ижтимоий ҳимоя', 'Қизил тоифадаги 90 та маҳаллада «бир маҳалла — бир драйвер» тамойилини жорий этиш керак. Камбағаллик 2021–2025 да 21,2% дан 10,8% га тушган — ижобий тренд. Лекин 43 079 камбағал оила ва 142 309 ижтимоий ёрдамга муҳтож оила мавжуд. Оғир маҳалларда чорвачилик ва сабзавотчилик бўйича микролойиҳалар ишга тушириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (362, 9, 27, 4, '4', 'SQB рақамли хизматлари', 'Банкнинг рақамли платформалари ва хизматлари', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: 13 банк филиали, 679 банкомат, маҳалла банкирлари 129 та (20 аёл, 109 эркак)', TRUE, 'SQB / Марказий банк', '679 та банкомат мавжуд, лекин 452 та маҳалладан фақат 129 тасида маҳалла банкири бор — қопламни камида 250 тага етказиш зарур. NPL 5,2% — бу юқори кўрсаткич, молиявий саводхонлик дастурларини кучайтириш ва кредит скоринг тизимини такомиллаштириш лозим. Интернет қоплами 97,4% га етган — бу SQB Mobile кенгайишига қулай шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (363, 9, 28, 4, '4', 'Оилавий тадбиркорлик ва HAMROH дастури', 'Ижтимоий қўллаб-қувватлаш, оилавий тадбиркорлик ва хотин-қизлар учун молиявий дастур', 'Жами: 142 309 та муҳтож оила | Бола нафақаси олувчилар: 50 797 та оила | HAMROH дастури: гаровсиз кредит 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Ижтимоий ҳимоя агентлиги / SQB', '142 минг муҳтож оила ва 50 797 бола нафақаси олувчи оилаларни тадбиркорликка жалб қилиш учун «HAMROH» дастури орқали гаровсиз кредитлар ажратиш ва маҳалла банкирлари орқали бизнес-тренинглар ташкил этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (364, 9, 29, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Оғир тоифадаги маҳаллалар учун манзилли бандлик ва кредит дастурлари', 'Жами: 90 та маҳалла, оғир тоифа (102 та иқтисодий оғир) | Ишсизлар (2025): 42 408 киши | Ёшлар (16–30) ишсизлиги: 22 993 киши | Аёллар ишсизлиги: 19 727 киши | Ногиронлар: 59 304 (ишламайди: 50 863) | Кредит маҳсулотлари: 1) Микрокредит 2) Оилавий тадбиркорлик 3) ПК-312 4) Лизинг 5) Бизнесга биринчи қадам 6) Маҳалла лойиҳаси бўйича банк кредитлари | 2026 йил кредит режаси: Жами 11 900 млрд сўм (кичик бизнес: 6 500 млрд) | Қисқа муддат (0–12 ой): 1,5 трлн сўм | Ўрта муддат (1–3 йил): 3,9 трлн сўм | Узоқ муддат (3–5 йил): 3,4 трлн сўм | Мақсад: 2026 йил якунида ишсизликни 4,2% га тушириш | Микролойиҳалар: 21 252 та лойиҳа, 43 184 иш ўрни, 443 251 млрд сўм', TRUE, 'SQB / Бандлик бошқармаси / Иқтисодиёт бошқармаси', 'Оғир маҳаллаларда чорвачилик (қорамолчилик, қўйчилик) ва сабзавотчилик бўйича кичик лойиҳаларни молиялаштириш керак. 50 863 ишламайдиган ногирон учун уйда ишлаш имконини яратиш лозим. Ёшлар ишсизлиги (22 993) ва аёллар ишсизлиги (19 727) ни камайтириш учун тикувчилик, қандолат ва маиший хизмат бўйича қисқа муддатли ўқитиш дастурлари ташкил қилиш зарур. 2026 йилгача ишсизликни 4,2% га тушириш учун манзилли микрокредитлар ажратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (365, 9, 30, 5, '5', 'Қайта тикланувчи энергия (Шамол ва Қуёш)', 'Устюрт текислигида шамол ва қуёш энергиясининг юқори зичлиги', 'Жами: 300+ қуёшли кун/йил ва барқарор шамол оқими | Тармоқлардаги 62% эскиришни яшил микро-тармоқлар орқали компенсация қилиш имконияти | Инвестиция: 15–50 млн $ (йирик ВЭС ва СЭС лойиҳалари)', TRUE, 'Табиатни муҳофаза қилиш қўмитаси / Электр тармоқлари', 'Электр таъминотидаги узилишларни камайтириш учун саноат зоналарини автоном қуёш панеллари тизимига ўтказиш ва ортиқча энергияни банкдаги яшил кредит ҳисобига сотиш механизмини йўлга қўйиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (366, 9, 31, 5, '5', 'Рақамли иқтисодиёт ва СИ хаби', 'Интернет қамрови 97,4%, СИ платформа ва IT-аутсорсинг', 'Жами: Рақамли иқтисодиёт салоҳияти | Интернет қамрови: 97,4% | СИ орқали тадбиркорликка ўқитиш режаси (2026): 1 350 нафар | IT-аутсорсинг ва масофавий хизматлар (Gig-economy) | Ёшлар ишсизлиги: 23 минг киши', TRUE, 'SQB / Рақамли технологиялар вазирлиги', 'Қорақалпоғистонда Digital Nomad зоналарини яратиш ва маҳаллий ёшларни рус ва инглиз тилларини қўллаган ҳолда хорижий бозорларга чиқариш учун AI-менторлардан фойдаланиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (367, 9, 32, 5, '5', 'Агро-технологиялар ва Сув тежовчи тизимлар', '6,2 млн гектар ер фонди ва иқлим ўзгаришига мослашиш', 'Жами: 6,2 млн гектар ер фонди | Технология: Томчилатиб суғориш ва Smart Water тизими | Шўрланишга чидамли экинлар ва гидропоника | Бўш ерларни ГИС орқали инвесторларга тайёр пакет сифатида бериш', TRUE, 'Сув хўжалиги / Кадастр агентлиги', 'Қишлоқ хўжалигининг 87,6% улушини сақлаб қолган ҳолда, сув исрофини 30% га камайтирувчи СИ-назорат тизимларини жорий этган агро-кластерларга имтиёзли кредитлар ажратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (368, 9, 33, 5, '5', 'Устюрт минерал хомашё кластери', 'Маҳаллий хомашёни қайта ишлаш орқали саноатни диверсификация қилиш', 'Жами: 29,1 трлн сўм саноат ҳажми | Йўналиш: Кимё саноати, қурилиш материаллари, нодир металлар | Экспорт потенциали: 435,2 млн $ дан 600 млн $ гача | Ташқи савдо сальдоси: +59,5 млн $', TRUE, 'Статистика ва Саноат бўлимлари', 'Хомашёни оддий экспорт қилишдан воз кечиб, кичик саноат зоналарида тайёр маҳсулот (шиша, кимёвий ўғитлар) ишлаб чиқаришни СИ таҳлиллари асосида мақсадли молиялаштириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (369, 9, 34, 5, '5', 'Эко-туризм ва Оролбўйи бренди', 'Мўйноқ, Кемалар қабристони ва Савицкий музейи', 'Туристлар сони (минг нафар): 2021: 12,5 | 2022: 18,3 | 2023: 25,7 | 2024: 34,2 | 2025: 45,0', TRUE, 'Ҳокимият / Туризм бошқармаси', 'Орол денгизининг қуриган тубида Яшил қоплама лойиҳаларини туристик маршрутларга айлантириш ва СИ-гидлар орқали кўп тилли хизматни йўлга қўйиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (370, 9, 35, 5, '5', 'Логистика ва Транзит коридори', 'Қозоғистон ва Россия билан чегарадошлик, шимолий дарвоза', 'Юк айланмаси (млн тонна): 2021: 28,4 | 2022: 31,2 | 2023: 35,8 | 2024: 40,1 | 2025: 46,3', TRUE, 'Йўл хўжалиги / Статистика', 'Йўлларни сақлаш харажатларини камайтириш учун юк оқимини СИ орқали прогноз қилиш ва йўл бўйи сервисини (кемпинг, тиббий ёрдам, техник сервис) 24/7 режимига ўтказиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (371, 9, 36, 5, '5', 'Иқлим профили ва экологик хавфлар', 'Континентал қурғоқчил иқлим, Орол таъсири', 'Жами: UNEP 1-гуруҳ (энг заиф ҳудуд) | Ҳарорат кўтарилиши: +1,8–2,5°C | Ёғингарчилик: 10 баробар камайган', TRUE, 'Табиатни муҳофаза қилиш қўмитаси', 'Иқлимга мослашган лойиҳаларни (томчилатиб суғориш) устувор кредитлаш ва Яшил жамғармалар билан эко-лойиҳалар бўйича ҳамкорликни кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (372, 9, 37, 6, '6', 'Саноат барқарорлиги ва SME қўллаб-қувватлаш', 'Ёпилган корхоналар (6 194) очилганлардан (3 602) кўп', 'Жами: 6 194 та ёпилган корхона (3 602 та очилган) | Режа: Инқирозга қарши СИ-диагностика тизими | Мақсад: 2027 йилгача ёпилиш коэффициентини 2 баробар камайтириш', TRUE, 'Статистика бўлими / SQB', 'Кичик саноат зоналарида инфратузилмани (электр, газ) СИ-мониторинг асосида тақсимлаш ва бизнес-инкубаторларни кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (373, 9, 38, 6, '6', 'Инсон капитали ва Бандлик (Мақсад 2027)', 'Ишсизлик 5%, лекин ёшлар ва аёллар ўртасида юқори', 'Банд аҳоли (минг киши): 2021: 702,7 | 2022: 728,4 | 2023: 756,1 | 2024: 781,3 | 2025: 805,8', TRUE, 'Бандлик маркази / SQB', 'Ҳар бир маҳаллада (452 та) Рақамли касблар маркази ни ташкил этиш орқали миграцияни 15% га қисқартириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (374, 9, 39, 6, '6', 'Камбағалликни қисқартириш (Мақсад: 3,0%)', '2025 йилда 6,6%, қолган оилалар — 1 574 та', 'Камбағаллик даражаси (%): 2021: 21,2 | 2022: 20,5 | 2023: 19,9 | 2024: 13,6 | 2025: 6,6', TRUE, 'Статистика бўлими / SQB', 'Камбағалликдан чиқиш учун фақат молиявий ёрдам эмас, балки оила аъзоларини СИ орқали касбга йўналтириш ва бозор топиб бериш асосий драйвер бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (375, 9, 40, 6, '6', 'Энергетика ва Инфратузилма модернизацияси', 'Линиялар 62%, трансформаторлар 42% эскирган', 'Электр узилишлари (марта/ой): 2021: 26 | 2022: 22 | 2023: 19 | 2024: 16 | 2025: 13', TRUE, 'Электр тармоқлари / Ҳокимият', 'Узилишларни камайтириш учун Smart Grid тизимини пилот лойиҳа сифатида Нукус ва йирик туман марказларида ишга тушириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (376, 9, 41, 6, '6', 'СИ-бошқарув ва Рақамли маҳалла', '452 та маҳаллада SQB AI Advisor платформасини тўлиқ жорий этиш', 'СИ қамрови (маҳалла): 2021: 0 | 2022: 0 | 2023: 45 | 2024: 180 | 2025: 320 | 2026 режа: 452', TRUE, 'SQB / Ҳокимият', 'Давлат бошқаруви ва банк хизматларида СИ-скоринг тизимини қўллаш орқали коррупция хавфини камайтириш ва шаффофликни таъминлаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (377, 9, 42, 6, '6', 'Экологик хавфсизлик ва Климат-резильентлик', 'Ҳарорат +2,5°C гача кўтарилиши ва сув танқислиги', 'Ўрмонлаштириш (минг га): 2021: 120 | 2022: 145 | 2023: 175 | 2024: 210 | 2025: 250 | 2026 режа: 300', TRUE, 'Табиатни муҳофаза қилиш қўмитаси / Ҳокимият', 'Қорақалпоғистонни иқлим ўзгаришига мослашиш бўйича халқаро лабораторияга айлантириш орқали ҳудудга юқори технологияли инвестицияларни олиб кириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
