INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (378, 10, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва экспорт ҳажмининг 5 йиллик динамикаси', 'Жами: 2025 йил кўрсаткичлари | Саноат ҳажми: 1 679,9 млрд сўм (2021: 777,0 → 2025: 1 679,9, +216,2%) | Хизматлар ҳажми: 2 214,8 млрд сўм (2021: 1 191,9 → 2025: 2 214,8, +186%) | Экспорт ҳажми: 36 298 минг $ (2021: 1 570,3 → 2025: 36 298, +2 277%)', TRUE, 'Туман статистика бўлими', 'Қўнғирот туманида экспорт ҳажми 5 йил ичида 23 баробардан ортиқ ўсгани (1,5 млн доллардан 36,3 млн долларга) ҳудуднинг улкан ташқи иқтисодий салоҳиятини кўрсатади. Саноат ва хизматлар ҳажми ҳам барқарор (2 баробардан зиёд) ўсиш траекториясида. Стратегия: экспортнинг кескин ўсишини инобатга олиб, маҳаллий ишлаб чиқарувчилар учун логистика занжирларини янада оптималлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (379, 10, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Устувор соҳалар ва уларнинг улуши', 'Жами: 4 та устувор соҳа | 1-устувор: Нефть ва газ — ҳудуднинг стратегик пойдевори | 2-устувор: Саноат (34,1%) — йирик ва кичик корхоналарнинг жадал ривожланиши | 3-устувор: Чорвачилик — қишлоқ хўжалигидаги асосий драйвер | 4-устувор: Хизмат кўрсатиш (34,9%) — аҳоли бандлиги энг юқори бўлган соҳа (10,3 минг киши)', TRUE, 'Туман ҳокимияти / Статистика бўлими', 'Туман иқтисодиётида саноат ва хизматлар улуши деярли тенглашгани (34% ва 35%) мувозанатли ривожланишдан далолат беради. Стратегия: нефть-газ сектори атрофида хизмат кўрсатиш ва кичик ишлаб чиқариш субъектларини (кооперация) кўпайтириш орқали бандликни янада ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (380, 10, 3, 1, '1', 'Саноат маҳсулотлари динамикаси (2021-2025)', 'Ишлаб чиқариш ҳажми ва ўсиш суръати', '2021: 777,0 | 2022: 921,2 | 2023: 1245,5 | 2024: 1359,1 | 2025: 1679,9 (млрд сўм)', TRUE, 'Туман статистика бўлими', 'Йирик корхоналар ишлаб чиқаришда етакчи (1,1 трлн сўм), бироқ кичик бизнес улуши 2024 йилдан бошлаб кескин ортгани (180 млрддан 482 млрдга) диққатга сазовор. Стратегия: кичик бизнеснинг бундай «сакраши» (3 баробар) туманда тадбиркорлик муҳити яхшиланганини билдиради. Бу динамикани сақлаб қолиш учун кичик саноат зоналари инфратузилмасини кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (381, 10, 4, 1, '1', 'Маҳаллий бюджет динамикаси', 'Даромадлар ҳажми (млрд сўм)', '2021: 27,6 | 2022: 52,6 | 2023: 63,9 | 2024: 48,8 | 2025: 90,5 (млрд сўм)', TRUE, 'Туман молия бўлими', 'Маҳаллий бюджет даромадлари 5 йил ичида 3 баробардан зиёд ошган. 2025 йилги прогноз (90,5 млрд сўм) режалаштирилган контингентдан (80,2 млрд сўм) юқорилиги солиқ тушумларининг кутилганидан кўпроқ бўлишини англатади. Стратегия: бюджетнинг қўшимча даромадларини ҳудуднинг логистика ва йўл инфратузилмасига йўналтириш юк айланмасини (3,4 млн тонна) янада оширишга хизмат қилади. Бу эса ўз навбатида туманнинг транзит салоҳиятини кенгайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (382, 10, 5, 1, '1', 'Ажратилган кредитлар', 'Банк кредитлари ҳажми ва тақсимоти', 'Жами: Маълумот мавжуд эмас', TRUE, 'SQB', 'Ажратилган кредитлар бўйича маълумот ҳозирча тўпланмоқда. Маълумот тайёр бўлгандан кейин янгиланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (383, 10, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Рақамли қизиқиш индекси (0-100 балл)', 'Жами: Google Trends таҳлили | 2025 йил ҳолати: 72 балл (100 дан) — юқори фаоллик | Динамика: +44 балл (+157,1% ўсиш) | Асосий қидирувлар: Қўнғирот саноат, Инвестиция имкониятлари, Нефть-газ лойиҳалари, Қўнғирот логистика', TRUE, 'Google Trends', '72 балл — бу жуда юқори иқтисодий фаоллик индекси. Қўнғирот туманининг рақамли макондаги қизиқиши 2021 йилга нисбатан 1,5 баробар ошган. Тавсия: туманнинг экспорт ва саноат салоҳиятини хорижий тилларда ҳам тарғиб қилиш орқали қидирув қамровини кенгайтириш ва тўғридан-тўғри хорижий инвестицияларни жалб қилиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (384, 10, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолининг тоза ичимлик суви билан таъминланиш динамикаси (%)', '2021: 85 | 2022: 87 | 2023: 90 | 2024: 93 | 2025: 95 (%)', TRUE, 'Сув хўжалиги бўлими', 'Қўнғирот тумани ичимлик суви таъминоти бўйича республикадаги энг юқори кўрсаткичлардан бирига (95%) эга. 5 йил ичида ўсиш +10% ни ташкил этган. Стратегия: эндиги асосий эътиборни сув сифатини назорат қилиш ва сув қувурларининг техник ҳолатини рақамли мониторинг (Smart Water) қилишга қаратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (385, 10, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Йўл инфратузилмаси ҳолати', 'Жами: Йўл инфратузилмаси | Умумий йўллар узунлиги: 1 332,5 км | Темир йўл станциясигача масофа: 0,5 км | Асфальтланган йўллар: 746,1 км (тахминан 56%)', TRUE, 'Йўл хўжалиги бўлими', 'Темир йўл станциясининг туман марказига жуда яқинлиги (500 метр) логистика учун улкан устунлик беради. Тавсия: юк айланмаси юқорилигини (3,4 млн тонна) инобатга олиб, ички йўлларнинг юк кўтариш қобилиятини ошириш ва станция атрофида замонавий транспорт-логистика хабларини ташкил этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (386, 10, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Тизимдаги муаммолар ва модернизация эҳтиёжи', 'Жами: Электр инфратузилмаси | Электр узилишлари: ойига ўртача 1,8 марта (паст, ижобий) | Трансформаторлар: 50% эскирган | Электр линиялари: 58% алмаштирилиши керак', TRUE, 'Электр тармоқлари корхонаси', 'Узилишлар сони кам бўлса-да, тармоқнинг ярмидан кўпи (50-58%) модернизацияга муҳтож. Бу саноат ҳажми ортиши билан (2025 йилда 1,6 трлн сўм) тизимга оғирлик қилиши мумкин. Тавсия: давлат дастурлари доирасида трансформатор паркини янгилашни тезлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (387, 10, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Ҳудудий тақсимот ва ер ресурслари (га)', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 7 599 581 гектар | Суғориладиган ер майдони: 38 675 гектар | Суғориш каналлари бетонлашиши: 32,4% | Аҳоли зичлиги: 0,54 киши/км²', TRUE, 'Кадастр агентлиги', 'Ҳудуднинг катталиги ва аҳоли зичлигининг пастлиги (0,54 киши/км²) тоғ-кон ва йирик саноат лойиҳалари учун қулай. Тавсия: каналларнинг бетонлашишини (32%) ошириш орқали 38,7 минг гектар суғориладиган ерда сув исрофини камайтириш ва аграр драйверни кучайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (388, 10, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Мобиллик ва транспорт кўрсаткичлари', 'Жами: Транспорт ва алоқа | Йўловчи ташиш: йилига 7,9 млн киши | Юк ташиш: йилига 3,4 млн тонна | Интернет қоплами: 97,4% / 1 Гбит/с', TRUE, 'Туман статистика бўлими', 'Интернет қоплами ва тезлиги (1 Гбит/с) идеал даражада. Бу жамоат транспортини рақамлаштириш, онлайн чипталар ва йўналишларни GPS орқали кузатиш тизимини 100% жорий этиш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (389, 10, 12, 2, '2', 'Мактабгача таълим қамрови', 'Болаларни боғчаларга қамраб олиш даражаси (%)', '2021: 88,6 | 2022: 90,5 | 2023: 87,0 | 2024: 93,2 | 2025: 91,2 (%)', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Қўнғирот туманида мактабгача таълим қамрови республика ўртача кўрсаткичларидан анча юқори ва барқарор (90% атрофида) сақланиб қолмоқда. 2023 йилдаги бироз пасайишдан сўнг, 2024 йилда кўрсаткич рекорд даражага (93,2%) етган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (390, 10, 13, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурслари, банд аҳоли ва маош динамикаси', '2021: 72,3 | 2022: 72,5 | 2023: 73,2 | 2024: 73,8 | 2025: 74,8 (минг киши)', TRUE, 'Бандлик маркази / Статистика бўлими', 'Меҳнат ресурслари 5 йил ичида барқарор ўсиб, иш ҳақи миқдори 68% га ошган (3 237,7 дан 5 437,1 минг сўмга). Бу саноат драйверларининг ижобий таъсирини кўрсатади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (391, 10, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Расмий ва норасмий бандлик динамикаси', 'Жами: Бандлик таҳлили | Расмий рўйхатдагилар (2025): 29 441 киши (2021: 25 256 → 2025: 29 441) | Норасмий бандлик (2025): 14 116 киши (2021: 13 987 → 2025: 14 116) | Солиқ йўқотиш: йиллик ~13 млрд сўм', TRUE, 'Бандлик маркази / Давлат солиқ қўмитаси', 'Норасмий секторда 14,1 минг кишининг мавжудлиги бюджет учун йиллик 13 млрд сўм солиқ йўқотишини англатади. Уларни легаллаштириш асосий имкониятдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (392, 10, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик, ишсизлар сони ва қайтган мигрантлар динамикаси', '2021: 9,9 | 2022: 9,6 | 2023: 7,4 | 2024: 6,0 | 2025: 4,6 (%)', TRUE, 'Бандлик маркази', 'Ишсизлик даражаси 5 йил ичида 2 баробардан кўпроққа камайган (9,9% дан 4,6% га). Қайтган мигрантларни (2025: 2 435 киши) қайта ўқитиш ва бандлигини таъминлаш асосий вазифа бўлиб қолмоқда.', 3064, 4.6, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (393, 10, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони динамикаси', '2021: 18,2 | 2022: 16,3 | 2023: 13,5 | 2024: 9,1 | 2025: 3,2 (%)', TRUE, 'Статистика бўлими / МФЙ', 'Камбағаллик даражаси 18,2% дан 3,2% гача тушиши кескин ижобий натижа. Қолган 1 086 та оилани микрокредит ва субсидиялар орқали қамраб олиш зарур.', 1086, 3.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (394, 10, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва рақамли имкониятлар', 'Жами: Ёшлар бандлиги кўрсаткичлари | Ёшлар ишсизлиги (2025): 1 661 киши | Ёшлар саноат ва тадбиркорлик зонаси: 1 та | Интернет тезлиги: 1 Гбит/с | Интернет қоплами: 97,4%', TRUE, 'Бандлик маркази / Ёшлар агентлиги', 'Ёшларнинг юқори интернет тезлигидан фойдаланиб IT-сервис соҳасига йўналиши уларнинг даромадини 2 баробарга ошириши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (395, 10, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлов', 'Жами: Аёллар бандлиги кўрсаткичлари | Аёллар ишсизлиги (2025): 1 425 киши | Бола нафақаси олувчи оилалар: 3 091 та | Ногиронлиги бўлган банд аҳоли: 8 441 киши', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя', 'Аёллар учун касаначилик ва кичик бизнес лойиҳаларини кўпайтириш, ишсиз 1 425 нафар аёлни банд қилишнинг энг самарали йўлидир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (396, 10, 19, 3, '3', 'Қўнғирот туманидаги техникумлар', 'Профессионал таълим ва касбга йўналтириш самарадорлиги', 'Жами: 1 760 нафар ўқувчи | Муассасалар сони: 2 та техникум | Жами ўқувчилар: 1 760 нафар | Ёшлар ишсизлиги: 1 661 нафар | Қайтган мигрантлар: 2 435 нафар', TRUE, 'Бандлик маркази / Туман ҳокимияти', 'Туманда 2 та техникумда 1 760 нафар ўқувчи таҳсил олаётгани — ҳудуднинг йирик саноат салоҳияти (нефть-газ ва кимё) учун мустаҳкам пойдевордир. Ишсиз ёшлар сони (1 661 нафар) техникумлардаги ўқувчилар сонига деярли тенглиги таълим ва меҳнат бозори ўртасида кучли мутаносиблик яратиш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (397, 10, 20, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Туманда бошқарув ва хизмат кўрсатиш жараёнларини СИ орқали оптималлаштириш', 'Жами: «Digital Kung''irot» СИ дастури | Тадбир: ҳар чоршанба — СИ ўқув куни | Қамров: банк ходимлари ва ҳокимият мутахассислари | Инновация: маҳаллий муаммоларни СИ таҳлили орқали ечиш тизими', TRUE, 'SQB / Туман ҳокимияти', 'Туман ходимларининг рақамли саводхонлигини ошириш саноат соҳасидаги катта ҳажмли маълумотларни (Big Data) қайта ишлаш имконини беради. Кейинги босқичда СИ ёрдамида туманнинг экспорт прогнозларини автоматик шакллантириш модулини жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (398, 10, 21, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Қўнғирот тумани сектор раҳбарлари ва банк бошқарувчилари учун интенсив курслар', 'Жами: 4 босқичли таълим модели | Стратегия: Ҳоким ва ўринбосарлари — ҳудудий ривожланишни СИ орқали моделлаштириш | Таҳлил: Банк раҳбарлари — нефть-газ ва кимё лойиҳалари учун СИ-скоринг | Хизмат: Маҳалла банкирлари — 1 Гбит/с тезликдаги интернетдан фойдаланиб онлайн хизмат | Назорат: МФЙ раислари — «Рақамли маҳалла» ҳисобот тизими', TRUE, 'SQB / Рақамли технологиялар вазирлиги', 'Раҳбарларни ўқитишда асосий урғуни Қўнғиротнинг юқори интернет инфратузилмасидан фойдаланишга қаратиш лозим. Бу қарор қабул қилиш тезлигини 3 баробарга оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (399, 10, 22, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Қўнғирот аҳолисини СИ платформаси ёрдамида замонавий касбларга йўналтириш', 'Жами: 2026 йил режаси | Мақсад: 1 100 нафар ишсиз ва мигрантларни СИ орқали профиллаш | СИ-диагностика: мурожаатчининг саноат ёки хизмат кўрсатишга мойиллигини аниқлаш | Натижа: тайёр бизнес-лойиҳа + имтиёзли кредит таклифи', TRUE, 'Бандлик маркази / SQB', 'Қайтган мигрантлар (2 435 нафар) учун СИ-платформа орқали «Техник қайта тайёрлаш» дастурини йўлга қўйиш лозим. Бу уларнинг норасмий бандликдан расмий секторга ўтишини тезлаштиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (400, 10, 23, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Қўнғиротлик тадбиркорлар ва маҳалла еттилиги учун интеллектуал тизим', 'Жами: SQB AI Advisor имкониятлари | Бизнес-инкубатор: кимё ва қурилиш материаллари соҳасида автоматик бизнес-режалар | Маркет-аналитик: туманнинг экспорт салоҳиятини ҳисобга олган бозор таҳлили | Молиявий консалтинг: кредит олиш имкониятларини 1 дақиқада ҳисоблаш', TRUE, 'SQB', '«SQB AI Advisor» орқали туманнинг 18 та минерал туз конлари атрофида кичик лойиҳаларни генерация қилиш ва тадбиркорларга тайёр кейс сифатида тақдим этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (401, 10, 24, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида иқтисодий ўсишни бошқарувчи тармоқлар', 'Жами: 3 та драйвер сектор | Хизматлар: транспорт ва халқаро йўл бўйи сервиси | Ишлаб чиқариш: кимёвий хом ашёни қайта ишлаш | Чорвачилик: яйлов ресурсларидан фойдаланиш (1,7 млн га)', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни туманнинг кучли томони бўлган халқаро транспорт йўли билан боғлаш керак. Хизмат кўрсатиш соҳасида «Ақлли логистика» тизимини жорий этиш ва чорвачиликда сув танқислиги сабабли интенсив технологияларни қўллаш орқали самарадорликни 2 баробар ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (402, 10, 25, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', '2026 йил учун инвестиция ва бандлик дастури', 'Жами: 2026 йил режаси | Микролойиҳалар сони: 390 та | Янги иш ўринлари: 250 та (100 кунлик режа доирасида) | Маҳаллий банкирлар: 3 нафар (1 аёл, 2 эркак)', TRUE, 'SQB / Туман ҳокимияти', '390 та микролойиҳани амалга ошириш учун ҳар бир маҳаллий банкирга юклама юқори. Тавсия: «SQB AI Advisor» платформаси орқали лойиҳаларни скоринг қилиш ва бизнес-режаларни автоматлаштириш орқали жараённи тезлаштириш лозим. Асосий урғуни 18% гина ишлатилаётган табиий ресурсларни қайта ишлашга қаратиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (403, 10, 26, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Ижтимоий-иқтисодий аҳволи оғир бўлган ҳудудлар', 'Жами: 7 та оғир тоифадаги маҳалла | Фокус: манзилли бандлик ва 100 кунлик ҳаракат режаси', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 7 та маҳаллани «Енгил» тоифага ўтказиш учун «Маҳалла драйвери» тизимидан фойдаланиш керак. Бу ҳудудларда кичик саноат зоналарини ташкил этиш ва аҳолини Ҳамроҳ дастури орқали тадбиркорликка жалб қилиш, ишсизлик даражасини йил якунигача 3-4% га тушириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (404, 10, 27, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Қишлоқ хўжалиги ва кичик бизнесни молиялаштириш', 'Жами: Оилавий тадбиркорлик салоҳияти | Қишлоқ хўжалиги ҳажми (2025): 1 242,4 млрд сўм | Фермер кластерлари: 2 та | Яйлов ресурси: 1,7 млн гектар', TRUE, 'Марказий банк / Қ/х бўлими', 'Дастур доирасида маблағларни туманнинг заиф томони бўлган сув танқислигини камайтирувчи технологияларга (томчилатиб суғориш) йўналтириш лозим. Шунингдек, яйловларда чорвачиликни ривожлантириш учун оилавий микро-фермаларни ташкил этиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (405, 10, 28, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Аёллар бандлигини ошириш ва молиявий қўллаб-қувватлаш', 'Жами: Аёллар тадбиркорлиги дастури | Масъул банкир: 1 нафар аёл банкир | Мақсад: хотин-қизлар орасидаги ишсизликни камайтириш', TRUE, 'SQB / Марказий банк', 'Қўнғиротда аёллар бандлигини таъминлаш учун ҳунармандчилик ва кичик хизмат кўрсатиш соҳаларида (7 та маҳалла ихтисослашган) «HAMROH» кредитидан фойдаланиш керак. Аёл банкир бошчилигида маҳаллаларда «Тадбиркор аёллар клуби»ни ташкил этиш орқали лойиҳалар сифатини ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (406, 10, 29, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', '100 кунлик тезкор ҳаракат дастури', 'Жами: 100 кунлик режа | Янги иш ўринлари: 250 та | Янги лойиҳалар: 100 та | Экспорт ўсиши: +10%', TRUE, 'SQB / Туман ҳокимияти', 'Ишсизлик юқори бўлган 7 та оғир маҳаллани ҳоли ҳудудга айлантириш учун чегара ҳудудидаги саноат зонаси имкониятларидан фойдаланиш зарур. Бу ҳудудларда ишлаб чиқарилган маҳсулотларни экспортга йўналтириш орқали ҳам бандлик, ҳам валюта тушуми таъминланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (407, 10, 30, 5, '5', 'Кимё ва газ-кимё кластери', 'Тайёр полимер ва кимёвий маҳсулотлар ишлаб чиқариш йўналиши', 'Жами: Кимёвий хаб салоҳияти | Хомашё базаси: «Устюрт ГКМ» (Surgil) ва «Қўнғирот сода заводи» яқинлиги | Имконият: полиэтилен ва сода асосида маиший кимё, пластик буюмлар ва шиша маҳсулотлари | Инвестиция салоҳияти: $50–150 млн', TRUE, 'Иқтисодиёт ва молия вазирлиги', 'Қўнғиротни нафақат хомашё етказувчи, балки тайёр маҳсулот ишлаб чиқарувчи «Кимёвий хаб»га айлантириш лозим. Саноат зоналарида кичик ва ўрта бизнес учун хомашёга тўғридан-тўғри квоталар ажратиш самара беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (408, 10, 31, 5, '5', 'Халқаро транспорт-логистика маркази', 'А-380 халқаро трассаси ва темир йўл кесишмаси — логистика қуввати', 'Жами: Транспорт-логистика салоҳияти | Стратегик жойлашув: Шимолий дарвоза (Қозоғистон орқали Россия ва Европага чиқиш) | Лойиҳа: «Қуруқ порт» ва божхона терминали | Хизмат экспорти: юк ташиш ва омборхона хизматлари', TRUE, 'Транспорт вазирлиги', 'Йўл бўйи инфратузилмасини (Truck Stop) халқаро стандартларга келтириш керак. Ҳайдовчилар ва экспедиторлар учун замонавий сервис марказларини қуриш орқали хизмат кўрсатиш соҳасини 25% га ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (409, 10, 32, 5, '5', 'Қайта тикланувчи энергия (Шамол ва Қуёш)', 'Устюрт текислигидаги доимий шамол оқими — яшил энергия потенциали', 'Жами: Яшил энергия салоҳияти | Кўрсаткич: 320+ кун шамолли ва қуёшли давр | Йўналиш: йирик шамол электр станциялари (WPP) | Инвестиция: $100 млн+ (хорижий инвесторлар ҳисобига)', TRUE, 'Энергетика вазирлиги', 'Устюрт кенгликларидан «Яшил энергия» ишлаб чиқаришда фойдаланиш, бу нафақат туманни, балки қўшни ҳудудларни ҳам арзон энергия билан таъминлашга хизмат қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (410, 10, 33, 5, '5', 'Экстремал ва Экотуризм', 'Орол денгизи қирғоқлари, Устюрт каньонлари, Барсакелмес', 'Жами: Экотуризм салоҳияти | Объектлар: Орол денгизи, Устюрт каньонлари, Барсакелмес | Йўналиш: «Off-road» турлар, кемпинг ва астротуризм (юлдузларни кузатиш) | Потенциал: йиллик 50 000+ хорижий экстремал сайёҳ', TRUE, 'Туризм қўмитаси', '«Орол денгизига йўл» брендини кучайтириш. Мўйноқ билан интеграциялашган ҳолда Устюрт платосида эко-меҳмонхоналар ва Глэмпинглар тармоғини ташкил этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (411, 10, 34, 5, '5', 'Қурилиш материаллари саноати', 'Оҳактош, кварц қуми ва минерал туз конлари — қурилиш кластери', 'Жами: Қурилиш материаллари салоҳияти | Ресурс: оҳактош, кварц қуми ва минерал туз конлари | Имконият: ойна, қуруқ қурилиш аралашмалари ва иссиқлик сақловчи плиталар | Лойиҳа: 10 га майдонда «Қурилиш материаллари кластери»', TRUE, 'Геология қўмитаси', 'Маҳаллий хомашёдан фойдаланиб, экспортга йўналтирилган энергия тежовчи қурилиш материаллари ишлаб чиқаришни йўлга қўйиш, логистика харажатлари пастлиги ҳисобига рақобатбардошликни таъминлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (412, 10, 35, 5, '5', 'Агротехнология ва чорвачилик', 'Катта ер майдонлари ва яйловлар — чорвачилик ва агротехнология салоҳияти', 'Жами: Агро салоҳият | Ресурс: катта ер майдонлари ва яйловлар | Йўналиш: туячилик ва терини қайта ишлаш | Технология: шўрланишга чидамли экинлар ва гидропоника', TRUE, 'Қишлоқ хўжалиги вазирлиги', 'Туя сути (қимиз) ва юнгини қайта ишлаш бўйича кичик корхоналар очиш. Бу чўл шароитида аҳоли бандлигини таъминлашнинг энг оптимал йўлидир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (413, 10, 36, 6, '6', 'Стратегик хулоса: Қўнғирот – 2030', 'Концепция: «Саноат ва Логистика маркази»', 'Жами: Қўнғирот — Ўзбекистоннинг шимолий иқтисодий қалқони | Хулоса: кимё саноати ва транзит имкониятлари туманни яқин 5 йилда вилоятдаги энг йирик донорга айлантириши мумкин | Асосий драйвер: газ-кимё ва логистика уйғунлиги', TRUE, 'SQB', 'Туман иқтисодиётини диверсификация қилиш учун фақат хомашёга боғланиб қолмай, хизмат кўрсатиш ва юқори технологияли ишлаб чиқаришни (IT-логистика) ривожлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (414, 10, 37, 6, '6', '«Йўл харитаси» – Биринчи босқич (2026)', 'Инфратузилма ва рақамлаштириш мақсадлари', 'Жами: 2026 йил биринчи босқич | Логистика: А-380 трассаси бўйича 3 та замонавий сервис мажмуасини ишга тушириш | Энергетика: корхоналарнинг 30% қисмини қуёш панелларига ўтказиш | Таълим: кимё ва логистика бўйича профессионал кадрлар тайёрлаш марказини очиш', TRUE, 'Хокимият', 'Биринчи босқичда 3 та устувор йўналишга эътибор қаратиш керак: логистика инфратузилмаси, яшил энергетика ва кадрлар тайёрлаш. Бу учлик бирга ишлаганда синергия эффекти пайдо бўлади — замонавий сервис марказлари янги иш ўринлари яратади, қуёш энергияси таннархни пасайтиради, малакали кадрлар эса барча лойиҳаларнинг сифатини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (415, 10, 38, 6, '6', 'Кутилаётган натижалар (KPI)', 'Прогноз кўрсаткичлари — 2027 йил якунигача', 'Жами: 2027 йил KPI мақсадлари | ЯҲМ ўсиши: +12–15% йиллик | Янги иш ўринлари: 5 000 та (асосан ёшлар ва хотин-қизлар учун) | Инвестиция ҳажми: $500 млн (тўғридан-тўғри хорижий инвестициялар)', TRUE, 'SQB', 'Ушбу мақсадларга эришиш учун «Инвесторлар учун очиқ эшиклар» тизимини яратиш ва бюрократияни минималлаштириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (416, 10, 39, 6, '6', 'Хавф-хатарларни бошқариш', 'Сув тақчиллиги ва экология — асосий муаммо ва ечимлар', 'Жами: Экологик хавф-хатарлар | Муаммо: сув тақчиллиги ва экология | Ечим: сув тежовчи технологияларни 100% жорий этиш ва «Яшил белбоғ» лойиҳасини кенгайтириш (Саксовул экиш)', TRUE, 'Хокимият', 'Экологик барқарорлик — иқтисодий ўсишнинг асоси бўлиши керак. Ҳар бир йирик лойиҳа экологик экспертизадан ўтиши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
