INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (36, 11, 'Хонадон', 9674, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (417, 11, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат ҳажми ва ташқи савдо динамикаси', 'Жами: 2025 йил кўрсаткичлари | Саноат ҳажми: 2021: 356,4 → 2022: 332,6 → 2023: 431,0 → 2024: 443,2 → 2025: 548,3 (млрд сўм) | Экспорт (2024): 13 872,3 минг $ | Импорт (2024): 3 265,7 минг $ | Ташқи савдо сальдоси: +10,6 млн $ (ижобий)', TRUE, 'Статистика ва Савдо-саноат палатаси', 'Туман иқтисодиётида экспорт ҳажми импортдан қарийб 4 баробар кўплиги жуда ижобий кўрсаткич. Саноат ҳажми 2025 йилда 548,3 млрд сўмга етиши прогноз қилинмоқда. Тавсия: экспортнинг асосий қисми тўқимачиликка тўғри келишини инобатга олиб, маҳсулот турини диверсификация қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (418, 11, 2, 1, '1', 'Туман иқтисодиётининг драйверлари', 'Асосий ўсиш нуқталари ва бандлик тақсимоти', 'Жами: 3 та драйвер | 1-устувор: Тўқимачилик (саноат пойдевори) | 2-устувор: Қишлоқ хўжалиги (бандликнинг асосий манбаи) | 3-устувор: Озиқ-овқат маҳсулотлари ишлаб чиқариш | Бандлик: Қ/х 9,3 минг, Хизмат 3,4 минг, Саноат 2,5 минг киши', TRUE, 'Туман ҳокимияти / Бандлик маркази', 'Қишлоқ хўжалигида бандлик юқори (9,3 минг киши), лекин ЯҲМ таркибида хизматлар улуши 63,4% ни ташкил этади. Тавсия: қишлоқ хўжалиги маҳсулотларини чуқур қайта ишлаш (агрокластерлар) орқали саноатдаги бандликни ва қўшилган қийматни ошириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (419, 11, 3, 1, '1', 'Саноат ишлаб чиқариш динамикаси', 'Саноат ишлаб чиқариш индекси ва корхоналар кесими', 'Жами: Саноат таҳлили | Саноат индекси: 2021: 104,0% → 2022: 96,0% (пасайиш) → 2023: 102,8% → 2024: 100,8% → 2025: 109,4% | Йирик корхоналар (2025): 328,1 млрд сўм | Кичик бизнес (2025): 220,1 млрд сўм', TRUE, 'Туман статистика бўлими', '2022 йилдаги пасайишдан сўнг саноат тикланиш босқичига кирди. 2025 йилда кичик бизнеснинг улуши кескин ортиши (220,1 млрд) кутилмоқда. Тавсия: кичик бизнес субъектларини тўқимачилик кластерлари атрофида кооперация асосида ривожлантириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (420, 11, 4, 1, '1', 'Маҳаллий бюджет', 'Бюджет даромадлари динамикаси (млрд сўм)', '2021: 7,4 | 2022: 13,1 | 2023: 14,0 | 2024: 14,1 | 2025: 27,8 (млрд сўм)', TRUE, 'Туман молия бўлими', '2025 йилда маҳаллий бюджет даромадлари икки баробар (14,1 дан 27,8 га) ошиши прогноз қилинмоқда. Бу солиқ базасининг кенгайишини англатади. Тавсия: бюджет тушумларининг барқарорлигини таъминлаш учун солиқ имтиёзлари берилган корхоналарнинг самарадорлигини мониторинг қилиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (421, 11, 5, 1, '1', 'Ажратилган кредитлар (кичик бизнес)', 'Кичик тадбиркорликка ажратилган кредитлар динамикаси', '2021: 80 | 2022: 120 | 2023: 150 | 2024: 200 | 2025: 250 (млрд сўм)', TRUE, 'SQB', 'Кредитлаш ҳажмининг барқарор ўсиши (йиллик ўртача 25-30%) туманда тадбиркорлик фаоллиги ошаётганидан далолат беради. Бироқ, корхоналар демографиясидаги ёпилиш кўрсаткичларини инобатга олган ҳолда, кредитларни нафақат миқдор жиҳатидан кўпайтириш, балки уларнинг самарадорлигини (ROI) назорат қилиш зарур. Тавсия: кредит олган тадбиркорларга «Бизнес-инкубатор» хизматларини кўрсатиш орқали уларнинг фаолиятини ёпилиб кетишдан ҳимоя қилиш ва кредитларнинг қайтувчанлигини таъминлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (422, 11, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Рақамли фаоллик индекси (0-100 балл)', 'Жами: Google Trends таҳлили | 2025 йил ҳолати: 54 балл (100 дан) — ўртача фаоллик | 2024 йил ўртача: 48 балл | 2025 йил ўртача: 54 балл (+12,5% ўсиш) | Асосий қидирувлар: Текстиль корхоналари, Иш ўринлари, Тадбиркорлик кредитлари', TRUE, 'Google Trends', 'Рақамли фаоллик индексининг ошиши аҳоли ва бизнеснинг интернет орқали иқтисодий имкониятларни қидириши ортганини билдиради. Тавсия: тўқимачилик ва озиқ-овқат маҳсулотларини сотиш учун маҳаллий тадбиркорларга электрон тижорат (E-commerce) майдончаларидан фойдаланишни ўргатиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (423, 11, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Таъминот даражаси динамикаси (%)', '2021: 80,3 | 2022: 82,2 | 2023: 83,4 | 2024: 86,6 | 2025: 86,6 (%)', TRUE, 'Сув хўжалиги бўлими', 'Ичимлик суви таъминоти 5 йил ичида 6,3% га яхшиланган ва республика бўйича ижобий кўрсаткичлардан бирига эга. Бироқ, 2024-2025 йилларда ўсиш тўхтаган. Тавсия: қамровни 90% дан ошириш учун чекка овулларда кичик локал сув тозалаш иншоотларини қуриш ва мавжуд тизимни рақамлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (424, 11, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Йўл инфратузилмаси ҳолати', 'Жами: Йўл инфратузилмаси | Умумий йўллар узунлиги: 470,1 км | Асфальтланган йўллар улуши: 85,4% | Вилоят марказигача масофа: 80 км | Темир йўл станциясигача масофа: 0,5 км', TRUE, 'Йўл хўжалиги бўлими', 'Қонлиқўл йўлларнинг асфальтланиш даражаси (85,4%) бўйича юқори кўрсаткичга эга. Энг катта афзаллик — темир йўл станциясининг туман марказига жуда яқинлиги (500 метр). Тавсия: темир йўл яқинида «Қурилиш материаллари логистика маркази»ни ташкил этиш орқали мавжуд йўл инфратузилмасидан фойдаланиш самарадорлигини ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (425, 11, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Тизим барқарорлиги ва модернизация ҳолати', 'Жами: Электр инфратузилмаси | Ойига ўртача узилишлар: 1,2 марта | Трансформаторлар: 100% соз (эскирганлари йўқ) | Линияларни алмаштириш эҳтиёжи: 12,4% (паст) | Газ билан таъминланганлик: 98,7%', TRUE, 'Электр тармоқлари корхонаси', 'Электр таъминоти тизими республикадаги энг намунали ҳолатлардан бирида: трансформаторлар янгиланган ва узилишлар минимал. Тавсия: ушбу барқарор энергия тизимидан фойдаланиб, туманда энергия талаб қиладиган ишлаб чиқариш қувватларини (масалан, совутиш омборхоналари) кўпайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (426, 11, 10, 2, '2', 'Ер тоифалари ва ресурслар', 'Ресурс базаси ва фойдали қазилмалар', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 74 409 гектар | Суғориладиган ер майдони: 33 144 гектар | Аҳоли зичлиги: 74,1 киши/км² | Суғориш каналлари бетонланиши: 67% | Фойдали қазилмалар: 2 та лёссимон жинслар (ғишт хомашёси) кони', TRUE, 'Кадастр агентлиги / Геология', 'Туман суғориш тизими яхши бетонланган (67%), бу сув тежаш имконини беради. Ер майдони кенг ва аҳоли зичлиги пастлиги катта саноат лойиҳалари учун қулай. Тавсия: мавжуд 1 085 минг куб метр лёссимон жинслар захираси асосида пишиқ ғишт ва қурилиш материаллари ишлаб чиқаришни кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (427, 11, 11, 2, '2', 'Жамоат транспорти ва коммуникация', 'Интернет, канализация ва алоқа сифати', 'Жами: Коммуникация таҳлили | Интернет қоплами: 65% | Интернет тезлиги: 25 Мбит/с | Канализация тармоғи: 2,2% (жуда паст)', TRUE, 'Алоқа компаниялари / Коммунал хизмат', 'Туманнинг энг заиф нуқтаси — канализация тизими (2,2%) ва интернет қоплами (65%). Тавсия: урбанизация даражасини ошириш учун марказий канализация тизимини қуриш бўйича давлат-хусусий шериклик лойиҳаларини ишлаб чиқиш ва интернет қопламини 4G/5G станциялари ҳисобига кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (428, 11, 12, 2, '2', 'Мактабгача таълим қамрови', '3 645 нафар бола қамраб олинган (81%, 2025 йил)', '2021: 68 | 2022: 74 | 2023: 76 | 2024: 79 | 2025: 81 (%)', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', 'Қамровнинг 81% га етиши ижобий натижа, бироқ қолган 19% болаларни қамраб олиш учун давлат-хусусий шериклик асосидаги нодавлат МТМларни кўпайтириш лозим. Чекка маҳаллаларда оилавий МТМларни қўллаб-қувватлаш ва боғча ёшидаги болаларнинг интеллектуал салоҳиятини ошириш учун МТМларда СИ ёрдамида ишлайдиган интерфаол таълим ўйинларини жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (429, 11, 13, 3, '3', 'Меҳнат ресурслари', 'Аҳоли, меҳнат ресурслари ва маош динамикаси', 'Жами: Меҳнат бозори таҳлили | Аҳоли (2025): 54,8 минг киши | Меҳнат ресурслари: 2021: 19,37 → 2025: 16,94 (минг киши) | Ўртача маош (2025): 4 007,1 минг сўм | Маҳаллалар: 11 та | Оилалар: 10 787 та | Хонадонлар: 9 674 та', TRUE, 'Статистика бўлими ва Бандлик маркази', 'Аҳоли сони ўсаётган бир шароитда меҳнат ресурсларининг камайиши (19,3 мингдан 16,9 мингга) кузатилмоқда. Бу аҳолининг қариши ёки миграция белгиси бўлиши мумкин. Иш самарадорлигини ошириш учун рақамли технологияларни жорий этиш ва қолган ресурсни юқори даромадли соҳаларга қайта ўқитиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (430, 11, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Расмий ва норасмий бандлик динамикаси', 'Жами: Бандлик таҳлили | Банд аҳоли (2025): 10 180 киши (2021: 8 143 → 2025: 10 180) | Норасмий секторда бандлик: 5 215 киши | Солиқ йўқотиши: йилига 5 млрд сўм', TRUE, 'Бандлик маркази / Давлат солиқ қўмитаси', 'Банд аҳоли сонининг 2024 йилдан бошлаб ўсиши (9,4 минг) ижобий суръат. Норасмий сектордаги 5,2 минг кишини «ўзини-ўзи банд қилиш» орқали легаллаштириш бюджет тушумини кескин оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (431, 11, 15, 3, '3', 'Ишсизлик кўрсаткичлари', '906 нафар ишсиз (5,3%)', '2021: 10,1 | 2022: 9,3 | 2023: 7,5 | 2024: 5,8 | 2025: 5,3 | 2026: 4,9 (%)', TRUE, 'Бандлик маркази', 'Ишсизликни 2021 йилдаги 10,1% дан 2025 йилда 5,3% гача тушириш прогноз қилинган. Бунга эришиш учун асосий эътиборни ишсиз аёлларга (528 киши) қаратиш ва уларни касаначиликка жалб қилиш лозим.', 906, 5.3, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (432, 11, 16, 3, '3', 'Камбағаллик кўрсаткичлари', '1 543 та кам таъминланган оила (6%)', 'Жами: Камбағаллик кўрсаткичлари | Камбағаллик даражаси (2025): 7,5% | Камбағал оилалар: 1 543 та | Камбағаллик тренди: 18% → 14% → 15% → 9% → 7,5% | Мақсад: 2026 йил охиригача 3,6% га тушириш', TRUE, 'Статистика бўлими / МФЙ', 'Камбағалликни 2026 йил охиригача 3,6% га тушириш учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. Ижтимоий ёрдамни иш билан ва микролойиҳалар билан боғлаш, барқарор даромад манбаини яратишга эътиборни қаратиш зарур.', 1543, 7.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (433, 11, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '328 нафар ишсиз ёшлар бандлигини таъминлаш (2026 режа)', 'Жами: 328 нафар ёшлар (2026 режа) | Доимий ишга жойлаштириш: 150 нафар | Тадбиркорликка жалб қилиш: 85 нафар | Кредит ва субсидия ажратиш: 45 нафар | Қайта касбга ўқитиш: 48 нафар', TRUE, 'Бандлик маркази', 'Ёшлар бандлигини таъминлаш учун тумандаги мавжуд бўш ер майдонларидан деҳқончилик учун ажратиш ва рақамли технологиялар (IT) бўйича қисқа муддатли курсларни ташкил этиш орқали масофавий хизматлар (freelance) бозорига кириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (434, 11, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', '528 нафар ишсиз аёлларнинг бандлигини таъминлаш (2026 режа)', 'Жами: 528 нафар аёллар (2026 режа) | Доимий ва мавсумий иш: 320 нафар | Касаначилик ва ҳунармандчилик: 120 нафар | Тадбиркорлик ва касбга ўқитиш: 88 нафар | Ижтимоий ҳимоя: 4 501 та оила қамровида', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя агентлиги', 'Хотин-қизлар бандлигини оширишда туманнинг ҳунармандчилик салоҳиятидан фойдаланиш, «Уста-шогирд» анъаналарини қайта тиклаш ва уйда ўтирган аёллар учун микро-кредитлар ажратиш орқали кичик ишлаб чиқариш цехларини ташкил этиш самара беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (435, 11, 19, 3, '3', 'Коллежлар ва ўқувчилар', 'Касб-ҳунар таълими', 'Жами: Коллеж таълими | Коллежлар сони: 2 та | Ўқувчилар сони: 1 480 та', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Туманда 2 та коллежда 1 480 нафар ўқувчи таҳсил олмоқда. Коллеж битирувчиларини маҳаллий корхоналарга ишга жойлаштириш тизимини кучайтириш ва дуал таълим дастурларини жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (436, 11, 20, 3, '3', 'Техникумлар', 'Касб-ҳунар таълими муассасалари', 'Жами: Касб-ҳунар таълими | Техникумлар сони: 1 та | Ўқувчилар сони: 1 060 та', TRUE, 'Ҳокимият', 'Туманда 1 та техникумда 1 060 нафар ўқувчи таҳсил олмоқда. Ўқувчиларни тумандаги устувор соҳалар (тўқимачилик, қишлоқ хўжалиги) бўйича тайёрлаш ва маҳаллий меҳнат бозорига йўналтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (437, 11, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Маълумотлар таҳлили ва автоматизация — ҳар ойнинг сўнгги жума куни «AI Day»', 'Жами: 3 босқичли СИ ўқитиш тизими | 1-босқич: Маълумотлар билан ишлаш — Excel ва СИ ёрдамида катта ҳажмдаги маълумотларни тезкор таҳлил қилиш | 2-босқич: Жараёнларни автоматлаштириш — кундалик такрорланувчи ишларни СИ га топшириш | 3-босқич: Натижадорлик аудити — СИ ёрдамида бажарилган ишларнинг сифати ва вақт тежалишини баҳолаш', TRUE, 'SQB / Туман ҳокимияти', '«AI Day» фақат назария эмас, балки амалий воркшоп бўлиши керак. Мақсад — ходимларнинг техник кўникмаларини ошириш орқали туман ҳокимияти ва банк тизимидаги қоғозбозликни 30% га камайтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (438, 11, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Раҳбар кадрлар ва банк ходимларининг қарор қабул қилиш тезлигини ошириш учун тизимли СИ таълими', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлари — СИ стратегияси ва маълумотларга асосланган қарорлар | 2-босқич: Банк филиал раҳбарлари — СИ скоринг, рискларни бошқариш ва портфель таҳлили | 3-босқич: Маҳалла банкирлари — СИ платформалари орқали мижозларга тезкор хизмат | 4-босқич: МФЙ раислари — СИ ёрдамида маҳалла маълумотларини таҳлил ва ҳисобот', TRUE, 'SQB / Туман ҳокимияти', 'Раҳбарларни ўқитиш «юқоридан пастга» тамойилида амалга оширилади. Аввал стратегик даражада СИ имкониятлари тушунилади, кейин ижрочилар даражасида техник кўникмалар шакллантирилади. Ҳар бир босқич учун махсус тайёр буйруқлар тўплами яратиш орқали иш самарадорлигини 2 баробарга ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (439, 11, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Ёшлар ва ишсиз аҳолини замонавий технологиялар орқали онлайн даромад топишга ўргатиш', 'Жами: 3 та асосий йўналиш | 1-йўналиш: No-code платформалар — дастурлаш кодларисиз веб-сайтлар ва мобил иловалар яратиш | 2-йўналиш: СИ дизайн ва контент — СИ ёрдамида профессионал реклама ролик ва баннерлар тайёрлаш | 3-йўналиш: SMM ва СИ — ижтимоий тармоқларда бизнесни СИ ботлари орқали бошқариш', TRUE, 'Маҳаллабай ишлаш маркази / SQB', 'Ушбу ўқитиш тизими тумандаги ишсизлик юқори бўлган маҳаллаларда «Рақамли тадбиркорлик» экотизимини яратади. Бу аҳолига ўз уйидан туриб, нафақат Ўзбекистон, балки глобал бозорга хизмат кўрсатиш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (440, 11, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит мослаштириш: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси Қонлиқўл туманидаги маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча маҳаллаларда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (441, 11, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Туман маҳаллаларининг типологияси ва ихтисослашув йўналишлари', 'Жами: 11 та маҳалла | Енгил (яхши): 4 та | Ўрта: 6 та | Оғир: 1 та | Маҳалла-8: деҳқончилик (сабзавот ва полиз) | Маҳалла-1: савдо ва хизмат кўрсатиш | Маҳалла-2: чорвачилик (сут ва гўшт йўналиши)', TRUE, 'МФЙ агентлиги / SQB', 'Маҳаллаларнинг 50% дан ортиғи «ўрта» тоифада эканлиги иқтисодий ўсиш учун катта захира борлигини англатади. Деҳқончилик маҳаллаларида қайта ишлаш даражасининг 0% эканлиги асосий нуқта ҳисобланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (442, 11, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Иқтисодий ўсишни ҳаракатлантирувчи соҳалар', 'Жами: 3 та драйвер сектор | Қишлоқ хўжалиги: пахта ва ғалладан ташқари мева-сабзавотчилик | Чорвачилик: яйлов ерларининг кенглиги (45 000 га) ҳисобига | Ҳунармандчилик: маҳаллий анъанавий ишлаб чиқариш', TRUE, 'МФЙ агентлиги / SQB', 'Маҳалла драйверларини ривожлантиришда 45 минг гектар яйлов ерларидан самарали фойдаланиш учун чорвачилик кластерларини кўпайтириш ва гўштни қайта ишлашни йўлга қўйиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (443, 11, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Микролойиҳалар самарадорлиги', 'Жами: 110 та лойиҳа | Яратилган иш ўринлари: 200 та | Банк маблағлари: 7,7 млрд сўм | Ўртача битта иш ўрни харажати: 38,5 млн сўм', TRUE, 'SQB / Туман ҳокимияти', 'Ажратилган маблағлар (7,7 млрд сўм) ҳажми лойиҳалар сонига нисбатан юқори эмас. Бу кичик оилавий тадбиркорликка урғу берилаётганини кўрсатади. Навбатдаги босқичда лойиҳаларни «кичик»дан «ўрта» бизнесга ўтказиш орқали иш ўринлари барқарорлигини таъминлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (444, 11, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Жорий ҳолат ва бандлик режаси', 'Жами: 1 та оғир тоифадаги маҳалла | Бандлик режаси: 60 та янги иш ўрни яратиш | Лойиҳавий ечим: 3 та янги ишлаб чиқариш лойиҳасини ишга тушириш | Экспорт кутилмаси: маҳалла корхоналари экспортини +25% га ошириш', TRUE, 'МФЙ агентлиги / Бандлик маркази', 'Ишсизлик юқори бўлган маҳаллада 60 та иш ўрни яратиш учун «Ҳар бир оила — тадбиркор» дастури доирасида карам ва картошка етиштиришга ихтисослашган кичик иссиқхоналар ташкил этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (445, 11, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили', TRUE, 'SQB', 'Сунъий интеллектга асосланган «AI Advisor» мавжудлиги сабабли, кредит скоринги ва инвестиция таҳлилини тўлиқ автоматлаштириш керак. Масофавий молиявий амалиётларни кенгайтириш учун мижозларни «Mobile» ва «Business» платформаларига фаол ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (446, 11, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: SQB ва бошқа тижорат банклари | Фоиз ставкаси: 12% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (447, 11, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB ва бошқа тижорат банклари | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Қонлиқўлда аёллар тадбиркорлиги потенциали юқори (тикувчилик, савдо-хизмат, ҳунармандчилик). Тавсия: маҳалла банкирлари орқали аёлларни актив жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (448, 11, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', 'Бостон МФЙда 78 нафар ишсизни бандликка жалб қилиш режаси', 'Жами: 1 та маҳалла, 78 нафар ишсиз | Бостон МФЙ: 78 нафар — аёллар 28, эркаклар 32, ёшлар 18 | Таркиб: ёшлар 23%, аёллар 36%, эркаклар 41% | Кредит маҳсулотлари: Ёшлар бизнесда, Ҳамроҳ (аёллар), Маҳалла лойиҳаси | Ишчилар: 114 нафар (хотин-қизлар 16, ёшлар 22, эркак 98)', TRUE, 'SQB / МФЙ агентлиги', 'Бостон МФЙда ишсизлик даражаси юқори бўлиб, асосий улушни эркаклар (41%) ва аёллар (36%) ташкил қилади. «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (449, 11, 33, 5, '5', 'Қуёш ва шамол энергетикаси', 'Қорақалпоғистоннинг очиқ кенгликлари ва юқори инсоляцияси', 'Жами: Муқобил энергия имкониятлари | 300+ қуёшли кун ва доимий шамол оқими | Йўналиш: гибрид (қуёш+шамол) кичик станциялар | Имконият: сув насослари ва фермер хўжаликларини мустақил энергия билан таъминлаш | Инвестиция: $5–15 млн (пилот лойиҳалар)', TRUE, 'Энергетика вазирлиги / Ҳокимият', 'Қонлиқўлда ер майдони кенг, лекин шўрланиш даражаси юқори ерлардан айнан «яшил энергия» парклари учун фойдаланиш керак. Бу қишлоқ хўжалигида сув чиқариш таннархини 30% гача камайтириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (450, 11, 34, 5, '5', 'Транспорт-логистика «Дарвозаси»', 'А380 халқаро автомагистрали ва темир йўл кесишмаси', 'Жами: Логистика потенциали | Локация: Қўнғирот ва Нукус оралиғидаги стратегик нуқта | Объект: йўл бўйи хизмати (Camping, TIR-park) | Салоҳият: кунига 2–3 минг транзит юкли автомобиллар', TRUE, 'Транспорт вазирлиги', 'Туман орқали ўтувчи А380 трассаси бўйида замонавий логистика маркази ва юк машиналари учун сервис хабини ташкил этиш лозим. Бу фақат «ошхона» эмас, балки омборхона ва тезкор таъмирлаш хизматларини ҳам ўз ичига олиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (451, 11, 35, 5, '5', 'Шўрга чидамли агро-кластерлар', 'Тупроқ иқлимига мос экинлар ва қайта ишлаш', 'Жами: Агро-кластер стратегияси | Ресурс: мия (солодка) ва озуқабоп экинлар | Имконият: хом ашёни қайта ишлаш ва экспорт қилиш | Инновация: томчилатиб суғоришнинг «ақлли» тизимлари', TRUE, 'Қишлоқ хўжалиги вазирлиги', 'Анъанавий пахта ва ғалладан ташқари, Қонлиқўлда мия илдизини саноат усулида қайта ишлаш заводини қуриш керак. Тайёр экстракт хом ашёдан 5-7 баробар қимматроқ сотилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (452, 11, 36, 5, '5', 'Чорвачилик ва терини қайта ишлаш', 'Яйлов чорвачилиги салоҳияти ва қайта ишлаш', 'Жами: Чорвачилик стратегияси | Кўрсаткич: қорамол ва майда шохли моллар сонининг барқарор ўсиши | Лойиҳа: гўшт консерва заводи ва терини бошланғич ишлаш', TRUE, 'Ветеринария қўмитаси', 'Шу вақтгача чорва маҳсулотлари тирик вазнда сотилган бўлса, энди «Қонлиқўл гўшт маҳсулотлари» бренди остида ярим тайёр маҳсулотлар занжирини яратиш вақти келди. Бу маҳаллий аҳоли учун камида 200 та янги иш ўрни демакдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (453, 11, 37, 5, '5', 'Қурилиш материаллари кластери', 'Маҳаллий хом ашё захиралари ва ишлаб чиқариш имкониятлари', 'Жами: Қурилиш материаллари | Хом ашё: қум захиралари | Имконият: ғишт, қуруқ қоришмалар ва бетон маҳсулотлари | Бозор: Нукус ва Қўнғиротдаги қурилиш бумлари учун яқин етказиб берувчи', TRUE, 'Геология қўмитаси', 'Транспорт харажатлари камлиги ҳисобига Қонлиқўлда ишлаб чиқарилган қурилиш материаллари қўшни туманларда рақобатбардош бўлади. Кичик саноат зонасида қурилиш материалларига ихтисослашган технопарк яратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (454, 11, 38, 5, '5', 'Рақамли таълим ва IT-аутсорсинг', 'Ёшлар демографияси ва масофавий иш имкониятлари', 'Жами: IT салоҳияти | Аҳоли: ёшлар улуши 40% дан юқори | Инфратузилма: рақамли технологиялар маркази | Йўналиш: масофавий хизматлар (BPO) ва IT-аутсорсинг', TRUE, 'IT-Park', 'Жисмоний ер ва сув ресурслари чекланган шароитда, «интеллектуал экспорт»га урғу бериш керак. Қонлиқўллик ёшларни масофавий хизматлар (BPO) кўрсатишга ўқитиш орқали туманга валюта тушумини таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (455, 11, 39, 6, '6', 'Стратегик хулоса: «Логистик Хаб ва Агро-Инновация»', 'Туманнинг иқтисодий моделини трансформация қилиш', 'Жами: Стратегик хулоса | Хулоса: Қонлиқўл фақат қишлоқ хўжалиги тумани эмас, балки шимолий йўналишдаги муҳим транзит-хизмат кўрсатиш марказига айланиши керак', TRUE, 'СИ таҳлили', 'Туманнинг иқтисодий барқарорлигини таъминлаш учун «Қишлоқ хўжалиги + Транспорт хизмати + Яшил энергия» триадасини асосий драйвер сифатида қабул қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (456, 11, 40, 6, '6', '2025–2026 йиллар учун «Йўл харитаси»', 'Босқичма-босқич ривожланиш режаси', 'Жами: 3 босқичли режа | 1-босқич: А380 бўйида «Сервис зонаси» учун ер ажратиш ва инвестор жалб қилиш | 2-босқич: Мия ва озуқа экинлари кластерини тўлиқ қувватга чиқариш | 3-босқич: Ижтимоий соҳа ва сув таъминотини рақамлаштириш', TRUE, 'Ҳокимият режаси', 'Босқичма-босқич ёндашув тўғри стратегия. Биринчи навбатда А380 трассаси бўйида сервис зонасини ташкил этиш тезкор даромад манбаи бўлади, кейинги босқичларда агро-кластер ва рақамлаштириш узоқ муддатли барқарорликни таъминлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (457, 11, 41, 6, '6', 'Инвестициявий жозибадорлик', 'Инвесторлар учун таклиф ва имтиёзлар', 'Жами: Инвестиция таклифи | Пакетлар: «Тайёр лойиҳа» тамойили асосида 10 та истиқболли лойиҳа | Имтиёз: Қорақалпоғистон учун белгиланган махсус солиқ ставкалари (1%)', TRUE, 'Инвестициялар, саноат ва савдо вазирлиги', 'Инвесторларни жалб қилишда «кам солиқ ва арзон логистика» аргументидан фойдаланиш керак. Қонлиқўл — Қозоғистон ва Россия бозорига чиқиш учун энг қулай нуқталардан биридир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (458, 11, 42, 6, '6', 'Сув тежовчи технологияларга ўтиш', 'Экологик барқарорлик режаси', 'Жами: Сув тежаш стратегияси | Мақсад: сув сарфини 40% га камайтириш | Механизм: субсидиялар ва имтиёзли кредитлар ҳисобига лазерли текислаш ва томчилатиб суғоришни жорий этиш', TRUE, 'Сув хўжалиги вазирлиги', 'Сув тақчиллиги Қонлиқўлнинг энг катта экологик хавфи. Томчилатиб суғориш ва лазерли текислаш технологияларини жорий этиш орқали сув сарфини 40% га камайтириш ва фермер даромадини ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (459, 11, 43, 6, '6', 'Ижтимоий капитал ва бандлик', 'Иш ўринлари яратиш прогнози', 'Жами: Бандлик прогнози | Прогноз: йилига 1 500 та янги иш ўрни | Йўналиш: хизмат кўрсатиш соҳаси (40%) ва қайта ишлаш саноати (60%)', TRUE, 'Бандлик вазирлиги', 'Йилига 1 500 та янги иш ўрни яратиш режаси саноат ва хизматлар секторида бандликни барқарор ошириш имконини беради. Қайта ишлаш саноатига 60% урғу бериш тўғри стратегия — бу қишлоқ хўжалиги маҳсулотларига қўшимча қиймат яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
