INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (460, 13, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва экспорт ҳажми динамикаси (2021–2025)', 'Саноат ҳажми (млрд сўм): 2021: 361,7 | 2022: 362,0 | 2023: 423,5 | 2024: 447,2 | 2025: 526,3 | Хизматлар ҳажми (млрд сўм): 2021: 194,0 | 2022: 225,0 | 2023: 264,0 | 2024: 350,0 | 2025: 419,0 | Экспорт ҳажми (минг $): 2021: 9000 | 2022: 11500 | 2023: 15000 | 2024: 20500 | 2025: 26500 | Янги корхоналар: 1 500 та (600 та ёпилган)', TRUE, 'Статистика бўлими', 'Гулистон туманида экспорт ҳажми 5 йил ичида қарийб 3 бараварга ошгани иқтисодиётнинг ташқи бозорга йўналтирилганлигини кўрсатади. 2026 йилда хизмат кўрсатиш соҳасининг иқтисодиётдаги улуши (45%) юқорилигини инобатга олиб, туманни вилоятнинг сервис ва логистика марказига айлантириш стратегик аҳамиятга эга.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (461, 13, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Ихтисослашув ва бандлик тақсимоти', 'Жами: 4 та драйвер | Хизмат кўрсатиш: 45% (20,3 минг киши банд) | Саноат: 30% (11,2 минг киши банд) | Қишлоқ хўжалиги: 25% (14,5 минг киши банд) | Ташқи савдо: Йиллик 26,5 млн $ экспорт', TRUE, 'Статистика бўлими / Ҳокимият', 'Хизматлар соҳаси драйвер бўлса-да, саноатнинг ўсиш индекси (2025 йилда 140-160) истиқболлироқ. 2026 йилда қишлоқ хўжалиги маҳсулотларини саноат усулида қайта ишлаш кластерларини кенгайтириш орқали қўшилган қиймат занжирини яратиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (462, 13, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '2021-2026 йиллар давомида саноат ҳажми ўзгариши', 'Саноат ҳажми (млрд сўм): 2021: 361,7 | 2022: 362,0 | 2023: 423,5 | 2024: 447,2 | 2025: 526,3 | 2026 (прогноз): ~560,0 (105-106% ўсиш)', TRUE, 'Статистика бўлими', '2025 йилда йирик корхоналар (700 млрд сўм) ва кичик бизнес (690 млрд сўм) ўртасидаги мувозанат саноатнинг соғлом ривожланаётганидан далолат беради. 2026 йилда янги ташкил этилган 1500 та корхонанинг экспорт салоҳиятини оширишга эътибор қаратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (463, 13, 4, 1, '1', 'Маҳаллий бюджет', 'Бюджет даромадлари динамикаси (2021–2025)', 'Бюджет даромадлари (млрд сўм): 2021: 62,5 | 2022: 80,0 | 2023: 95,0 | 2024: 140,0 | 2025: 185,0 | Контингент бюджет (2025): 370,0 млрд сўм', TRUE, 'Туман молия бўлими', 'Маҳаллий бюджет даромадлари 5 йил ичида 3 баравар ўсган. 2026 йилда маҳаллий бюджетнинг даромад манбаларини диверсификация қилиш ва солиқ базасини кенгайтириш орқали контингент бюджет режасини 400 млрд сўмдан ошириш имконияти мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (464, 13, 5, 1, '1', 'Ажратилган кредитлар — NPL ҳолати', 'Кредит сифати ва муаммоли кредитлар динамикаси', 'NPL (%): 2021: 3,9 | 2022: 4,5 | 2023: 4,9 | 2024: 5,0 | 2025: 5,5 (%)', TRUE, 'Марказий банк / SQB', 'Муаммоли кредитлар (NPL) улушининг йилдан-йилга ўсиб бораётгани (3,9% дан 5,5% гача) хавотирли сигналдир. 2026 йилда кредит ажратишда лойиҳаларнинг молиявий барқарорлигини қаттиқ назорат қилиш ва муаммоли активлар билан ишлаш тизимини такомиллаштириш зарур. Кредитларни кўпроқ хизмат кўрсатиш ва экспортёр корхоналарга йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (465, 13, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Транспорт фаоллиги ва ижтимоий кутишлар', 'Юк айланмаси: 7 281 минг тонна | Йўловчи ташиш: 25 483,2 минг киши | Ижтимоий кутиш: Аҳоли ва бизнеснинг 65% и келажакка ижобий қарайди', TRUE, 'Google Trends таҳлили', 'Юк айланмасининг юқорилиги (7,2 млн тонна) Гулистон туманининг логистик жозибадорлигини исботлайди. 2026 йилда Google қидирув сўровларида «транспорт логистикаси» ва «омборхона хизматлари»га бўлган қизиқишни таҳлил қилиш орқали туманга йирик инвесторларни жалб қилиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (466, 13, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолини тоза ичимлик суви билан таъминлаш динамикаси (%)', 'Таъминланганлик (%): 2021: 96,0 | 2022: 96,5 | 2023: 97,0 | 2024: 97,6 | 2025: 97,9 | 2026 (прогноз): 98,2+ (%)', TRUE, 'Сув хўжалиги', 'Гулистон туманида ичимлик суви билан таъминланиш даражаси республика бўйича энг юқори кўрсаткичлардан бири. Эндиги асосий эътиборни сув тармоқларининг техник ҳолатини сақлаб туриш ва сув исрофини камайтириш учун «ақлли» ҳисоблагичлар тизимини 100% га етказишга қаратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (467, 13, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Йўллар узунлиги ва асфальтланган улуши', 'Жами: Йўллар таҳлили | Йўллар узунлиги: 310 км | Асфальтланган йўллар улуши (2025): 82% | Суғориш каналлари бетонлаш: 80%', TRUE, 'Йўл хўжалиги / Ҳокимият', 'Йўлларнинг 82% асфальтлангани туманнинг логистик жозибадорлигини оширади. 2026 йилда саноат зоналарига олиб борувчи йўллар сифатини халқаро стандартларга мослаштириш ва мавжуд ички йўлларни жорий таъмирлаш тизимини рақамлаштиришга қаратиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (468, 13, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр тармоқлари ҳолати ва модернизация эҳтиёжи', 'Жами: Энергия таъминоти таҳлили | Электр узилишлари: Ойига ўртача 2 марта | Трансформаторлар: 35% эскирган | Линиялар: 25% алмаштириш зарур | Интернет қоплами: 97%, тезлик 70-120 Мбит/с', TRUE, 'Электр тармоқлари / Ҳокимият', 'Электр узилишлари сони кам бўлса-да, трансформаторларнинг 35% эскирганлиги саноат корхоналари учун хавф туғдириши мумкин. 2026 йилда модернизация ишларини «Гул-истон» кичик саноат зонаси атрофидан бошлаш ва муқобил энергия манбаларини жамоат биноларига жорий этишни тезлаштириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (469, 13, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Ер фонди таркиби ва саноат зоналари', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 34 900 га | Суғориладиган ер: 12 000 га | Саноат зонасидан фойдаланиш: 75-85% | Фойдали қазилмалар: 3 та қум-шағал кони', TRUE, 'Кадастр агентлиги / Ҳокимият', 'Саноат зонасида ердан фойдаланиш 75-85% атрофида — янги инвесторлар учун захира ерлар мавжуд. 2026 йилда бўш турган ерларни «Loyiha fabrikasi» орқали қурилиш материаллари (қум-шағал захирасига таяниб) ишлаб чиқариш лойиҳаларига йўналтириш самарали бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (470, 13, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Транспорт инфратузилмаси ва йўловчи айланмаси', 'Вилоят марказигача: 10 км | Темир йўл станциясигача: 2 км | Йўловчи ташиш (йиллик): 25 483,2 минг киши | Канализация таъминоти: 60%', TRUE, 'Йўл хўжалиги / Статистика бўлими', 'Вилоят марказига жуда яқинлиги (10 км) туман аҳолисининг кундалик мобиллигини оширади. 2026 йилда Гулистон шаҳри ва туман ўртасидаги транспорт оқимини бошқариш учун электробуслар қатновини йўлга қўйиш ва бекатларда «ақлли» мониторинг тизимини жорий этиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (471, 13, 12, 2, '2', 'Мактабгача таълим қамрови', 'МТТга қамраб олиш даражаси динамикаси', 'МТТ қамрови (%): 2023: 82,6 | 2024: 84,8 | 2025: 87,1 | 2026 (прогноз): 90,0 (%)', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Қамров даражасининг йиллик барқарор ўсиши (ўртача +2,2%) инфратузилма аҳоли ўсишига мос кенгаяётганидан далолат беради. 2026 йилда 90% маррага эришиш учун давлат-хусусий шериклик асосидаги МТТларни қўллаб-қувватлаш ва мавжуд 340 та бўш ўриндан самарали фойдаланиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (472, 13, 13, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурслари динамикаси ва бандлик кўрсаткичлари', 'Меҳнат ресурслари (минг киши): 2021: 43,5 | 2022: 44,5 | 2023: 45,0 | 2024: 45,5 | 2025: 46,0', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор ўсиб бормоқда. Бандликни ошириш учун чорвачилик, қурилиш ва хизматлар соҳалари бўйича қисқа муддатли ўқув дастурларини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (473, 13, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва миграция динамикаси', 'Банд аҳоли (2025): 40 500 киши (+2,8%) | Қайтган мигрантлар (2025): 5 000 киши (+11,1%) | Норасмий секторда бандлик (2021): 17 000 киши | Хорижга кетганлар: 2021: 8500 | 2022: 9500 | 2023: 10000 | 2024: 10500 | 2025: 11500', TRUE, 'Бандлик маркази / ИИВ миграция', 'Хорижга кетиш йилдан йилга ошиб бормоқда — бу меҳнат бозорига кучли юк туширади. Норасмий секторни расмийлаштириш ва қайтган мигрантларни маҳаллий иқтисодиётга жалб қилиш орқали бандликни сезиларли ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (474, 13, 15, 3, '3', 'Ишсизлик кўрсаткичлари', '2 000 нафар ишсиз — 7,0% (2025)', 'Ишсизлик (%): 2021: 9,5 | 2022: 9,0 | 2023: 8,5 | 2024: 8,0 | 2025: 7,0 (%) | Ишсизлар сони (2025): 2 000 киши (−9,1%) | Мақсад: 2027 йилгача 2% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим. Ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш зарур.', 2000, 7.0, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (475, 13, 16, 3, '3', 'Камбағаллик кўрсаткичлари', '2 200 оила - 10.5% (2025)', 'Камбағаллик (%): 2021: 14,0 | 2022: 13,5 | 2023: 13,0 | 2024: 12,0 | 2025: 10,5 (%) | Камбағал оилалар (2025): 2 200 та (−8,3%) | Ижтимоий ҳимояга муҳтож: 7 000 оила', TRUE, 'Статистика бўлими / МФЙ', 'Камбағалликни камайтириш учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. Ижтимоий ёрдамни иш ва микролойиҳалар билан боғлаш, барқарор даромад манбаини яратишга эътиборни қаратиш зарур.', 2200, 10.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (476, 13, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва миграция оқими', '', FALSE, 'SQB', 'Маълумот SQB дан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (477, 13, 18, 3, '3', 'Аёллар бандлиги 2026 режаси', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлаш', '', FALSE, 'Бандлик вазирлиги', 'Маълумот Меҳнат вазирлигидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (478, 13, 19, 3, '3', 'Олий таълим муассасалари', 'ОТМ сони, талабалар ва қуввати', '', FALSE, 'Ҳокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (479, 13, 20, 3, '3', 'Техникумлар ва мактаблар', 'Мактаб/техникум сони, сменалар, ўқувчилар', '', FALSE, 'Мактабгача ва мактаб таълими бўлими', 'Маълумот Халқ таълимидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (480, 13, 21, 4, '4', 'Маҳалла ихтисослашуви', '24 та маҳалланинг иқтисодий фаолият йўналишлари ва тоифалари', 'Жами: 24 та маҳалла | Ипакчилик маҳаллалари: 3 та (Сойибобод, Мустақиллик, Чортоқ) | Картошка/карам: 6 та МФЙ | Маҳалла типологияси: Оғир: 8 та, Ўрта: 10 та, Енгил: 8 та', TRUE, 'МФЙ агентлиги', 'Ипакчилик (3 МФЙ) ва картошкачилик (6 МФЙ) салоҳиятини қайта ишлаш занжирига уланиш орқали маҳалла даражасида қўшимча иш ўринлари яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (481, 13, 22, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида иқтисодий ўсишни бошқарувчи тармоқлар', 'Жами: 3 та драйвер сектор | 1-сектор Чорвачилик: асосий даромад манбаи | 2-сектор Қурилиш: инфратузилма ва иш ўринлари | 3-сектор Хизматлар: турмуш даражасини ошириш', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни алоҳида эмас, «чорвачилик + қишлоқ хўжалиги + хизмат» занжирида боғлаш керак. Тайёр маҳсулотни бозорга чиқариш ва онлайн сотув каналларини кенгайтириш орқали қўшимча қийматни ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (482, 13, 23, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', '2026 йил учун режалаштирилган лойиҳалар ва иш ўринлари', 'Жами: 80 та лойиҳа, 400 та иш ўрни | Умумий қиймат: 25 млрд сўм | Саноат лойиҳалари (2026): 3 та, 2,27 млрд сўм | Хизмат лойиҳалари (2026): 6 та, 10 млрд сўм | Жами иш ўрни (режа): 2 280 та | Инвестиция (режа): 120 млрд сўм', TRUE, 'SQB / Шаҳар ҳокимияти', '80 та микролойиҳа орқали 400 та иш ўрни яратилган. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа амалга оширилишини мониторинг; (4) тадбиркорларга молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (483, 13, 24, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 24 та маҳалла | Қизил тоифа: 8 та | Сариқ тоифа: 10 та | Яшил тоифа: 8 та | Оғир маҳаллалар: А. Яссавий, Бирлашган, А. Навоий, Иноқлик, Чортоқ', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 5 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Аввало ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳага улаш механизмлари қўлланиши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (484, 13, 25, 4, '4', 'SQB рақамли хизматлари', 'Банк инфратузилмаси ва маҳалла банкирлари', 'Жами: SQB рақамли хизматлари | Банкоматлар: 7 та | Бошқа банклар: 2 та | Банк ходимлари: 55 нафар | Маҳалла банкирлари: 4 нафар', TRUE, 'SQB / Марказий банк', 'Маҳалла банкирлари сони жуда кам (4 та) — бу 24 та МФЙ учун етарли эмас. Банкирлар сонини ошириш ва аёл банкирларни жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (485, 13, 26, 4, '4', 'Ишсизлик юқори маҳаллаларни ривожлантириш режаси', 'Оғир тоифадаги 5 та маҳаллада бандликни таъминлаш стратегияси', 'Жами: 5 та маҳалла, оғир тоифа | А.Яссавий, Бирлашган, А.Навоий, Иноқлик, Чортоқ | Ишсизлар (2025): 2 000 киши | Ёшлар (16–30): 1 200 киши | Аёллар: 1 190 киши | Мақсад: 2027 йилгача 2% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '5 та оғир маҳаллада ёшлар (1 200) ва аёллар (1 190) ишсизлиги юқори. «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (486, 13, 27, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | «Сунъий интеллект куни» — ҳар ҳафтанинг жума куни СИ ўқитишга бағишланади | 1-босқич: Ҳар ҳафта жума куни СИ ўқитиш куни | 2-босқич: Туман ҳокимлари ва ҳоким ўринбосарлари — СИ ўқитиш ва қўллашни жорий қилиш | 3-босқич: Банк филиал раҳбарлари ва маҳалла банкирлари — СИ скоринг, риск таҳлили | 4-босқич: Маҳалла раислари ва ҳоким ёрдамчилари — СИ маълумотлар таҳлили', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Ҳафталик «СИ куни» амалиёти орқали ходимлар янги технологияларни кундалик ишга татбиқ этишни ўрганмоқда. Кейинги босқичда ҳар бир бўлим учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (487, 13, 28, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади: аввал ҳоким даражасида стратегик қарорлар учун СИ, кейин банк раҳбарларига скоринг ва таҳлил, сўнг маҳалла банкирларига мижоз билан ишлаш учун СИ платформа ўргатилади. Ҳар босқич 2–4 ҳафта давом этади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (488, 13, 29, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча маҳаллаларда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (489, 13, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: SQB ва бошқа тижорат банклари | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринг, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (490, 13, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: HAMROH дастури | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Маҳалла банкирлари орқали аёлларни фаол жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (491, 13, 32, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'Жами: 250 нафар СИ орқали ўқитиш (2026 режа) | СИ таҳлили: ҳар бир мурожаатчининг кўникмаси ва қизиқиши аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури тузилади | Тадбиркорлик йўналиши: бизнес-режа + микрокредит | Касб йўналиши: тайёр иш ўринларига йўналтириш | 24 та маҳалладан камида 10 нафардан жалб қилиш', TRUE, 'SQB', 'СИ платформаси орқали ҳар бир фуқаро индивидуал баҳоланади: кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтирилади. 24 та маҳалладан камида 250 нафарни 2026 йил якунигача СИ тренингига жалб қилиш ва 80% иштирокчини 3 ой ичида даромадли фаолиятга ўтказиш мақсад қилинган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (492, 13, 33, 5, '5', 'Агрокластер ва чуқур қайта ишлаш саноати', 'Қишлоқ хўжалиги — туман драйвери, аммо қайта ишлаш даражаси паст', 'Жон бошига қ/х ҳажми: 24 038 минг сўм (вилоят ўртачасидан 26% юқори) | Дон экин майдони: 21 800 га | Гўшт қайта ишлаш: 21% | Сабзавот қайта ишлаш: 11% | Фермер кластерлари: 5 та', TRUE, 'Туман ҳокимияти / SQB', 'Жон бошига қ/х ҳажми вилоят ўртачасидан сезиларли юқори, лекин гўшт (21%) ва сабзавот (11%) қайта ишлаш улуши жуда паст. 3–5 та «ФудПарк» қуриш ва фермер кластерларини 5 тадан 12 тагача ошириб, ҳар бирига SQB орқали 3–5 млрд сўмлик «кластер кредити» таклиф қилиш импорт ўрнини босувчи маҳсулотлар ҳажмини 2028 йилгача 2 баравар оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (493, 13, 34, 5, '5', 'Ипакчилик ва пистачилик — ноёб ихтисослашув', 'Уч маҳалла ипак қурти, 30 гектар пистачилик — премиум экспорт тармоғи', 'Ипакчилик маҳаллалари: 3 та (Сойибобод, Мустақиллик, Чортоқ) | Пистачилик: 30 га янги боғлар (2026–2028) | Узумчилик: 800 га (қайта ишлаш 15%) | Картошка/карам: 6 та маҳалла', TRUE, 'Туман ҳокимияти', 'Ипакчилик ва пистачилик — стратегик «ниша маҳсулотлар»: экспорт нархи бошқа қ/х маҳсулотларидан 4–10 баравар юқори. Ипакчилик маҳаллаларида «тўла сикл» ишлаб чиқариш тизимини йўлга қўйиш ҳар бир маҳаллада 80–120 та янги иш ўрни яратади. Пистачиликни 30 дан 150 га га кенгайтириш — «Гулистон пистаси» халқаро бренди имконияти.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (494, 13, 35, 5, '5', 'Логистика хаби ва «Қуруқ порт» салоҳияти', 'Темир йўлгача 2 км, вилоят марказига 10 км — Тошкент–Фарғона йўналиши', 'Темир йўлгача: 2 км | Шаҳар йўллари: 310 км | Асфальтланган: 82% | Омборхоналар: 4 та (800 м²), керак +2 та | Йўловчи ташиш: 25 483 минг/йил | Юк айланмаси: 7 281 минг тонна/йил', TRUE, 'Туман ҳокимияти', 'Темир йўлга яқинлик (2 км) ва Тошкент–Фарғона автомагистралига тушиш — асосий афзаллик. «Агро-Қуруқ порт» мажмуасини шакллантириш — совуткичли омборлар, қадоқлаш линиялари ва юк станциясини ягона ҳудудда жойлаштириш юк айланмасини 7,3 дан 12 млн тоннагача (+65%) оширади. Инвестиция: $15–25 млн.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (495, 13, 36, 5, '5', 'Қуёш энергияси ва «яшил саноат»', 'Сирдарё — Ўзбекистоннинг энг қуёшли ҳудудларидан, равнин ер, паст зичлик', 'Қуёшли кунлар: 300+ кун/йил | Ер майдони: 34 900 га | Аҳоли зичлиги: 720 киши/км² | Инвестиция: $10–25 млн/лойиҳа', TRUE, 'Энергетика вазирлиги / Ҳокимият', 'Йилига 300+ қуёшли кун ва паст аҳоли зичлиги — кенг майдонли қуёш панеллари учун ноёб шароит. Биринчи босқичда КСЗга 10–20 МВт қуёш станцияси қуриш электр харажатини 25–30% камайтиради. Иккинчи босқичда 100 МВт миқёсидаги қуёш парки — Сирдарёдан Тошкентга «яшил электр» экспорт қилувчи биринчи туман бўлиш имкони.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (496, 13, 37, 5, '5', 'КСЗ кенгайтириш ва инвестиция ўсиши', 'Гулистон КСЗ — 35 корхона, 1 200 иш ўрни; ер ресурси мўл', 'Жалб қилинган инвестиция (2025): $30 млн (2021 дан 3,75x) | ТТИ динамикаси: $12 млн (2023) → $18 млн (2025) | Саноат: 526,3 млрд сўм (ўсиш 105,8%) | Йирик корхоналар: 700 млрд сўм', TRUE, 'Туман ҳокимияти', 'КСЗни 2 баравар кенгайтириш (70–80 корхона) ва «ихтисослашган кластерларга» бўлиш — тайёр инфратузилмани инвесторларга сотишни осонлаштиради. ТТИни $18 млн дан 2028 йилгача $45–50 млн га етказиш учун «Fast-Track Invest» режимини жорий этиш Гулистонни вилоятда 1-ўринга кўтаради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (497, 13, 38, 5, '5', 'Рақамли инфратузилма ва BPO/IT хизматлари', 'Интернет қоплами 97%, тезлик 70–120 Мбит/с — мамлакат бўйича юқори', 'Интернет қоплами: 97%, тезлик 70–120 Мбит/с | 18–24 ёш таълими: 53,6% | МТТ қамрови: 87,1% | Қайтган мигрантлар: 5 000 киши/йил | Ёшлар ишсизлиги: 1 200 киши', TRUE, 'Туман ҳокимияти / SQB', 'Интернет тезлиги ва қоплами Гулистонни рақамли хизматлар учун тайёр ҳудудга айлантиради. Тошкентга яқинлик ва арзон меҳнат ресурсидан фойдаланиб, BPO/IT-аутсорсинг маркази очиш — Тошкент IT-паркининг «филиали» сифатида. Қайтган 5 000 мигрант ва 1 200 ёшлар — потенциал кадрлар. 500–800 иш ўрнига 2–3 та Call-Center ишга тушириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (498, 13, 39, 5, '5', 'Туризм, агротуризм ва транзит зона', '3 та туризм маршрути (2026–2028), Тошкент ва Фарғона ўртасида транзит ҳудуд', 'Инвестиция (2026–2028 режа): 50 млрд сўм | 3 та туристик маршрут | Агротуризм: ипакчилик + пистачилик + узумчилик | Гастротуризм: маҳаллий қ/х маҳсулотлари | Дам олиш масканлари: 2026–2028', TRUE, 'Туман ҳокимияти', 'Энг тўғри стратегия — «транзит + агротуризм» модели: сайёҳлар учун «йўл бўйи хабилари» яратиш. 50 млрд сўмни: 20 млрд — 2 та «Eco/Silk Resort»; 15 млрд — агротур маршрутларини рақамли карта ва брендга улаш; 15 млрд — гастробозор ва ҳунармандчилик марказлари. Мақсад — 2028 йилгача 150 минг транзит сайёҳни ушлаб қолиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (499, 13, 40, 6, '6', 'Стратегик хулоса — 3 та устувор тармоқ', 'Гулистон иқтисодиётининг 5 йиллик таҳлилидан келиб чиққан асосий йўналишлар', 'Жами: 3 устун: Агро — Саноат — Хизматлар | 1-устун — Агрокластер: қ/х 4 500 млрд сўм, 21 800 га дон | 2-устун — Саноат: 526 млрд сўм, +5,8% ўсиш | 3-устун — Бозор хизматлари: 419 млрд сўм, 2,2× ўсиш | Ноёб нишалар: ипакчилик, пистачилик', TRUE, 'SQB / Туман ҳокимияти', 'Туман «уч устунли» модел бўйича ривожланмоқда (қ/х 25% / саноат 30% / хизматлар 45%). Диверсификация — кучли томон, лекин қайта ишлаш даражаси паст. 2026–2028 да қ/х ва саноат ўртасидаги «узилиш»ни агросаноат орқали боғлаш, хизматларни рақамли инфратузилма асосида 2× га ошириш. Мақсад — Гулистонни «Сирдарё вилоятининг иқтисодий пойтахти» қилиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (500, 13, 41, 6, '6', 'Иш ўринлари ва бандлик KPI режаси', '2026–2028: 6 780 янги иш ўрни, ишсизликни 5,5% дан 3% га тушириш', 'Жами: 6 780 иш ўрни (2026–2028) | Қ/х: 1 700 | Саноат: 2 650 | Туризм: 350 | Расмийлаштириш: 1 300 | Ёшлар: 1 200 → 400 гача | Аёллар: 1 190 → 500 гача', TRUE, 'Туман ҳокимияти / SQB', '6 780 иш ўрни ишсизликни 5,5% дан 3,0% га тушишга етарли. Асосий муаммо — 17 000 норасмий банд ва 11 500 мигрант. Норасмий секторни расмийлаштиришга 2 500 иш ўрни (9 млрд сўм солиқни қайтаради), қайтган мигрантлар учун «Reintegrate» дастури, ёшлар ва аёллар учун алоҳида «вертикал» дастурлар зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (501, 13, 42, 6, '6', 'Инвестиция жалб қилиш режаси 2026–2031', '6 йиллик график — 50 дан 70 млрд сўмгача йиллик ўсиш', 'Жами (6 йил): 374 млрд сўм | 2026: 50 млрд | 2027: 57 млрд (+14%) | 2028: 60 млрд | 2029: 67 млрд | 2030: 70 млрд | ТТИ: $18 млн (2025) → $45–50 млн (2028)', TRUE, 'Шаҳар ҳокимияти / SQB', '374 млрд сўмлик режани «фаол воронка»га айлантириш — 40% КСЗ ва саноат, 35% агрокластерлар, 25% инфратузилма. ТТИни $45–50 млн га етказиш учун 5 та йирик стратегик инвестор билан тўғридан-тўғри шартнома тузиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (502, 13, 43, 6, '6', 'Маҳалла-даражадаги стратегия — 8 та оғир маҳалла', '24 та маҳалла, улардан 8 таси стратегик «қизил зона»', 'Маҳалла тоифалари: Оғир: 8 та, Ўрта: 10 та, Енгил: 6 та | Камбағал оилалар: 2 200 | Ижтимоий ҳимояга муҳтож: 7 000 оила | Микролойиҳалар: 80 та, 25 млрд сўм | Маҳаллий банкирлар: 4 та', TRUE, 'МФЙ агентлиги / SQB', '8 та оғир маҳалла учун «Маҳалла 360» модели — ҳар бири учун 5 йиллик паспорт (ихтисослашув + иш ўрни + микрокредит + инфратузилма). Банкирларни 4 тадан 12 тага (6 аёл, 6 эркак) етказиш, микролойиҳаларни 80 дан 150 тага, маблағни 25 дан 50 млрд сўмгача кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (503, 13, 44, 6, '6', '2026 лойиҳа портфели ва кредит режаси', '9 та лойиҳа + 1 400 млрд сўм банк кредити', 'SQB 2026 режаси: 1 400 млрд сўм | Саноат лойиҳалари: 3 та, 2,27 млрд, 900 иш ўрни | Хизмат лойиҳалари: 6 та | Кичик бизнес: 400 млрд | Қ/х: 350 млрд | Саноат: 350 млрд | Хизматлар: 350 млрд | NPL: 5,5% → мақсад 2,0%', TRUE, 'SQB / Туман ҳокимияти', '1 400 млрд сўмлик кредит режасида ҳар блокда 3–5 та «флагман лойиҳа» аниқлаш ва кредитнинг 60% ини шуларга йўналтириш лозим. NPLни 2,0% га тушириш калити — «прекредит тавсия» босқичида маҳаллий банкир ва AI-баҳолаш тизимидан фойдаланиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (504, 13, 45, 6, '6', 'Босқичли амалиёт режаси — 0–12 ой / 1–3 йил / 3–5 йил', 'Қисқа, ўрта ва узоқ муддатли вазифалар тақсимоти', 'Жами режа: 1 458 млрд сўм | 0–12 ой (2026): 1 362 млрд (банк 1 122 + бюджет 240) | 1–3 йил: 56 млрд (микрокредит + оилавий) | 3–5 йил: 120 млрд (инфратузилма 90 + туризм 30) | 100 кунлик режа: бандлик + иш ўрни', TRUE, 'SQB / Ҳокимият', '0–12 ой босқичи (93%) — тўғри, тезкор таъсир. Лекин 3–5 йиллик режа (120 млрд) заиф — узоқ муддатли лойиҳалар (қуёш станция, агро-dry-port, BPO-марказ) учун 250–300 млрд сўмгача ошириш зарур. Ҳар фаза учун 3 та KPI ва чорак-чоракда «Stop/Go» ҳисобот талаб қилиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (505, 13, 46, 6, '6', 'ГУЛИСТОН 2028 — асосий натижа рамкаси', '5 йиллик мақсад — «Сирдарёнинг иқтисодий дарвозаси»', 'Аҳоли: 78 → ~85 минг (+9%) | Саноат: 526 → 900+ млрд (+70%) | Экспорт: $26,5 → $50+ млн (+90%) | Камбағаллик: 5,9% → 2,5% | Ишсизлик: 5,5% → 3,0% | Жон бошига кредит: 3,6 → 6,0 млн | Рейтинг: 4 → 2 ўрин', TRUE, 'SQB / Туман ҳокимияти', 'Гулистон олдида стратегик «чорраҳа» турибди: ё «ўртача» бўлиб қолади, ё вилоятнинг иқтисодий пойтахтига айланади. Ғолиб формуласи: (1) уч устун — агро-саноат-хизматлар; (2) уч ниша — ипакчилик, пистачилик, қуёш энергияси; (3) уч механизм — SQB лойиҳа фабрикаси, ТТИ-fast-track, маҳалла-360. Ҳар бир рақам учун масъул одам ва 6 ойлик ҳисобот расмийлаштирилиши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (14, 6, 'mirzoulgbek', 'Мирзо Улуғбек', 'Мирзо-Улугбек', 'Mirzo Ulugbek', 'Мирзо Улуғбек тумани', 'mirzoulgbek.json', TRUE, NULL, 2026, 44, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
