INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (506, 14, 1, 1, '1', 'Макроиқтисодий кўрсаткичлар', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 12 318,7 млрд сўм (+21,2%) | Бозор хизматлари: 35 930,8 млрд сўм (+34,4%) | Саноат ўсиш суръати: 121,2% | Тармоқлар: Савдо, саноат, хизмат кўрсатиш — устувор 3 та | ЯҲМ жон бошига: 26 596,3 минг сўм | 2021→2025: Саноат 5 186,1 → 12 318,7 млрд сўм (2,4 баробар)', TRUE, 'stat.uz / Туман статистика бўлими', 'Саноат 5 йилда 2,4 баробарга ўсиши ва ўсиш суръати 96,1% дан 121,2% гача кўтарилиши ижобий тенденция, аммо қиймат занжирининг пастки қисмида қолмаслик учун юқори қўшимча қийматли маҳсулотлар улушини ошириш керак. Бозор хизматлари 3,4 баробарга ўсгани — туманнинг савдо-хизмат ихтисослашувини тасдиқлайди, шу сабабли логистика-омборхона инфратузилмасига ва рақамли савдо платформаларига инвестицияни кучайтириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (507, 14, 2, 1, '1', 'Шаҳар иқтисодиётининг 4 та драйвери', 'Мирзо Улуғбек тумани устувор тармоқлари ва ривожланиш йўналишлари', 'Жами: 4 та устувор соҳа | 1-ўрин Савдо ва чакана савдо: бозор хизматлари 35 930,8 млрд сўм (+34,4%) | 2-ўрин Саноат ва ишлаб чиқариш: 12 318,7 млрд сўм (+21,2%) | 3-ўрин Хизмат кўрсатиш: енгил саноат, транспорт тугуни | 4-ўрин Қурилиш ва маҳалла тадбиркорлик: микролойиҳалар 3 000 та (6 000 иш ўрни, 120 млрд сўм) | Кичик бизнес 2021→2025: 39 653 → 143 971 млн сўм (3,6 баробар)', TRUE, 'Туман статистика бўлими / Туман ҳокимияти', 'Туман 3 та ноқишлоқ хўжалиги драйверига таянгани учун бу шаҳар типидаги иқтисодиёт учун табиий. 4 та драйверни бир йўналишдаги «савдо–хизмат» кластерига ҳаддан ташқари боғлиқ қилмаслик учун юқори технологияли ишлаб чиқаришни ажратиб ривожлантириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (508, 14, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', 'Ҳажм (млрд сўм): 2021: 5 186,1 | 2022: 5 649,4 | 2023: 8 245,0 | 2024: 11 007,8 | 2025: 12 318,7 | Ўсиш %: 2021: 96,1 | 2022: 101,6 | 2023: 108,8 | 2024: 114,7 | 2025: 121,2 | Йирик корхоналар (2025): 358 692,8 млн сўм | Кичик бизнес (2025): 143 971,3 млн сўм', TRUE, 'Туман статистика бўлими', '2021 йилда ўсиш манфий (96,1%) бўлган, кейинги 4 йилда суръат барқарор ошиши структуравий ўсиш белгиси. Йирик корхоналар кичик бизнесга нисбатан 2,5 баробар катта — бу концентрация хавфини келтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (509, 14, 4, 1, '1', 'Маҳаллий бюджет', 'Туман маҳаллий бюджет даромадлари ва солиқ тушумлари динамикаси', 'Бюджет (млн сўм): 2021: 111 045,8 | 2022: 158 695,5 | 2023: 140 634,0 | 2024: 177 179,8 | 2025: 169 249,5 | Контингент: 2021: 3 156,2 | 2022: 4 218,6 | 2023: 2 774,5 | 2024: 7 055,1 | 2025: 14 247,2 | Солиқ прогнози (млрд): 2021: 53,1 | 2022: 58,1 | 2023: 66,3 | 2024: 79,9 | 2025: 84,1', TRUE, 'Туман молия бўлими / Давлат солиқ қўмитаси', 'Бюджет даромадлари барқарор ўсмаяпти — 2023 ва 2025 йилларда пастга тушиш кузатилган. Контингент бюджет 4,5 баробар ошди. Солиқ даромадлари 5 йилда +58% ўсган бўлса-да, бюджет барқарорлигини таъминлаш учун даромад манбаларини диверсификация қилиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (510, 14, 5, 1, '1', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми ва банк инфратузилмаси', 'ТТИ: 2021: 500 → 2025: 1 200 минг $ (2,4 баробар) | Микролойиҳалар: 2024: 1 800 та (3 600 иш ўрни, 100 млрд) → 2025: 3 000 та (6 000 иш ўрни, 120 млрд) | 2026 кредит режаси: 300 млрд (кичик бизнес: 100, Қ/х: 50, Саноат: 150) | Банк: SQB 2 филиал, 8 банкомат, 72 ходим, 30 маҳаллий банкир | NPL: 2021: 2,9% → 2025: 3,6%', TRUE, 'SQB / Туман ҳокимияти', 'Микролойиҳалар +67% ошиши жуда ижобий, аммо NPL 2,9% дан 3,6% га кўтарилгани огоҳлик сигнали. Кредит сифатини назорат қилиш ва муаммоли қарзларни эрта аниқлаш тизимини кучайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (511, 14, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида', 'Маълумот мавжуд эмас — Марказий гуруҳ ҳисоблайди | Интернет қоплами (2025): 95%, 50 Мбит/с', TRUE, 'SQB Аналитика', 'Google Trends индекси туман бўйича мавжуд эмас. Интернет қоплами 95% ва тезлик 50 Мбит/с — рақамли фаоллик учун зарур инфратузилма тайёр. Рақамли савдо ва онлайн хизматлар ривожланиши учун асос яратилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (512, 14, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', 'Динамика (%): 2021: 98,0 | 2022: 99,2 | 2023: 99,7 | 2024: 99,3 | 2025: 100,0 | Канализация: 100% (барча йиллар) | Суғориш бетонлаш: 2021: 45% → 2025: 90%', TRUE, 'Сув хўжалиги', '2025 йилда 100% га етгани аъло натижа. Эндиги бош масала — қоплам эмас, сифат. Сув тармоғи модернизацияси ва сифат назорати тизимини кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (513, 14, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Туман ички йўлларининг таъмирланганлик даражаси', 'Асфальтланган: 100% (2021-2025) | Йўллар: 345 км | Темир йўл: 11 км масофада | Вилоят маркази: 11,3 км', TRUE, 'Йўл хўжалиги', 'Асфальтланган йўллар 100%, аммо йўллар узунлиги 345 км ўзгармагани парадокс. Туман майдони 60% га кенгайган бўлса-да, йўл тармоғи кенгайтирилмаган — янги ҳудудларда йўл қуриш режасини ишлаб чиқиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (514, 14, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр узилишлари ва тармоқ модернизация ҳолати', 'Узилишлар (марта/ой): 2021: 5 | 2022: 2 | 2023: 3 | 2024: 1 | 2025: 1 | Газ: 100% (2021-2025)', TRUE, 'Электр тармоқлари', 'Узилишлар 5 мартадан 1 мартага тушгани — энг яхши яхшиланиш. Электр тармоқлари модернизацияси бўйича маълумот мавжуд эмас, аммо барқарорлик юқори даражада сақланмоқда.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (515, 14, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ер фонди тузилмаси', 'Умумий (га): 2021: 3 074 | 2022: 3 074 | 2023: 3 074 | 2024: 4 015 | 2025: 4 911 | Экин/яйлов: йўқ (шаҳар типидаги туман) | Зичлик: 2021: 417 → 2025: 483 киши/км² | Саноат зона фойдаланиш: 2021: 50% → 2025: 90% | Фойдали қазилмалар: 0 та', TRUE, 'Кадастр агентлиги', 'Туман майдони +60% га кенгайгани жиддий маъмурий ўзгариш. Саноат зонаси 90% банд — 10% захира қолган. Янги саноат объектлари учун кўп қаватли ишлаб чиқариш биноларини режалаштириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (516, 14, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Аҳолини жамоат транспорти билан қамраб олинганлик даражаси', 'Юк/йўловчи айланмаси (минг): 2021: 214 308,4 | 2022: 325 028,1 | 2023: 436 938,6 | 2024: 456 235,6 | 2025: 521 268,1 | Темир йўл: 11 км | Омборхоналар: 2021: 9 та (4 500 м²) → 2025: 21 та (20 500 м²)', TRUE, 'Статистика бўлими / ИИВ', 'Мобиллик 2,4 баробар ошиши — иқтисодий фаоллик далили. Омборхоналар сони 9 дан 21 тага ва майдони 4 500 дан 20 500 м² га ошгани логистика инфратузилмасининг ривожланаётганидан далолат беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (517, 14, 12, 2, '2', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик', 'Қамров (%): 2021: 52,0 | 2022: 55,5 | 2023: 56,6 | 2024: 60,5 | 2025: 65,1 | Мактаб: 1-смена: 40 та, 2-смена: 25 та | Ёшлар ишсизлиги: 2021: 1 125 → 2025: 704 (–37%) | Оилалар: 2021: 55 000 → 2025: 85 000 (+55%)', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', '5 йилда +13,1% ошди. 2030 йилгача 80% мақсадига етиш учун суръатни ошириш зарур. Давлат-хусусий шериклик асосида янги мактабгача таълим муассасаларини ташкил этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (518, 14, 13, 3, '3', 'Меҳнат ресурслари', 'Туман меҳнатга лаёқатли аҳолиси ва меҳнат ресурслари динамикаси', 'Меҳнат ресурслари (минг): 2021: 400 | 2022: 450 | 2023: 2120 | 2024: 2450 | 2025: 2880', TRUE, 'Бандлик маркази', '2023 йилдаги кескин сакраш ишончсиз — манбадан қайта тасдиқлаш тавсия этилади. Агар маълумот тўғри бўлса, туман майдони кенгайиши билан боғлиқ бўлиши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (519, 14, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Норасмий секторда бандлик ва ижтимоий ёрдам кўрсаткичлари', 'Норасмий секторда: 2024: 45250 | 2025: 60211 | Бола нафақаси: 2021: 3569 | 2022: 5567 | 2023: 8195 | 2024: 6582', TRUE, 'Бандлик маркази', 'Норасмий секторда бандлик 45 000 дан 60 000 га ошган. Расмийлаштириш орқали солиқ базасини кенгайтириш мумкин. Бунинг учун соддалаштирилган рўйхатдан ўтиш ва имтиёзли солиқ ставкалари жорий этилиши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (520, 14, 15, 3, '3', 'Ишсизлик даражаси', 'Туман бўйича расмий ишсизлик кўрсаткичлари ва тренд', 'Ишсизлар (2025): 101 киши (−55,3%) | Тренд: 389 → 633 → 407 → 226 → 101 | Ёшлар ишсизлиги: 704 киши (16-30 ёш) | Аёллар ишсизлиги: 169 киши | Мақсад: 2027 йилгача 2% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари лозим. Расмий ишсизлик 101 кишига тушгани ижобий, аммо ёшлар ва аёллар бўйича алоҳида чора-тадбирлар зарур.', 101, 3.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (521, 14, 16, 3, '3', 'Камбағаллик даражаси', 'Туман аҳолиси орасида камбағаллик кўрсаткичлари', 'Камбағаллик (2025): 20% (−28 пп) | Камбағал оилалар (2025): 1800 та (+20%) | Тренд: 51% → 45% → 33% → 28% → 20% | Кам таъминланган: 150 та', TRUE, 'Статистика бўлими / МФЙ', 'Камбағалликни камайтириш учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. 5 йилда 51% дан 20% га тушиши жиддий натижа, аммо абсолют сонда камбағал оилалар сони ошаётгани эътиборга олиниши лозим.', 1800, 20, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (522, 14, 17, 3, '3', 'Ёшлар даромади ва бандлиги', 'Ёшлар ишсизлиги ва ўртача маош динамикаси', 'Ёшлар ишсизлиги (16-30): 2021: 1125 → 2025: 704 (−37,4%) | Маош (минг сўм): 2021: 3041 | 2022: 3078 | 2023: 3329 | 2024: 3732 | 2025: 4094 | Ўзгариш 2024→2025: +362 (+9,7%)', TRUE, 'Бандлик маркази / Статистика бўлими', 'Ёшлар ишсизлиги 5 йилда 37% га камайган. Дуал таълим ва тезкор қайта тайёрлаш дастурлари орқали ёшларни расмий бандликка кўпроқ жалб қилиш мумкин. Маош ўсиши барқарор, аммо инфляцияга мос келиши таҳлил қилиниши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (523, 14, 18, 3, '3', 'Аёллар бандлиги', 'Аёллар ишсизлиги ва ногиронлар бандлиги кўрсаткичлари', 'Аёллар ишсизлиги: 2021: 143 | 2022: 157 | 2023: 162 | 2024: 166 | 2025: 169 | Ногиронлар бандлиги (2021): Ишлайди 3200, Ишламайди 1710 | Маош: 2021: 3041 → 2025: 4094 (+34,6%)', TRUE, 'Бандлик маркази', 'Аёллар ишсизлиги йилдан йилга секин ошиб бормоқда (143 дан 169 га). Касбга йўналтириш ва имтиёзли молиялаштириш тавсия этилади. Аёллар учун уйдан ишлаш имкониятларини кенгайтириш ва онлайн тадбиркорлик дастурларини жорий этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (524, 14, 19, 3, '3', 'Мирзо Улуғбек туманидаги олий таълим муассасалари', 'Туман ҳудудидаги олий таълим муассасалари тўғрисида маълумот', '', FALSE, '', '', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (525, 14, 20, 3, '3', 'Мирзо Улуғбек туманидаги техникумлар', 'Туман ҳудудидаги техникум ва коллежлар тўғрисида маълумот', '', FALSE, '', '', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (526, 14, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'СИ малака ошириш дастури ва «Сунъий интеллект куни» ташкил этилиши', 'Жами: СИ малака ошириш дастури (Мирзо Улуғбек филиали қамрови — 100%) | «Сунъий интеллект куни» — ҳар чоршанба | Онлайн ўқитиш тизими жорий (LMS) | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Мирзо Улуғбек филиали ходимларининг СИ саводхонлигини ошириш орқали мижозларга кредит ажратишда скоринг таҳлилларини тезлаштириш мумкин. Ҳар ҳафталик СИ куни амалиётга йўналтирилган бўлиши ва натижалар KPI орқали ўлчаниши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (527, 14, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', '4 босқичли СИ ўқитиш дастури — раҳбарлар, филиал бошлиқлари, маҳалла банкирлари ва МФЙ раислари', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', '4 босқичли ўқитиш тизими барча даражадаги қарор қабул қилувчиларни қамраб олади. Ҳар босқич учун амалий натижа кўрсаткичларини белгилаш ва ўқув самарадорлигини баҳолаш тизимини жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (528, 14, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'СИ технологиялари орқали аҳолини тадбиркорликка йўналтириш дастури', 'СИ таҳлили: кўникма ва қизиқиш аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури | Тадбиркорлик: бизнес-режа + микрокредит | Касб: тайёр иш ўринларига йўналтириш', TRUE, 'SQB', 'СИ орқали аҳолининг кўникма ва қизиқишларини аниқлаш ва уларга мос бизнес-режа тузиш — замонавий ёндашув. Чатбот орқали индивидуал ўқув дастури тақдим этиш микролойиҳалар самарадорлигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (529, 14, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'SQB AI Advisor платформаси функциялари ва имкониятлари', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги', TRUE, 'SQB', 'AI Advisor платформаси кредит жараёнини тезлаштириш ва мижоз учун мос маҳсулот танлашда катта самара беради. KPI мониторинг функцияси маҳалла банкирлари самарадорлигини реал вақтда кузатиш имконини яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (530, 14, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Туман маҳаллаларининг ихтисослашуви ва типологияси', 'Жами: 60 та маҳалла | Ихтисослашув: Тикувчилик, Савдо ва хизмат кўрсатиш, Саноат зонаси (1 та) | Типология: ўрта тоифа', TRUE, 'МФЙ агентлиги', 'Туман хизмат ва савдо соҳасига ихтисослашган. Тикувчилик маҳаллаларида қўшимча қиймат занжирини кенгайтириш тавсия этилади. Маҳаллалар ихтисослашувини чуқурлаштириш ва ҳар бирига мос бизнес-модел ишлаб чиқиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (531, 14, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Туман маҳаллаларининг драйвер секторлари ва иқтисодий йўналишлари', '3 та драйвер: 1) Савдо ва хизмат кўрсатиш | 2) Қурилиш | 3) Хизматлар', TRUE, 'МФЙ агентлиги / SQB', 'Туман иқтисодиёти хизмат ва савдо соҳасига йўналтирилган. «Ишлаб чиқариш + савдо + хизмат» занжирида боғлаш орқали қўшимча иш ўринлари яратиш мумкин. Секторлар ўртасидаги синергияни кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (532, 14, 27, 4, '4', 'Микролойиҳалар', 'Туман бўйича микролойиҳалар сони, иш ўринлари ва молиялаштириш ҳажми', '2024: 1800 лойиҳа, 3600 иш ўрни, 100 млрд | 2025: 3000 лойиҳа, 6000 иш ўрни, 120 млрд | Ўзгариш: +1200 (+66,7%)', TRUE, 'SQB / Туман ҳокимияти', 'Микролойиҳалар 1,7 баробар ошган. Банк кредити улушини ошириш ва лойиҳаларни мониторинг қилиш тавсия этилади. Ҳар бир лойиҳанинг иш ўрни яратиш самарадорлигини KPI орқали баҳолаш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (533, 14, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Ишсизлик ва камбағаллик даражаси юқори маҳаллалар таҳлили', 'Жами: 60 та маҳалла | Типология: Ўрта тоифа | Асосий муаммо: ишсизлик ва камбағаллик даражаси юқори маҳаллалар | Маҳаллабай банкирлар: 30 та ходим (40 аёл, 32 эркак)', TRUE, 'МФЙ агентлиги / Бандлик маркази', 'Маҳалла кесимида ишсизлик ва камбағалликни аниқлаш ва ҳар бир маҳаллага мос ечим ишлаб чиқиш зарур. Маҳаллабай банкирлар институтини фаоллаштириш орқали манзилли ёрдам кўрсатиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (534, 14, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB филиаллари, банкоматлар, ходимлар ва интернет инфратузилмаси', 'SQB филиаллари: 2 та | Банкоматлар: 8 та | Бошқа банклар: 5 та | Банк ходимлари: 72 нафар | Маҳалла банкирлари: 30 нафар (40 аёл, 32 эркак) | Интернет: 2021: 70%/15 Мбит → 2023: 85%/25 Мбит → 2025: 95%/50 Мбит', TRUE, 'SQB', 'Интернет қоплами 70% дан 95% га ошган — рақамли хизматларни кенгайтириш учун яхши асос. Банкоматлар сонини ошириш ва мобил банкинг хизматларини кенгайтириш орқали мижозлар қулайлигини янада яхшилаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (535, 14, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', '«Ҳар бир оила — тадбиркор» давлат дастури шартлари', 'Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Дастур камбағал оилаларга тадбиркорлик бошлаш учун имконият яратади. Аммо 18% фоиз ставкаси юқори — имтиёзли ставкалар ва субсидиялар орқали оилаларга қўшимча ёрдам кўрсатиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (536, 14, 31, 4, '4', '«HAMROH» дастури', '«HAMROH» гаровсиз кредит дастури шартлари', 'Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'Гаровсиз кредит дастури кичик тадбиркорлар учун муҳим молиявий восита. 70% кафиллик банклар учун хавфни камайтиради ва кредит олиш имконини кенгайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (537, 14, 32, 5, '5', 'Юқори технологик кичик саноат зоналари', 'Туманда юқори технологик ишлаб чиқариш йўналишлари ва лойиҳа портфели', 'Йўналиш: Электроника, фармацевтика, мебелсозлик | Имконият: «Vertical Industry» (кўп қаватли саноат) | Лойиҳа портфели: 15 та (35 млрд, 150 иш ўрни)', TRUE, 'SQB / Туман ҳокимияти', 'Мирзо Улуғбек туманида ер танқис, шу боис мавжуд саноат зоналарида юқори технологик ва ихчам ишлаб чиқаришни йўлга қўйиш керак. «Vertical Industry» концепцияси чекланган ер ресурсларидан самарали фойдаланиш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (538, 14, 33, 5, '5', 'Таълим ва интеллектуал хизматлар хаби', 'Туманда таълим ва интеллектуал хизматлар ривожлантириш имкониятлари', 'Потенциал: Инҳа, Амити ва бошқа нуфузли ОТМлар талабалари | Йўналиш: IT-аутсорсинг, лойиҳалаш, консалтинг | Қамров: Ёшлар ва талабалар бандлиги', TRUE, 'Статистика бўлими', 'Туманни «Education City» бренди остида ривожлантириш лозим. ОТМлар яқинида коворкинг марказлари ва стартап инкубаторларини ташкил этиш тавсия этилади. Талабаларнинг ишлаб чиқариш ва хизмат кўрсатиш соҳаларига жалб қилиниши туман иқтисодиётини кучайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (539, 14, 34, 5, '5', 'Микролойиҳалар ва маҳаллабай тадбиркорлик', 'Микролойиҳалар орқали маҳаллабай тадбиркорликни ривожлантириш режаси', 'Режа (2025): 3 000 та (6 000 иш ўрни) | Банк кредити: 120 млрд сўм | Йўналиш: Хизмат кўрсатиш, чакана савдо, умумий овқатланиш', TRUE, 'SQB Ички маълумотлари', 'Туман ихтисослашуви савдо ва сервисга йўналтирилганлигини ҳисобга олиб, «Бизнесга биринчи қадам» орқали кичик хизмат кўрсатиш нуқталарини кўпайтириш керак. Ҳар бир маҳаллада камида 1 та янги хизмат нуқтаси ташкил этиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (540, 14, 35, 5, '5', 'Урбанизация ва чакана савдо ритейли', 'Туман аҳоли зичлиги ва савдо инфратузилмаси имкониятлари', 'Аҳоли: 337,1 минг (2025 прогноз) | Зичлик: 483 киши/км² | SWOT кучли: Савдо ва транспорт тугуни', TRUE, 'Туман ҳокимияти', '«Street Retail» концепциясини ривожлантириш ва савдо объектларини 24/7 иш режимига ўтказиш орқали маҳаллий бюджет тушумларини 15-20% га ошириш имкони мавжуд. Юқори аҳоли зичлиги чакана савдо ва хизматлар учун катта бозор яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (541, 14, 36, 5, '5', 'Импорт ўрнини босувчи маҳсулотлар', 'Туманда импорт ўрнини босувчи маҳсулотлар ишлаб чиқариш имкониятлари', 'Дефицит: Қурилиш материаллари, мебел, пластик идишлар | Ечим: Лойиҳа фабрикаси механизми', TRUE, 'Лойиҳа фабрикаси', 'Кичик саноат технопаркларида имтиёзли шартлар яратиш зарур. Импорт ўрнини босувчи маҳсулотлар ишлаб чиқариш туман иқтисодиётини мустаҳкамлайди ва валюта тежалишига олиб келади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (542, 14, 37, 5, '5', 'Яшил энергия ва самарадорлик', 'Туманда яшил энергия ва энергия самарадорлигини ошириш имкониятлари', 'Инфратузилма: 2025 да янги трансформаторлар ва йўл таъмири | Имконият: Таннархни 10-15% камайтириш', TRUE, 'Туман статистика бўлими / SQB', 'Йирик савдо марказлари ва банклар томида қуёш панелларини ўрнатиш бўйича «Energy Service» компанияларини жалб қилиш лозим. Яшил энергия ечимлари туман инфратузилмасини модернизация қилиш ва операцион харажатларни камайтириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (543, 14, 38, 5, '5', 'Ишсизлик юқори маҳаллаларни фаол ҳудудга айлантириш', 'Ишсизлик юқори маҳаллаларда иқтисодий фаолликни ошириш чоралари', 'Маҳалла тикувчилик кластери | ОТМ талабаларини стартапга жалб этиш | Микролойиҳалар орқали сервис нуқталарини кўпайтириш', TRUE, 'Туман ҳокимияти', 'Маҳалла тикувчилик кластери ва ОТМ талабаларини стартапга жалб этиш орқали иккита йўналишда бандликни ошириш мумкин. Микролойиҳалар орқали сервис нуқталарини кўпайтириш маҳаллий даромадни ошириш учун самарали восита.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (544, 14, 39, 6, '6', 'Туман рейтингини ошириш', 'Туманнинг шаҳар туманлари рейтингидаги ўрни ва мақсадлар', 'Ҳолат: 12 та тумандан 9-ўрин | Мақсад: 2026 якуни билан топ-5 га кириш | Драйвер: Жон бошига саноат ва ЯҲМ ҳажмини ошириш (2025: 26,5 млн сўм)', TRUE, 'SQB ва мониторинг', 'Паст кўрсаткичларга сабаб омилларни (ишсизлик ва инвестиция ҳажми) манзилли бартараф этиш, маҳалла кесимида «ўсиш нуқталари» белгилаш керак. 9-ўриндан топ-5 га кириш учун саноат ва хизмат кўрсатиш соҳаларида сифат ўзгаришлар зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (545, 14, 40, 6, '6', 'Молиявий воситалар ва банк сектори', 'Туман банк инфратузилмаси ва молиявий воситалар', 'Банклар: 2 та SQB филиали + 5 та бошқа | Ходимлар: 65 нафар банк ходими | Янги восита: «Бизнесга биринчи қадам» микроқарзлари', TRUE, 'Марказий банк', 'Банк филиалларини «Лойиҳа маркази» сифатида ишлатиш. Маҳаллий банкирлар институтини фаоллаштириш лозим. «Бизнесга биринчи қадам» микроқарзлари кичик тадбиркорларни қўллаб-қувватлаш учун самарали механизм.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (546, 14, 41, 6, '6', 'Инсон капитали ва бандлик', 'Туман аҳоли ўсиши ва бандлик стратегияси', 'Аҳоли ўсиши: Йиллик +10-15 минг | Меҳнат ресурслари: Хизмат соҳаси устувор', TRUE, 'Бандлик маркази', '1 800 та оғир оилани «Лойиҳа фабрикаси» орқали кичик бизнесга йўналтириш, субсидия ва микрокредит бериш тавсия этилади. Аҳоли тез ўсаётганлиги сабабли бандлик дастурларини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (547, 14, 42, 6, '6', 'Коммунал ва йўл инфратузилмаси', 'Туман коммунал инфратузилмаси ва йўл таъмирлаш устуворликлари', 'Устуворлик: Янги трансформаторлар ва йўл таъмирлаш | Манба: Маҳаллий бюджет ва давлат дастурлари', TRUE, 'Инфратузилма бошқармаси', 'Инфратузилма лойиҳаларини бизнес объектлари жойлашувига қараб оптималлаштириш. «Тайёр коммуникация» тизимини яратиш орқали янги корхоналар учун улаш харажатларини камайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (548, 14, 43, 6, '6', 'Стратегик устунликлар', 'Туманнинг SWOT таҳлили асосидаги стратегик устунликлар', 'Устунлик 1: Транспорт тугуни | Устунлик 2: Савдо фаоллиги | Устунлик 3: Инсон капитали', TRUE, 'СИ таҳлили', 'Учта устунликни «Ақлли савдо ва логистика» (Smart Retail & Logistics) хабида бирлаштириш. Талабаларни IT-ечимлар ишлаб чиқиш учун жалб қилиш орқали инсон капиталидан самарали фойдаланиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (549, 14, 44, 6, '6', 'Стратегик якун: 2026-2027 мақсадлари', 'Туман учун 2026-2027 йилларга мўлжалланган стратегик мақсадлар', 'Савдо ва сервис хаби (Савдо-хизмат кластери) | Юқори технологик саноат (Электроника, фармацевтика) | Таълим ва интеллектуал хизматлар («Education City» бренди)', TRUE, 'Ҳокимият / СИ таҳлили', 'Мирзо Улуғбек тумани учун «Ақлли шаҳар» моделини таклиф этамиз. Бунда савдо-хизмат, юқори технологик ишлаб чиқариш ва таълим интеграцияси асосида 2027 йилгача шаҳарнинг топ-5 туманлар қаторига кириш реал мақсад.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
