INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (48, 15, 'Хонадон', 57547, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (550, 15, 1, 1, '1', 'Макроиқтисодий кўрсаткичлар', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Саноат: 13 760,4 млрд сўм (+148,2%) | Бозор хизматлари: 18 866,5 млрд сўм | Саноат динамикаси индекси: 110,1 | Хизматлар динамикаси индекси: 102,4 | Экспорт: 242 минг $ | Импорт: 533,8 минг $ | Устувор 3 тармоқ: Саноат, Савдо, Хизмат кўрсатиш', TRUE, 'Туман статистика бўлими', 'Саноат ҳажми 2024 йилга нисбатан 2,2 баравар ўсган (6 293 → 13 760 млрд сўм) — бу жуда юқори суръат. Импортга боғлиқлик 7,8 баравар ошган (экспорт/импорт нисбати 1:2,2). Импорт ўрнини босиш стратегияси зарур: маҳаллий хомашёни қайта ишлаш кластерларига инвестиция йўналтириш. Хизматлар улуши юқори бўлгани учун логистика ва савдо-сервис инфратузилмасини кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (551, 15, 2, 1, '1', 'Шаҳар иқтисодиётининг 4 та драйвери', 'Учтепа тумани устувор тармоқлари ва ривожланиш йўналишлари', 'Драйвер 1 — Чакана савдо: 7 523,6 млрд сўм | Драйвер 2 — Бозор хизматлари: 18 866,5 млрд сўм | Драйвер 3 — Саноат: 13 760,4 млрд (йирик: 8 708 + кичик: 5 052) | Драйвер 4 — Микро-тадбиркорлик: 3 000 та лойиҳа, 6 000 иш ўрни, 120 млрд сўм', TRUE, 'Туман ҳокимияти', '4 та драйвердан 3 таси истеъмолга йўналтирилган — бу ички талабга боғлиқлик хавфини оширади. Учтепа СИТИ лойиҳаси (250 млн $, 2027-2030) доирасида саноат кластери ташкил этилса, чакана савдога боғлиқлик камайиб, меҳнат самарадорлиги ошади. Маҳаллий банкирлар 2024 да 16 тадан 2025 да 30 тага етган — микро-драйверни кучайтириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (552, 15, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '2021-2025 йиллар давомида саноат ҳажми ва ўсиш суръати', 'Саноат ҳажми (млрд сўм): 2021: 4 743,6 | 2022: 5 430,0 | 2023: 4 953,3 | 2024: 6 293,3 | 2025: 13 760,4 | Ўсиш (%): 2021: 105,1 | 2022: 105,6 | 2023: 108,8 | 2024: 110,4 | 2025: 148,2 | Йирик корхоналар (2025): 8 708 млрд (63%) | Кичик бизнес (2025): 5 052,4 млрд (37%)', TRUE, 'Туман статистика бўлими', '5 йилда саноат ҳажми 2,9 баравар ўсган. 2025 йилда 2,2 баравар сакраш жуда ғайриоддий — йирик корхоналар 2024→2025 да 3,2 бараварга ошган. Кичик бизнес барқарор ўсаётгани (+40%) ижобий — оилавий тадбиркорлик кредитларини кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (553, 15, 4, 1, '1', 'Маҳаллий бюджет ва молиявий ҳолат', 'Туман бюджет даромадлари ва солиқ тушумлари', 'Маҳаллий бюджет (млрд сўм): 2021: 157,4 | 2022: 163,3 | 2023: 169,8 | 2024: 189,3 | 2025: 182,3 | Контингент (млрд): 2021: 1 392,5 | 2022: 1 237,4 | 2023: 1 011,8 | 2024: 1 367,3 | 2025: 1 420,2 | Солиқ прогнози (млрд): 2021: 53,1 | 2022: 59,3 | 2023: 65,3 | 2024: 72,9 | 2025: 82,0 | Иш ҳақи фонди (2025): 325 млрд сўм (+78%)', TRUE, 'Туман молия бўлими / SQB', 'NPL 5 йил давомида доимий ўсган (4,3% → 6,8%, +58%) — хавотирли тренд. Кредитлаш сифатини қайта кўриб чиқиш, гаров механизмларини кучайтириш шошилинч. 2025 йилда бюджет пасайиши (189,3 → 182,3) контингент бюджет ўсаётгани билан номутаносиб. Норасмий секторда 12,6 млрд сўм йўқотиляпти — расмийлаштириш дастурлари орқали бюджетни 5-7% га ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (554, 15, 5, 1, '1', 'Ажратилган кредитлар', 'SQB ва бошқа манбалардан молиялаштириш ҳажми', 'Кредит портфели (млрд сўм): 2021: 642,8 | 2022: 651,6 | 2023: 668,9 | 2024: 674,5 | 2025: 699,6 | Кичик бизнес (млрд): 2021: 286,6 | 2022: 290,9 | 2023: 321,5 | 2024: 365,0 | 2025: 380,9 | NPL: 2021: 4,3% | 2022: 4,8% | 2023: 5,2% | 2024: 6,1% | 2025: 6,8% | Банк: SQB 2 филиал, 8 банкомат, 5 та бошқа банк | Маҳаллий банкирлар: 30 та | ТТИ (2025): 1 400 минг $ (3,1 баравар ўсган)', TRUE, 'SQB ички маълумотлар', 'Кредит портфели ўсиш суръати жуда паст (+8,8% за 5 йил) — саноат 190% ўсган шароитда банк-иқтисодиёт боғлиқлиги сустлашган. NPL параллел 58% га ошгани сифат муаммосини очиб беради. 2026 режаси (300 млрд) амалдаги портфелнинг 43% га тенг — NPL ни тушириш учун кредит бериш жараёнида риск баҳолашни кучайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (555, 15, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Цифровой фаоллик индекси — қидирув трендлари асосидаги иқтисодий сигнал', 'Google Trends индекси: Марказий гуруҳ ҳисоблайди | Аҳоли ва бизнес кутишлари (2025): Ижобий 68%, Салбий 20%, Нейтрал 15% | Ижобий кутишлар тренди 2021→2025: 52% → 68% (+16 б.п.) | Шошилинч муаммо: Аҳоли идрокида «Ишсизлик» юқори (расмий 4,3%, ҳақиқий 6,9%)', TRUE, 'SQB Аналитика', 'Аҳоли кутишлари сўрови жуда ижобий тренд кўрсатади — 5 йилда ижобий баҳолаш 16 б.п. га ошган. Лекин аҳоли ишсизликни юқори деб баҳолаяпти, гарчи расмий кўрсаткич 4,3% бўлса ҳам — ёшлар ишсизлиги 1 504 кишини ташкил этади. Коммуникация стратегияси орқали реал ютуқларни аҳолига тушунтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (556, 15, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолининг тоза ичимлик сув билан таъминланганлик даражаси (%)', 'Таъминланганлик (%): 2021: 98,0 | 2022: 99,2 | 2023: 99,7 | 2024: 99,3 | 2025: 100,0 | Канализация тармоғи: 95% | Суғориш каналлари бетонлаш: 80% | Суғориладиган ер: 300 га', TRUE, 'Сув хўжалиги', '2025 йилда 100% таъминланганликка эришилган — аъло натижа. Энди диққат сифатга қаратилиши керак: сув босими, 24/7 узлуксизлик. Канализация тармоғи 95% — қолган 5% (айниқса оғир тоифадаги 4 та маҳаллада) учун мақсадли лойиҳа зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (557, 15, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Қаттиқ қопламали йўллар улуши ва йирик лойиҳалар', 'Асфальтланган йўллар: 100% (2021-2025) | Йўллар узунлиги: 180-300 км | Темир йўл стансиясигача: 8 км | Вилоят марказигача: 9,2 км | А-378 автомагистрали: мавжуд эмас | 2026 қарори: Йўлларни таъмирлаш', TRUE, 'Йўл хўжалиги', '100% асфальтланганлик яхши, аммо аҳоли зичлиги 1 083 киши/км² ва тирбандлик SWOT таҳдиди — йўл кенгайтириш ва алтернатив маршрутлар устувор вазифа. 2026 режасидаги «йўлларни таъмирлаш» лойиҳасига аниқ KPI (км, бюджет, муддат) белгилаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (558, 15, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр узилишлари, модернизация эҳтиёжи ва газ таъминоти', 'Электр узилишлари: 1 марта/ой (барча йиллар) | Газ билан таъминланганлик: 100% | Трансформаторлар эскирган: 25% | Линиялар алмаштириш: 40% | 2026 қарори: Янги трансформатор яратиш', TRUE, 'Электр тармоқлари', '1 марта/ой узилиш кўрсаткичи яхши, лекин тармоқ ҳолати ташвишли: 40% линия ва 25% трансформатор модернизацияга муҳтож. Саноат 2,2 баравар ўсган шароитда 2-3 йил ичида тизим жиддий муаммога дуч келиши мумкин. Учтепа СИТИ лойиҳаси учун алоҳида электр таъминот манбаи лойиҳалаш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (559, 15, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Туман ер фонди тузилмаси ва фойдаланиш', 'Умумий майдон: 2 808 гектар | Аҳоли зичлиги: 1 083 киши/км² | Экин ва яйлов: мавжуд эмас (шаҳар типидаги туман) | Фойдали қазилмалар: 0 та | Саноат зонаси ер фойдаланиш: 70,2% | Саноат зонаси (2025): 2 корхона, 700 иш ўрни', TRUE, 'Кадастр агентлиги', 'Учтепа — соф урбанлашган туман (1 083 киши/км²). Ер интенсивлаштириш стратегияси зарур: кўп қаватли ишлаб чиқариш, mixed-use development. Саноат зонаси 70,2% банд — қолган 29,8% (тахм. 250 га) потенциал 4-5 та янги корхона ва 1 500-2 000 иш ўрни.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (560, 15, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Йўловчи ва юк ташиш ҳажмлари', 'Юк/йўловчи айланмаси (минг): 2021: 236 028,1 | 2022: 158 208,4 | 2023: 136 938,6 | 2024: 152 235,6 | 2025: 113 268,0 | Вилоят марказигача: 9,2 км | Темир йўл стансиясигача: 8 км | SWOT таҳдиди: Тирбандлик', TRUE, 'Туман статистика бўлими', 'Жамоат транспорти айланмаси 5 йилда 52% га пасайган — жуда салбий тренд. Сабаблари: шахсий автомобил ошиши, инфратузилма эскириши. Метро/BRT линияларини кенгайтириш (Учтепа Тошкентга яқин), электр автобус лойиҳаси тавсия этилади. Учтепа СИТИ лойиҳасига интеграциялашган транспорт зудлик билан киритилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (561, 15, 12, 2, '2', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик (%)', 'Қамров (%): 2021: 52,0 | 2022: 55,5 | 2023: 56,6 | 2024: 60,5 | 2025: 65,1 | Мактаб юкламаси: 1 смена 40 та, 2 смена 25 та | Оилалар: 63 678 | Хонадонлар: 57 547 | Бола нафақаси олувчилар: 2 499 та оила', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', 'МТТ қамрови 5 йилда +13,1 б.п. ошган — ижобий, лекин қолган 34,9% қамров ташқарисида. Республика мақсади 100% (2030) — тезлаштириш зарур. Ҳар йили 4-5 та янги МТТ очиш, айниқса оғир тоифадаги маҳаллаларда. 2-сменада 25 та мактаб ишлаётгани сиғим муаммоси кўрсаткичи.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (562, 15, 13, 3, '3', 'Меҳнат ресурслари', 'Инсон капитали ва меҳнат салоҳияти динамикаси', 'Меҳнат ресурслари (киши): 2021: 168 863 | 2022: 164 120 | 2023: 156 483 | 2024: 158 120 | 2025: 147 200 | Ўзгариш 2024→2025: −10 920 (−6,9%) | 5 йилда: −21 663 (−12,8%)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари 5 йилда 12,8% га камайган — бу аҳолининг меҳнатга лаёқатли қисмини ишга жалб қилишни кучайтириш зарурлигини кўрсатади. Айниқса аёллар бандлигига эътиборни қаратиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (563, 15, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва норасмий бандлик', 'Банд аҳоли (2025): 98 600 киши (−4,7%) | Қайтган мигрантлар (2025): 2 875 киши (+8,3%) | Норасмий секторда бандлик (2021): 9 633 киши', TRUE, 'Бандлик маркази / ИИВ миграция', 'Бандликни ошириш учун маҳалла даражасида талаб юқори касблар рўйхатини шакллантириб, қисқа муддатли ўқув дастурларини кенгайтириш керак. Кичик хизматлар, савдо ва ишлаб чиқаришда тез иш ўрни яратадиган лойиҳаларни қўллаб-қувватлаш самарали бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (564, 15, 15, 3, '3', 'Ишсизлик кўрсаткичлари', '13 118 нафар ишсиз (4,3%)', 'Ишсизлик (%): 2021: 6,3 | 2022: 5,8 | 2023: 5,3 | 2024: 4,5 | 2025: 4,3 | Ишсизлар сони (2025): 13 118 киши (−3,4%) | Мақсад: 2027 йилгача 2% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизлик 5 йилда 6,3% дан 4,3% га камайган — ижобий тренд. 2% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим.', 13118, 4.3, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (565, 15, 16, 3, '3', 'Камбағаллик кўрсаткичлари', '5 057 та камбағал оила (1,9%)', 'Камбағаллик (%): 2021: 8,3 | 2022: 8,1 | 2023: 7,8 | 2024: 7,4 | 2025: 1,9 | Камбағал оилалар (2025): 5 057 та (−2,8%) | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Статистика бўлими / МФЙ', 'Камбағаллик 5 йилда 8,3% дан 1,9% га тушгани жиддий натижа. Қолган 5 057 та оилага мақсадли микрокредит ва субсидия пакети шакллантириб, барқарор даромад манбаини яратишга эътиборни қаратиш зарур.', 5057, 1.9, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (566, 15, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва ўртача маош динамикаси', 'Ёшлар ишсизлиги (16-30 ёш): 1 504 киши | Аёллар ишсизлиги: 9 798 киши (74,7%) | Эркаклар ишсизлиги: 13,8%', TRUE, 'Бандлик маркази', 'Ишсизлар таркибида аёллар 74,7% ни ташкил этади — бу жуда юқори. Ёшлар ишсизлиги 1 504 киши. Дуал таълим ва тезкор қайта тайёрлаш дастурлари орқали ёшларни расмий бандликка кўпроқ жалб қилиш, аёллар учун маҳалла кесимида касбга йўналтириш дастурлари тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (567, 15, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлаш', 'Аёллар ишсизлиги: 9 798 киши (74,7%) | Бола нафақаси олувчилар: 2 499 та оила | Кам таъминланган оилалар: 5 057 та', TRUE, 'Бандлик маркази', 'Аёллар ишсизлик таркибида 74,7% ни ташкил этиши жиддий муаммо. Маҳалла кесимида касбга йўналтириш дастурлари ва имтиёзли молиялаштириш орқали бу трендни тўхтатиш тавсия этилади. «HAMROH» дастури орқали хотин-қизлар тадбиркорлигини қўллаб-қувватлаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (568, 15, 19, 3, '3', 'Учтепа туманидаги олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', '', FALSE, '', '', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (569, 15, 20, 3, '3', 'Учтепа туманидаги техникумлар', 'Касб-ҳунар таълим муассасалари', '', FALSE, '', '', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (570, 15, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури (Учтепа филиали қамрови — 100%) | «Сунъий интеллект куни» — ҳар чоршанба | Онлайн ўқитиш тизими жорий (LMS) | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Учтепа филиали ходимларининг СИ саводхонлигини ошириш орқали мижозларга кредит ажратишда скоринг таҳлилларини тезлаштириш мумкин. NPL 6,8% га етганини ҳисобга олиб, СИ асосидаги риск баҳолаш модулини жорий этиш энг устувор вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (571, 15, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', 'Учтепа тумани стратегик ривожланиш режасини тузишда раҳбарларнинг СИ воситаларидан фойдаланиши маълумотлар асосида қарор қабул қилиш тезлигини 3 баробар оширади. Маҳалла банкирларига мижознинг кредит лаёқатини СИ орқали олдиндан баҳолаш кўникмаларини бериш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (572, 15, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'СИ таҳлили: кўникма ва қизиқиш аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури | Тадбиркорлик: бизнес-режа + микрокредит | Касб: тайёр иш ўринларига йўналтириш', TRUE, 'SQB', 'СИ платформаси орқали ҳар бир фуқаро индивидуал баҳоланади. Мақсад: 80% иштирокчи 3 ой ичида даромадли фаолиятга ўтади. 13 118 ишсиз ва 9 798 аёлни мақсадли СИ тренинг дастурларига жалб қилиш энг самарали чора.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (573, 15, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради. NPL 6,8% бўлгани учун кредит скоринги ва мониторинг модулларини фаоллаштириш алоҳида муҳим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (574, 15, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари ва тоифаланиши', 'Жами маҳаллалар: 60 та | Савдо ва хизмат: 52 та МФЙ (87%) | Саноат: 8 та МФЙ (13%) | Типология: Оғир 4, Ўрта 24, Енгил 30', TRUE, 'МФЙ агентлиги', 'Маҳалла ихтисослашуви таркибида савдо ва хизмат 87% — шу сегментда рақамли савдо, логистика ва сервис сифат стандартларини жорий этиш керак. Саноатга ихтисослашган 8 та МФЙда кичик кооперация асосида даромадни ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (575, 15, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Иқтисодий ўсишни таъминловчи асосий тармоқлар', 'Жами: 1 та драйвер сектор | 1-сектор — Савдо ва хизмат кўрсатиш', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторни алоҳида эмас, «ишлаб чиқариш + савдо + хизмат» занжирида боғлаш керак. Саноатга мўлжалланган 8 та маҳалла потенциалидан фойдаланиб, тайёр маҳсулотни бозорга чиқариш ва онлайн сотув каналларини кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (576, 15, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Амалга оширилаётган инвестиция лойиҳалари', '2025 йил: 3 000 та лойиҳа, 6 000 иш ўрни, 120 млрд сўм | 2024 йил: 1 800 та лойиҳа, 3 600 иш ўрни, 100 млрд сўм | Ўзгариш: +1 200 та (+66,7%)', TRUE, 'SQB / Туман ҳокимияти', '3 000 та микролойиҳа орқали 6 000 та иш ўрни яратилган. NPL ошиб бораётгани (4,3% → 6,8%) инобатга олиниб, банкирлар вазифалари: лойиҳани скоринг, кредит расмийлаштиришда ёрдам, лойиҳа мониторинг, молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (577, 15, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Бандликни таъминлаш бўйича манзилли чоралар', 'Оғир тоифа: 4 та МФЙ | Ўрта тоифа: 24 та МФЙ | Енгил тоифа: 30 та МФЙ | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 4 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (578, 15, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'SQB филиаллари: 2 та | Банкоматлар: 8 та | Бошқа банклар: 5 та | Банк ходимлари: 72 нафар | Маҳалла банкирлари: 30 та (40 аёл, 32 эркак) | Рақамли платформалар: SQB Mobile, SQB Business, SQB AI Advisor', TRUE, 'SQB', 'Маҳалла банкирлари 2024 йилда 16 тадан 2025 да 30 тага ошган — ижобий тренд. Интернет қоплами юқори бўлгани учун SQB Mobile ва AI Advisor платформаларини фаол тарғиб қилиш орқали рақамли хизматлар улушини ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (579, 15, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. 5 057 та камбағал оилага мақсадли микрокредит ажратиш орқали камбағаллик даражасини янада камайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (580, 15, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'Аёллар ишсизлик таркибида 74,7% (9 798 киши) ни ташкил этганини ҳисобга олиб, HAMROH дастурини Учтепа туманида энг устувор молиявий восита сифатида фаоллаштириш зарур. Маҳалла банкирлари орқали аёлларни актив жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (581, 15, 32, 5, '5', '«Uchtepa City» мега-лойиҳаси', 'Инвестиция ва урбанизация салоҳияти', 'Инвестиция: 250 млн $ (2027-2030) | Йўналиш: Замонавий турар-жой ва бизнес мажмуалари | Имконият: Туман марказий қисмини реновация | Инвестиция: Хорижий ва маҳаллий ТТИ', TRUE, 'Туман ҳокимияти', '«Uchtepa City» лойиҳаси туман иқтисодиёти учун драйвер бўлиши керак. Нафақат уй-жой, балки юқори технологик офис майдонлари ва «А» классдаги савдо марказларини ташкил этиш орқали юқори даромадли иш ўринларини яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (582, 15, 33, 5, '5', 'Саноат 2.0: Кескин ўсиш суръати', '2025 йилда ишлаб чиқариш ҳажмининг 148% га ўсиши', 'Саноат маҳсулотлари (2025): 13,7 трлн сўм | Ўсиш: +48,2% (2024 йилга нисбатан) | Асосий драйвер: Енгил саноат ва қурилиш материаллари | Янги лойиҳалар: 15 та', TRUE, 'Статистика бўлими', 'Саноат ҳажми 6,3 трлн дан 13,7 трлн сўмгача кескин сакраш кутилмоқда. «Кичик саноат зоналари»ни вертикал (кўп қаватли) кўринишда ташкил этиш ва юқори қўшилган қийматли маҳсулотлар экспортини йўлга қўйиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (583, 15, 34, 5, '5', '«Гастрономик Учтепа» ва тунги иқтисодиёт', 'Лутфий ва Фарҳод кўчаларини 24/7 хизмат кўрсатиш зонасига айлантириш', 'Иш режими: 24/7 | Лойиҳа: «Таомлар кўчаси» (Food Street) ва бренд дўконлар | Имконият: Туман ичидаги истеъмол ҳажмини ошириш | Натижа: Хизматлар соҳасида +15-20% ўсиш', TRUE, 'Туман ҳокимияти', 'Учтепа — аҳоли зич яшайдиган «ётоқхона тумани». Тунги иқтисодиётни ривожлантириш (хавфсиз овқатланиш ва дам олиш масканлари) орқали аҳолининг маблағларини туманнинг ўзида қолдириш ва янги иш ўринлари яратиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (584, 15, 35, 5, '5', '«Фозилтепа» ва маданий мерос туризми', 'Учтепанинг қадимий тарихини туристик маҳсулотга айлантириш', 'Давр: V-XII асрлар | Лойиҳа: Археологик парк ва музейлаштириш | Мақсад: Маҳаллий ва хорижий туристлар оқимини яратиш | Ҳолат: Реновация ва ободонлаштириш талаб этилади', TRUE, 'Фанлар академияси', 'Фозилтепа ёдгорлигини «очиқ осмон остидаги музей»га айлантириш ва шаҳар туристик маршрутига киритиш лозим. Бу туманга фақат «савдо маркази» деб эмас, балки тарихий манзил сифатида қараш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (585, 15, 36, 5, '5', 'Агро-саноат: Озиқ-овқат хавфсизлиги', 'Гўшт ва сут маҳсулотларини қайта ишлаш кластерлари', 'Лойиҳалар портфели: 30 млрд сўм | Лойиҳалар сони: 15 та | Ихтисослашув: Тайёр ярим тайёр маҳсулотлар (полуфабрикатлар) | Истеъмолчи: 63 мингта оила ва Тошкент бозорлари', TRUE, 'SQB / Лойиҳа фабрикаси', 'Лойиҳа фабрикаси доирасида озиқ-овқат саноатига урғу бериш мақсадга мувофиқ. Тумандаги йирик бозорлар (Фарҳод, Ўрикзор яқинлиги) тайёр сотиш бозори. Импорт ўрнини босувчи сифатли маҳсулотлар ишлаб чиқаришни қўллаб-қувватлаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (586, 15, 37, 5, '5', 'Демографик дивиденд: Юқори истеъмол қуввати', 'Аҳоли зичлиги — тайёр бизнес экотизими', 'Аҳоли зичлиги: 1 083 киши/км² | Аҳоли: 305,8 минг киши | Оилалар: 63,6 мингта | Потенциал: Таълим ва тиббиёт хизматларига юқори талаб', TRUE, 'Статистика бўлими', 'Юқори зичлик — ҳар бир квадрат метрдан юқори даромад олиш имкониятидир. Хусусий боғчалар, соғломлаштириш марказлари ва таълим курсларига бўлган талаб тўлиқ қондирилмаган. Бу соҳаларга инвестиция энг кам хавфли (low-risk) бизнес ҳисобланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (587, 15, 38, 5, '5', 'Ишсизлик юқори маҳаллаларни фаол ҳудудга айлантириш', 'Ишсизлик юқори маҳаллаларни ривожлантириш режаси', 'Ишсизлар (2025): 13 118 киши | Таркиб: аёллар 74,7% (9 798), ёшлар 11,5% (1 504), эркаклар 13,8% | Кредит маҳсулотлари: Микрокредит, Оилавий тадбиркорлик, Давлат субсидияси, Автокредит, Ипотека, Бизнесга биринчи қадам | Мақсад: 2027 йилгача 2% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '4 та маҳаллада ишсизлик юқори, асосий улуши аёллар (74,7%). «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2-3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (588, 15, 39, 6, '6', 'Стратегик йўналиш: Сервис ва Савдо', 'Учтепа туманининг асосий ихтисослашуви', 'Туман иқтисодиёти: хизматлар соҳасига (60%+) боғланган | Режа: Савдо ва хизмат кўрсатиш соҳасини рақамлаштириш | Онлайн савдо платформаларини кенгайтириш | Сервис сифатини халқаро стандартларга олиб чиқиш', TRUE, 'Туман ҳокимияти', 'Учтепа иқтисодиётининг 60% дан ортиғи хизматлар соҳасига боғланган — бу шаҳар тумани учун табиий ихтисослашув. Рақамлаштириш ва онлайн савдо платформалари орқали сервис сифатини ошириш энг устувор вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (589, 15, 40, 6, '6', 'Инвестициявий драйвер: Учтепа Сити', 'Туман қиёфасини ўзгартирувчи йирик лойиҳа', 'Инвестиция: 250 млн $ | Мақсад: Инвестиция оқимини 3 баробар ошириш | Режа: 2025 йил якунига қадар лойиҳа-смета ҳужжатларини якунлаш | Инфратузилма: Электр, йўл тайёрлаш', TRUE, 'Туман ҳокимияти', '250 млн долларлик лойиҳа туманга инвестиция оқимини 3 баробар оширади. Лойиҳа-смета ҳужжатларини якунлаш ва инфратузилмани (электр, йўл) тайёрлаш 2025 йил якунигача устувор вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (590, 15, 41, 6, '6', 'Саноатни модернизация қилиш', 'Ишлаб чиқариш ҳажмининг 13,7 трлн сўмга етиши', 'Саноат ўсиши: 148% | Солиқ базаси: мустаҳкамланмоқда | Режа: Енгил саноат ва озиқ-овқатда «брендинг» | Экспорт: МДҲ ва Европа бозорларига чиқиш', TRUE, 'Статистика бўлими', 'Саноат ўсиши (148%) туманнинг солиқ базасини мустаҳкамлайди. Енгил саноат ва озиқ-овқат соҳасида «брендинг» ва экспорт географиясини кенгайтириш (МДҲ ва Европа бозорлари) тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (591, 15, 42, 6, '6', 'Инфратузилма ва Энергия', '24/7 режимда ишлаш учун ресурслар билан таъминлаш', 'Электр ва газ: юклама юқори | Режа: Янги трансформаторлар ўрнатиш | Қуёш панеллари: энергия мустақиллигини 15-20% га ошириш | Линиялар: 40% модернизация талаб', TRUE, 'Инфратузилма бошқармаси', 'Электр ва газ таъминотидаги юклама юқори — янги трансформаторлар ва қуёш панелларини ўрнатиш орқали энергия мустақиллигини 15-20% га ошириш мумкин. 40% линия модернизация талаб қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (592, 15, 43, 6, '6', 'Лойиҳа фабрикаси механизми', 'Банк ва тадбиркор ҳамкорлиги', 'Мақсадлар: иш ўрни, даромад, импорт ўрнини босиш | Режа: Ҳар бир маҳаллада камида 2 та янги микро-лойиҳа | «Бизнесга биринчи қадам» дастурини фаоллаштириш', TRUE, 'SQB / Лойиҳа фабрикаси', 'Лойиҳаларнинг 3 та асосий мақсади: иш ўрни, даромад, импорт ўрнини босиш. Ҳар бир маҳаллада камида 2 тадан янги микро-лойиҳаларни ишга тушириш ва «Бизнесга биринчи қадам» дастурини фаоллаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (593, 15, 44, 6, '6', 'Стратегик якун: «Ақлли туман» концепцияси', 'Учтепани юқори технологияли ва қулай яшаш ҳудудига айлантириш', 'Smart City технологиялари жорий этиш | Жамоат транспортини оптималлаштириш | Яшил ҳудудларни кенгайтириш | Давлат хизматларини тўлиқ электрон шаклга ўтказиш', TRUE, 'Ҳокимият / СИ таҳлили', 'Аҳоли зичлиги юқорилиги «Smart City» технологияларини жорий этиш учун қулай муҳит яратади. Жамоат транспортини оптималлаштириш, яшил ҳудудларни кенгайтириш ва давлат хизматларини электрон шаклга ўтказиш — 2027 йилгача асосий мақсадлар.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
