INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (594, 16, 1, 1, '1', 'Иқтисодий фаоллик', 'Саноат, хизматлар, чакана товар айланмаси, экспорт ва импорт ҳажми', 'Саноат ҳажми: 4 133,7 млрд сўм (2021 йил: 1 900,7 млрд сўм, 2,1 баробар ўсиш) | Хизматлар ҳажми: 883,2 млрд сўм (2021 йил: 350,2 млрд сўм, 2,5 баробар ўсиш) | Чакана товар айланмаси: 336,4 млрд сўм (2021 йил: 163,2 млрд сўм, 2,1 баробар ўсиш) | Экспорт ҳажми: 13,7 млн доллар, ўсиш суръати 302% | Импорт ҳажми: 65 млн доллар, ўсиш суръати 97,5%', TRUE, 'Туман статистика бўлими', 'Хонобод туманида барча иқтисодий кўрсаткичлар 2021 йилдан 2 баробардан ортиқ ўсган. Хизматлар соҳаси энг юқори ўсишга эга (2,5 баробар). Экспорт 302% ўсган бўлса-да, импорт (65 млн $) экспортдан (13,7 млн $) 4,7 баробар юқори — импорт ўрнини босиш стратегик вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (595, 16, 2, 1, '1', 'Тадбиркорлик субъектлари', 'Рўйхатдан ўтган тадбиркорлар сони ва тармоқлар бўйича тақсимоти', 'Жами рўйхатдан ўтган тадбиркорлар сони: 808 та | Савдо ва хизмат кўрсатиш: 353 та | Туризм хизматлари: 180 та | Саноат: 201 та | Қурилиш: 45 та | Қишлоқ хўжалиги: 29 та', TRUE, 'Туман статистика бўлими', '808 та тадбиркордан энг катта улуш савдо ва хизмат кўрсатишда (353 та, 43,7%). Саноат (201 та, 24,9%) ва туризм (180 та, 22,3%) ҳам салмоқли. Қишлоқ хўжалиги (29 та, 3,6%) энг кам — аграр тадбиркорликни рағбатлантириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (596, 16, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '2021-2025 йиллардаги ҳажм ва ўсиш суръати', 'Саноат ишлаб чиқариш ҳажми (млрд сўм): 2021: 1 900,7 | 2022: 2 491,4 | 2023: 2 986,1 | 2024: 3 201,3 | 2025: 4 133,7 | Саноат ўсиш суръати (%): 2021: 108,4 | 2022: 106,3 | 2023: 103,7 | 2024: 103,6 | 2025: 108,3', TRUE, 'Туман статистика бўлими', 'Саноат ҳажми 5 йилда 1 900,7 дан 4 133,7 млрд сўмга (2,2 баробар) ўсган. Ўсиш суръати 2023-2024 йилларда секинлашган (103,7-103,6%), аммо 2025 йилда 108,3% га қайта тикланган. Барқарор ўсишни давом эттириш учун саноат диверсификацияси ва экспортга йўналтирилган ишлаб чиқаришни кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (597, 16, 4, 1, '1', 'Маҳаллий бюджет ва молиявий ҳолат', 'Шаҳар бюджет даромадлари ва солиқ тушумлари', 'Бюджет даромадлари (млрд сўм): 2021: 49,0 | 2022: 110,0 | 2023: 218,3 | 2024: 258,6 | 2025: 215,3 | Контингент бюджет (2025): 366,0 млрд сўм', TRUE, 'Шаҳар молия бўлими', '2025 йилда бюджет тушумларида бироз пасайиш кузатилган, контингент бюджет режаси (366 млрд) юқори. 2026 йилда солиқ базасини кенгайтириш ва янги 619 та корхонанинг тўлиқ қувватда ишлашини таъминлаш орқали даромадларни қайта тиклаш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (598, 16, 5, 1, '1', 'Ажратилган кредитлар', 'Жами ажратилган кредитлар динамикаси (млрд сўм)', 'Жами ажратилган кредитлар (млрд сўм): 2021: 72 | 2022: 95 | 2023: 123 | 2024: 139 | 2025: 217', TRUE, 'SQB ички маълумотлар', 'Кредитлар ҳажми 5 йилда 72 млрд дан 217 млрд сўмга (3 баробар) ўсган. 2025 йилдаги кескин ўсиш (+56%) тадбиркорликка талаб ортганини кўрсатади. Кредитларни экспортга йўналтирилган лойиҳаларга мақсадли тақсимлаш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (599, 16, 6, 1, '1', 'Асосий капиталга инвестициялар', 'Инвестициялар, иш ҳақи, миграция ва ижобий кутишлар', 'Жами: 869,4 млрд сўм инвестиция | Марказлашган манбалар: 14,9 млрд сўм | Марказлашмаган манбалар: 854,5 млрд сўм | Ўртача ойлик иш ҳақи: 5 млн сўм | Кўчиб келганлар: 351 киши | Кўчиб кетганлар: 210 киши | Аҳоли ва бизнес ижобий кутиш: 72%', TRUE, 'Туман статистика бўлими', 'Асосий капиталга инвестициялар 869,4 млрд сўмни ташкил этиб, шундан 98,3% марказлашмаган манбалар ҳисобидан. Миграция сальдоси ижобий (+141 киши) — туман аҳоли учун жозибадор. Аҳолининг 72% ижобий кутишга эга эканлиги иқтисодий барқарорлик белгиси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (600, 16, 7, 1, '1', 'Экспорт таркиби', 'Экспорт маҳсулотлари тармоқлар бўйича тақсимоти', 'Турли хил тайёр маҳсулотлар: 6 476 минг доллар | Машиналар ва транспорт ускуналари: 3 102,4 минг доллар | Саноат маҳсулотлари: 2 534,5 минг доллар | Озиқ-овқат ва тирик ҳайвонлар: 882,1 минг доллар | Ёқилғидан ташқари ноозиқ-овқат хомашё: 238,1 минг доллар | Кимёвий моддалар ва шунга ўхшаш маҳсулотлар: 201,3 минг доллар', TRUE, 'Туман статистика бўлими', 'Экспортда тайёр маҳсулотлар (6 476 минг $) асосий улушга эга (48,3%). Машиналар ва транспорт ускуналари (3 102,4 минг $) иккинчи ўринда. Озиқ-овқат экспортини (882,1 минг $) кенгайтириш ва қўшимча қиймат яратиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (601, 16, 8, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолининг тоза ичимлик сув билан таъминланганлик даражаси (%)', 'Таъминланганлик (%): 2023: 96,5 | 2024: 100 | 2025: 100 | 2026 прогноз: 99,6%+', TRUE, 'Сув хўжалиги', '100% — республикадаги энг юқори кўрсаткичлардан бири. 2024 йилдаги пасайиш (95,5%) сабабини аниқлаш профилактик хизматни яхшилашга хизмат қилади. Рақамли сенсорларни ўрнатиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (602, 16, 9, 2, '2', 'Йўлларни таъмирланиш даражаси', 'Автомобил йўллар узунлиги ва ички йўлларнинг таъмирланганлик даражаси', 'Автомобил йўллар узунлиги: 113,4 км | Ички йўлларнинг таъмирланганлик даражаси (%): 2023: 65 | 2024: 73 | 2025: 100', TRUE, 'Йўл хўжалиги', 'Ички йўллар таъмирланганлиги 2023 йилдаги 65% дан 2025 йилда 100% га етган — тўлиқ қамров таъминланган. 113,4 км автомобил йўлларни сифатли ҳолатда сақлаб қолиш ва профилактик таъмирлаш режасини шакллантириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (603, 16, 10, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр тармоқлари, трансформаторлар ва модернизация режаси', 'Электр тармоқлари узунлиги: 334,8 км | Трансформатор сони: 179 та | Электр узилишлари: 0,5-1 марта/ой | Кейинги 3 йилда трансформатор янгиланади: 24 та (13%) | Кейинги 3 йилда янги тармоқ тортилади: 21 км (6,2%) | Интернет қамрови: 100%, 128 Мбит/сек', TRUE, 'Электр тармоқлари', '334,8 км тармоқ ва 179 та трансформатор мавжуд. Узилишлар минимал (0,5-1 марта/ой). 3 йилда 24 та трансформатор (13%) янгиланиши ва 21 км (6,2%) янги тармоқ тортилиши режалаштирилган. Интернет 100% қамровда. Саноат зоналари учун қувватни ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (604, 16, 11, 2, '2', 'Шаҳар ер тоифаси', 'Шаҳар ер фонди тузилмаси ва қишлоқ хўжалиги ерлари', 'Жами ер майдони: 3 623 га | Суғориладиган майдон: 1 386 га | Жами қишлоқ хўжалигида фойдаланилади: 1 034 га | Экин ерлар: 748 га | Кўп йиллик дарахтзорлар: 136 га | Бўз ерлар: 14 га | Пичанзор яйловлар: 136 га', TRUE, 'Кадастр агентлиги', '3 623 га ер майдонидан 1 034 га (28,5%) қишлоқ хўжалигида фойдаланилмоқда. Суғориладиган майдон (1 386 га) умумий ердан 38,3% ни ташкил этади. Экин ерлар (748 га) асосий улушга эга. Ердан самарали фойдаланиш учун бўз ерларни (14 га) ишга солиш ва дарахтзорларни кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (605, 16, 12, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Транспорт қамрови динамикаси', 'Жамоат транспорти қамрови (%): 2023: 86,8 | 2024: 93,0 | 2025: 96,5 | 2026 прогноз: 98,5 | Вилоят марказигача: 92 км', TRUE, 'Туман статистика бўлими', '96,5% қамров Хонободнинг вилоятдаги йирик туристик ва сервис маркази эканлигини тасдиқлайди. Транспорт тизимини рақамлаштириш ва электробуслар сонини ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (606, 16, 13, 2, '2', 'Ижтимоий соҳа', 'Мактаблар, ўқувчилар, мактаб юкламаси ва соғлиқни сақлаш муассасалари', 'Жами мактаблар сони: 8 та | Мактаб ўқувчилар сони: 7,7 минг | Умумтаълим мактабларининг юкламаси (смена) 2025 йил: 0,9 | Соғлиқни сақлаш муассасалари: 4 та (640 ўрин) | Стационар даволаниш масканлари: 1 та (100 ўрин)', TRUE, 'Мактабгача ва мактаб таълими вазирлиги / Соғлиқни сақлаш бўлими', '8 та мактабда 7,7 минг ўқувчи таълим олмоқда, смена юкламаси 0,9 — мактаб қувватлари етарли. Соғлиқни сақлаш тизимида 4 та муассаса (640 ўрин) ва 1 та стационар (100 ўрин) мавжуд. Аҳоли сонига нисбатан тиббий ўринлар етарлилигини мониторинг қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (607, 16, 14, 2, '2', 'Мактабгача таълим қамрови', 'Боғча ёшидаги болалар сони ва МТБ га қамраб олиш даражаси', 'Боғча ёшидаги болалар сони: 3 117 нафар | МТБ га қамраб олиш даражаси (%): 2021: 77 | 2022: 79 | 2023: 85,2 | 2024: 90 | 2025: 91,4', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', 'МТБ га қамраб олиш даражаси 5 йилда 77% дан 91,4% гача (+14,4 пп) барқарор ўсган. 3 117 нафар боғча ёшидаги боладан 8,6% ҳали қамраб олинмаган. 2026 йилда 95%+ қамровга эришиш учун янги оилавий ва нодавлат МТТларни кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (608, 16, 15, 2, '2', 'Ўрта таълим', 'Коллежлар, ўқувчилар сони ва гуруҳлар', 'Хонобод шаҳарда 2 та коллеж мавжуд | Қуввати: 1 570 нафар | Ўқувчилар сони: 1 253 нафар (1-курс: 766, 2-курс: 457, 3-курс: 30) | Гуруҳлар сони: 52 та', TRUE, 'Мактабгача ва мактаб таълими бўлими', '2 та коллежда 1 253 ўқувчи таълим олмоқда — қуввати 1 570 нафар бўлиб, бандлик даражаси 79,8%. 3-курс ўқувчилари атиги 30 нафар бўлиши битирувчилар сонининг камлигини кўрсатади. Тавсия: коллежларни маҳаллий меҳнат бозори талабларига мослаштириш, айниқса қурилиш, хизмат кўрсатиш ва қишлоқ хўжалиги йўналишларида дуал таълим дастурларини кенгайтириш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (609, 16, 16, 3, '3', 'Меҳнат ресурслари', 'Инсон капитали ва меҳнат салоҳияти динамикаси', 'Меҳнат ресурслари (минг киши): 2021: 24,3 | 2022: 23,5 | 2023: 23,2 | 2024: 24 | 2025: 26,6 | Ўзгариш 2024→2025: +2,6 (+10,8%)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор ўсиб бормоқда. Бандликни ошириш учун маҳалла даражасида савдо, туризм ва енгил саноат соҳалари бўйича қисқа муддатли ўқув дастурларини кенгайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (610, 16, 17, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва норасмий бандлик', 'Банд аҳоли (2025): 17718 киши (+3,1%) | Миграцияда (2025): 409 киши (+33,3%) | Норасмий секторда бандлик (2021): 7520 киши | Бандлиги таъминланадиган ахоли (2026): 5851 киши', TRUE, 'Бандлик маркази / ИИВ миграция', 'Бандликни ошириш учун маҳалла даражасида талаб юқори касблар рўйхатини шакллантириш керак. Норасмий секторни расмийлаштириш орқали солиқ базасини кенгайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (611, 16, 18, 3, '3', 'Ишсизлик кўрсаткичлари', '879 нафар ишсиз (4,7%)', 'Расмий ишсизлик (2025): 4,7% | Ишсизлар сони (2025): 879 киши | Ишсизлик тренди: 7,5% → 6,8% → 5,8% → 5,2% → 4,7% | Мақсад: 2027 йилгача 2,4% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2027 йилгача 2,4% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим.', 879, 4.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (612, 16, 19, 3, '3', 'Камбағаллик кўрсаткичлари', '635 та камбағал оила (3,5%)', 'Камбағаллик (2025): 3,5% | Камбағал оилалар (2025): 635 та | Тренд: 17,8% → 14,7% → 11,2% → 6,2% → 3,5% | Мақсад: 2026 йил охиригача 2.0% га тушириш', TRUE, 'Статистика бўлими / Ижтимоий ҳимоя', 'Камбағалликни янада камайтириш учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. Ижтимоий ёрдамни иш ва микролойиҳалар билан боғлаш зарур.', 635, 3.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (613, 16, 20, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва маош динамикаси', '2026 йилда даромади ошириладиган ёшлар: 78 нафар | Доимий ишга жойлаштириш: 50 нафар | Тадбиркор жалб қилиш: 7 нафар | Кредит ажратиш ҳисобига: 16 нафар | Қайта касбга ўқитиш: 5 нафар | Техникумлар: 59 дона | Ёшлар ишсизлиги (16-30 ёш): 1 489 киши | Аёллар ишсизлиги: 3 426 киши | Ўртача ойлик маош (минг сўм): 2 960 → 5 040 (+70%)', TRUE, 'Бандлик маркази', 'Ёшлар ишсизлиги 1 489 кишини ташкил этади. Дуал таълим ва тезкор қайта тайёрлаш дастурлари орқали ёшларни расмий бандликка жалб қилиш мумкин. Маош 70% га ошгани ижобий тренд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (614, 16, 21, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар ишсизлиги ва ижтимоий қўллаб-қувватлаш', '2026 йил режаси: 184 та хотин-қиз | Доимий ишга жойлаштириш: 52 нафар | Ўзини-ўзи банд: 7 нафар | Маҳалла банкирлари (аёл): 8 нафар | Ишсиз аёллар: 3 426 та | Бола нафақаси олувчи: 4 634 оила', TRUE, 'Оила ва хотин-қизлар бўлими', '2026 режаси 184 киши — бор салоҳиятнинг атиги 5%. Ишсиз 3 426 аёлни инобатга олганда 1 500+ кишига чиқиш реал. Маҳалла даражасида 68 та «аёллар ишбилармонлик кластери» ташкил этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (615, 16, 22, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури (Хонобод филиали қамрови — 100%) | «Сунъий интеллект куни» — ҳар чоршанба | Онлайн ўқитиш тизими жорий (LMS) | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Хонобод филиали ходимларининг СИ саводхонлигини ошириш орқали мижозларга кредит ажратишда скоринг таҳлилларини тезлаштириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (616, 16, 23, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', 'Раҳбарларнинг СИ воситаларидан фойдаланиши маълумотлар асосида қарор қабул қилиш тезлигини 3 баробар оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (617, 16, 24, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш ва тадбиркорликка тайёрлаш', 'СИ таҳлили: кўникма ва қизиқиш аниқланади | СИ-ментор (чатбот): индивидуал ўқув дастури | Тадбиркорлик: бизнес-режа + микрокредит | Касб: тайёр иш ўринларига йўналтириш', TRUE, 'SQB', 'СИ платформаси орқали ҳар бир фуқаро индивидуал баҳоланади. 879 нафар ишсиз ва 226 нафар аёлни мақсадли СИ тренинг дастурларига жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (618, 16, 25, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти | Бизнес-режа генератори | Кредит мослаштириш | KPI мониторинг | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', '«SQB AI Advisor» маҳалла банкири ва тадбиркорларга СИ ёрдамини беради. NPL 2,1% га тушганини сақлаб қолиш учун кредит скоринги модулини фаоллаштириш муҳим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (619, 16, 26, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари ва тоифаланиши', 'Жами: 15 та маҳалла | Типология: Оғир 2 та (Навоий, Оқ тоғ), Ўрта 6 та, Аъло 7 та | Савдо ва хизмат: 6 та МФЙ | Туризм хизмати: 4 та МФЙ | Ишлаб чиқариш: 2 та МФЙ | Деҳқончилик: 3 та МФЙ', TRUE, 'МФЙ агентлиги', '15 та маҳалладан 6 таси савдо ва хизматга, 4 таси туризмга ихтисослашган. Оғир тоифадаги 2 та маҳаллага (Навоий, Оқ тоғ) алоҳида «интенсив ёрдам пакети» тайёрлаш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (620, 16, 27, 4, '4', 'Маҳалла драйвер секторлари', 'Иқтисодий ўсишни таъминловчи асосий тармоқлар', 'Жами: 4 та драйвер сектор | Савдо ва хизмат: 40% | Туризм: 26,6% | Қишлоқ хўжалиги: 20% | Ишлаб чиқариш: 13,4%', TRUE, 'МФЙ агентлиги / SQB', 'Савдо ва хизмат кўрсатиш (40%) асосий драйвер. Туризм (26,6%) иккинчи ўринда — Хонободнинг туристик салоҳиятини янада ривожлантириш имконияти юқори. Ишлаб чиқариш (13,4%) улушини ошириш учун кичик саноат лойиҳаларини кўпайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (621, 16, 28, 4, '4', '2026 йилда ташкил этиладиган лойиҳалар', 'Ҳудудий инвестиция лойиҳалари ва микролойиҳалар', 'Жами: 159 та лойиҳа, 1 153 та иш ўрни | Ҳудудий инвестиция лойиҳалари: 9 та | Қиймати: 44,7 млн доллар | Иш ўрни: 841 нафар | Микролойиҳалар: 150 та | Иш ўринлари: 312 нафар | Маҳаллалар: 15 та | Қиймати: 6,6 млрд сўм', TRUE, 'SQB / Шаҳар ҳокимияти', '2026 йилда 9 та ҳудудий инвестиция лойиҳаси (44,7 млн $, 841 иш ўрни) ва 150 та микролойиҳа (6,6 млрд сўм, 312 иш ўрни) режалаштирилган. Жами 1 153 та янги иш ўрни яратилади. Микролойиҳаларни 15 та маҳаллага тенг тақсимлаш ва лойиҳа скорингини кучайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (622, 16, 29, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (623, 16, 30, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. 3 426 ишсиз аёлни жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (624, 16, 31, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Ижтимоий реестрдаги оилалар ва ишсизлик юқори МФЙлар', 'Жами: 635 та оила ижтимоий реестрда (3,5%) | Истиқлол МФЙ: 66 та (7,6%) | Хон тоғ МФЙ: 53 та (7,3%) | Мустақиллик МФЙ: 54 та (6,5%) | 2026 йилда янги иш ўринлари: 5 851 нафар | Мақсад: ишсизлик даражасини 2,4% га тушириш', TRUE, 'SQB / МФЙ агентлиги', 'Ижтимоий реестрда 635 та оила (3,5%) мавжуд. Энг оғир аҳвол Истиқлол (7,6%), Хон тоғ (7,3%) ва Мустақиллик (6,5%) МФЙларида. 2026 йилда 5 851 та янги иш ўрни яратиш ва ишсизликни 2,4% га тушириш учун шу 3 та МФЙга манзилли бандлик дастурларини йўналтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (625, 16, 32, 5, '5', 'Тадбиркорлик саноат зонаси', 'Мавжуд саноат зонаси — инвестиция ва иш ўрни яратиш платформаси', 'Лойиҳалар: 69 та | Банд иш ўрни: 960 та | Ер фойдаланиш: 80% | Зона ихтисослашуви: Ишлаб чиқариш, енгил саноат | 2026 саноат лойиҳалари: 36 та, 455,9 млрд сўм, 839 иш ўрни', TRUE, 'Ҳокимият / SQB', 'Саноат зонасидан 80% фойдаланилаётган. Қолган 20% ни «Индустриал лофт» (кўп қаватли ишлаб чиқариш) моделига ўтиш орқали 2-3 ҳисса самарадор ишлатиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (626, 16, 33, 5, '5', 'Импорт ўрнини босиш салоҳияти', 'Импорт экспортдан 4 баравар юқори — ички ишлаб чиқариш учун катта бозор', 'Импорт-экспорт фарқи: 262,4 млн $ | Импорт: 351,3 млн $ | Экспорт: 88,9 млн $ | Дефицит товарлар: гўшт, сут, қурилиш материаллари, дорилар, кимёвий маҳсулотлар | КПИ мақсади: 30% импорт ўрнини босиш', TRUE, 'Ҳокимият / Статистика', 'Йилига $262 млн лик импорт-экспорт дисбаланси — тайёр ички бозор. 5 та дефицит товардан 3 таси маҳаллий ресурслар асосида ишлаб чиқарилиши мумкин. 2027 йилгача импорт ўрнини босишни 25% гача ошириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (627, 16, 34, 5, '5', 'Демографик зичлик ва ички истеъмол бозори', 'Ҳар 1 км² га 3 733 киши — республикадаги энг юқори кўрсаткичлардан бири', 'Аҳоли: 319,6 минг киши | Аҳоли зичлиги: 3 733 киши/км² | Оилалар: 87 141 та | Хонадонлар: 69 085 та | Жон бошига саноат: 29,7 млн сўм | Товар айланмаси: 6 589 млрд сўм', TRUE, 'stat.uz', 'Юқори зичлик — тайёр, компакт ва харид қобилияти мавжуд истеъмол бозори. E-commerce, маҳаллий брендлар ва экспресс-логистика учун идеал шароит.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (628, 16, 35, 5, '5', 'Хотин-қизлар тадбиркорлиги ва бандлиги', 'Аёллар даромадини ошириш дастури', '2026 режа: 184 та хотин-қиз | 1-чорак амалда: 39 та | Доимий иш: 52 та | Ўзини-ўзи банд: 7 та | Ишсиз аёллар: 3 426 та | Бола нафақаси олувчи: 4 634 оила', TRUE, 'Оила ва хотин-қизлар бўлими / SQB', 'Режа 184 киши — салоҳиятнинг атиги 5%. 1 500+ кишига чиқиш реал. 68 та «аёллар кластери» ташкил этиш, уй-ишлаб чиқариш учун кредитни 100 млрд сўмгача ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (629, 16, 36, 5, '5', 'Микролойиҳалар фабрикаси', 'Аҳоли тадбиркорлигини оммавийлаштириш', 'Микролойиҳалар: 800 та | Иш ўринлари: 1 320 та | Молиялаштириш: 35,5 млрд сўм | 2026 режа: 680 та янги микролойиҳа | Оилавий тадбиркорлик NPL: 32% (юқори) | Маҳаллий банкирлар: 14 та (8 аёл, 6 эркак)', TRUE, 'SQB / Ҳокимият', 'Микролойиҳалар самарали иш ўрни механизми. Аммо NPL 32% — огоҳлантирувчи. Банкирларни 68 тагача кенгайтириш, AI скоринг тизими жорий этиш ва кредит олишдан олдин 8 соатлик мажбурий тайёргарлик модули тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (630, 16, 37, 5, '5', 'ТТИ ўсиши ва инвестиция', '5 йилда 26 баравар ўсиш — инвесторлар учун жозибадор шаҳар', 'ТТИ (2025): 332 млн $ | 2021 йил: 12,2 млн $ | Ўсиш: 27 баравар (5 йилда) | 2026 режа: 415 млрд сўм | 2031 режа: 700 млрд сўм', TRUE, 'Ҳокимият / Марказий банк', 'ТТИнинг 12,2 → 332 млн $ га ўсиши рекорд. Бироқ диверсификация зарур. «Хонобод Инвест Промоушн» офисини ташкил этиш ва 15 та корхонани «экспорт чемпионлари» дастурига киритиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (631, 16, 38, 5, '5', 'Туризм ва ҳунармандчилик инфратузилмаси', '3 та туристик маршрут ва маҳаллаларда туризм', 'Инвестиция (2027 режа): 42 млрд сўм | 1-маршрут: Янги чорсу | 2-маршрут: Туғонбоши, Ғиштли масжид, Азиз тепа, Оқ олтин | 3-маршрут: Исфара, Калвак, Қаймоқ гузарлари | Туризмда иш ўрни (2026): 327 та | 2027 режа: 420 та', TRUE, 'Ҳокимият', '42 млрд сўм инвестиция катализатор. 3 та маршрутни рақамли харита + AR/QR-аудиогид билан таъминлаш, «Хонобод тажриба пакети» остида ҳунармандчилик + гастротуризм + агротуризмни бирлаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (632, 16, 39, 5, '5', 'Стратегик ҳолат ва ривожланиш ўрни', 'Вилоят бўйича 2-ўрин — барқарор ўсиш тренди', 'Рейтинг: 2-ўрин (19 шаҳар орасида) | Саноат ўсиши (2021→2025): 5 145 → 9 410 (+83%) | Камбағаллик: 10,1% → 4,2% | Маош: 2 960 → 5 040 минг сўм | Аҳоли: 259,7 → 319,6 минг | Ижобий кутиш: 72%', TRUE, 'SQB / Ҳокимият', 'Хонобод 4 йилда иқтисодиётни 83% га оширди, камбағалликни 10,1% дан 4,2% гача тушурди. Кейинги босқичда «миқдорий ўсиш»дан «сифат ўсиши»га ўтиш керак. Мақсад: 2030 йилга вилоятда 1-ўрин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (633, 16, 40, 6, '6', 'Қисқа муддатли режа (0-12 ой) — 2026 йил', '679 миллиард сўмлик лойиҳалар портфели', 'Жами лойиҳалар: 59 та | Умумий инвестиция: 679,2 млрд сўм | Иш ўрни режаси: 1 154 та | Саноат: 36 та, 455,9 млрд | Хизмат: 23 та, 223,1 млрд | Микролойиҳалар: 680 та | 2026 кредит режа: 890 млрд сўм', TRUE, 'Ҳокимият / SQB', '2026 «лойиҳаларни ишга тушириш йили» сифатида эълон қилиниши керак. «Бир дарча» хизмати — 21 кун ичида ер/рухсат/кредит пакети. 890 млрд кредит режасидан 30% кичик бизнесга ажратилиши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (634, 16, 41, 6, '6', 'Ўрта муддатли режа (1-3 йил) — 2026-2028', 'Туризм кластери, саноат зонаси кенгайтириш, экспорт экспансияси', '3 та стратегик йўналиш | 1: Туризм маршрутлари (42 млрд сўм) | 2: Саноат зонаси кенгайтириш + 10 та импорт ўрнини босувчи лойиҳа | 3: Экспорт 88,9 → 150 млн $ | Инвестиция (2028): 450 млрд сўм | Иш ўрни (2027): 2 520 та', TRUE, 'Ҳокимият', 'Ўрта муддатли калит — «импорт → экспорт» бурилиши. 351 млн $ импортдан камида 60 млн $ ни маҳаллий ишлаб чиқариш билан алмаштириш + экспортни 150 млн $ гача ошириш ташқи савдо балансини 150 млн $ га яхшилайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (635, 16, 42, 6, '6', 'Узоқ муддатли режа (3-5 йил) — 2029-2031', 'Логистика маркази ва Технопарк', '2 та мега-лойиҳа | 1: «Қуруқ порт» логистика маркази (темир йўлга 1,1 км) | 2: IT/Технопарк — рақамли иқтисодиёт маркази | 2031 инвестиция: 700 млрд сўм | КЎК→Йирик: 15 → 50 корхона | ТТИ мақсад (2031): 500 млн $ | Интернет: 100%, 128 Мбит/с', TRUE, 'Ҳокимият / SQB', 'Темир йўл станциясигача 1,1 км — Хонободни «Қуруқ порт» ва транзит логистика ҳуби сифатида ривожлантириш учун стратегик имконият. Технопарк 2 000+ юқори ҳақ тўланадиган иш ўрни яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (636, 16, 43, 6, '6', 'КПИ мақсадлари 2026', 'Аниқ рақамли мақсадлар', '6 та КПИ | Янги иш ўринлари: 2 364 та | Янги тадбиркорлар: 700 та | Аҳоли даромади ўсиши: +17% | Импорт ўрнини босиш: 30% | Кредит қайтариш: 95,5% | NPL: 1,2%', TRUE, 'Ҳокимият', '6 та КПИ орасида NPL 2,1% → 1,2% (оилавий тадбиркорлик NPL 32% инобатга олганда амбициоз). КПИларни ҳар чоракда очиқ рейтингда чиқариш ва энг яхши/ортда қолган МФЙларга мос чора кўриш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (637, 16, 44, 6, '6', 'Инвестиция тренди ва молиявий калибрлаш 2026-2031', '415 → 700 млрд сўм — йиллик 10-12% ўсиш', '6 йиллик режа | 2026: 415 млрд | 2027: 430 млрд | 2028: 450 млрд | 2029: 500 млрд | 2030: 600 млрд | 2031: 700 млрд | Жами: ~3 095 млрд сўм', TRUE, 'Ҳокимият / SQB', '3,1 трлн сўмлик дастур учун 3 манба: банк кредитлари 45%, давлат бюджети 25%, хусусий/хорижий инвестициялар 30%. 2027 йилдан «маҳаллий облигация» чиқариш ва халқаро ташкилотлар билан лойиҳалар очиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (638, 16, 45, 6, '6', 'Маҳалла тоифалаш ва дифференциал ёндашув', '68 та МФЙ — ҳар тоифага ўз чораси', 'Жами: 68 та маҳалла | Оғир: 2 та (Янги чорсув, Мўйимуборак) | Ўрта: 7 та | Енгил: 39 та | Яхши: 20 та | Драйвер тармоқлар: Савдо, енгил саноат, туризм, хизмат | Мутахассислик: 23 та ишлаб чиқариш, 41 та савдо, 3 та чорвачилик, 1 та паррандачилик', TRUE, 'МФЙ агентлиги / SQB', 'Ҳар тоифа учун алоҳида паспорт: 2 та Оғир — «интенсив ёрдам», 7 та Ўрта — «ривожлантириш», 39 та Енгил — «мустаҳкамлаш», 20 та Яхши — «экспорт чемпионлари». Чора-тадбирларнинг 60% и 9 та муаммоли МФЙга йўналтирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
