INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (639, 18, 1, 1, '1', 'Шаҳарнинг макроиқтисодий кўрсаткичлари', 'Саноат, хизматлар ва экспорт ҳажми динамикаси (2021–2025)', 'Саноат ҳажми (млрд сўм): 2021: 1059,5 | 2022: 1387,2 | 2023: 1423,2 | 2024: 1973,7 | 2025: 3152,8 | Хизматлар ҳажми (млрд сўм): 2021: 854,6 | 2022: 958,4 | 2023: 1176,2 | 2024: 1401,8 | 2025: 2005,8 | Экспорт ҳажми (млн $): 2021: 36,1 | 2022: 67,5 | 2023: 36,9 | 2024: 114,6 | 2025: 115,7 | Янги корхоналар (2025): 282 та', TRUE, 'Статистика бўлими', '2025 йилда саноат ҳажми қарийб 60% га ўсганлиги туманнинг иқтисодий салоҳияти кескин ошганини кўрсатади. 2026 йилда ушбу суръатни сақлаб қолиш учун экспорт ҳажмини 150 млн доллардан оширишга эътибор қаратиш лозим. Хизматлар соҳасидаги 2 трлн сўмлик натижани рақамли хизматлар ҳисобига кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (640, 18, 2, 1, '1', 'Шаҳар иқтисодиётининг 4 та драйвери', 'Ихтисослашув ва тармоқлар улуши', 'Жами: 4 та драйвер | Қишлоқ хўжалиги: 48,4% (мева-сабзавот ва ғаллачилик) | Саноат: 31,5% (тўқимачилик, трикотаж, чарм-пойабзал) | Хизмат кўрсатиш: 20,1% (савдо, маиший хизмат, транспорт) | Ҳунармандчилик: пичоқчилик ва косибчилик мактаби', TRUE, 'Статистика бўлими / Ҳокимият', '2026 йилда иқтисодиётни диверсификация қилиш орқали саноат улушини ошириш зарур. Қишлоқ хўжалиги маҳсулотларини шу ернинг ўзида қайта ишлаб, тайёр озиқ-овқат саноати маҳсулотлари сифатида экспорт қилиш «драйвер» соҳалар ўртасидаги занжирни мустаҳкамлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (641, 18, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', '2021-2026 йиллар давомида саноат ҳажми ўзгариши', 'Саноат ҳажми (млрд сўм): 2021: 1059,5 | 2022: 1387,2 | 2023: 1423,2 | 2024: 1973,7 | 2025: 3152,8 | 2026 (прогноз): ~3850,0 (122% ўсиш)', TRUE, 'Статистика бўлими', '2025 йилда кичик бизнес саноатнинг асосий қисмини (3,1 трлн сўм) таъминлади. 2026 йилда саноат ўсишини таъминлаш учун йирик корхоналар ишлаб чиқариш қувватларини модернизация қилиш ва янги кичик саноат зоналарини (КСЗ) тўлиқ ишга тушириш талаб этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (642, 18, 4, 1, '1', 'Маҳаллий бюджет', 'Бюджет тушумлари динамикаси (2021–2026)', 'Бюджет тушумлари (млрд сўм): 2021: 30,2 | 2022: 38,1 | 2023: 67,1 | 2024: 82,6 | 2025: 169,3 | 2026 (прогноз): 190,0+', TRUE, 'Статистика бўлими', '2025 йилда бюджет тушумларининг кескин ошиши (169,3 млрд сўм) солиқ интизомининг яхшиланганидан далолат беради. 2026 йилда маҳаллий бюджет эркинлигини ошириш учун «Маҳаллабай» тизими орқали яширин иқтисодиётни қисқартириш ва тадбиркорларга берилган имтиёзларнинг самарадорлигини таҳлил қилиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (643, 18, 5, 1, '1', 'Ажратилган кредитлар', '2025 йил якуни бўйича кредитлаш ҳолати', 'Умумий кредитлаш: 1 622,4 млрд сўм | Давлат бюджети ҳисобидан: 285,4 млрд сўм | Микрокредитлар: 1 227 млрд сўм | Оилавий тадбиркорлик: 37 млрд сўм', TRUE, 'Марказий банк / SQB', '2026 йилда кредит сиёсатини «Loyiha fabrikasi» томонидан ишлаб чиқилган 133,7 млрд сўмлик 16 та устувор лойиҳага йўналтириш лозим. Айниқса, дефицит товарлар (сут, гўшт, қурилиш материаллари) ишлаб чиқарувчи тадбиркорларни молиялаштириш туманнинг импортга қарамлигини камайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (644, 18, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Транспорт фаоллиги ва рақамли қизиқиш кўрсаткичлари', 'Юк айланмаси: 2 118,4 минг тонна | Йўловчи ташиш: 25 209,3 минг киши | Рақамли қизиқиш: Ҳунармандчилик ва савдо бўйича қидирув сўровлари юқори', TRUE, 'Google Trends таҳлили', 'Юқори мобиллик ва юк айланмаси Шаҳрихонни водийнинг муҳим логистика хабига айлантирмоқда. 2026 йилда ҳудудий маркетплейсларни ривожлантириш ва маҳаллий маҳсулотларни онлайн реклама қилиш орқали савдо ҳажмини яна 15-20% га ошириш имконияти мавжуд.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (645, 18, 7, 2, '2', 'Ичимлик суви билан таъминланганлик', 'Аҳолини тоза ичимлик суви билан таъминлаш динамикаси (%)', 'Таъминланганлик (%): 2021: 65,0 | 2022: 75,0 | 2023: 76,0 | 2024: 80,0 | 2025: 84,0 | 2026 (прогноз): 88+ (%)', TRUE, 'Сув хўжалиги', 'Ичимлик суви билан таъминланиш даражаси барқарор ўсиб бораётгани (5 йил ичида +19%) ижобий кўрсаткич. 2026 йилда чекка маҳаллаларда янги сув тармоқларини қуришни давом эттириш ва сув исрофини камайтириш учун рақамли ҳисоблагичлар тизимини тўлиқ жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (646, 18, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси', 'Йўллар узунлиги ва асфальтланган улуши', 'Жами: Йўллар таҳлили | Йўллар узунлиги: 68 км | Асфальтланган йўллар улуши (2025): 6,2% | Суғориш каналлари бетонлаш: 35,1%', TRUE, 'Йўл хўжалиги / Ҳокимият', 'Қаттиқ қопламали йўллар улуши (6,2%) жуда паст даражада қолмоқда. Бу иқтисодий фаоллик ва логистика учун асосий тўсиқдир. 2026 йилда «Ташаббусли бюджет» ва давлат дастурлари доирасида ички йўлларни асфальтлаш ва шағаллаштириш ишларини камида 3-4 бараварга жадаллаштириш стратегик аҳамиятга эга.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (647, 18, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр тармоқлари ҳолати ва модернизация эҳтиёжи', 'Жами: Энергия таъминоти таҳлили | Электр узилишлари: Ойига ўртача 2,2 марта | Трансформаторлар: 35% эскирган | Линиялар: 25% алмаштириш зарур | Интернет қоплами: 100%, тезлик 128 Мбит/с', TRUE, 'Электр тармоқлари / Ҳокимият', 'Электр тармоқларининг эскирганлиги саноат зоналарининг тўлиқ қувватда ишлашига халақит бериши мумкин. 2026 йилда инвестиция дастурларини эскирган 35% трансформаторларни янгилашга йўналтириш ва муқобил энергия манбаларини (қуёш панеллари) саноат корхоналарига кенг жорий этиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (648, 18, 10, 2, '2', 'Ер тоифалари бўйича рўйхат', 'Ер фонди таркиби ва саноат зоналари', 'Жами: Ер ресурслари таҳлили | Умумий майдон: 28 827 га | Суғориладиган ер: 16 065 га | КСЗ: 59 та лойиҳа | Ёшлар КСЗ: 37 та лойиҳа | Ердан фойдаланиш: 100%', TRUE, 'Кадастр агентлиги / Ҳокимият', 'Саноат зоналаридаги ерлардан фойдаланиш коэффициенти 100% га етгани иқтисодий фаоллик юқорилигини кўрсатади. 2026 йилда янги саноат зоналари учун қўшимча ер майдонларини ажратиш ёки мавжудларини вертикал кенгайтириш (кўп қаватли кичик саноат бинолари) имкониятларини кўриб чиқиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (649, 18, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Транспорт инфратузилмаси ва йўловчи айланмаси', 'Вилоят марказигача: 30 км | Темир йўл станциясигача: 4 км | Йўловчи ташиш (йиллик): 25 209,3 минг киши', TRUE, 'Йўл хўжалиги / Статистика бўлими', 'Йўловчи ташиш ҳажми юқорилигини ҳисобга олиб, туман ичидаги жамоат транспорти йўналишларини маҳаллалар кесимида оптималлаштириш керак. 2026 йилда экологик тоза транспорт (электробуслар) улушини ошириш ва бекатларда рақамли таблоларни ўрнатиш йўловчилар оқимини бошқаришда самара беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (650, 18, 12, 2, '2', 'Мактабгача таълим қамрови', 'МТТга қамраб олиш даражаси динамикаси (%)', 'МТТ қамрови (%): 2023: 79,7 | 2024: 79,1 | 2025: 78,5 | 2026 (прогноз): 82,0 (%)', TRUE, 'Мактабгача ва мактаб таълими бўлими', 'Сўнгги уч йил ичида қамров даражасининг бироз пасайиши (79,7% дан 78,5% гача) аҳоли ўсиш суръатининг боғчалардаги янги ўринлар яратилиш суръатидан юқори эканлигини англатади. 2026 йилда «Loyiha fabrikasi» доирасида нодавлат МТТлар тармоғини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (651, 18, 13, 3, '3', 'Меҳнат ресурслари', 'Меҳнат ресурслари динамикаси ва бандлик кўрсаткичлари', 'Меҳнат ресурслари (минг киши): 2021: 143,7 | 2022: 148,3 | 2023: 154,6 | 2024: 160,5 | 2025: 165,8', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор ўсиб бормоқда — 2021–2025 йилларда +22,1 минг кишига кўпайди. Бандликни ошириш учун маҳалла даражасида тўқимачилик ва савдо соҳалари бўйича қисқа муддатли ўқув дастурларини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (652, 18, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Меҳнат бозори резервлари ва миграция динамикаси', 'Банд аҳоли (2025): 108 453 киши (+3,1%) | Норасмий секторда бандлик (2021): 41 183 киши | Хорижга кетган мигрантлар: 2021: 4912 | 2022: 4510 | 2023: 4430 | 2024: 4265 | 2025: 2854 (−33,1%)', TRUE, 'Бандлик маркази / ИИВ миграция', 'Бандликни ошириш учун маҳалла даражасида талаб юқори бўлган касблар рўйхатини шакллантириб, шу йўналишларда қисқа муддатли ўқув ва амалиёт дастурларини кенгайтириш керак. Норасмий секторни расмийлаштириш самарали натижа беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (653, 18, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Ишсизлик даражаси ва сонининг пасайиш тренди', 'Ишсизлик (%): 2021: 9,7 | 2022: 9,0 | 2023: 6,8 | 2024: 5,3 | 2025: 4,8 (%) | Ишсизлар сони (2025): 6 533 киши (−9,2%) | Мақсад: 2027 йилгача 2,0% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2% га тушириш учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим. Ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш зарур.', 6533, 4.8, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (654, 18, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағалликни қисқартириш динамикаси', 'Камбағаллик даражаси (2025): 2,9% (−70,1%) | Камбағал оилалар (2025): 2 220 та (−71,7%) | Кам таъминланган оилалар: 2 017 та | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Статистика бўлими / МФЙ', 'Камбағалликни 1% га тушириш учун ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши керак. Ижтимоий ёрдамни иш ва микролойиҳалар билан боғлаш, барқарор даромад манбаини яратишга эътиборни қаратиш зарур.', 2220, 2.9, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (655, 18, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '2026 йилда даромади ошириладиган ёшлар — 580 нафар', 'Жами: 580 нафар ёшлар | Доимий ишга жойлаштириш: 450 нафар | Тадбиркор жалб қилиш: 40 нафар | Кредит ажратиш ҳисобига: 40 нафар | Қайта касбга ўқитиш: 50 нафар', TRUE, 'Бандлик маркази / SQB', '580 нафар ёшлар даромадини ошириш режалаштирилган. Доимий ишга жойлаштириш (450 нафар) асосий йўналиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (656, 18, 18, 3, '3', 'Аёллар бандлигини таъминлаш ва даромадини ошириш', '2026 йилда даромади ошириладиган аёллар — 2 012 нафар', 'Жами: 2 012 нафар аёллар | Доимий ишга жойлаштириш: 341 нафар | Тадбиркор жалб қилиш: 749 нафар | Кредит ажратиш (3 млрд сўм): 749 нафар | Қайта касбга ўқитиш: 100 нафар | Ўзини ўзи банд қилиш: 69 нафар', TRUE, 'Бандлик маркази / Ижтимоий ҳимоя', '2 012 нафар аёлларнинг бандлигини таъминлаш режалаштирилган. HAMROH дастуридан фаол фойдаланиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (657, 18, 19, 4, '4', 'Маҳалла ихтисослашуви', '79 та маҳалланинг иқтисодий фаолият йўналишлари', 'Жами: 79 та маҳалла | Савдо ва хизмат: 41 та МФЙ (52%) | Ишлаб чиқариш: 23 та МФЙ (29%) | Чорвачилик: 3 та МФЙ (4%) | Паррандачилик: 1 та МФЙ (1%)', TRUE, 'МФЙ агентлиги', 'Маҳалла ихтисослашуви таркибида савдо ва хизмат улуши юқори (41/79). Ишлаб чиқаришга ихтисослашган 23 та МФЙда кичик кооперация ва қиймат занжири асосида даромадни ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (658, 18, 20, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида иқтисодий ўсишни бошқарувчи тармоқлар', 'Жами: 4 та драйвер сектор | 1: Савдо ва хизмат кўрсатиш | 2: Ҳунармандчилик | 3: Деҳқон хўжалиги | 4: Чорвачилик', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни алоҳида эмас, «ишлаб чиқариш + савдо + хизмат» занжирида боғлаш керак. Чарм-пойабзал ва ҳунармандчилик йўналишларида тайёр маҳсулотни бозорга чиқариш ва онлайн сотув каналларини кенгайтириш орқали қўшимча қийматни ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (659, 18, 21, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', '2026 йил учун режалаштирилган кредит режа ва иш ўринлари', 'Лойиҳалар сони: 790 та | Иш ўринлари: 1 374 та | Умумий қиймат: 133,7 млрд сўм | Саноат лойиҳалари: 9 та, 88,7 млрд сўм, 850 иш ўрни | Хизмат лойиҳалари: 5 та, 32,9 млрд сўм, 503 иш ўрни', TRUE, 'SQB / Шаҳар ҳокимияти', '790 та микролойиҳа режалаштирилган — умумий қиймати 133,7 млрд сўм. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа амалга оширилишини мониторинг; (4) тадбиркорларга молиявий маслаҳат.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (660, 18, 22, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 3 та оғир тоифадаги маҳалла | 1: Қумқайроқ | 2: Мустақиллик | 3: Марказ | Маҳалла типологияси: Оғир: 3 та, Ўрта: 7 та, Енгил: 39 та, Яхши: 20 та', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 3 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Аввало ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳага улаш механизмлари қўлланиши лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (661, 18, 23, 4, '4', 'SQB рақамли хизматлари', 'Банк инфратузилмаси ва маҳалла банкирлари', 'Жами банклар: 13 та | SQB филиали: 1 та | Банкоматлар: 170 та | Банк ходимлари: 104 нафар | Маҳалла банкирлари: 20 нафар (6 аёл, 14 эркак)', TRUE, 'SQB / Марказий банк', '170 та банкомат ва 13 та банк мавжудлиги рақамли хизматларни кенгайтириш учун яхши асос. Маҳалла банкирлари сонини ошириш ва аёл банкирлар улушини кўпайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (662, 18, 24, 4, '4', 'Ишсизлик юқори маҳаллаларни ривожлантириш режаси', 'Оғир тоифадаги 3 та маҳаллада бандликни таъминлаш стратегияси', 'Жами: 3 та маҳалла, оғир тоифа | Қумқайроқ, Мустақиллик, Марказ | Ишсизлар (2025): 6 533 киши | Ёшлар (16–30): 1 489 киши | Аёллар: 3 426 киши | Мақсад: 2027 йилгача 2,0% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '3 та маҳаллада ишсизлик юқори, асосий улуши аёллар (3 426). «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. Ишсиз аҳолини сегментация қилиб, 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (663, 18, 25, 4, '4', 'Сунъий интеллект куни ва ходимлар малакаси', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | «Сунъий интеллект куни» — ҳар чоршанба | Онлайн ўқитиш тизими жорий қилинди | Раҳбар ходимлар ўқувларни тўлиқ якунлади', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Ҳафталик «СИ куни» амалиёти орқали ходимлар янги технологияларни кундалик ишга татбиқ этишни ўрганмоқда. Кейинги босқичда ҳар бир бўлим учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (664, 18, 26, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ўринбосарлар — стратегия | 2-босқич: Филиал раҳбарлари — скоринг ва риск | 3-босқич: Маҳалла банкирлари — мижоз хизмати | 4-босқич: МФЙ раислари — маълумотлар таҳлили', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади: аввал ҳоким даражасида стратегик қарорлар учун СИ, кейин банк раҳбарларига скоринг ва таҳлил, сўнг маҳалла банкирларига мижоз билан ишлаш учун СИ платформа ўргатилади. Ҳар босқич 2–4 ҳафта давом этади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (665, 18, 27, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик тузиш | Кредит мослаштириш: мижозга мос маҳсулот | KPI мониторинг: маҳалла агенти самарадорлиги | Прогноз: даромадни ошириш тавсиялари', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча маҳаллаларда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (666, 18, 28, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Иштирокчи банклар: SQB ва бошқа тижорат банклари | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринг, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (667, 18, 29, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Маҳалла банкирлари орқали аёлларни фаол жалб қилиш, бизнес тренинглар ташкил этиш ва муваффақиятли намуналарни кенг оммавий таништириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (668, 18, 30, 5, '5', 'Чарм-пойабзал ва ҳунармандчиликни саноатлаштириш', 'Тарихий ҳунармандчилик брендидан йирик экспорт кластерига ўтиш', 'Асосий йўналишлар: Чарм-пойабзал ва пичоқчилик | Мавжуд ҳолат: Тарқоқ ва якка тартибдаги ишлаб чиқариш | Потенциал: МДҲ ва Марказий Осиё бозорларига экспорт', TRUE, 'Шаҳар ҳокимияти / СИ таҳлили', 'Шаҳрихоннинг анъанавий ҳунармандчилик бренди жуда кучли. Буни якка тартибдаги меҳнатдан замонавий саноат кластери тизимига ўтказиш вақти келди. Ҳунармандлар учун махсус кичик саноат зонаси яратиб, Италия ёки Туркия технологияларини олиб келишга субсидия бериш ва «Made in Shahrixon» бренди остида кафолатланган B2B экспорт каналларини очиш катта иқтисодий сакраш беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (669, 18, 31, 5, '5', 'Дефицит товарлар орқали импорт ўрнини босиш', 'Ички бозор талабини қондириш ва маҳаллий саноатни кафолатланган бозор билан таъминлаш', 'Жами: 5 та дефицит товар | 1: Парранда гўшти | 2: Сут маҳсулотлари | 3: Қурилиш материаллари | 4: Антибиотиклар ва базавий дорилар | 5: Кимёвий маҳсулотлар', TRUE, 'Савдо палатаси / SQB', 'Туманнинг ички истеъмол бозори катта, бироқ юқоридаги 5 та йўналишда жиддий дефицит мавжуд. Инвесторларга тайёр лойиҳалар (Project Factory) шаклида паррандачилик фабрикалари, сутни қайта ишлаш цехлари ва базавий қурилиш материаллари ишлаб чиқаришни таклиф қилиш орқали 100% сотилиш кафолатига эга бизнес муҳитини яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (670, 18, 32, 5, '5', 'Ультра-юқори демографик зичлик ва Service Economy', 'Аҳоли зичлиги (1 170 киши/км²) — хизмат кўрсатиш соҳаси учун идеал «қайноқ нуқта»', 'Аҳоли сони (2025): 337,3 минг киши (79 та маҳалла) | Аҳоли зичлиги: 1 170 киши/км² | Хизматлар ҳажми: Жон бошига 20,1 млн сўм', TRUE, 'Статистика бўлими', '1 км² га 1 170 киши — бу савдо ва хизмат кўрсатиш учун жуда катта ва зич истеъмол бозори. Туман марказида кўп қаватли савдо-кўнгилочар комплекслари, IT-марказлар ва 24/7 ишлайдиган хизмат кўрсатиш кўчаларини яратиш керак. Зичлик юқорилиги логистика харажатларини минималлаштириб, хизматлар рентабеллигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (671, 18, 33, 5, '5', 'Мева-сабзавотни қайта ишлаш ва Агро-логистика', 'Асосий заиф томонни энг кучли экспорт драйверига айлантириш', 'Хомашё базаси: Етиштириш ҳажми юқори | Муаммо: Қайта ишлаш даражаси паст | Ечим: Шок музлатиш, қуритиш, консервация', TRUE, 'Қишлоқ хўжалиги бўлими / СИ таҳлили', 'Мева-сабзавот етиштириш ҳажми юқори бўлса-да, қайта ишлашнинг пастлиги сабабли маҳсулот қўшимча қийматсиз сотилмоқда. Замонавий Агро-логистика хаби ва камида 3-4 та шок музлатиш ҳамда қадоқлаш корхоналарини ишга тушириш орқали даромадни 3 бараварга ошириш ва экспорт географиясини кенгайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (672, 18, 34, 5, '5', 'Транзит-логистика хаби (Темир йўл яқинлиги)', 'Темир йўл станциясигача бор-йўғи 4 км масофадан стратегик фойдаланиш', 'Темир йўл станциясигача: 4 км | Вилоят марказигача: 30 км | Йўллар узунлиги: 68 км (асосий)', TRUE, 'Шаҳар ҳокимияти', 'Темир йўл станциясининг жуда яқинлиги (4 км) Шаҳрихонни транзит-логистика марказига айлантириш имконини беради. Станция атрофида «Қуруқ порт» типидаги йирик улгуржи омборхоналар ва божхона терминаллари тармоғини яратиш орқали нафақат Шаҳрихон, балки қўшни туманларнинг ҳам юкларига хизмат кўрсатиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (673, 18, 35, 5, '5', 'Микролойиҳалар орқали NPL''ни соғломлаштириш', '32% муаммоли кредитлар хавфини тайёр бизнес-моделлар билан бартараф этиш', 'Камбағал оилалар: 7 847 (2024) → 2 220 (2025), 3,5x камайиш | Оилавий кредитлар NPL: 32% (жуда юқори) | Микролойиҳалар режаси: 790 та (SQB ва бошқа банклар)', TRUE, 'Марказий банк / SQB', 'Камбағалликни қисқартиришда зўр натижага эришилган (3,5 баравар), бироқ оилавий кредитлар NPL 32% га етган. Аҳолига шунчаки кредит бериш ўрнига, «Маҳаллий банкир» тизими орқали юқори рентабелли 790 та микролойиҳани (тайёр ускуна + бозор кафолати билан) тақдим этиш ва молиявий мониторингни кучайтириш энг устувор имкониятдир.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (674, 18, 36, 5, '5', 'Яшил энергетика ва саноат ўсишини мувофиқлаштириш', '122,2% лик саноат ўсишини барқарор энергия ва модернизация билан таъминлаш', 'Саноат ҳажми (2025): 3,15 трлн сўм (ўсиш 122,2%) | Инфратузилма: Электр тармоқлари ва трансформаторлар эскирган | Инвестиция имконияти: Саноат зоналарида қуёш панеллари', TRUE, 'Энергетика вазирлиги / Статистика бўлими', 'Шаҳрихон саноат ўсиши бўйича етакчилардан бири (122,2%), аммо эскирган инфратузилма тўсиқ бўлиши мумкин. Янги ва мавжуд саноат корхоналари учун қуёш станциялари ўрнатишни субсидиялаш тизимини яратиш керак. Бу корхоналарни энергия узилишларидан асрайди, таннархни туширади ва тармоқдаги босимни кескин камайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (675, 18, 37, 6, '6', 'Минтақавий етакчилик ва рақобатбардошлик', 'Шаҳрихон туманининг вилоят иқтисодиётидаги стратегик ўрни ва мақсади', 'Вилоятдаги ўрни: 2-ўрин (19 та ҳудуд ичида) | Жон бошига саноат: 29,7 млн сўм | Жон бошига хизматлар: 20,1 млн сўм', TRUE, 'Вилоят ҳокимияти', 'Хулоса: Шаҳрихон саноат ва иқтисодий фаоллик бўйича вилоятда мустаҳкам 2-ўринни эгаллаб турибди. Режа (2026–2027): Вилоятда 1-ўринга чиқиш учун хизматлар соҳасидаги «яширин иқтисодиёт»ни рақамлаштириш орқали легаллаштириш ҳамда йирик саноат кластерларини ишга тушириш стратегияси қабул қилиниши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (676, 18, 38, 6, '6', 'Камбағалликни кескин қисқартириш динамикаси', 'Бир йил ичида муҳтож оилалар сонини 3,5 бараварга камайтириш натижаси', '2024 йилда: 7 847 та камбағал оила | 2025 йилда: 2 220 та камбағал оила | Ишга туширилган механизм: «Маҳаллий банкир» микролойиҳалари', TRUE, 'Статистика бўлими / Ижтимоий ҳимоя', 'Хулоса: Камбағалликни қисқартиришда ўта юқори натижа қайд этилган. Режа: Қолган 2 220 оилага доимий даромад келтирувчи микролойиҳаларни (кафолатланган харид тизими билан) боғлаш ва касб-ҳунарга ўқитишни тизимли давом эттириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (677, 18, 39, 6, '6', 'Инвестиция ва Лойиҳа фабрикаси', 'Қисқа муддатли инвестиция дастури орқали саноат драйверини яратиш', 'Лойиҳалар сони: 16 та йирик лойиҳа | Умумий қиймати: 133,7 млрд сўм | Янги иш ўринлари: 1 374 та', TRUE, 'SQB / Ҳокимият', 'Хулоса: 133,7 млрд сўмлик 16 та лойиҳа туман иқтисодиёти учун янги қон вазифасини ўтайди. Режа: Инвестицияларни энг дефицит йўналишларга (паррандачилик, қурилиш материаллари, сут маҳсулотлари) йўналтириш. «Тезкор штаб» (Fast-Track) механизмини яратиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (678, 18, 40, 6, '6', 'Инфратузилмани 2026 йилги модернизация дастури', 'Саноатнинг 122% лик ўсишини энергия билан таъминлаш', 'Жами: 3 та устувор қадам | 1: Янги трансформаторлар ўрнатиш | 2: Электр тармоқ линияларини янгилаш | 3: Сув тармоқларини кенгайтириш', TRUE, 'Шаҳар ҳокимияти', 'Хулоса: Жадал саноатлашув мавжуд инфратузилмага оғир юк туширмоқда. Режа: 2026 йилги бюджет ва инвестицияларнинг салмоқли қисми базавий инфратузилмага йўналтирилиши шарт. Саноат зоналарида қуёш панеллари ўрнатишни рағбатлантирувчи тизимга ўтказиш лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (679, 18, 41, 6, '6', 'Стратегик мақсад: «Шаҳрихон — 2027»', 'Туманни Фарғона водийсининг саноат ва транзит хабига айлантириш', 'Зичлик: 1 170 киши/км² (тайёр бозор ва ишчи кучи) | Транспорт: Темир йўлгача 4 км | Саноат ўсиши: Йиллик 122,2%', TRUE, 'СИ стратегик таҳлили', 'Хулоса: Шаҳрихон аграр тумандан йирик саноат, ҳунармандчилик ва савдо-логистика марказига айланиш учун барча фундаментал асосларга эга. Режа: «Инфратузилма + Малакали кадрлар + Тадбиркорлик» учбурчаги асосида 2027 йилгача мастер-режа ишлаб чиқиш. «Қуруқ порт» зонасини яратиш ва 24/7 хизмат кўрсатиш кўчаларини ташкил этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (19, 8, 'yangiqorgon', 'Янгиқўрғон', 'Янгикурган', 'Yangiqorgon', '', 'yangiqorgon.json', TRUE, NULL, NULL, 44, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
