INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (60, 19, 'Хонадон', 49377, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (680, 19, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат ишлаб чиқариш: 579,1 млрд сўм (+19,3%) | Бозор хизматлари: 1 371 млрд сўм (+26,7%) | Саноат ўсиш суръати: 112,7% | Тармоқлар улуши: Қ/х 49%, Саноат 15%, Хизматлар 36%', TRUE, 'stat.uz', 'Саноат 2024 йилдан кейин кескин ўсиш динамикасини кўрсатмоқда (+19,3%), лекин туман иқтисодиётида қишлоқ хўжалиги улуши ҳалигача 49% — республика ўртачасидан анча юқори. Бу қайта ишлаш ва қиймат занжирини чуқурлаштириш заҳирасини билдиради. Хизматлар улуши 36% га етган, шу боис савдо-логистика ва бозор инфратузилмасига сармоя киритиш мақсадга мувофиқ. Юқори қийматли қайта ишлаш йўналишига боғлаш — Молиялаштириш ва ажратилган кредитлар билан мувофиқлашиб режалаштирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (681, 19, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Туман иқтисодиётида энг катта салмоққа эга тармоқлар ва меҳнат ресурслари', 'Жами: 4 та драйвер | 1-ўрин Қишлоқ хўжалиги: 49% улуш — туман тарихий ихтисослашуви | 2-ўрин Хизмат кўрсатиш: 36% улуш, 1 371 млрд сўм, +143% (5 йилда) | 3-ўрин Қайта ишлаш/Саноат: 15% улуш, 579,1 млрд сўм, +19,3% | 4-ўрин Қурилиш материаллари кластери: 13 корхона, 51 млрд сўм/йил, +89% | Меҳнат ресурслари: 2021 — 121,2 → 2025 — 129,1 минг киши', TRUE, 'SQB', 'Тўрт драйвернинг иккиси (қ/х ва саноат) йирик меҳнат сиғимига эга, бири (қурилиш материаллари) экспорт салоҳиятига эга. Қишлоқ хўжалигидан саноатга меҳнат миграциясини рағбатлантириш керак — банд аҳоли ва камбағаллик даражасини пасайтириш билан боғлиқ. Қурилиш материаллари кластерини алоҳида капитал эътибор маркази сифатида ажратиш мақсадга мувофиқ. Хизматлар секторини институционал қўллаб-қувватлаш — янги корхоналар фаоллигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (682, 19, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Саноат ҳажми ва индекс ўзгариши 2021–2025', '2021: 249 | 2022: 301.1 | 2023: 314.4 | 2024: 485.3 | 2025: 579.1 (млрд сўм)', TRUE, 'stat.uz', '2024 йилдаги +54,4% ўсиш — рекорд, лекин саноатнинг 100% улуши кичик бизнесга тегишли (йирик корхоналар йўқ). Бу — таркибий хавф: бир ёки иккита йирик корхона очилса, динамика янада барқарорлашади. Тавсия — ЭИЗ «Нурафшон» КСЗ ва «Бунёдкор» саноат зоналари асосида 100+ ишчили корхоналар жалб қилиш. Кичик бизнесдан йирик бизнесга ўтишни рағбатлантириш дастури — асосий восита. Шу йўналишда 2026–2028 йилларда 2-3 та «локомотив» корхона ишга туширилмаса, ўсиш сурати секинлашиши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (683, 19, 4, 1, '1', 'Маҳаллий бюджет ва молиявий ҳолат', 'Маҳаллий бюджет даромадлари ва контингент режалаштириш', 'Жами: 2025 йил даромад 164,3 млрд сўм (+90,6%) | 2021: 55,5 | 2022: 81,1 | 2023: 100 | 2024: 86,2 (-13,8%) | 2025: 164,3 | Контингент 2025: 58,3 млрд сўм | Бажарилиш фоизи 2025: 281,8% — верификация талаб қилади', TRUE, 'Молия вазирлиги', '2024 йилдаги -13,8% пасайишдан кейин 2025 даги +90,6% сакраш — туман бюджети барқарор эмаслигини билдиради. Контингент режалаштиришни 2025 йил ҳақиқий даромад асосида қайта кўриб чиқиш керак (28% ҳисоб-китоб ҳатоси — режа сифатининг муаммоси). Бюджет даромадини диверсификациялаш (саноат улушини ва аҳоли зичлиги асосида солиқ базасини кенгайтириш) — узоқ муддатда асосий йўналиш. Солиқ маъмуриятчилиги ва кичик бизнес легализацияси кучайтирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (684, 19, 5, 1, '1', 'Ажратилган кредитлар', 'Туманга ажратилган кредитлар умумий ҳажми ва портфел сифати', 'Жами: Excel да тўлиқ берилмаган | NPL муаммоли кредитлар: 2021 — 55,7% | 2022 — 34,7% | 2023 — 8,7% | 2024 — 3,7% | 2025 — 7,5% | Молиялаштириш режаси: ~64 млрд сўм (қисқа + ўрта + узоқ муддатли)', FALSE, 'SQB', 'Маълумотларни тўлдириш зарур: SQB филиалидан туман бўйича жами кредит портфели, физик/юридик шахс улуши, тармоқлар бўйича тақсимоти сўралиши керак. NPL динамикаси умуман яхши (55,7% → 3,7%), лекин 2025 йилдаги +3,8 п.п. ўсиш — диққат талаб қилади. Молиялаштириш режасининг 64 млрд сўмлик пакети 4 та драйверга мутаносиб тақсимланмаган — қишлоқ хўжалиги (49% улуш) учун алоҳида сатр кўрсатилмаган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (685, 19, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман бўйича онлайн қидирув активлиги индекси', 'Жами: марказий аналитика гуруҳи ҳисоблайди — маҳаллий маълумот мавжуд эмас | Прокси кўрсаткичлар: Интернет қоплами 2025 — 26%, тезлик 150 Мбит/с | Аҳоли ва бизнес кутишлари: ижобий 80%, нейтрал 5%, салбий 15%', FALSE, 'SQB', 'Google Trends индекси марказий аналитика гуруҳи томонидан ҳисобланганидан кейин ушбу карточка тўлдирилади. Ҳозирча, маҳаллий онлайн фаолликнинг прокси сифатида интернет қопламининг ўсиши (8% → 26%, +225% беш йилда) ва аҳоли кутишлари сўрови (80% ижобий) кўрсаткичларидан фойдаланиш мумкин. Туманнинг сайёрлигини ва тадбиркорлигини рақамли каналлар орқали тарғиб қилиш — марказий гуруҳ келгуси ҳисоботида тавсия этилиши кутилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (686, 19, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолининг тоза ичимлик сув билан таъминланганлиги', '2021: 81 | 2022: 85 | 2023: 87 | 2024: 91.5 | 2025: 92 (%)', TRUE, 'Сув хўжалиги', 'Кўрсаткич барқарор ўсиш қилмоқда, лекин 2024–2025 ўсиш сурaти кескин секинлашган (+0,5 п.п.). Бу қолган 8% — энг қийин қамраб бўлиши мумкин (узоқ маҳаллалар, тоғли минтақалар) деган сигнал. 100% га етиш учун энг кам сурaтда +1,5 п.п./йил суръатини сақлаш керак. Канализация тармоғи (1,7%) билан биргаликда комплекс лойиҳа сифатида молиялаштирилиши керак. Сув таъминоти инвестициясини аҳоли зичлиги (464,7 киши/км²) асосида приоритетлаштириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (687, 19, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Қаттиқ қопламали (асфальтланган) йўлларнинг улуши ва йўллар умумий узунлиги', '2021: 18 | 2022: 25 | 2023: 44 | 2024: 56 | 2025: 69 (%) | Йўллар узунлиги 2025: 1 346 км (+41 км) | Асфальтланган: ~929 км | Тупроқ/шағал: ~417 км (~31%)', TRUE, 'Йўл хўжалиги', 'Туман йўл инфратузилмасида беш йиллик муваффақиятли модернизация: 18% дан 69% га (+51 п.п.). 2023 йилдаги +19 п.п. сакраш — давлат дастурининг кўрсаткичи. 100% га етиш учун яна 2-3 йил мобайнида +13-15 п.п./йил суръатини сақлаш керак. Жамоат транспортидан фойдаланиш билан боғлаш — фойдаланиш ҳажми тарихан йўл сифатига боғлиқ. Маҳалла даражасида приоритет — таълим муассасаларига кетувчи йўллар.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (688, 19, 9, 2, '2', 'Электр таъминоти сифат даражаси (%)', 'Электр узилишлар частотаси ва тармоқлар модернизацияси эҳтиёжи', 'Жами: Туман инфратузилмасининг асосий хавфли нуқтаси | Электр узилишлар: 2021 — 130 → 2025 — 50 марта/ой (-61,5%) | Модернизация талаб қилувчи улуш: 2021 — 35% → 2025 — 54% (+19 п.п. ёмонлашмоқда) | Газ таъминоти: 2021 — 35% → 2025 — 38% (+3 п.п.)', TRUE, 'Электр тармоқлари', 'Узилишлар камайган бўлса-да (рисбатий яхши), физик тармоқларнинг 54% и эскирган — бу 2026–2030 даврда инцидентларнинг сонида сакраш бўлишини кутишга асос. Тавсия: модернизация дастурини бошлаш — ҳозирда йилига +1-3 п.п. ёмонлашиш суръати, бу 2030 йилга 70% эскиришни беради. Газ таъминоти 38% — республика ўртачасидан паст; қишлоқ хўжалик минтақалари учун насос-стансиялар электр узилишларидан зарар кўрмоқда. Электр сифати янги корхоналарнинг ишга тушишини бевосита чегаралаб қўяди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (689, 19, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ҳудудининг ер тоифалари бўйича тақсимоти', 'Жами: тоифалар бўйича расмий тақсимот Excel да топилмади | Умумий майдон: 525 км² (52 500 га) | Суғориладиган ер: 28 300 га (~54%) | Фойдали қазилмалар конлари: 0 | Саноат зонаси ер фойдаланиш: 78,9%', FALSE, 'Кадастр', 'Маълумотни Ер ва геодезия қўмитасининг туман бўлимидан расмий сўровнома орқали тўлдириш зарур (8 та тоифа бўйича гектарда). Мавжуд маълумот асосида: суғориладиган ер 28 300 га (54%) — ҳудуд аграр-ихтисослашган эканлигини тасдиқлайди. Аҳоли зичлиги 464,7 киши/км² — республика ўртачасидан юқори. Ушбу карточкани тўлдириш — Суғориладиган ер майдонини баҳолаш ҳамда саноат зоналари (Бунёдкор, Қораполвон, Нурафшон) учун ер ажратишда ҳал қилувчи.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (690, 19, 11, 2, '2', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳолининг жамоат транспортидан фойдаланиш улуши', 'Жами: маълумот тўлиқ берилмаган | Йўловчи ташиш ҳажми (2025): 8 770 минг йўловчи | Жон бошига: ~36,7 марта/йил (қишлоқ типига мос) | Аҳоли (2025): 239 193 киши | Юк ташиш: 1 150 минг тонна', FALSE, 'Хокимият', 'Кўрсаткични тўлдириш учун Туман транспорт бўлими / «Ўзавтотранс» филиалидан расмий маълумот сўралиши зарур. Тахминий 36,7 сафар/йил/киши — бу қишлоқ типидаги динамикага мос (республика шаҳарларида 80–150 марта). Йўллар таъмирланиш даражаси (69%) ва аҳоли зичлиги (464,7 киши/км²) асосида жамоат транспортини ривожлантириш заҳираси аниқ. 2026–2028 йилларда туман-марказ ва марказ-вилоят транспорт йўналишлари режасини ишлаб чиқиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (691, 19, 12, 2, '2', 'Мактабгача таълим қамрови', '3–6 ёшли болаларнинг мактабгача таълим муассасаларига жалб қилиниш улуши', 'Жами: маълумот тўлиқ берилмаган | Туман аҳолиси (2025): 239 193 | Хонадонлар: 49 377 | Оилалар: 69 827 | Камбағаллик: 6,2% | Тахминий 3–6 ёшли: 14 350–19 135 бола', FALSE, 'Мактабгача ва мактаб таълими вазирлиги', 'Маълумотни Туман халқ таълими бўлимидан / Мактабгача таълим бошқармасидан расмий сўровнома орқали тўлдириш зарур (МТМ сони, болалар сони, ёш гуруҳлари бўйича қамров %). Бу карточка туман инфратузилмасининг социаль қисмини баҳолашда муҳим. Юқори қамров — туман таълим инфратузилмасининг тугaллaнган ҳолат, паст қамров эса оналар бандлигини чегaралaб қўйганини билдиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (692, 19, 13, 3, '3', 'Меҳнат ресурслари', 'Жами меҳнат ресурслари сони — йиллик динамика', '2021: 121.153 | 2022: 127.653 | 2023: 126.810 | 2024: 109.668 | 2025: 129.808 (минг киши)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари 2024 йилдаги пасайишдан кейин 2025 йилда кескин ошди (+18,4%). Бандликни ошириш учун маҳалла даражасида боғдорчилик, чорвачилик ва туризм соҳалари бўйича қисқа муддатли ўқув дастурларини кенгайтириш зарур. Қайтган мигрантлар ва норасмий сектор иш кучи резерви сифатида рағбатлантирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (693, 19, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Иш ўрни яратиш ва меҳнат бозори резервлари', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 96 083 киши (+21,4%) | Қайтган мигрантлар (2025): 1 920 киши (+33,7%) | Норасмий секторда бандлик (2021): 36 200 киши | Хорижга кетган мигрантлар: 2021 — 6 812 → 2025 — 5 266 (-7,8%)', TRUE, 'Бандлик маркази', 'Қайтган мигрантлар (+33,7%) ва норасмий сектор (36 200 киши) катта иш кучи резерви ҳисобланади. Норасмий секторни расмийлаштириш ва қайтган мигрантларни маҳаллий лойиҳаларга жалб қилиш орқали бандликни ошириш мумкин. Ҳар бир МФЙда «бир маҳалла — бир драйвер йўналиш» модели орқали аниқ бандлик режасини ишлаб чиқиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (694, 19, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси ва ишсизлар сони', 'Жами: Ишсизлик кўрсаткичлари | Расмий ишсизлик (2025): 5,4% (-8,5%) | Ишсизлар сони (2025): 5 478 киши (-20,1%) | Ишсизлик тренди: 10,6% → 9,0% → 8,6% → 5,9% → 5,4% | Ёшлар (16–30): 1 753 киши | Аёллар: 2 356 киши | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Бандлик маркази', 'Ишсизлик барқарор камайиб бормоқда (10,6% → 5,4%). Аёллар ишсизлиги (2 356 киши, умумийнинг 43%) диққатга сазовор. Аёлларга мўлжалланган касб-ҳунар курслари ва микролойиҳаларга жалб механизмини кучайтириш зарур. Ёшлар ишсизлиги (32%) учун ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш керак.', 5478, 5.4, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (695, 19, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони', 'Жами: Камбағаллик кўрсаткичлари | Камбағаллик даражаси (2025): 6,2% (-12,7%) | Камбағал оилалар (2025): 3 629 та (-1,2%) | Камбағаллик тренди: 13,2% → 11,7% → 9,5% → 7,1% → 6,2% | Кам таъминланган: 3 087 та | Ижтимоий ҳимояга муҳтож: 4 838 та | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'stat.uz', 'Камбағаллик даражаси пасайяпти (13,2% → 6,2%, -53%), аммо камбағал оилалар сони 2025 йилда амалда ўзгармади (3 673 → 3 629). Ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши, ижтимоий ёрдам иш билан боғлиқ қилиниши зарур. 18 та МФЙни 2026 йилгача камбағалликдан холи қилиш мақсади учун маҳалла даражасида «Бизнес-Инкубатор» нуқтаси очиш керак.', 3629, 6.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (696, 19, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', 'Ёшлар бандлиги ва даромадини ошириш режаси', '', FALSE, 'SQB', 'Маълумот SQB ва Туман ҳокимиятидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Ёшлар даромадини ошириш учун дуал таълим, биринчи иш ўрнига субсидия ва талаб юқори касблар бўйича тезкор қайта тайёрлаш дастурларини кучайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (697, 19, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар бандлиги ва даромадини ошириш — 2026 йил режаси', '', FALSE, 'Бандлик вазирлиги', 'Маълумот Меҳнат вазирлигидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Аёллар бандлигини ошириш учун имтиёзли молиялаштириш, мос иш режими (масофавий/ярим ставка) ва маҳалла кесимида касбга йўналтириш дастурларини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (698, 19, 19, 3, '3', 'Олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Олий таълим муассасалари сони ва қуввати — кадрлар тайёрлаш салоҳиятининг муҳим кўрсаткичи.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (699, 19, 20, 3, '3', 'Мактабгача таълим ва мактаб юкламаси', 'Мактабгача таълим қоплами ва мактаблардаги смена тақсимоти', 'Жами: Мактабгача таълим қоплами | 2021: 40,0% | 2022: 51,0% | 2023: 62,0% | 2024: 64,0% | 2025: 70,0% | Ўзгариш (2021→2025): +30 п.п. (+75%) | Мактаб юкламаси: 1 сменали — 36 та, 2 сменали — 20 та, Жами — 56 та | 2 сменали улуши: 35,7%', TRUE, 'Халқ таълими', 'Мактабгача таълим қоплами 5 йилда 40% дан 70% га ошган — кучли натижа. 2 сменали мактаблар улуши (35,7%) нисбатан мақбул. Қопламни 2027 йилгача 85% га етказиш учун мактабгача таълим муассасалари сонини ошириш зарур. Хусусий секторни жалб қилиш ва ҳудудий тенгликка эътибор қаратиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (700, 19, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | Банкда «Сунъий интеллект куни» ташкил этилди — ҳар чоршанба | Ходимларга онлайн ўқитиш тизими жорий қилинди | Раҳбар ходимлар ўқувлари тўлиқ якунланди | СИ ечимларидан фойдаланиш бўйича қисқа ўқув курслари ташкил этилди', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Ҳафталик «СИ куни» амалиёти орқали ходимлар янги технологияларни кундалик ишга татбиқ этишни ўрганмоқда. Кейинги босқичда ҳар бир бўлим учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (701, 19, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, ҳоким ўринбосарлари, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 2-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 3-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 4-босқич: МФЙ раислари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади: аввал ҳоким даражасида стратегик қарорлар учун СИ, кейин банк раҳбарларига скоринг ва таҳлил, сўнг маҳалла банкирларига мижоз билан ишлаш учун СИ платформа ўргатилади. Ҳар босқич 2–4 ҳафта давом этади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (702, 19, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш, тадбиркорлик ва ишга жойлашишга тайёрлаш', '', FALSE, 'SQB', 'Маълумот SQB маҳаллий филиалидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. СИ платформаси орқали ҳар бир фуқарони индивидуал баҳолаш — кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтириш — Янгиқўрғонда ҳам жорий этилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (703, 19, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 68 МФЙда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (704, 19, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари', 'Жами: 68 та маҳалла | Боғдорчилик: ~33 та МФЙ (49%) | Деҳқончилик/Картошкачилик: ~21 та МФЙ (31%) | Чорвачилик: ~10 та МФЙ (15%) | Ҳунармандчилик/Туризм: ~4 та МФЙ (6%)', TRUE, 'МФЙ агентлиги', 'Боғдорчилик (49%) ва картошкачилик (31%) устунлик қилади. Мева-сабзавотни қайта ишлаш занжирига уланиш (ҳозир 15% ишлатилган) ва Ҳазрати Довуд туристик зонаси (280 000 сайёҳ) базасида туризм МФЙларини ривожлантириш мумкин. Ҳунармандчилик улушини 6% дан 10–12% га кўтариш реал имконият.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (705, 19, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида ўсишни таъминловчи тармоқлар', 'Жами: 2 та драйвер сектор | 1-сектор: Қишлоқ хўжалиги (боғдорчилик, картошкачилик, чорвачилик) | 2-сектор: Туризм (Ҳазрати Довуд, Нурмулоқ)', TRUE, 'SQB', 'Қишлоқ хўжалиги ва туризмни «ишлаб чиқариш + қайта ишлаш + агротуризм» занжирида боғлаш керак. Нурмулоқ курорт лойиҳаси (1 555 млрд сўм инвестиция, 2026–2027) туман иқтисодиётини тубдан ўзгартириш имконини беради. Ягона «Yangiqorgon Experience» брендида бирлашмоғи лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (706, 19, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва маҳалла тақсимоти', 'Жами: 680 та лойиҳа | Иш ўринлари: 5 440 та | Лойиҳалар умумий қиймати: 32 млрд сўм | Жами маҳаллалар: 68 та | 2026 йил кредит режаси: 554 млрд сўм | Кичик бизнес: 252 млрд сўм | Саноат: 302 млрд сўм', TRUE, 'Марказий банк', '680 та микролойиҳа орқали 5 440 та иш ўрни яратилган. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа мониторинги; (4) молиявий маслаҳат. 2026 йилда саноат улушининг 55% ва кичик бизнес 45% нисбатида тақсимланиши қ/х секторида тегишли яратилаётган қувватнинг ошиши учун қайта кўриб чиқилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (707, 19, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 4 та оғир тоифадаги маҳалла | Маҳалла типологияси: Оғир — 4 та, Ўрта — 23 та, Енгил — 41 та | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 4 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳага улаш механизмлари қўлланиши лозим. Ҳар ой KPI мониторинг (иш ўрни, даромад, қайтмаслик) юритилиши тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (708, 19, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: SQB филиали 1 та, банкоматлар 1 та, бошқа банклар 21 та, банк ходимлари 68 нафар, маҳалла банкирлари 18 та (3 аёл, 15 эркак), маҳалла агентлари 68 та', TRUE, 'SQB', 'Туманда банкомат сони жуда кам (1 та) — бу рақамли хизматларга кириш имконини чеклаяпти. Банкомат тармоғини кенгайтириш ва мижозларни «Mobile» ва «Business» платформаларига ўтказиш зарур. Маҳалла банкирлари (18 та) ва агентлари (68 та) сони МФЙ сони билан мослиги — ҳар маҳаллада қамров асосини яратади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (709, 19, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (710, 19, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Туманда аёллар ишсизлиги (2 356 киши) юқорилигини инобатга олиб, маҳалла банкирлари орқали аёлларни фаол жалб қилиш ва боғдорчилик/чорвачилик бўйича бизнес тренинглар ташкил этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (711, 19, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', '4 та оғир маҳаллада ишсизликни камайтириш режаси', 'Жами: 4 та маҳалла, оғир тоифа | Ишсизлар (2025): 5 478 киши | Ёшлар (16–30): 1 753 киши | Аёллар: 2 356 киши | Кредит маҳсулотлари: 1) Микрокредит, 2) Оилавий тадбиркорлик, 3) Давлат субсидияси, 4) Лизинг | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'SQB', '4 та оғир тоифали маҳаллада аёллар ишсизлиги (43%) ва ёшлар ишсизлиги (32%) устунлик қилади. «Бир маҳалла — бир драйвер йўналиш» (боғдорчилик ёки туризм) модели жорий қилиниши мақсадга мувофиқ. 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (712, 19, 33, 5, '5', 'Боғдорчилик ва мева-сабзавот қайта ишлаш кластери', 'Туман қишлоқ хўжалик ҳажми ва экспорт салоҳияти', 'Жами: Қ/х маҳсулоти ҳажми (2025) — 254,7 млрд сўм | Йўналиш: интенсив боғдорчилик, муздуратма-омборхона, шарбат/қуритилган мева | Имконият: қайта ишлаш улушини 15% дан 40% га ошириш ва экспорт ўзаги яратиш | Инвестиция: $5–18 млн/лойиҳа', TRUE, 'Туман статистика бўлими', 'Янгиқўрғонда 47 та маҳалланинг асосий ихтисослашуви боғдорчилик ва картошкачилик бўлгани боис, мева-сабзавот қайта ишлаш салоҳиятининг ҳозирда атиги 60% и ишлатилган. Биринчи навбатда маҳаллаларда (Бунёдкор, Хадикент, Кўкёр, Ғалаба, Тинчлик) хом ашё йиғув марказлари ва 3–5 минг тонналик муздаткич-омборхоналар қуриш зарур. Иккинчи босқичда олма-олхўри-шафтоли асосида олхўри какоси, шарбат концентрати, қуритилган мева чиқарувчи 2 та йирик завод қуриш — экспортни жорий $21,8 мингдан 5–7 млн долларгача ошириш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (713, 19, 34, 5, '5', 'Ҳазрати Довуд зиёратгоҳи ва Нурмулоқ курорт шаҳри', 'Диний-тарихий туризм ва шифобахш курорт зонаси', 'Жами: 280 минг сайёҳ/йил (Ҳазрати Довуд, режа 230 минг) | Йўналиш: зиёрат туризми, эко-курорт, wellness & SPA, глампинг | Имконият: 1 555 млрд сўм инвестиция (2026–2027) орқали йиллик 1 млн+ сайёҳ | Инвестиция: $120–200 млн (Нурмулоқ курорт шаҳри лойиҳа қиймати)', TRUE, 'Туризм бўлими', 'Ҳазрати Довуд бўйича режадан 50 минг сайёҳ ортиқча келаётгани (280K факт vs 230K режа) — қувватдан фойдаланиш чегарага етганини билдиради. Шошилинч равишда 2026 йилгача «Hazrati Dovud Pilgrim Pass» рақамли пакет жорий этиш ва атрофдаги Заркент, Қорасув, Қизилёзи маҳаллаларида гостевой уйлар тармоғини оч-кий+нонушта формати бўйича 200+ ўрингача кенгайтириш керак. Нурмулоқда ПЧШ механизми орқали хусусий инвесторларни жалб қилиш — шифобахш сув + тоғ туризми + халол-фрэндли инфратузилмани бирлаштириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (714, 19, 35, 5, '5', 'Узумчилик ва вино/шарбат саноати', 'Узум хом ашёси ҳажми катта, лекин қайта ишлаш атиги 5%', 'Жами: 56 978 тонна узум ҳосили (2025), 1 719 га майдон | Йўналиш: қуритилган узум (мавиз), узум шарбати, табиий вино, узум сирка | Имконият: қайта ишлашни 5% дан 30% га ошириш орқали қўшилган қиймат +180 млрд сўм | Инвестиция: $3–7 млн (мавиз қуритиш) + $8–15 млн (шарбат-вино заводи)', TRUE, 'Қ/х бўлими', 'Дехқонобод, Гулшан, Гаистон, Туман, Боғ, Радивон маҳаллалари узумчилик ихтисослашган — лекин ҳосилнинг 95% и хом ҳолда сотилмоқда. Бу — энг катта йўқотилган имконият. Биринчи қадам: 4 та маҳаллавий мавиз қуритиш цехи (қуёш+газ гибрид) очиш, ҳар бирида 30–50 иш ўрни. Иккинчи қадам: туман даражасида 1 та маркази шарбат-концентрат заводи (10 минг тонна/йил) — Россия ва Қозоғистон бозорига экспорт. Учинчи қадам: маҳаллий «GI» (Geographical Indication) ҳимояси билан «Янгиқўрғон узуми» брендини рўйхатга олиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (715, 19, 36, 5, '5', 'Қурилиш материаллари кластерини кенгайтириш', 'Мавжуд 13 та корхона ва Нурмулоқ-курорт лойиҳаси талаби', 'Жами: 51 млрд сўм/йил кластер ҳажми (2025) | Корхоналар сони: 13 та (2021 — 9 та → +44%) | Имконият: Нурмулоқ ва туризм инфратузилмаси учун ички талабни 100% қоплаш | Инвестиция: $2–10 млн/лойиҳа (ғишт, темир-бетон, керамика)', TRUE, 'Туман ҳокимияти', 'Кластер ўсиш динамикаси барқарор (2021–2025: +89% ҳажм). Лекин Нурмулоқ курорт шаҳрига 1 555 млрд сўм инвестиция режалаштирилгани ва йил давомида 1 010 та янги иш ўрни яратилиши кутилаётгани шуни кўрсатадики, ички талаб 2026–2028 йилларда сезиларли ошади. SQB кредит дастури орқали 5–7 та янги ўрта корхона (хорижий керамика, рангли ғишт, smart blocks) очиш — импорт ўрнини босиш бўйича 25% га ҳисса қўшади. Қум-шағал тоғ-кон секторини ривожлантириш учун геологик қидирув ишларини бошлаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (716, 19, 37, 5, '5', 'Қуёш энергетикаси ва энергия мустақиллиги', 'Йилига 280–300 қуёшли кун, газ таъминоти 38%', 'Жами: 50 марта/ой электр узилиши (2025), 5 йил олдин 130 эди | Йўналиш: қуёш панеллари, гибрид станциялар (агро+СЭС), биогаз | Имконият: газ танқислигини бартараф этиш ва саноат электр харажатини 30% га камайтириш | Инвестиция: $5–25 млн/лойиҳа (1–10 МВт қувватли СЭС)', TRUE, 'Минэнерго', 'Электр тармоғи модернизация талаб қилувчи қисми 54% га етган (2021 йилда 35% эди — ёмон тенденция). Ҳамон 38% хонадон газга уланмаган. Бу — қуёш ва биогаз учун муқим бозор. Биринчи навбатда саноат зоналари (Бунёдкор-1, Бунёдкор-2, Қораполвон ёшлар, Нурафшон КСЗ) усти 1–2 МВт қувватли қуёш панеллари билан жиҳозланиши керак. Иккинчи қадам: чорвачиликка ихтисослашган 14 та маҳаллада кичик биогаз қурилмалари — гўнгдан газ ва органик ўғит. Учинчи қадам: туман маркази учун 5 МВт қувватли пилот СЭС лойиҳаси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (717, 19, 38, 5, '5', 'Касаначилик ва ҳунармандчилик кластери', 'Маҳалла даражасида ҳунармандчилик ва ёғочга ишлов потенциали', 'Жами: 400 хонадон Қизилқиёқ маҳалласида ёғочга ишлов беради (36,2%) | Йўналиш: мебел, эшик-дераза, ёғоч ўймакорлиги, тикувчилик, нонвойчилик | Имконият: касаначиликни расмий секторга ўтказиш ва экспорт занжири қуриш | Инвестиция: $0,5–3 млн/маҳалла кластери (умумий устахона, дизайн маркази)', TRUE, 'МФЙ агентлиги', 'Баркамол маҳалласида 205 хонадон касаначилик билан, Қизилқиёқда 400 хонадон ёғочга ишлов бериш билан, бошқа маҳаллаларда тикувчилик, саватчилик, нонвойчилик, қандолат билан шуғулланади — лекин буларнинг кўпчилиги норасмий секторда. Янги иш ўринлари 1 100 та / йил мақсадини бажариш учун шу 3–4 та «ҳунарманд маҳалла»ни умумий тармоқли касаначилик кластерига айлантириш керак: ягона хом ашё таъминоти, дизайн ва брендинг маркази, онлайн платформа орқали сотув. Норасмий 36 200 ишчиларнинг ҳеч бўлмаса 30% ини расмийлаштириш йилига 6,8 млрд сўм қўшимча солиқ беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (718, 19, 39, 5, '5', 'Логистика ва транспорт инфратузилмаси', 'Темир йўл стансиясидан 30 км, асфальт йўллар улуши кескин ўсди', 'Жами: 69% асфальтланган йўллар улуши (2025), 2021 йилда 18% эди | Йўналиш: муздуратма омборхоналар тармоғи, транспорт-логистика хаби | Имконият: Фарғона водийси–Хитой йўналиши учун транзит хизматлари | Инвестиция: $10–35 млн (мультимодал омбор+автотерминал)', TRUE, 'Йўл хўжалиги', 'Йўл инфратузилмаси охирги 4 йилда тубдан яхшиланди (18% → 69% асфальт), 26 та омборхона (18 000 м²) мавжуд — лекин бу қ/х маҳсулоти ҳажми (254,7 млрд сўм) учун камлик қилади. D-111 автомобил йўлининг 17 км ли қисми ҳозир таъмирланмоқда. Темир йўл стансияси яқинида (30 км) «Cold Chain Logistics Hub» қуриш — мева-сабзавот, гўшт ва сут маҳсулотлари учун -5°C дан +15°C гача харорат режимли омбор тармоғини яратиш. Бу нафақат маҳаллий ишлаб чиқарувчилар учун, балки бутун Фарғона водийсидан Қозоғистон-Россияга экспорт учун айланма марказ бўла олади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (719, 19, 40, 5, '5', 'Туризм инфратузилмасига давлат инвестицияси', '2027 йилга мўлжалланган маҳаллалар туризм инфратузилмасини ривожлантириш дастури', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Туризм инфратузилмасига давлат инвестицияси Нурмулоқ курорт шаҳри (1 555 млрд сўм) ва Ҳазрати Довуд зиёратгоҳи талабларига мутаносиб режалаштирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (720, 19, 41, 6, '6', 'Стратегик хулоса — 4 та устувор йўналиш', 'Туман иқтисодиётининг асосий ўсиш ўқлари', 'Жами: 4 та стратегик кесим (агро-қайта ишлаш, туризм, ҳунармандчилик, қурилиш) | 1-устунлик: Боғдорчилик-сабзавот қайта ишлаш (қ/х 49% улушни 30% гача оптимизация) | 2-устунлик: Туризм + Нурмулоқ курорт (1 555 млрд сўм инвестиция) | 3-устунлик: Қурилиш материаллари кластери (13 корхона → 20+ кенгайтириш) | 4-устунлик: Касаначилик ва ҳунармандчиликни расмийлаштириш (норасмий 36 200 → 25 000)', TRUE, 'SQB', 'Туман қ/х устуворлигидан саноат-хизмат балансланган моделга ўтиш йўлида: ҳозирги тузилма (Қ/х: 49%, Саноат: 15%, Хизматлар: 36%) 2030 йилгача (Қ/х: 30%, Саноат: 25%, Хизматлар: 45%) тенденциясига йўналтирилиши керак. Бу 4 устунликни алоҳида эмас, ўзаро боғлаб ривожлантириш зарур: туризм-агрозона-ҳунармандчилик ягона «Yangiqorgon Experience» брендида бирлашмоғи лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (721, 19, 42, 6, '6', 'Инвестиция жалб қилиш режаси 2026–2031', '6 йиллик инвестиция дастури ва йиллик тақсимот', 'Жами: 900 млрд сўм инвестиция режаси (2026–2031) | 2026: 100 млрд сўм | 2027: 120 млрд сўм (+20%) | 2028: 140 млрд сўм | 2029: 160 млрд сўм | 2030: 180 млрд сўм | 2031: 200 млрд сўм (барқарор +14%/йил)', TRUE, 'Туман ҳокимияти', 'Жалб қилиш бажарилиш фоизи охирги 5 йилда 72% дан 95% га ўсди — режа реал. Лекин ТТИ (тўғридан-тўғри хорижий инвестициялар) ҳозирда атиги 100 минг $ — бу муҳим заиф нуқта. 2026 йилда ТТИ ни камида 2 млн долларгача (20 баробар) ошириш учун 2 та халқаро инвестор учрашуви, инглиз тилидаги «investment dossier» ва «Invest in Yangiqorgon» сайт-портал тайёрлаш керак. ЕБРР билан жорий 0,2 млн $ ҳажмидаги ҳамкорликни 5 млн долларгача ошириш бўйича музокаралар бошлаш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (722, 19, 43, 6, '6', 'Иш ўрни яратиш ва бандлик режаси (2026–2027)', 'Тармоқлар бўйича янги иш ўринлари тақсимоти', 'Жами: 1 010 та янги иш ўрни (2026–2027) | Саноат: 2026 — 551 → 2027 — 601 та (+9%) | Туризм: 2026 — 90 → 2027 — 140 та (+56%) | Қ/х ва расмийлаштириш: 2026 — 850 та (норасмий бандликни расмий секторга ўтказиш) | КПИ: 2026 йилда йиллик 1 100 та янги иш ўрни (доимий мақсад)', TRUE, 'SQB', 'Туризмда иш ўрни ўсиш суръати энг юқори (+56%) — Нурмулоқ ва Ҳазрати Довуд лойиҳалари самараси. Лекин расмийлаштириш орқали 850 та иш ўрни — энг муҳим, чунки норасмий 36 200 ишчилар расмий секторга ўтса, йилига 6,8 млрд сўм солиқ йўқотиш қопланади. Ёшлар ишсизлиги (1 753 киши) ва аёллар ишсизлиги (2 356 киши) бўйича алоҳида дастур керак: ёшларга — IT ва туризм соҳаларида грант асосли ўқитиш, аёлларга — масофавий тикувчилик ва уй-ишлаб чиқариш кластери орқали бандлик. Қайтган мигрантлар (1 920 киши, 2025) — тайёр кадрлар ресурси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (723, 19, 44, 6, '6', 'Маҳалла типологияси ва дифференциал ёрдам', '68 та МФЙ ни оғирлик даражасига кўра тоифалаш', 'Жами: 68 та МФЙ (2025 йилда 71 → 68 га оптимизация қилинди) | Оғир тоифа: 4 та МФЙ — интенсив ёрдам, ҳар бирига 5–7 та микролойиҳа | Ўрта тоифа: 23 та МФЙ — ривожлантириш дастури, инфратузилма | Енгил тоифа: 41 та МФЙ — мустаҳкамлаш, ўз-ўзини бошқариш | Камбағаллик: 6,2% (2025), 2027 йилгача 2,2% га тушириш мақсади', TRUE, 'МФЙ агентлиги', 'Камбағаллик 2021 йилдан 2025 йилгача 2 баробар камайди (13,2% → 6,2%) — миллий ўртачадан тезроқ суръат. Лекин қолган 4 та «оғир» маҳалла учун стандарт чора-тадбирлар самарасиз: уларга махсус «ман-чизма» таҳлили қилиб, ҳар бир оила учун индивидуал кўрсаткичлар (мониторинг 1 ой даврида) ишлаб чиқиш керак. 2026 йилгача 18 та МФЙ камбағалликдан холи бўлиши режа қилинган — бу учун маҳалла даражасида 18 та «Бизнес-Инкубатор» нуқтаси очиш ва ҳар бирини SQB маҳаллий банкири билан боғлаш керак (айни пайтда 18 банкир, 68 маҳалла агенти бор).', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
