INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (724, 20, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 1 618,7 млрд сўм | Бозор хизматлари: 685,9 млрд сўм | Саноат ўсиш суръати: 113,5% | Хизматлар индекс динамикаси: 115,0 | Тармоқлар улуши: Қ/х 30,4%, Саноат 28,6%, Хизматлар 41% | ЯҲМ республика ўртачасига нисбатан: 64,5%', TRUE, 'Туман статистика бўлими', 'Фориш туманининг ЯҲМ кўрсаткичи республика ўртачасининг атиги 64,5% даражасида — ўсиш заҳираси катта. Иқтисодиётда Қ/х (30,4%) ва Хизматлар (41%) етакчи бўлгани сабабли қишлоқ хўжалиги маҳсулотларини қайта ишлаш ва туризм-сервис инфратузилмасига йўналтирилган инвестициялар ЯҲМ ни тез ўстириш имконини беради. Саноат улуши 28,6% — қурилиш материаллари кластери ва тоғ-кон хомашёси базасида қўшимча қиймат занжирини чуқурлаштириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (725, 20, 2, 1, '1', 'Туман иқтисодиётининг устувор драйверлари', 'Фориш туманининг устувор тармоқлари ва ривожланиш йўналишлари', 'Жами: 2 та расмий устувор тармоқ + туризм потенциали | 1-ўрин Қишлоқ хўжалиги: улуши 30,4%, бандлик 18,2 минг киши | 2-ўрин Қурилиш материаллари: базальт, цемент, оҳак, қум-шағал — 7 та хомашё тури | Қўшимча: Туризм-экологик йўналиш — BCG/халқaрo бaҳo «ўсиш нуқтaсигa эгa стрaтeгик тумaн» сифaтидa тaн oлингaн | Хизмaтлaр улуши 41% — eнг кaттa тaрмoқ', TRUE, 'Туман ҳокимияти', 'Фориш учун «3 устунли кластер» модели оптимал: (1) қишлоқ хўжалиги маҳсулотларини қайта ишлаш, (2) қурилиш материаллари саноати (тоғ-кон хомашёси базасида), (3) эко-туризм. Ҳар бир йўналиш бўйича 1–2 та «тез натижа» лойиҳасини молиялаштириб, бандлик ва туман бюджетига таъсирини ойма-ой кузатиш керак. Саноат улуши 28,6% дан 35%+ га ўткaзилишигa қурилиш материаллари кластери хизмат қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (726, 20, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', '2021: 256.3 | 2022: 322.3 | 2023: 656.0 | 2024: 1004.0 | 2025: 1618.7 (млрд сўм)', TRUE, 'Туман статистика бўлими', 'Саноат ишлаб чиқариш 5 йилда 6,3 баробарга ўсган — бу истисноий юқори суръат. Айниқса йирик корхоналар улуши кескин ошган (176,6 → 1 035,1 млрд сўм), бу қурилиш материаллари сектори ишга тушганини кўрсатади. Кейинги босқичда: (a) экспортбоп маҳсулот улушини ошириш, (b) энергия самарадорлигини ошириш, (c) хомашё таъминоти узилиш хавфларини бошқариш. Ўсиш суръати барқарорлигини сақлаш учун логистика инфратузилмаси (йўллар, жамоат транспорти) приоритет бўлмоғи лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (727, 20, 4, 1, '1', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми', 'Маълумот мавжуд эмас — ҳужжатларда туман кесимида кредит портфели акс этмаган | NPL муаммоли кредитлар фоизи: 2021 — 4,0% | 2022 — 3,8% | 2023 — 4,2% | 2024 — 3,3% | 2025 — 2,9% — портфел сифати яхшиланмоқда', FALSE, 'Марказий банк / SQB', 'Кредитлар ҳажми бўйича йил кесимидаги маълумот топилмади — Марказий банк ва SQB филиалидан туман бўйича кредит портфели динамикасини сўраб олиш зарур. Мавжуд кўрсаткич — NPL улуши 4,0% дан 2,9% га тушгани — портфел сифати яхшиланганини кўрсатади ва янги кредит маҳсулотларини жорий этиш учун қулай муҳит яратади. Кредит ҳажми аниқлангача, унинг саноат ишлаб чиқариш ўсиши ва инвестициялар билан корреляциясини баҳолаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (728, 20, 5, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0-100 балл шкаласи', 'Маълумот мавжуд эмас — Excel шакли бўйича бу кўрсаткич Марказий аналитика гуруҳи томонидан ҳисобланади (''⚠ Тўлдириш шарт эмас'') | Туман даражасида ҳозирча тўлдирилмаган', FALSE, 'Марказий аналитика', 'Google Trends индекси Марказий гуруҳ томонидан ҳисобланадиган кўрсаткич бўлгани сабабли туман ўз даражасида маъумот киритган эмас. SQB ИТ департаментидан «Forish» / «Фориш» / «Forish tumani» қидирув орқали ойлик динамикани сўраб олиш мумкин. Қидирув фаоллигини ошириш учун: (1) туман брендини рақамли каналларда илгари суриш, (2) экотуризм маркази сифатида танитиш кампанияси, (3) хорижий инвесторларга Англия/рус тилида контент яратиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (729, 20, 6, 1, '1', 'Махсус саноат зонаси (ЭИЗ/СЭЗ)', 'Фориш туманида махсус саноат зонаси (ЭИЗ ёки СЭЗ) мавжудлиги', 'Жами: ЭИЗ ёки СЭЗ ҳозирда мавжуд эмас (қиймат: 0) | Саноат зонаси ер фойдаланиш: 0% | Қурилиш материаллари кластери: 1 та корхона, йиллик ҳажм 50 млрд сўм | Импорт ҳажми 2025: 183,2 млн $ — экспортдан (18,8 млн $) ~10 баробар юқори | Янги корхоналар (2025): очилган 548, ёпилган 279', TRUE, 'Туман ҳокимияти', 'Форишда ЭИЗ/СЭЗ ҳозирча йўқ — бу йирик имконият. Тоғ-кон хомашёси заҳиралари жуда бой (базальт 22,2 млн т, цемент 131 млн т) бўлгани сабабли қурилиш материаллари СЭЗ ёки кластерини ташкил қилиш стратегик таклиф. Импорт-экспорт дисбаланси (10:1) хорижий маҳсулотларга қарамликни кўрсатади — маҳаллийлаштириш СЭЗ орқали ҳал этилади. Учкўприк/Қўқон ЭИЗ моделини ўрганиб, Фориш ШЭИЗ концепциясини ишлаб чиқиш ва ВМ қарори чиқариш учун таклиф киритиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (730, 20, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2023: 60.55 | 2024: 61.53 | 2025: 62.53 (%) | 3 йилда +2 п.п. ўсиш | Канализация тармоғи: 2% | Суғориладиган ер: 766 га (умумий 956 000 га дан)', TRUE, 'Сув хўжалиги', 'Ичимлик суви қамрови 62,5% — республика ўртачаси (95%+) дан жуда паст ва йиллик ўсиш суръати атиги ~1 п.п. Канализация эса фақат 2% — бу эпидемиологик хавф. Аввалом­бор: (1) туман маркази ва йирик маҳаллаларга замонавий сув-канализация тармоғини қуриш бўйича давлат-хусусий шериклик лойиҳаси, (2) узоқ маҳаллалар учун локал сув олиш стансиялари (қудуқ + фильтр), (3) суғориш каналлари бетонлаш улуши атиги 0,15% бўлгани сабабли шу йўналишга тезкор инвестиция талаб этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (731, 20, 8, 2, '2', 'Йўллар инфратузилмаси ва асфальтланганлик даражаси (%)', 'Туман автомобил йўлларининг умумий узунлиги ва қаттиқ қопламали йўллар улуши', '2021: 32 | 2022: 35 | 2023: 37 | 2024: 38 | 2025: 39 (%) | Йўллар умумий узунлиги: 1 456 км (5 йил мобайнида ўзгармаган) | Темир йўл стансиясигача: 75 км | Вилоят марказигача: 70 км', TRUE, 'Йўл хўжалиги', 'Асфальтланган йўллар улуши 39% — республика ўртачаси (70%+) дан паст ва ўсиш суръати 1 п.п./йил — жуда секин. Жорий суръатда 70% га чиқиш ~30 йил керак бўлади. Тавсиялар: (1) йирик маҳаллаларни бирлаштирувчи магистрал йўлларга приоритет, (2) қурилиш материаллари кластери базасида маҳаллий асфальт ишлаб чиқариш — логистика харажатларини камайтиради, (3) темир йўлгача 75 км бўлгани сабабли хаб-йўл яратилиши экспорт логистикаси учун муҳим. Йўловчи ва юк айланмаси (5,9 млн киши, 999 минг тонна) ҳозирдаёқ сезиларли — инфратузилмани тезлик билан янгилаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (732, 20, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр узилишлари ва тармоқ модернизация ҳолати', 'Жами: 5 йилда 4,5 баробар яхшиланиш | Электр узилишлар (марта/ой): 2021 — 9, 2022 — 8, 2023 — 4, 2024 — 3, 2025 — 2 | Модернизация талаб қиладиган тармоқлар: 2021 — 33-30%, 2025 — 30-25% | Газ билан таъминланганлик: 2021 — 42% → 2025 — 44% (амалда ўзгармаган)', TRUE, 'Электр тармоқлари', 'Электр узилишлари 9 → 2 марта/ой га тушгани — катта тараққиёт. Лекин трансформаторларнинг 30% ва линияларнинг 25% ҳали модернизация талаб қилади. Газ таъминоти эса 5 йилда амалда ўзгармаган (42→44%) — аҳолининг 56% и ҳали табиий газдан фойдаланмайди, бу муаммо тез ҳал этилиши лозим. Таклиф: (1) саноат зонаси учун алоҳида юқори кучланишли подстанция, (2) қишлоқ маҳаллаларига газ олиб бориш ўрнида қуёш панеллари + биогаз солюшнларини кенг қўллаш — бу экономик жиҳатдан оқилона, (3) инвестициялар самарадорлигини ошириш учун энергетика секторига таргетланган моделлар.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (733, 20, 10, 2, '2', 'Ер фонди ва сув ресурслари тузилмаси', 'Туман ер фонди тузилмаси, суғориладиган ерлар ва каналлар ҳолати', 'Жами: туман умумий майдони 956 000 га (Ўзбекистоннинг йирик туманларидан) | Аҳоли зичлиги: 10 киши/км² (республикадаги энг паст кўрсаткичлардан) | Суғориладиган ер: 766 га (атиги 0,08% умумий майдондан) | Суғориш каналлари бетонлаш улуши: 0,15% (амалда йўқ) | Омборхоналар: ҳозирча мавжуд эмас', TRUE, 'Ер қўмитаси / Сув хўжалиги', 'Фориш — майдони жуда катта (956 минг га), лекин суғориладиган ер атиги 766 га — бу жуда кичик, чунки ҳудудда чўл-адир табиати ҳукмрон. Каналлар бетонлаш 0,15% — амалда йўқ, натижада сув йўқотиши улкан. Тавсиялар: (1) дамлагич конструкциялари ва томчилатиб суғориш технологиялари жорий этиш — қишлоқ хўжалиги (улуши 30,4%) самарадорлигини оширади, (2) Адир-чўл ҳудудларида солнечный, ветро энергетика лойиҳалари учун ер ажратиш мақсадга мувофиқ, (3) тоғ-кон хомашёси базасидаги ер участкаларини саноат зонаси учун заҳирага киритиш, (4) омборхоналар базаси йўқлиги қишлоқ хўжалиги маҳсулотларини сақлаш-қайта ишлашда чеклов яратади — приоритет инвестиция.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (734, 20, 11, 2, '2', 'Жамоат транспортидан фойдаланиш', 'Аҳолини жамоат транспорти билан қамраб олинганлик даражаси', 'Маълумот мавжуд эмас — туман маълумот тўплаш шаклида жамоат транспорти қоплами кўрсаткичи акс этмаган | Боғлиқ кўрсаткичлар: йўловчи айланмаси 2025 — 5 879,4 минг киши, юк айланмаси — 999,3 минг тонна', FALSE, 'Хокимият / транспорт бўлими', 'Жамоат транспорти қамрови бўйича туман даражасидаги маълумот топилмади — туман ҳокимиятининг транспорт бўлимидан маршрутлар сони, кундалик йўловчи ҳажми ва қамров % сини алоҳида сўраб олиш зарур. Аҳоли зичлиги жуда паст (10 киши/км²) ва йўлларнинг атиги 39% и асфальтланган бўлгани сабабли классик жамоат транспорт модели самарали бўлмайди. Альтернатив таклиф: (1) маҳалла-маркaзи «micro-mobility» (маршрут такси, электр транспорт), (2) мактаб-касалхона учун етар келувчи моно-маршрут тизими, (3) тоғ-кон ва қурилиш зоналари учун корпоратив транспорт сервиси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (735, 20, 12, 2, '2', 'Тоғ-кон хомашёси ва фойдали қазилмалар базаси', 'Туман ҳудудидаги фойдали қазилмалар конлари, заҳиралари ва саноат потенциали', 'Жами: 8 та йирик кон | Цемент хомашёси: 3 та кон, 131 333 минг тонна заҳира | Базальт: 3 та кон, 22,2 млн тонна заҳира | Барит: 11,9 млн тонна | Оҳак: 2 та кон, 531 минг тонна | Қурилиш тошлари: 13 245 минг м³ | Табиий қопламали тошлар: 853 минг м³ | Қум-шағал: 5 070 минг м³ | Қурилиш материаллари кластери: 1 та корхона, 50 млрд сўм/йил', TRUE, 'Геология қўмитаси', 'Фориш — қурилиш материаллари саноати учун стратегик минераль-хомашё базаси. Цемент заҳираси (131 млн т) Ўзбекистонда ёирик конлардан биридан ҳисобланади — бу жуда катта имконият. Аммо ҳозирча атиги 1 та корхона (50 млрд сўм/йил) ишламоқда — потенциалнинг ~5% и ҳам фойдаланилмайди. Таклиф: (1) Цемент заводи + барит қайта ишлаш корхонаси учун хорижий инвестор (Хитой / Турк) жалб қилиш, (2) Саноат зонаси ташкил этиб, шу заҳираларни база қилиш — 2,5+ млрд $ инвестиция ва 5–10 минг иш ўрни (Қўқон ЭИЗ модели мисолида), (3) темир йўлгача 75 км бўлгани сабабли маҳсулотни жонажон ва экспорт бозорларига транспорт-логистика хаб қуриш приоритет.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (736, 20, 13, 3, '3', 'Меҳнат ресурслари', 'Жами меҳнат ресурслари сони — йиллик динамика', '2021: 50.315 | 2022: 50.409 | 2023: 50.527 | 2024: 50.906 | 2025: 51.942 (минг киши)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор, аммо секин ўсмоқда (+1 036 киши, +2,0% 2025 йилда). Бандликни ошириш учун чорвачилик, боғдорчилик ва туризм соҳалари бўйича маҳалла даражасида қисқа муддатли ўқув дастурларини кенгайтириш зарур. АЭС қурилиши, тоғ-кон ва туризм лойиҳалари кадрлар талабини оширади — олдиндан касб-ҳунар тайёрлаш дастурларини бошлаш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (737, 20, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Иш ўрни яратиш ва меҳнат бозори резервлари', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 40 471 киши (+12,6%) | Қайтган мигрантлар (2025): 259 киши | Норасмий секторда бандлик (2021): 19 045 киши | Хорижга кетган мигрантлар: 2021 — 2 133, 2022 — 3 363, 2023 — 3 558, 2024 — 934, 2025 — 2 219', TRUE, 'Бандлик маркази / ИИВ миграция', 'Бандликни ошириш учун маҳалла даражасида талаб юқори бўлган касблар рўйхатини шакллантириб, шу йўналишларда қисқа муддатли ўқув ва амалиёт дастурларини кенгайтириш керак. Норасмий секторни расмийлаштириш орқали солиқ базасини кенгайтириш мумкин. Қайтган мигрантлар (259 киши) — тайёр кадрлар ресурси, уларни АЭС ва тоғ-кон лойиҳаларига жалб этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (738, 20, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси ва ишсизлар сони', 'Жами: Ишсизлик кўрсаткичлари | Расмий ишсизлик (2025): 5,5% (-14,1%) | Ишсизлар сони (2025): 2 438 киши (-3,2%) | Ишсизлик тренди: 10,5% → 9,4% → 7,9% → 6,4% → 5,5% | Ёшлар (16–30): 588 киши | Аёллар: 855 киши | Мақсад: 2027 йилгача 2,2% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2,2% га туширишга учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим. Аёллар ишсизлиги (855 киши, умумийнинг 35%) алоҳида диққатга сазовор. Ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш зарур.', 2438, 5.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (739, 20, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони', 'Жами: Камбағаллик кўрсаткичлари | Камбағаллик даражаси (2025): 6,3% (-34,4%) | Камбағал оилалар (2025): 1 545 та (-54,6%) | Камбағаллик тренди: 11,4% → 9,6% → 6,3% (3 йил кесими) | Кам таъминланган оилалар: 3 584 та | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Статистика бўлими / МФЙ агентлиги', 'Камбағал оилалар сони 2 йилда икки баробардан кўп камайган (3 400 → 1 545). Ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши, ижтимоий ёрдам иш билан боғлиқ қилиниши зарур. Кам таъминланган 3 584 оила — алоҳида профилактик дастур талаб қилади, акс ҳолда улар камбағаллик чегарасига тушиб кетиш хавфи остида.', 1545, 6.3, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (740, 20, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '«Барқарор келажак» дастури — 2026 йилда ёшлар даромадини ошириш режаси', 'Жами: 498 нафар ёшлар бандлиги таъминланди (2026) | Доимий ишга жойлаштириш: 157 нафар | Тадбиркорлик учун кредит: 40 нафар | Касб-ҳунар ўқитиш: 219 нафар | Тартибли миграция: 23 нафар | Ўзини-ўзи банд: 36 нафар', TRUE, 'Бандлик маркази', 'Ёшлар бандлигини ошириш учун дуал таълим, биринчи иш ўрнига субсидия ва талаб юқори касблар бўйича тезкор қайта тайёрлаш дастурларини кучайтириш зарур. АЭС қурилиши учун техник коллеж очиш — ёшларга 5+ йиллик доимий иш бериш имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (741, 20, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар бандлиги ва даромадини ошириш — 2026 йил режаси', 'Жами: 2026 йил режаси | Иш жойларига жойлаштириш: 3 135 нафар | Доимий ишга жойлаштириш: 610 нафар | Тадбиркорликка жалб: 612 нафар | Кредит ажратиш ҳисобига: 552 нафар | Қайта касбга ўқитиш: 1 116 нафар | Ўзини-ўзи банд: 245 нафар | Пилла боқиш (мавсумий): 3 352 нафар', TRUE, 'Оила ва хотин-қизлар бўлими', 'Аёллар бандлигини ошириш учун имтиёзли молиялаштириш, мос иш режими ва маҳалла кесимида касбга йўналтириш дастурларини кенгайтириш зарур. Пилла боқиш мавсумий 3 352 нафар — буни доимий бандликка айлантириш учун ипак гавлама ва тикувчилик кооперативларини яратиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (742, 20, 19, 3, '3', 'Олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. АЭС лойиҳаси контекстида туманда техник олий таълим муассасаси очиш — стратегик зарурият: ядро энергетикаси, геологик қидирув, қурилиш материаллари бўйича мутахассислар тайёрлаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (743, 20, 20, 3, '3', 'Мактабгача таълим ва мактаб юкламаси', 'Мактабгача таълим қоплами ва мактаблардаги смена тақсимоти', 'Жами: Мактабгача таълим қоплами | 2021: 87,4% | 2022: 86,1% | 2023: 82,3% | 2024: 80,5% | 2025: 81,5% | Ўзгариш (2021→2025): -5,9 п.п. | Мактаб юкламаси: 1 сменали — 12 та, 2 сменали — 55 та, Жами — 67 та | 2 сменали улуши: 82,1%', TRUE, 'Халқ таълими', 'Мактабгача қоплам 2021 йилдан пасайиб бормоқда (87,4% → 81,5%). 82,1% мактаб 2 сменада ишлаши инфратузилмага жиддий босим борлигини кўрсатади. Янги мактаб ва мактабгача муассасалар очиш зарур. АЭС қурилишида ишчилар оилалари кўчиб келиши натижасида таълим талаби кескин ошиши кутилади — олдиндан 5–7 та янги МТМ ва 2–3 та мактаб қуриш режасини ишлаб чиқиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (744, 20, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | Банкда «Сунъий интеллект куни» ташкил этилди — ҳар чоршанба | Ходимларга онлайн ўқитиш тизими жорий қилинди | Раҳбар ходимлар ўқувлари тўлиқ якунланди | СИ ечимларидан фойдаланиш бўйича қисқа ўқув курслари ташкил этилди', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Ҳафталик «СИ куни» амалиёти орқали ходимлар янги технологияларни кундалик ишга татбиқ этишни ўрганмоқда. Кейинги босқичда ҳар бир бўлим учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (745, 20, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, ҳоким ўринбосарлари, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 2-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 3-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 4-босқич: МФЙ раислари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади: аввал ҳоким даражасида стратегик қарорлар учун СИ, кейин банк раҳбарларига скоринг ва таҳлил, сўнг маҳалла банкирларига мижоз билан ишлаш учун СИ платформа ўргатилади. Ҳар босқич 2–4 ҳафта давом этади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (746, 20, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш, тадбиркорлик ва ишга жойлашишга тайёрлаш', '', FALSE, 'SQB', 'Маълумот SQB маҳаллий филиалидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. СИ платформаси орқали ҳар бир фуқарони индивидуал баҳолаш — кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтириш — Фориш туманида ҳам жорий этилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (747, 20, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 24 МФЙда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (748, 20, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари', 'Жами: 24 та маҳалла | Чорвачилик: 10 та МФЙ (42%) | Боғдорчилик: 9 та МФЙ (38%) | Савдо ва хизмат: 4 та МФЙ (17%) | Кичик ишлаб чиқариш: 1 та МФЙ (4%)', TRUE, 'МФЙ агентлиги', 'Чорвачилик (42%) ва боғдорчилик (38%) устунлик қилади. Мева-сабзавотни қайта ишлаш ва чорва маҳсулотларини қадоқлаш занжирига уланиш орқали маҳалла даражасида қўшимча иш ўринлари яратиш мумкин. Ҳозирда қайта ишлаш улуши 0% — 30%га ошириш йилига 200+ млрд сўмлик қўшимча қиймат беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (749, 20, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида ўсишни таъминловчи тармоқлар', 'Жами: 4 та драйвер сектор | 1-сектор: Чорвачилик | 2-сектор: Боғдорчилик | 3-сектор: Туризм ва хизматлар | 4-сектор: Саноат', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни «ишлаб чиқариш + қайта ишлаш + савдо» занжирида боғлаш керак. Боғдорчилик ва чорвачилик маҳсулотларини бозорга чиқариш, брендлаш ва онлайн сотув каналларини кенгайтириш орқали қўшимча қийматни ошириш тавсия этилади. Туризм-сервис йўналишини Айдаркўл ва Нурота туристик зоналари асосида ривожлантириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (750, 20, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва маҳалла тақсимоти', 'Жами: 2025 йилда 1 010 та лойиҳа | Иш ўринлари: 2 046 та | Лойиҳалар умумий қиймати: 46,7 млрд сўм | Тақсимот: Қ/х — 759 та (34,7 млрд сўм), Саноат — 106 та (4,7 млрд сўм), Хизмат — 145 та (7,3 млрд сўм) | 2026 режа: 240 та лойиҳа, 480 та иш ўрни', TRUE, 'SQB / Туман ҳокимияти', '1 010 та микролойиҳа орқали 2 046 та иш ўрни яратилган. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа мониторинги; (4) молиявий маслаҳат. 2026 режа (240 лойиҳа) 2025дан кескин кам — буни ўрта ва йирик саноат лойиҳалари ҳисобига кўпайтириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (751, 20, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 5 та оғир тоифадаги маҳалла | 1-маҳалла: Амир Темур | 2-маҳалла: Оқтепа | 3-маҳалла: Қизилқум | 4-маҳалла: Илонли | 5-маҳалла: Мустақиллик | Маҳалла типологияси: Оғир — 5 та, Ўрта — 19 та | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги / Ижтимоий реестр', 'Оғир тоифадаги 5 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳага улаш механизмлари қўлланиши лозим. Ҳар ой KPI мониторинг (иш ўрни, даромад, қайтмаслик) юритилиши тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (752, 20, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: Агробанк (1 филиал), Халқбанки (1 БХМ), Трастбанк (1 БХМ) | Банк ходимлари: 65 нафар | Маҳалла банкирлари: 7 та (1 аёл, 6 эркак)', TRUE, 'SQB / Марказий банк', 'Маҳалла банкирлари сони (7 та) 24 та МФЙ учун жуда кам. Банкирлар сонини ошириш ва аёл банкирлар улушини кўпайтириш тавсия этилади. SQB филиали йўқлиги — стратегик муаммо: АЭС лойиҳаси контекстида туманда SQB филиали очиш приоритет вазифа.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (753, 20, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (754, 20, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Туманда 3 352 нафар аёл пилла боқиш орқали банд эканлиги инобатга олиниб, уларни расмий молиялаштиришга уланиш ва боғдорчилик/чорвачилик бўйича бизнес тренинглар ташкил этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (755, 20, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', '5 та оғир маҳаллада ишсизликни камайтириш режаси', 'Жами: 5 та маҳалла, оғир тоифа — Амир Темур, Оқтепа, Қизилқум, Илонли, Мустақиллик | Ишсизлар (2025): 2 438 киши | Ёшлар (16–30): 588 киши | Аёллар: 855 киши | Кредит маҳсулотлари: 1) Микрокредит, 2) Оилавий тадбиркорлик, 3) Давлат субсидияси | Мақсад: 2027 йилгача 2,2% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '5 та оғир тоифали маҳаллада аёллар (35%) ва ёшлар (24%) ишсизлиги юқори. «Бир маҳалла — бир драйвер йўналиш» модели асосида 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш ва бандликни таъминлаш мумкин. Оғир МФЙларга ажратилган 25 млрд сўмни айланма капитал фонди сифатида (3–5% ставка, гровсиз микрокредит) ишлатиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (756, 20, 33, 5, '5', 'Атом электр станцияси қурилиши', 'Фориш тумани — Ўзбекистоннинг биринчи АЭС-кичик модулли реакторлар лойиҳаси марказига айланмоқда', 'Жами: 1 та йирик стратегик объект (қурилиш босқичида) | Йўналиш: АЭС инфратузилмаси, йўл бўйи хизмат, кадрлар тайёрлаш | Имконият: қурилиш даврида 5 000+, ишга туширилгандан кейин 1 000+ доимий иш ўрни | Инвестиция: мулти-миллиардли давлат стратегик лойиҳаси', TRUE, 'Ўзатом / Ҳокимият', 'АЭС қурилиши Фориш учун «генерация ўзгариши» имконияти. Туман дарҳол АЭС атрофида сервис кластери (йўл бўйи объектлари, ётоқхона, ошхона, лойиҳалаштириш бюроси) ва техник коллеж/ўқув маркази (АЭС ишчиларини тайёрловчи) лойиҳаларини шакллантириши керак. 2026–2028 йилларда 5 та «мегапилот» — қурувчилар учун ётоқ комплекси, тиббий пункт, логистика хабидан бошлаш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (757, 20, 34, 5, '5', 'Тоғ-кон ва қурилиш материаллари ресурслари', 'Республикадаги энг бой қазилма захираларидан бирига эга — фойдаланиш атиги 25%', 'Жами: 7 турдаги мажмуавий минерал хомашё захираси | Базальт: 22,2 млн тонна | Барит: 11,9 млн тонна | Цемент хомашёси: 131 333 минг тонна | Қурилиш тошлари: 13 245 минг м³ | Қум-шағал: 5 070 минг м³ | Йўналиш: карьер + қайта ишлаш заводлари (цемент, базальт тола) | Инвестиция: $20–50 млн ҳар бир йирик кон учун', TRUE, 'Геология қўмитаси', 'Туманда қурилиш материаллари ишлаб чиқариш салоҳияти ҳозир атиги 25% га ишлатилган. АЭС қурилиши маҳаллий цемент, базальт ва қурилиш тоши учун катта ички бозор очади — 2–3 та йирик кон ва қайта ишлаш заводини ДХШ (давлат-хусусий шериклик) асосида ишга тушириш лозим. Бу нафақат экспорт, балки АЭС қурилишига импорт ўрнини босиш орқали ҳам валютани тежайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (758, 20, 35, 5, '5', 'Қуёш энергетикаси салоҳияти', 'Чўл-дашт зонаси — қайта тикланувчи энергия учун идеал ҳудуд', 'Жами: 280–300+ қуёшли кун/йил | Йўналиш: ўрта ва йирик СЭС лойиҳалари, саноат корхоналари учун рутоп қуёш тизимлари | Имконият: 956 000 га ҳудуддан фойдаланилмаган бўш ерлар улкан — фотовольтаик парклар учун идеал | Инвестиция: $8–30 млн/лойиҳа', TRUE, 'Минэнерго', 'АЭС билан ҳибрид энергетика модели ярата олишнинг ягона имконияти Фориш ҳудудида мавжуд: АЭС асосий базали ишлаб чиқариш + қуёш СЭС кундузги пик соатларга. Энг муҳими — ҳозирданоқ Фориш АЭС хизматидаги ишчилар учун 2–5 МВт ли пилот СЭС лойиҳасини ишга тушириш ва бу орқали қуёш паналлари йиғиш заводини туманда лакализациялашга йўл очиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (759, 20, 36, 5, '5', 'Айдар-Арнасой кўли ва эко-туризм', 'Туман — Айдаркўл-Нурота турзонаси кириш дарвозаси', 'Жами: 3 та туристик йўналиш | Йўналиш 1: Айдаркўл бўйи дам олиш (қум-кулмоч, балиқ овлаш, кемасиёр) | Йўналиш 2: Нурота тоғларида треккинг ва глампинг | Йўналиш 3: Чўл сафари (4×4, юлдузларни кузатиш) | Инвестиция: $10–30 млн йирик кўлбўйи комплекси учун', TRUE, 'Ҳокимият', 'Айдаркўлни Жиззах ва Нурота туманлари билан биргаликда «Aydarkul-Nurata Eco Region» ягона бренди остида сотиш керак. 2026–2028 йилларда 1–2 та халқаро даражадаги эко-резорт ҳамда 5–10 та маҳаллий гестҳауз тармоғини яратиш ва Самарқанд–Бухоро туристик оқимининг 5–10% ни Айдаркўлга йўналтириш мумкин (йилига 50–100 минг сайёҳ).', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (760, 20, 37, 5, '5', 'Чорвачилик кластери ва гўшт қайта ишлаш', 'Туман ихтисослашувининг №1 йўналиши, аммо қайта ишлаш — 0%', 'Жами: 10 та МФЙ чорвачиликка ихтисослашган (6 чуқур) | Яйлов фонди: 505 200 га (туман умумий ер фондининг 53%) | Гўшт қайта ишлаш: ҳозир 0% (катта потенциал!) | Йўналиш: замонавий гўшт-сут мажмуи, мини-қассобхоналар | Инвестиция: 50–100 млрд сўм мажмуа учун', TRUE, 'Ҳокимият', 'Ҳозирда гўшт қайта ишлаш тумандан фактик 0% ни ташкил этади — бу йирик имкониятни кўрсатади. Биринчи қадам сифатида 1 та ўрта (5–10 тонна/кун) гўшт қайта ишлаш заводи + тоифалаш-сақлаш совуткичлари тармоғини қуриш керак. Қайта ишлаш улушини 30%гача ошириш — йилига 200+ млрд сўмлик қўшимча қиймат ва экспорт имконини беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (761, 20, 38, 5, '5', 'Боғдорчилик ва узумчилик', '9 та МФЙ боғдорчиликка ихтисослашган — экспорт салоҳияти юқори', 'Жами: 1 583 га узумзор | 4 654 т ҳосил | қайта ишлаш улуши: 35% | Йўналиш: қуритилган мева (кишмиш), сок, шинни, биологик пайвандлар | Имконият: Қозоғистон, Россия, Хитой бозорига экспорт | Инвестиция: $5–12 млн қайта ишлаш ва паковка комплекси учун', TRUE, 'Ҳокимият / Ер қўмитаси', 'Қайта ишлаш улушини 35% дан 70%гача оширишнинг тайёр имконияти бор. «Forish kishmishi» деган бренд остида ягона B2B савдо платформасини яратиш ва 1 та йирик паковка-сертификация маркази (HACCP, halal) орқали Самарқанд логистика йўлига уланиб, 2027 йилгача йиллик 8–10 минг тонна экспортга чиқиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (762, 20, 39, 5, '5', 'Аёллар бандлиги ва пиллачилик', '2026 йилда 3 135 нафар аёл доимий + 3 352 мавсумий бандлик режаси', 'Жами: 6 487 нафар аёл (доимий + мавсумий) | Пилла МФЙлари: 4 та (Учма, Ўхум, Ойбек, Нурак) | Йўналиш: пилла → ипак гавлама → тикувчилик кооперативлари | Кредит: 36,3 млрд сўм (552 нафар учун) | Инвестиция: 5–10 млрд сўм қайта ишлаш сехи учун', TRUE, 'Ҳокимият', 'Пиллачилик мавсумий бандликни доимийга айлантириш энг катта имконият: пилла → ипак гавлама → тайёр маҳсулот занжирини туманда лакализациялаш. Бу учун Учма ёки Ўхум МФЙларида 1 та кичик гавлама сехи + 2–3 та тикувчилик кооперативи очиш керак — натижада 3 352 мавсумий аёлнинг камида 1 000 нафари йил давомида банд бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (763, 20, 40, 5, '5', 'Туризм инфратузилмасига давлат инвестицияси', 'Маҳаллалар туризм инфратузилмасини ривожлантириш дастури', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Айдар-Арнасой кўли ва Нурота тоғлари асосида туризм инфратузилмасига давлат инвестицияси режасини шакллантириш — 2026–2028 йил приоритет вазифаси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (764, 20, 41, 6, '6', 'Стратегик хулоса — Фориш ўсиш нуқтаси', '«Тўғри инвестиция + инфратузилма модернизацияси + туризм» формуласи', 'Жами: 4 та стратегик ўсиш устуни | 1-устун: АЭС қурилиши — генерациявий иқтисодий импульс | 2-устун: Тоғ-кон бойликлари — салоҳият 25% ишлатилган | 3-устун: Туризм потенциали — Айдаркўл, Нурота | 4-устун: Чорвачилик — 505 минг га яйлов', TRUE, 'SQB / Ҳокимият', 'Фориш — республикадаги «уйқудан уйғонаётган» потенциал тумани. Туман ҳудуди катта (956 минг га) бўлиб, аҳоли зичлиги паст — бу йирик саноат, энергетика ва турзонани бир вақтда ривожлантириш имконини беради. Аммо бу ҳолат фақат бир-бирини қўлловчи кетма-кетлик билан ишлайди: АЭС → йўл → туризм → хизмат → бандлик. Ҳар йўналишни алоҳида эмас, мажмуавий мастер-режа доирасида олиб бориш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (765, 20, 42, 6, '6', '2026 йил аниқ KPI лар', 'Йил охиригача эришиладиган мақсадлар', 'Жами: 435 та янги иш ўрни (2026 йил, режа) | Тармоқ тақсимоти: Саноат — 40, Қ/х — 30, Тоғ-кон — 20, Туризм — 20, Расмийлаштириш — 38 | Микролойиҳалар: 240 та → +480 ишчи ўрни | Аёллар бандлиги: 3 135 нафар (610 доимий, 612 тадбиркор, 552 кредит, 1 116 қайта ўқитиш) | Инвестиция: 3 558,8 млрд сўм (2026–2028)', TRUE, 'Ҳокимият', 'KPI ларнинг ҳажми камтарона (435 иш ўрни кам), бу — ҳозирги давлат бюджетига боғлиқ режа. Хусусий инвестицияни 3 баравар ошириш мумкин: АЭС подрядчиларидан 1 000+, туризм/сервисдан 500+, тоғ-кон қайта ишлашдан 700+ иш ўрни. Шу сабабли 2026 йил охирида KPI ни ҳақиқий мақсадга — 1 500–2 000 янги иш ўрнига қайта кўриб чиқиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (766, 20, 43, 6, '6', 'Узоқ муддатли инвестиция режаси 2026–2031', '6 йиллик инвестиция тренди — барқарор ўсиш', 'Жами: 8 525 млрд сўм инвестиция (2026–2031) | 2026: 1 012,5 млрд сўм | 2027: 1 262,5 млрд сўм | 2028: 1 375 млрд сўм | 2029: 1 500 млрд сўм | 2030: 1 625 млрд сўм | 2031: 1 750 млрд сўм | Йиллик ўсиш: ~12% (барқарор) | Молия структураси (тавсия): 30% давлат, 70% хусусий + ХИ', TRUE, 'Ҳокимият', 'Жами 8,5 трлн сўмлик инвестицияни жалб қилиш учун «Forish Investment Box» яратиш керак: ҳар инвестор учун тайёр пакет — ер, техник шартлар, кредит шартлари, солиқ имтиёзлари. ДХШ (PPP) механизмини мажбурий босқичга айлантириш, давлат улушини максимал 30% билан чегаралаш — қолгани хусусий капитал ва ХИ (АБР, ЕБРР, Жаҳон банки) орқали йиғиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (767, 20, 44, 6, '6', 'Инфратузилмавий ўзгаришлар режаси', 'АЭСни инфратузилма катализатори сифатида ишлатиш', 'Жами: 5 та устувор инфратузилма йўналиши | 1-йўналиш: Йўл — 614 км таъмирлаш керак (хозир асфальт улуши 39%) | 2-йўналиш: Сув — танқислик мавжуд (камбағаллик #1 сабаби) | 3-йўналиш: Канализация тизими — 2% (амалда йўқ) | 4-йўналиш: Электр тармоғи — модернизация керак | 5-йўналиш: Газ — 44% таъминланганлик', TRUE, 'Ҳокимият', 'АЭС қурилиши учун давлат йирик инфратузилма блогини олиб келади — буни барча Фориш учун катализатор қилиш керак. АЭС га борадиган магистрал йўл, 110 кВ электр линияси ва ичимлик сув қувурини шундай йўналтирилсинки, у ёзишда йирик чорва, туристик ва саноат МФЙларидан ҳам ўтсин. Бу — давлат инвестицияси ҳажмини «+30% самара» билан кенгайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (21, 10, 'payariq', 'Пайариқ', 'Пайарык', 'Payariq', '', 'payariq.json', TRUE, NULL, NULL, 44, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
