INSERT INTO hero_kpis (hero_kpi_id, district_id, metric_name, metric_value, metric_unit, load_no, final_flag, date_modify) VALUES (68, 21, 'Хонадон', 45000, 'та', 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (768, 21, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил кўрсаткичлари | Саноат: 724,5 млрд сўм (2024 — 805,8 млрд сўмга нисбатан -10,1% — верификация талаб қилинади) | Бозор хизматлари: 1 894,5 млрд сўм (2024 — 1 450,3 млрд сўмга нисбатан +30,6%) | Саноат ўсиш суръати: 104,1% (қиймат пасайган бўлса-да индекс мусбат — методология аниқлаштирилиши шарт) | Тармоқлар улуши: Қ/х 8,7%, Саноат 1,3%, Хизматлар 2,4% (йиғинди 100% эмас — қайта тўпланиши керак)', TRUE, 'Туман статистика бўлими', 'Бозор хизматлари 5 йилда 2,9 баравар ўсган (654,7 → 1 894,5 млрд сўм) — бу туманнинг асосий драйвери. Лекин 2025 йилда саноат қиймати тушгани, шу билан бирга индекс мусбат кўрсатилгани — статистик ноаниқлик аломати. Биринчи навбатда саноат динамикасини верификация қилиш ва тармоқлар улушини (Қ/х+саноат+хизматлар = 100%) қайта ҳисоблаш керак. Саноат зонасини кенгайтириш ва инвестиция жалб қилиш ҳажмини сақлаб қолиш орқали саноат пасайишини қоплаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (769, 21, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Пайариқ туманининг устувор тармоқлари ва ривожланиш йўналишлари', 'Жами: 4 та устувор соҳа | 1-ўрин Савдо: туман савдо айланмаси ва бозор инфратузилмаси | 2-ўрин Узумчилик: вилоятдаги анъанавий узумзорлар ва токчилик кластери | 3-ўрин Чорвачилик: гўшт-сут маҳсулотлари ва қайта ишлаш | 4-ўрин Туризм: маҳаллий зиёратгоҳлар ва агротуризм имкониятлари', TRUE, 'Туман ҳокимияти', 'Драйверлар «1-савдо» билан бошланиши хизматлар ҳажми ўсишини изоҳлайди (1 894,5 млрд сўм). Узумчилик ва чорвачилик аграр-индустриал кластер сифатида қайта ишлаш корхоналари (кичик бизнес — 700,1 млрд сўм) билан боғланса, тайёр маҳсулот улуши кўпаяди. Туризм учун вилоят марказига 45 км яқинлиги қулай, лекин темир йўл стансиясига 38 км узоқлиги логистикани қийинлаштиради — автомобил йўли инвестиция йўналиши бўлиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (770, 21, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', '2021: 487.6 | 2022: 619.9 | 2023: 668.0 | 2024: 805.8 | 2025: 724.5 (млрд сўм)', TRUE, 'Туман статистика бўлими', '5 йиллик тренд: 2021–2024 даврида барқарор ўсиш (+65,2%), лекин 2025 йилда -10,1% пасайиш кузатилди. Алоҳида диққат: йирик корхоналар 2023 йилда 230 млрд сўмдан 2024 йилда 12,7 млрд сўмгача кескин тушган — йирик саноат корхонаси ёпилгани ёки регистрация ўзгариши эҳтимоли катта. Бу ҳолат верификация талаб этади. Қисқа муддатда кичик бизнес (700,1 млрд сўм — кучайиб бораётган) ва саноат зонаси орқали бўшлиқни тўлдириш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (771, 21, 4, 1, '1', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми', '{''type'': ''yearly_credits'', ''years'': [2021, 2022, 2023, 2024, 2025], ''values'': [1107, 637, 1062, 1149, 1186.8], ''total'': 5141.8, ''unit'': ''млрд сўм''}', TRUE, 'Марказий банк', 'Кредит ҳажми 2021 йилдан 2025 йилга секин ўсган (+7,2% / 5 йил), бошқа тумандаги жадал ўсишдан фарқли (масалан Қўқон 2025 — 3 169 млрд сўм). NPL (муаммоли кредитлар) 2024 йилда 4,1% дан 2025 йилда 78,5% га сакраганлиги ёзилган — бу аниқ техник хатолик ёки методология ўзгариши, верификация шарт. Кредит сиёсатини саноат пасайишини бартараф этишга йўналтириш — қайта ишлаш ва экспортбоп лойиҳаларга устуворлик бериш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (772, 21, 5, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида 0–100 балл шкаласи', 'Маълумот мавжуд эмас — Excel да «⚠ Тўлдириш шарт эмас» (Марказий гуруҳ ҳисоблайди)', FALSE, 'Марказий аналитика', 'Кўрсаткич Марказий гуруҳ томонидан кейинроқ ҳисоблаб чиқилади. Шу тариқа якуний ҳисоботда макрокўрсаткичлар ва туризм драйвери билан крос-таҳлил қилинади. Туман брендини рақамли каналларда (узумчилик, агротуризм) кучайтириш қидирув фаоллигига ижобий таъсир кўрсатади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (773, 21, 6, 1, '1', '«Тадбиркорлик саноат зонаси» — Пайариқ', 'Пайариқ тумани ҳудудидаги саноат зонаси, унда фаолият юритаётган лойиҳалар ва иш ўринлари', 'Жами: «Тадбиркорлик саноат зона» — 13 та лойиҳа | Иш ўринлари: 202 та | Ердан фойдаланиш: 0,6% — жуда паст | Қурилиш материаллари кластери: ҳозирда йўқ', TRUE, 'Туман ҳокимияти', 'Зонадаги ердан фойдаланиш атиги 0,6% — бу Қўқон ЭИЗ (10 минг иш ўрни режаси) масштабидан 50 марта кам. Биринчи қадам — 13 та мавжуд лойиҳа учун инфратузилма (электр модернизация, газ 40,7%) тайёрлаб, 2027 йилгача ердан фойдаланишни ≥30% га етказиш. Қурилиш материаллари кластерини очиш орқали маҳаллий хомашё (қум, шағал) асосида қўшимча 500–800 иш ўрни яратиш мумкин. Бу саноат пасайишини тескари бурадиган стратегик дастак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (774, 21, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2021: 65.3 | 2022: 65.3 | 2023: 65.3 | 2024: 65.3 | 2025: 68.9 (%)', TRUE, 'Сув хўжалиги', '4 йил давомида қамров қотиб қолган (65,3%), фақат 2025 йилда +3,6 п.б. ўзгариш юз берди — республика ўртачаси (≈97%) ва Қўқон шаҳри (99,3%) дан анча орқада. Бу инфратузилмадаги энг муҳим оғриқ нуқтаси: ҳар уч хўжаликдан биттаси марказлашган сув тармоғига уланмаган. Биринчи галда аҳоли зичлиги (221,4 киши/км²) юқори бўлган маҳаллаларга устуворлик бериб, 2027 йилгача 90% га чиқариш мақсадли режа қилиниши керак. Канализация (87%) билан биргаликда сув-санитария бирлаштирилган дастур самарали бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (775, 21, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Пайариқ тумани ички йўлларининг асфальтланган улуши ва умумий узунлиги', 'Жами: Йўллар узунлиги — 2 246 км | Асфальтланган йўллар улуши: 32,8% | Темир йўл стансиясигача масофа: 38 км | Вилоят марказига масофа: 45 км', TRUE, 'Йўл хўжалиги', 'Йўлларнинг 67,2% ҳали ҳам асфалтланмаган — бу туризм ва савдо драйверларини сезиларли тийиб турадиган омил. Қўқон шаҳрида 2025 йилда таъмирлаш 100% га етказилгани билан таққосласа, Пайариқ туман бу борада 5–7 йил ортда. Тавсия: 2 246 км дан 800–1 000 км узумчилик ва саноат зонаси йўналишидаги «иқтисодий йўллар»ни биринчи 2 йилда таъмирлаш — бу ROI ни тезлаштиради. Қишлоқ йўллари учун кейинги босқичда давлат-хусусий шериклик (ДХШ) механизмини ишлатиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (776, 21, 9, 2, '2', 'Электр таъминоти сифат даражаси', 'Электр узилишлари ва тармоқ модернизация ҳолати', 'Жами: 1–1,2 марта/ой (ўртача узилиш) | Трансформаторлар: 3,3% эскирган | Линиялар: 8,8% алмаштириш керак | Газ билан таъминланганлик: 40,7%', TRUE, 'Электр тармоқлари', 'Электр узилишлари 1–1,2 марта/ой — ўртача даражада, Қўқон шаҳри билан тенг. Эскирган тармоқ улуши паст (3,3% / 8,8%) — кутилмаганда яхши кўрсаткич, лекин газ таъминоти атиги 40,7% бўлгани сабабли қишда қўшимча электр юкламаси юзага келиши мумкин. Биринчи навбатда саноат зонаси ва узумчилик-чорвачилик кластерлари жойлашган ҳудудларга модернизацияни мақсадли йўналтириш керак. Газ танқислигини электрга алмаштириш йўли билан саноат барқарорлигини ошириш мумкин — лекин тариф ва қувват захираси олдиндан режалаштирилиши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (777, 21, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ер фонди тузилмаси', 'Маълумот мавжуд эмас — Excel да фақат умумий майдон (41 204 га) ва суғориладиган ер (42 100 га) кўрсатилган, ер тоифалари бўйича батафсил тақсимот тўлдирилмаган', FALSE, 'Кадастр', 'Ер тоифалари (тарихий-маданий, ўрмон, қишлоқ хўжалиги, саноат) бўйича батафсил тақсимот зарур — ҳозирги жами кўрсаткичларда ҳатто суғориладиган ер (42 100 га) умумий майдондан (41 204 га) катта чиқмоқда, бу аниқ методологик хатолик. Кадастр бўлимидан тозалаш сўралиши керак. Тўлдирилгач, узумчилик/чорвачилик ва саноат зонаси учун ер заҳираларини аниқ режалаштириш мумкин бўлади. Суғориш каналлари (32,3% бетонланган) — бетонлаш улушини ошириш қишлоқ хўжалиги ерлари самарадорлигини оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (778, 21, 11, 2, '2', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳолини жамоат транспорти билан қамраб олинганлик даражаси', 'Маълумот мавжуд эмас — Excel да жамоат транспорти қамрови алоҳида тўлдирилмаган. Фақат йўловчи айланмаси киритилган: 6 622,8 минг киши', FALSE, 'Хокимият', 'Йўловчи айланмаси (6 622,8 минг киши) ва йўлларнинг асфалтланиш даражаси (32,8%) бирлашиб таҳлил қилинса, аҳоли учун жамоат транспорти етишмаслиги аён. Қўшни шаҳарларда (Қўқон — 100%) бу масала ҳал қилинган, Пайариқ туманда эса маршрутлар, парк ва электрон тўлов тизими алоҳида ҳужжатлаштирилиши керак. Тавсия: вилоят марказигача 45 км масофа ҳисобига шахс автомобилига боғлиқлик юқори — қатнов автобуслари тармоғини кенгайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (779, 21, 12, 2, '2', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик', 'Маълумот мавжуд эмас — инфратузилма варағида (Excel «2. Инфратузилма») мактабгача таълим қамрови устуни тўлдирилмаган. Аҳоли ва бандлик варағида қаралади', FALSE, 'Мактабгача ва мактаб таълими вазирлиги', 'Мактабгача таълим қамрови инфратузилмавий ижтимоий бўғин сифатида аҳоли зичлиги (221,4 киши/км²) ва бандлик билан бевосита боғлиқ. Маълумот «3. Аҳоли ва бандлик» варағидан олиниши мумкин — алоҳида сўров шакли орқали тўлдирилиши тавсия этилади. Маълумот тўлдирилгач, ёш аҳоли қамрови ва аёл бандлиги орасидаги корреляцияни баҳолаш мумкин — бу хизматлар сектори ўсишини қўллаб-қувватлайдиган стратегик омил.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (780, 21, 13, 3, '3', 'Меҳнат ресурслари', 'Жами меҳнат ресурслари сони — йиллик динамика', '2021: 143.7 | 2022: 148.3 | 2023: 154.6 | 2024: 160.5 | 2025: 165.8 (минг киши)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари барқарор ўсиб бормоқда (+5,2 минг киши, +3,3% 2025 йилда). Бандликни ошириш учун узумчилик, чорвачилик ва туризм соҳалари бўйича маҳалла даражасида қисқа муддатли ўқув дастурларини кенгайтириш зарур. Қайтган мигрантлар (2 570 киши) — тайёр кадрлар ресурси, уларни маҳаллий лойиҳаларга жалб этиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (781, 21, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Иш ўрни яратиш ва меҳнат бозори резервлари', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 108 453 киши (+3,1%) | Қайтган мигрантлар (2025): 2 570 киши (+33,3%) | Норасмий секторда бандлик (2021): 41 183 киши | Хорижга кетган мигрантлар: 2021 — 4 912, 2022 — 4 510, 2023 — 4 430, 2024 — 4 265, 2025 — 2 854 (-33,1%)', TRUE, 'Бандлик маркази / ИИВ миграция', 'Хорижга кетиш кескин камайган (-33,1%), қайтиш ошган (+33,3%). Қайтган мигрантларни маҳаллий лойиҳаларга жалб қилиш ва норасмий секторни расмийлаштириш орқали бандликни ошириш мумкин. 41 183 норасмий ишчилар — катта резерв, расмийлаштириш орқали йилига 20+ млрд сўм солиқ тушуми кўпайтириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (782, 21, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси ва ишсизлар сони', 'Жами: Ишсизлик кўрсаткичлари | Расмий ишсизлик (2025): 5,8% (-3,3%) | Ишсизлар сони (2025): 5 497 киши (-1,3%) | Ишсизлик тренди: 10,1% → 9,7% → 7,2% → 6,0% → 5,8% | Ёшлар (16–30): 1 489 киши | Аёллар: 3 426 киши | Мақсад: 2027 йилгача 2,4% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизликни 2,4% га туширишга учун ёшлар ва аёллар бўйича манзилли ишга жойлаштириш дастурлари ва қисқа муддатли касбий курсларни кенгайтириш лозим. Аёллар ишсизлиги (3 426 киши, умумийнинг 62%) жиддий диққатга сазовор. Ҳар бир маҳаллада талаб юқори касблар бўйича тезкор ўқитиш ва микролойиҳаларга жалб қилиш механизмини кучайтириш зарур.', 5497, 5.8, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (783, 21, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони', 'Жами: Камбағаллик кўрсаткичлари | Камбағаллик даражаси (2025): 4,2% (-36,4%) | Камбағал оилалар (2025): 2 978 та (-36,1%) | Камбағаллик тренди: 10,1% → 8,7% → 7,2% → 6,6% → 4,2% | Кам таъминланган оилалар: 2 017 та | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Статистика бўлими / МФЙ агентлиги', 'Камбағаллик 5 йилда икки баробардан кўп камайган — яхши натижа. Ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши, ижтимоий ёрдам иш билан боғлиқ қилиниши зарур. Кам таъминланган 2 017 оила — алоҳида профилактик дастур талаб қилади.', 2978, 4.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (784, 21, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '«Барқарор келажак» дастури — 2026 йилда ёшлар даромадини ошириш режаси', '', FALSE, 'Бандлик маркази', 'Маълумот Бандлик марказидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Ёшлар даромадини ошириш учун дуал таълим, биринчи иш ўрнига субсидия ва талаб юқори касблар бўйича тезкор қайта тайёрлаш дастурларини кучайтириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (785, 21, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар бандлиги ва даромадини ошириш — 2026 йил режаси', '', FALSE, 'Оила ва хотин-қизлар бўлими', 'Маълумот Оила ва хотин-қизлар бўлимидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Туманда аёллар ишсизлиги жуда юқори (3 426 киши, умумийнинг 62%) — манзилли дастурлар билан қамраб олиниши лозим: имтиёзли молиялаштириш, мос иш режими ва маҳалла кесимида касбга йўналтириш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (786, 21, 19, 3, '3', 'Олий таълим муассасалари', 'Университетлар, талабалар сони ва қувватлар', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Самарқанд шаҳрига 45 км яқинлиги (вилоят маркази) — олий таълим имкониятлари юқори, лекин туман ҳудудида махсус қ/х ва агро-ишлаб чиқариш йўналишлари бўйича коллеж ёки филиал очилиши кадрлар тайёрлашга ёрдам беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (787, 21, 20, 3, '3', 'Мактабгача таълим ва мактаб юкламаси', 'Мактабгача таълим қоплами ва мактаблардаги смена тақсимоти', 'Жами: Мактабгача таълим қоплами | 2021: 83,9% | 2022: 84,6% | 2023: 86,0% | 2024: 87,1% | 2025: 87,9% | Ўзгариш (2021→2025): +4,0 п.п. | Мактаб юкламаси: 1 сменали — 30 та, 2 сменали — 28 та, Жами — 58 та | 2 сменали улуши: 48,3%', TRUE, 'Халқ таълими', 'Мактабгача таълим барқарор ўсяпти (83,9% → 87,9%, +4 п.п.). 28 та мактаб 2 сменада ишлаши инфратузилмага босим борлигини кўрсатади. Янги мактаблар қурилишини жадаллаштириш зарур. 2 сменали улуши 48,3% — республика ўртачасига нисбатан паст эмас, лекин узоқ муддатда 30% дан паст бўлиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (788, 21, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | Банкда «Сунъий интеллект куни» ташкил этилди — ҳар чоршанба | Ходимларга онлайн ўқитиш тизими жорий қилинди | Раҳбар ходимлар ўқувлари тўлиқ якунланди | СИ ечимларидан фойдаланиш бўйича қисқа ўқув курслари ташкил этилди', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Ҳафталик «СИ куни» амалиёти орқали ходимлар янги технологияларни кундалик ишга татбиқ этишни ўрганмоқда. Кейинги босқичда ҳар бир бўлим учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (789, 21, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, ҳоким ўринбосарлари, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 2-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 3-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 4-босқич: МФЙ раислари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади: аввал ҳоким даражасида стратегик қарорлар учун СИ, кейин банк раҳбарларига скоринг ва таҳлил, сўнг маҳалла банкирларига мижоз билан ишлаш учун СИ платформа ўргатилади. Ҳар босқич 2–4 ҳафта давом этади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (790, 21, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш, тадбиркорлик ва ишга жойлашишга тайёрлаш', '', FALSE, 'SQB', 'Маълумот SQB маҳаллий филиалидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. СИ платформаси орқали ҳар бир фуқарони индивидуал баҳолаш — кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтириш — Пайариқ туманида ҳам жорий этилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (791, 21, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради: мижозларга автоматик маслаҳат, бизнес-режа генератори, кредит мослаштириш ва самарадорлик мониторинги. 2026 йил якунигача барча 65 МФЙда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (792, 21, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари', 'Жами: 65 та маҳалла | Савдо ва хизмат: 35 та МФЙ (54%) | Чорвачилик: 12 та МФЙ (18%) | Ишлаб чиқариш: 10 та МФЙ (15%) | Деҳқончилик: 8 та МФЙ (12%)', TRUE, 'МФЙ агентлиги', 'Савдо ва хизмат улуши юқори (54%). Ишлаб чиқариш ва чорвачилик МФЙларида қиймат занжирини кенгайтириш ва бозорга чиқиш каналларини ривожлантириш орқали даромадни ошириш мумкин. Деҳқончилик МФЙлари (8 та) узумчилик ва писта плантациялари билан боғланса — экспорт салоҳияти кескин ошади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (793, 21, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида ўсишни таъминловчи тармоқлар', 'Жами: 4 та драйвер сектор | 1-сектор: Савдо | 2-сектор: Енгил саноат (тикувчилик, ҳунармандчилик) | 3-сектор: Чорвачилик | 4-сектор: Туризм', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни «ишлаб чиқариш + савдо + хизмат» занжирида боғлаш керак. Узумчилик (8 200 га) ва туризм потенциалидан фойдаланиб, тайёр маҳсулотни бозорга чиқариш ва онлайн сотув каналларини кенгайтириш орқали қўшимча қийматни ошириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (794, 21, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва маҳалла тақсимоти', 'Жами: 680 та лойиҳа | Иш ўринлари: 1 210 та | Жами маҳаллалар: 65 та | Лойиҳалар умумий қиймати: 29,4 млрд сўм | 2026 йил режаси: Саноат — 36 та (455,9 млрд сўм, 839 иш ўрни), Хизмат — 23 та (223,1 млрд сўм, 315 иш ўрни)', TRUE, 'SQB / Туман ҳокимияти', '680 та микролойиҳа орқали 1 210 та иш ўрни яратилган. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа мониторинги; (4) молиявий маслаҳат. 2026 йилда саноат портфели 455,9 млрд сўм — катта ҳажм, бу ёш меҳнат ресурси (165,8 минг киши) учун муҳим иш ўринлари манбаси.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (795, 21, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 11 та оғир тоифадаги маҳалла | Маҳаллалар: Янгиобод, Бешқўрғон, Полвонариқ, Бошчўрош, Фитрат, Жавшар ота, Бирлашув, Туркибола, Илғор, Бошқўрғон, Фидокор | Маҳалла типологияси: Оғир — 11 та, Ўрта — 6 та, Енгил — 35 та, Яхши — 11 та | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги', 'Оғир тоифадаги 11 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Ишсиз аҳолини кўникма бўйича сегментация қилиб, 3 ойлик қисқа циклда ишга жойлаштириш ва микролойиҳага улаш механизмлари қўлланиши лозим. Ҳар ой KPI мониторинг (иш ўрни, даромад, қайтмаслик) юритилиши тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (796, 21, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: Жами банклар — 13 та (SQB — 1 филиал) | Банкоматлар: 170 та | Маҳалла банкирлари: 3 та (0 аёл, 3 эркак)', TRUE, 'SQB / Марказий банк', 'Маҳалла банкирлари сони (3 та) 65 та МФЙ учун жуда кам — ҳар банкирга 21 МФЙ тўғри келади. Банкирлар сонини кескин ошириш (12–15 та) ва аёл банкирларни жалб қилиш (ҳозир 0%) тавсия этилади. 170 та банкомат — қулай рақамли инфратузилма, лекин маҳалла даражасидаги жонли кадр борлиги муҳимроқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (797, 21, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой', TRUE, 'Марказий банк', 'Оилавий тадбиркорликни кўпайтириш учун SQB AI Advisor платформасидан фойдаланиш тавсия этилади. Платформа орқали кредит скоринги, бизнес-режа тузиш ва молиявий маслаҳат олиш имконияти мавжуд. Маҳалла банкирлари ҳар бир оилани платформага йўналтириш ва имтиёзли кредитдан самарали фойдаланишга ёрдам бериши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (798, 21, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Туманда аёллар ишсизлиги (3 426 киши) юқорилигини инобатга олиб, маҳалла банкирлари орқали аёлларни фаол жалб қилиш ва бизнес тренинглар ташкил этиш зарур. Ипакчилик (7 та маҳалла) ва тикувчилик каби аёллар учун анъанавий йўналишларни кенгайтириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (799, 21, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', '11 та оғир маҳаллада ишсизликни камайтириш режаси', 'Жами: 11 та маҳалла, оғир тоифа — Янгиобод, Бешқўрғон, Полвонариқ, Бошчўрош, Фитрат, Жавшар ота, Бирлашув, Туркибола, Илғор, Бошқўрғон, Фидокор | Ишсизлар (2025): 5 497 киши | Ёшлар (16–30): 1 489 киши | Аёллар: 3 426 киши | Кредит маҳсулотлари: 1) Микрокредит, 2) Оилавий тадбиркорлик, 3) Давлат субсидияси | Мақсад: 2027 йилгача 2,4% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '11 та оғир тоифали маҳаллада аёллар ишсизлиги (62%) ва ёшлар ишсизлиги (27%) устунлик қилади. «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ. 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш тавсия этилади. Ҳар оғир МФЙга 2 та якорь лойиҳа (узум қайта ишлаш, тикувчилик кооперативи) бириктириш — самарали ёндашув.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (800, 21, 33, 5, '5', 'Узумчилик кластери — экспорт салоҳияти', '8 200 гектар узумзор ва 69 141 тонна йиллик ҳосил — водийдаги етакчи кўрсаткичлардан бири', 'Жами: 8 200 гектар узумзор майдони | Йиллик ҳосил: 69 141 тонна | Қайта ишлаш улуши: 34% (ҳозир) | Йўналиш: қуритилган узум, шарбатлар, винотовар | Имконият: ишлов улушини 60% гача ошириш | Инвестиция: $5–15 млн/қайта ишлаш заводи', TRUE, 'Туман ҳокимияти / Қ/х бўлими', 'Пайариқ узумчилигида хомашё ҳажми (69 минг тонна) катта, аммо қайта ишлаш улуши ҳозир бор-йўғи 34% — бу етишмаган қўшимча қиймат демакдир. Узум ишлов берадиган 2–3 та ўрта қувватли заводни (қуритиш, концентрат, шарбат) Дўстлик ва Накурт маҳаллалари атрофида жойлаштириш керак. Шунда хомашё экспортидан тайёр маҳсулот экспортига ўтиш, фермер дарoмадини 1,5–2 баравар ошириш ҳамда ҳосилни мавсумий йўқотишдан сақлаш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (801, 21, 34, 5, '5', 'Писта плантациялари — янги стратегик йўналиш', 'Дўстлик, Кўлтўсин, Ғаллакор ва Накурт маҳаллаларида 13 000 гектар майдонга писта боғлари барпо этилмоқда', 'Жами: 13 000 гектар янги писта боғлари | Жойлашув: Дўстлик, Кўлтўсин, Ғаллакор, Накурт | Ҳосил даври: 4–5 йилдан бошлаб | Экспорт нархи: $6–10/кг (жаҳон бозори) | Имконият: қурғоқ ерларни юқори даромадли активга айлантириш | Потенциал даромад: $50–80 млн/йил (тўлиқ ҳосилда)', TRUE, 'Қ/х бўлими', '13 минг гектар писта плантацияси Пайариқ учун узоқ муддатли валюта тушуми манбаига айланиши мумкин — ҳозир глобал бозорда писта талаби ҳар йили 6–8% ўсмоқда. Аммо плантация етилгунча 4–5 йил кутиш керак, шунинг учун шу даврда фермерларни оралиқ экинлар (мош, дуккакли) орқали қўллаб-қувватлаш, кейинчалик эса маҳаллий писта тозалаш-қадоқлаш цехини яратиш зарур. Писта брендини «Payariq Pistachio» сифатида ҳозирдан рўйхатдан ўтказиш ва GI (географик кўрсаткич) олишга тайёрланиш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (802, 21, 35, 5, '5', 'Эркин иқтисодий зоналар ва саноат портфели', '3 та ЭИЗ доирасида 100+ лойиҳа режалаштирилган. 2026 йил саноат лойиҳалари алоҳида устувор', 'Жами: 3 та эркин иқтисодий зона | Режалаштирилган лойиҳалар: 100+ та (1–3 йил ичида) | 2026 саноат портфели: 36 та лойиҳа / 455,9 млрд сўм / 839 иш ўрни | 2026 хизмат портфели: 23 та лойиҳа / 223,1 млрд сўм / 315 иш ўрни | Жами 2026 портфели: 59 та / 679,2 млрд сўм / 1 154 иш ўрни', TRUE, 'Туман ҳокимияти', 'Учта ЭИЗ — Пайариқнинг асосий «капитал жалб қилиш канали». Аммо 100+ лойиҳани сочиб қўйиш ўрнига, 2 та аниқ ихтисослашувга (1: узум-мева қайта ишлаш кластери, 2: енгил саноат-тикувчилик) йўналтириш керак — шунда инфратузилма (электр, сув, омборхона) ҳам мақсадли қурилади. 2026 йилги 679 млрд сўмлик портфел учун лойиҳа паспортларини инвесторларга «тайёр пакет» (ер + уланиш + солиқ имтиёзлари + ишчи кучи) кўринишида тақдим этиш конверсияни 2–3 баравар оширади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (803, 21, 36, 5, '5', 'Агро- ва экотуризм потенциали', 'Тарихий-маданий 76 га, ўрмон фонди 27 га ва қишлоқ хўжалик 1 095 га ерлар туризм базаси сифатида', 'Жами: 1 198 гектар жами туризм-агро ер ресурси | Тарихий-маданий ерлар: 76 га | Ўрмон фонди: 27 га | Қишлоқ хўжалик ерлари: 1 095 га | 2026–2027 туризм иш ўрни: 327 → 420 | Йўналиш: агротуризм + узумзор турлари + гастротуризм', TRUE, 'Туман ҳокимияти / Туризм бўлими', 'Пайариқда «йирик меҳмонхона + тарихий ёдгорлик» модели эмас, балки «фермер хўжалиги + узумзор + миллий таомлар» модели ишлайди. Самарқанд шаҳрига яқинликдан фойдаланиб, 1 кунлик «узум-сайр + тандир таом» турларини ишга тушириш керак — Самарқандга келган хорижий сайёҳнинг 8–10% ини 1 кунга Пайариққа жалб қилиш реал. Бу модель 7 та йирик инвестиция эмас, 30–40 та оилавий гестхауз ва дегустация уйини талаб қилади — кам капитал, юқори меҳнат сиғими.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (804, 21, 37, 5, '5', 'Қуёш энергияси — арзон электр манбаи', 'Самарқанд вилояти йилига 280–310 қуёшли кунга эга — қайта тикланувчи энергетика учун қулай ҳудуд', 'Жами: 300+ қуёшли кун/йил (баҳолаш) | Йўналиш: қуёш панеллари ва кичик СЭС | Имконият: саноат ва қайта ишлаш цехлари учун арзон электр | Жалб этиш модели: PPA (Power Purchase Agreement) шартномалари | Инвестиция: $8–25 млн/лойиҳа | Жойлашув: ЭИЗ ҳудудлари ва агрокластер яқинида', TRUE, 'Минэнерго', 'Пайариқда саноат лойиҳалари ҳажми (455 млрд сўм/2026) ўсиб бораётган бир пайтда электр харажати инвесторлар учун муҳим омил бўлади. 5–10 МВт қувватдаги қуёш станциясини ЭИЗ ёнида қуриш ва энергияни PPA орқали резидент корхоналарга йўналтириш керак — бу инвесторларни жалб қилишда «арзон электр» рағбатини яратади. Биринчи қадам — 2 та пилот лойиҳани давлат-хусусий шериклик (ДХШ) асосида бошлаш ва 18 ой ичида иқтисодий самарасини ўлчаш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (805, 21, 38, 5, '5', 'Маҳалла кластерлари — пастдан юқорига иқтисодиёт', '65 та маҳалланинг ҳар бирида аниқ ихтисослашув: ишлаб чиқариш 10, савдо-хизмат 35, чорвачилик 12, дехқончилик 8', 'Жами: 65 та маҳалла, 4 та ихтисослашув йўналиши | Савдо ва хизмат: 35 та МФЙ | Ишлаб чиқариш: 10 та МФЙ | Чорвачилик: 12 та МФЙ | Дехқончилик: 8 та МФЙ | Ипакчилик: 7 та маҳалла (қўшимча йўналиш) | Оғир тоифа: 11 та маҳалла (мақсадли ёрдам)', TRUE, 'МФЙ агентлиги / SQB', 'Маҳалла даражасида ихтисослашув аниқ кўрсатилган — бу нодир устунлик. Ҳар бир тоифа учун алоҳида парадигма керак: савдо-хизмат маҳаллалари (35) учун рақамли тўлов ва e-commerce, ишлаб чиқариш маҳаллалари (10) учун кооператив цехлар, чорвачилик маҳаллалари (12) учун зооветхизмат ва ем-хашак етказиб бериш тармоғи. 11 та оғир тоифадаги маҳаллага «100-кунлик интенсив пакет» (микрокредит + кадр тайёрлаш + 1 та якорь лойиҳа) жорий этиш керак — улар иш ўринлари яратишнинг энг тез манбаи.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (806, 21, 39, 5, '5', 'Импорт ўрнини босиш — дефицит маҳсулотлар', 'Туманда энг кўп етишмайдиган 5 гуруҳ маҳсулотни маҳаллий ишлаб чиқариш орқали 30% импортни қисқартириш мақсади', 'Жами: 30% импорт ўрнини босиш мақсади (KPI 2026) | Дефицит 1: гўшт ва сут маҳсулотлари | Дефицит 2: қурилиш материаллари | Дефицит 3: антибиотик ва базавий дорилар | Дефицит 4: кимёвий маҳсулотлар | Локализация имконияти: гўшт қайта ишлаш ҳозир 21%, сабзавот 28% — резерв катта', TRUE, 'Туман ҳокимияти / Савдо палатаси', 'Импорт рўйхатини сабр билан таҳлил қилиш керак: гўшт-сут ва қурилиш материаллари — Пайариқда хомашё мавжуд (1 та фермер кластери, чорвачилик 12 МФЙ), фақат қайта ишлаш қувватлари етишмайди. Дастлабки қадам сифатида 2–3 та ўрта (5–10 млрд сўм) гўшт ва сут қайта ишлаш цехларини оилавий тадбиркорлик кредити (ҳозирги ҳажми 1 186 млрд сўм) орқали молиялаш мумкин. Шунда импорт оқимининг 15–20% ини 2 йил ичида тўхтатиш ва 700 та янги тадбиркор (KPI) учун аниқ нишон яратиш реал.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (807, 21, 40, 5, '5', 'Туризм инфратузилмасига давлат инвестицияси', 'Маҳаллалар туризм инфратузилмасини ривожлантириш дастури', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Самарқанд вилоятининг туристик оқими (йилига 4+ млн сайёҳ) ҳисобига Пайариқ агротуризм ва узум сайёҳлиги бўйича давлат инвестициясига устуворлик бериши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (808, 21, 41, 6, '6', 'Стратегик хулоса — 4 устун устунлик', 'Пайариқ туман ривожланишининг тўрт асосий таянч устуни: агрокластер, туризм, маҳалла иқтисодиёти ва ЭИЗ', 'Жами: 4 та стратегик устунлик | 1-устунлик: Узумчилик-агрокластер (8 200 га, 69 минг тонна) | 2-устунлик: Туризм ва агротуризм потенциали (Самарқандга яқинлик) | 3-устунлик: 65 маҳалла бўйича ихтисослашган иқтисодиёт | 4-устунлик: 3 та ЭИЗ ва ёш меҳнат ресурси', TRUE, 'SQB / Туман ҳокимияти', 'Тўрт устуннинг ҳар бири алоҳида ишласа таъсири паст бўлади — уларни боғлаш керак: агрокластер хомашёси → ЭИЗ қайта ишлаш заводларига → маҳалла даражасида иш ўринлари → туризм орқали тайёр маҳсулотни сотиш ва бренд яратиш. Шу занжир тузилмаса, ҳар бир йўналиш «ўз ичида» қолиб кетади. Туман ҳокимияти бу 4 та йўналишни биргаликда бошқарувчи координация маркази (Project Office) яратиши шарт.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (809, 21, 42, 6, '6', 'Инвестиция жалб режаси 2026–2031', 'Олти йиллик инвестиция трактори: ҳажмни 415 млрд сўмдан 700 млрд сўмгача босқичма-босқич ошириш', 'Жами: 3 095 млрд сўм — 6 йиллик жами инвестиция режаси | 2026: 415 млрд сўм | 2027: ~430 млрд сўм | 2028: ~450 млрд сўм | 2029: ~500 млрд сўм | 2030: ~600 млрд сўм | 2031: ~700 млрд сўм', TRUE, 'Туман ҳокимияти / SQB', 'Инвестиция режаси барқарор ўсиш траекториясини кўрсатади (+68% олти йилда), аммо энг катта сакраш 2029–2031 йилларга тўғри келади. Бунгача 2026–2028 йилларда «инвестиция тайёргарлиги» ишлари — лойиҳа паспортлари, ер кадастри, муҳандислик инфратузилмаси — бажарилиши шарт, акс ҳолда 600+ млрд сўмлик жалбни ҳазм қилиш қувват етмайди. ТТИ 2021 йилги $988 мингдан 2025 йилги $4 111 мингга 4 баравар ўсди — энди $10 млн чегарасини ёриш учун халқаро инвесторларга йўналтирилган road-show зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (810, 21, 43, 6, '6', 'Иш ўринлари режаси — тармоқ кесимида', '2026 йилда 2 364 та янги иш ўрни (KPI), асосий улуш расмийлаштириш ва саноатга', 'Жами: 9 539 та иш ўрни — 2026 жами потенциал | Расмийлаштириш орқали: 7 024 та (норасмий → расмий) | Саноат: 839 та | Туризм: 327 та (2027: 420) | 2026 расмий KPI: 2 364 та янги иш ўрни | Янги тадбиркорлар KPI: 700 та', TRUE, 'Туман ҳокимияти / SQB', 'Иш ўринларининг асосий манбаи — янги корхоналар эмас, балки норасмий секторни расмийлаштириш (7 024 та). Бу аниқ кўрсатилишни талаб қилади: расмийлаштириш «жарима» эмас, «имтиёз пакети» (1 йиллик солиқ имтиёзи + микрокредит + интернет-савдо платформасида рўйхатдан ўтиш) орқали бўлиши керак. Шунда 2026 KPI (2 364) ва норасмий конверсия (7 024) бирлашиб, реал натижа беради. Туризм 327 → 420 ўсиш катта эмас — агротуризм пакетлари орқали 2 баравар ошириш реал.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (811, 21, 44, 6, '6', 'Молиялаштириш ва кредит режаси 2026', 'Жами 2 696 млрд сўмлик кредит портфели — 4 йўналиш бўйича тақсимот', 'Жами: 2 696 млрд сўм жами кредит режа 2026 | Кичик бизнес: 600 млрд сўм | Хизмат кўрсатиш: 250 млрд сўм | Саноат: 450 млрд сўм | Микрокредитлар (мавжуд): 1 227 млрд сўм | Оилавий тадбиркорлик: 1 186 млрд сўм (NPL 6,6%) | Банк инфратузилмаси: 13 банк / 170 банкомат', TRUE, 'SQB / Марказий банк', 'Кредит ҳажми катта (2,7 трлн сўм), аммо асосий хавф — оилавий тадбиркорлик кредитларининг NPL 6,6% даражасида (мақсад 1,8%). NPL ни тушириш учун кредит беришдан олдин эмас, кейин — мониторинг ва кадрлар тайёрлаш орқали ишлаш керак. Маҳаллий банкирлар сони ҳозир бор-йўғи 3 та (3 эркак, 0 аёл) — бу 65 маҳаллага етмайди. Маҳаллий банкирлар сонини 12–15 тагача (шу жумладан 30% аёл) ошириш ва уларни молиявий саводхонлик инструкторига айлантириш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO districts (district_id, region_id, slug, name_uz, name_ru, name_en, district_name, json_file, has_data, type, year, total_cards, load_no, final_flag, date_modify) VALUES (22, 11, 'karmana', 'Кармана', 'Кармана', 'Karmana', '', 'karmana.json', TRUE, NULL, NULL, 44, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
