INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (812, 22, 1, 1, '1', 'Туманнинг макроиқтисодий кўрсаткичлари', 'Саноат, бозор хизматлари ҳажми, тармоқлар улуши ва ўсиш суръати', 'Жами: 2025 йил прогноз кўрсаткичлари | Саноат ишлаб чиқариш: 13 580,5 млрд сўм | Бозор хизматлари: 3 071,9 млрд сўм | Экспорт: 83,3 млн $ | Вилоят саноатидаги туман улуши: 11,9% | Янги ташкил этилган корхоналар (нетто): 199 та (408 та очилган, 209 та ёпилган)', TRUE, 'Туман статистика бўлими', 'Кармана тумани вилоят саноатининг қариёб 12 фоизини таъминловчи стратегик нуқта ҳисобланади. 2025 йилда саноат ҳажми 2021 йилга нисбатан деярли 1,8 баробарга ўсиши кутилмоқда. Асосий эътиборни янги корхоналар яшаб қолиш даражасини оширишга қаратиш лозим, чунки корхоналар ёпилиши кўрсаткичи ҳам юқори даражада қолмоқда. Бу — кичик бизнесни «инкубация → барқарор фаолият» ўтиш даври учун махсус дастурни талаб қилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (813, 22, 2, 1, '1', 'Туман иқтисодиётининг 4 та драйвери', 'Кармана туманининг устувор тармоқлари ва ривожланиш йўналишлари', 'Жами: 4 та устувор соҳа | 1-ўрин Саноат: иқтисодиётнинг 84,1% қисмини эгаллайди, 46,6 минг киши банд | 2-ўрин Савдо: энг устувор тармоқ сифатида белгиланган | 3-ўрин Хизмат кўрсатиш: йиллик ўсиш динамикаси 114% | 4-ўрин Туризм: стратегик ривожланиш ва диверсификация йўналиши', TRUE, 'Туман ҳокимияти', 'Иқтисодиётнинг саноатга ҳаддан ташқари боғлиқлиги (84,1%) тизимли рискларни юзага келтириши мумкин. Хизмат кўрсатиш ва туризм соҳасини ривожлантириш орқали саноатдаги глобал тебранишларга нисбатан иқтисодий барқарорликни ошириш мумкин. Моноструктурадан чиқиш — Кармана 2030 стратегиясининг асосий мақсади бўлиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (814, 22, 3, 1, '1', 'Саноат маҳсулотлари ишлаб чиқариш динамикаси', 'Туманда саноат маҳсулотлари ишлаб чиқариш ҳажми — йиллик динамика', 'Жами: Саноат ҳажми ўсиши | 2021: 7 364,6 → 2025: 13 580,5 (млрд сўм) | Йирик корхоналар (2025): 9 728,1 млрд сўм | Кичик бизнес (2025): 18 559,7 млрд сўм | Саноат ўсиш суръати (2025 прогноз): 103,2%', TRUE, 'Туман статистика бўлими', 'Саноатда кичик бизнес субъектларининг роли кескин ошмоқда, бу прогноз кўрсаткичларида йирик корхоналар ҳажмидан ўзиб кетиши билан ҳам кўринади (18,5 трлн vs 9,7 трлн — 1,9 баравар олдинда). Бу тумандa кластер тизими самарали ишлaяётганидан далолат беради. Тавсия: Кичик корхоналарни йирик саноат субъектлари билан кооперация алоқаларини янада кучайтириш зарур. 17 та КЎК ўтиш жараёнидаги корхона учун «Кармана-Скейл» дастури шакллантирилиши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (815, 22, 4, 1, '1', 'Маҳаллий бюджет', 'Маҳаллий бюджет даромадлари ва контингент режалаштириш', 'Жами: 2025 прогноз | Маҳаллий бюджет даромадлари: 113,1 млрд сўм | Контингент бюджет: 535,1 млрд сўм | Даромадлар ўсиш динамикаси: 2021 — 43,4 млрд сўмга нисбатан 2,6 баробар ўсиш кутилмоқда', TRUE, 'Молия вазирлиги', 'Маҳаллий бюджет даромадларининг жадал ўсиши туман ўз-ўзини молиялаштириш даражаси ошиб бораётганини билдиради. Солиқ базасини кенгайтириш учун «соя»даги савдо ва хизмат кўрсатиш объектларини қонуниялаштириш ҳамда тадбиркорлик субъектларини қўллаб-қувватлаш тавсия этилади. Норасмий секторда 7 510 та банд аҳоли — расмийлаштириш орқали йилига ~11,2 млрд сўм қўшимча солиқ тушуми.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (816, 22, 5, 1, '1', 'Ажратилган кредитлар', 'Туман иқтисодиёти учун ажратилган жами кредитлар ҳажми ва портфел сифати', 'Жами: 2025 прогноз — 1 409 млрд сўм | NPL (муаммоли кредитлар) улуши: 2,2% (2021 — 4,1% дан сезиларли пасайган) | Аҳоли ва бизнес кутилмалари: 75% ижобий | Оилавий тадбиркорлик NPL: 6,2% (мониторинг талаб қилади)', TRUE, 'Марказий банк', 'Кредит портфелидаги NPL даражасининг пасайиши мижозлар тўлов қобилияти ва банк мониторинги яхшиланганини кўрсатади. Ресурсларни асосан экспортга йўналтирилган ва юқори қўшилган қиймат яратувчи лойиҳаларга йўналтириш орқали туман экспорт салоҳиятини ошириш лозим. Оилавий тадбиркорлик NPL 6,2% — диққат талаб қилади, SQB AI Advisor орқали скоринг ва бизнес-режа тузишни автоматлаштириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (817, 22, 6, 1, '1', 'Google Trends иқтисодий фаоллик', 'Туман иқтисодий фаоллиги Google Trends орқали — аҳоли қидирув сўровлари асосида', 'Жами: Иқтисодий индекс кўрсаткичлари | Саноат динамикаси индекси: 103,2 | Хизматлар динамикаси индекси: 114,0 | Транспорт фаоллиги: Юк айланмаси 93 424 минг тонна', TRUE, 'Марказий аналитика', 'Кармана тумани логистика ва саноат маркази бўлганлиги сабабли, рақамли қидирувларда асосан «инвестиция имкониятлари», «транспорт хизматлари» ва «ишлаб чиқариш хомашёси» каби сўровлар юқори туради. Платформада туманнинг саноат зоналаридаги бўш ер майдонлари ва мавжуд инфратузилма ҳақидаги маълумотларни кенгроқ ёритиш инвесторлар оқимини кўпайтиради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (818, 22, 7, 2, '2', 'Ичимлик суви билан таъминланганлик (%)', 'Аҳолини тоза ичимлик суви билан таъминланганлик даражаси', '2021: 98.0 | 2022: 99.0 | 2023: 99.2 | 2024: 99.5 | 2025: 99.8 (%)', TRUE, 'Сув хўжалиги', 'Кармана тумани ичимлик суви таъминоти бўйича республикадаги энг юқори кўрсаткичлардан бирига эга (99,8%). Эндиги асосий вазифа сув сифатини доимий назорат қилиш ва сув қувурларидаги йўқотишларни камайтириш учун рақамли мониторинг тизимларини жорий этишдан иборат. Қувурларни босқичма-босқич алмаштириш ва сув ҳисоблагичларини 100% жорий этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (819, 22, 8, 2, '2', 'Ички йўллар таъмирланиш даражаси (%)', 'Кармана тумани ички йўлларининг асфальтланган улуши ва жойлашуви', 'Жами: Йўл инфратузилмаси | Умумий йўллар узунлиги: 1 058 км | Асфальтланган йўллар улуши: 68,4% | Вилоят марказигача масофа: 6 км | Темир йўл стансиясигача масофа: 8 км | Юк ташиш ҳажми (2025): 93 424 минг тонна', TRUE, 'Йўл хўжалиги', 'Йўлларнинг 68,4 фоизи асфальтланганлиги туман логистика салоҳияти яхши эканлигини кўрсатади. Бироқ, қолган 31,6 фоиз йўлларни босқичма-босқич таъмирлаш, айниқса саноат зоналари ва янги массивларни боғловчи йўналишларга эътибор қаратиш юк ташиш таннархини пасайишига ва иқтисодий фаоллик ошишига хизмат қилади. М-37 халқаро магистрали бўйидаги хизмат кўрсатиш зонасини ишга тушириш — қўшимча 350–400 иш ўрни беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (820, 22, 9, 2, '2', 'Электр таъминоти сифат даражаси (%)', 'Электр узилишлари ва тармоқ модернизация ҳолати', 'Жами: Электр инфратузилмаси | Электр узилишлари: ойига ўртача 1 марта | Эскирган трансформаторлар: 14% | Алмаштирилиши керак бўлган линиялар: 10% | Интернет қоплами: 100%', TRUE, 'Электр тармоқлари', 'Электр таъминотидаги барқарорлик саноат корхоналари учун қулай муҳит яратади. Тизим ишончлилигини ошириш учун эскирган 14 фоиз трансформаторларни модернизация қилиш бўйича «Ақлли тармоқлар» (Smart Grid) лойиҳасини тажриба тариқасида қўллаш ва рақамли бошқарувни кучайтириш тавсия этилади. Интернет 100% қоплами — рақамли иқтисодиёт учун энг кучли омил.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (821, 22, 10, 2, '2', 'Ер тоифалари бўйича рўйхат (га)', 'Туман ҳудудининг ер тоифалари бўйича тақсимоти', 'Жами: Ер фонди тузилмаси | Умумий майдон: 95 200 га | Суғориладиган ер майдони: 560 га | Саноат зоналарида ердан фойдаланиш: 80% | Суғориш каналларини бетонлаштириш: 35% | Яйловлар: 62 250 га (65%) | Қ/х ерлари: 24 390 га | Ўрмон фонди: 8 560 га', TRUE, 'Кадастр', 'Умумий майдонга нисбатан суғориладиган ерларнинг камлиги (560 га / 95 200 — атиги 0,6%) туман иқтисодиёти саноатга ихтисослашганини тасдиқлайди. Каналларнинг атиги 35 фоизи бетонланганлиги сув исрофини кўрсатади. Саноат зоналари еридан фойдаланиш самарадорлигини 80 фоиздан 95 фоизга кўтариш орқали туман даромадларини янада ошириш мумкин. 62 250 га яйлов — туманнинг ишлатилмаган капитали.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (822, 22, 11, 2, '2', 'Жамоат транспортидан фойдаланиш (%)', 'Аҳолини жамоат транспорти билан қамраб олинганлик даражаси', 'Жами: 35% (2025) | Йўловчи айланмаси (бевосита): 93 424 минг тонна юк ва йўловчи оқими | Шаҳар маркази (Навоий) яқинлиги: 6 км — индивидуал транспорт улуши юқори', TRUE, 'Хокимият', 'Жамоат транспорти қамрови 35% — республика ўртачасидан паст, чунки Навоий шаҳри яқинлиги (6 км) индивидуал транспорт ва такси хизматлари улушини оширади. Тавсия: М-37 йўли бўйидаги саноат зоналарига ва Навоий ЭИЗга етар келувчи махсус ишчилар маршрутларини жорий этиш — 3 261 та ЭИЗ иш ўрни ва тумандаги саноат корхоналари учун қулай бўлади. Электр автобуслар парки ва GPS мониторинг тизими 2026 йил режасига киритилиши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (823, 22, 12, 2, '2', 'Мактабгача таълим қамрови', 'Мактабгача таълим муассасаларига қамраб олинганлик', 'Жами: 95,5% (2025) — республикадаги юқори кўрсаткичлардан бири', TRUE, 'Мактабгача ва мактаб таълими вазирлиги', 'Мактабгача таълим қамрови 95,5% — республика ўртачасидан анча юқори ва Қўқон шаҳри (87,9%) дан ҳам ўзиб кетган. Бу — туман инфратузилмасининг кучли таркибий қисми, аёл бандлигини ошириш учун муҳим омил (оналар ишга чиқиш имкони мавжуд). Эндиги вазифа — сифатни ошириш ва жорий 4,5% қолган қамровсизлик зонасига алоҳида эътибор бериш. МТМ дастурларига СТЕМ ва тил ўрганишни киритиш — болалар келажакдаги меҳнат бозори талабларига тайёрлайди.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (824, 22, 13, 3, '3', 'Меҳнат ресурслари', 'Жами меҳнат ресурслари сони — йиллик динамика', '2021: 52.0 | 2022: 54.0 | 2023: 58.1 | 2024: 60.5 | 2025: 63.1 (минг киши)', TRUE, 'Бандлик маркази', 'Меҳнат ресурслари 4 йилда +21,2% га ўсган — барқарор ўсиш мавжуд. Бандликни ошириш учун қишлоқ хўжалиги, электротехника ва қурилиш материаллари йўналишлари бўйича маҳалла даражасида қисқа муддатли ўқув дастурларини кенгайтириш зарур. Навоий ЭИЗ (3 261 иш ўрни) ва янги саноат лойиҳалари (2026 — 1 035 иш ўрни) учун кадрлар тайёрлаш приоритет бўлмоғи лозим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (825, 22, 14, 3, '3', 'Бандликни ошириш имкониятлари', 'Иш ўрни яратиш ва меҳнат бозори резервлари', 'Жами: Меҳнат бозори резервлари | Банд аҳоли (2025): 33 710 киши (+8,0%) | Қайтган мигрантлар (2025): 203 киши (-28,8%) | Норасмий секторда бандлик (2021): 7 510 киши | Хорижга кетган мигрантлар: 2021 — 1 450, 2022 — 1 580, 2023 — 1 320, 2024 — 1 565, 2025 — 1 440 (-8,0%)', TRUE, 'Бандлик маркази / ИИВ миграция', 'Банд аҳоли 1 йилда +8,0% га ошган — ижобий тенденция. Қайтган мигрантлар 28,8% га камайган, шу боис қайтиш дастурларини фаоллаштириш ва норасмий секторда бандлик (7 510 киши) расмий доирага ўтказиш орқали солиқ йўқотишларни (~11,2 млрд сўм) қайтариш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (826, 22, 15, 3, '3', 'Ишсизлик кўрсаткичлари', 'Расмий ишсизлик даражаси ва ишсизлар сони', 'Жами: Ишсизлик кўрсаткичлари | Расмий ишсизлик (2025): 4,5% (-15,1%) | Ишсизлар сони (2025): 2 157 киши (-39,3%) | Ишсизлик тренди: 7,2% → 6,8% → 6,2% → 5,3% → 4,5% | Ёшлар (16–30): 410 киши (2021) | Аёллар: 1 170 киши (2021) | Мақсад: 2027 йилгача 3,5% га тушириш', TRUE, 'Бандлик маркази', 'Ишсизлик 5 йилда 7,2% дан 4,5% га тушган — кучли натижа. 2027 йилги 3,5% мақсадини бажариш учун аёллар ишсизлиги (1 170 киши, умумийнинг 54%) ва ёшлар (410 киши, 19%) бўйича манзилли ишга жойлаштириш ва қисқа муддатли касбий курсларни кенгайтириш лозим.', 2157, 4.5, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (827, 22, 16, 3, '3', 'Камбағаллик кўрсаткичлари', 'Камбағаллик даражаси ва камбағал оилалар сони', 'Жами: Камбағаллик кўрсаткичлари | Камбағаллик даражаси (2025): 4,2% (-26,3%) | Камбағал оилалар (2025): 1 265 та (-8,0%) | Камбағаллик тренди: 4,7% → 9,2% → 7,6% → 5,7% → 4,2% | Кам таъминланган оилалар: 1 265 та | Мақсад: 2027 йилгача янада камайтириш', TRUE, 'Статистика бўлими / МФЙ агентлиги', 'Камбағаллик 2022 йилги 9,2% чўққисидан 2025 йилда 4,2% га (-54%) тушган. Ҳар бир камбағал оилага мақсадли микрокредит ва субсидия пакети шакллантирилиши, ижтимоий ёрдам иш билан боғлиқ қилиниши, бола нафақаси олувчи 904 оилани тадбиркорликка жалб қилиш зарур.', 1265, 4.2, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (828, 22, 17, 3, '3', '«Барқарор келажак» — ёшлар даромадини ошириш', '«Барқарор келажак» дастури — 2026 йилда ёшлар даромадини ошириш режаси', '', FALSE, 'Бандлик маркази', 'Маълумот Бандлик марказидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Ёшлар даромадини ошириш учун дуал таълим, биринчи иш ўрнига субсидия ва талаб юқори касблар бўйича тезкор қайта тайёрлаш дастурларини кучайтириш зарур. Кармана «Инновациялар институти» билан ҳамкорликда саноатга йўналтирилган ёшлар тренинг марказини ташкил этиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (829, 22, 18, 3, '3', 'Аёллар бандлиги ва даромадини ошириш', 'Аёллар бандлиги ва даромадини ошириш — 2026 йил режаси', '', FALSE, 'Оила ва хотин-қизлар бўлими', 'Маълумот Оила ва хотин-қизлар бўлимидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Кармана туманида аёллар ишсизлиги (1 170 киши) — умумий ишсизликнинг 54%. 8 та аёл маҳалла банкири орқали аёлларни HAMROH дастурига фаол жалб қилиш ва тикувчилик-ҳунармандчилик кооперативлари ташкил этиш — тезкор натижа берадиган йўл.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (830, 22, 19, 3, '3', 'Кармана туманидаги олий таълим муассасалари', 'Университетлар, техникумлар, талабалар сони ва қувватлар', 'Жами: 1 та ОТМ + 2 та техникум | Олий таълим муассасаси: 1 та (Инновациялар институти) | Тумандаги техникумлар: 2 та', TRUE, 'Хокимият', 'Кармана туманида 1 та олий таълим муассасаси (Инновациялар институти) ва 2 та техникум фаолият юритади — туман саноат маркази эканлиги ҳисобига кадрлар тайёрлаш салоҳияти борлигини кўрсатади. Тавсия: (1) Инновациялар институтида АЭС, ЭИЗ ва логистика йўналишларида махсус факультетлар очиш; (2) техникумларнинг битирувчиларини Навоий ЭИЗнинг 22 та лойиҳасига мақсадли жойлаштириш дастури; (3) дуал таълим (университет + корхона) моделини жорий этиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (831, 22, 20, 3, '3', 'Мактабгача таълим ва мактаб юкламаси', 'Мактабгача таълим қоплами ва мактаблардаги смена тақсимоти', 'Жами: Мактаб юкламаси (СМЕНАЛАР) | 1 сменали — 28 та | 2 сменали — 5 та | 3 сменали — мавжуд эмас | Жами — 33 та | 2 сменали мактаблар улуши: 15,2% | Мактабгача таълим қоплами: 2021 — 75,0%, 2022–2025 — расмий маълумот мавжуд эмас (статистика тизимини тиклаш зарур)', TRUE, 'Халқ таълими', 'Мактабгача таълим 2022–2025 йиллар бўйича расмий маълумотлар мавжуд эмас — статистика тизимини тиклаш зарур. Мактаб юкламаси нисбатан енгил (2 сменали улуши 15,2%), лекин 5 та 2 сменали мактаб бўйича модернизация режасини шакллантириш тавсия этилади. Туман инфратузилмаси таълим талабларига нисбатан мутаносиб.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (832, 22, 21, 4, '4', 'Сунъий интеллект куни ва ходимлар малакасини ошириш', 'Банкда СИ кўникмаларини мунтазам ошириш дастури', 'Жами: СИ малака ошириш дастури | Банкда «Сунъий интеллект куни» ташкил этилди — ҳар чоршанба | Ходимларга онлайн ўқитиш тизими жорий қилинди | Раҳбар ходимлар ўқувлари тўлиқ якунланди | СИ ечимларидан фойдаланиш бўйича қисқа ўқув курслари ташкил этилди', TRUE, 'SQB', 'Банк ходимларининг СИ саводхонлиги мунтазам оширилмоқда. Кармана туман филиали учун кейинги босқичда ҳар бир бўлим ва маҳаллий банкир (39 киши) учун СИ KPI жорий этиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (833, 22, 22, 4, '4', 'Раҳбарлар ва банкирларни СИ га ўқитиш', 'Ҳоким, ҳоким ўринбосарлари, банк раҳбарлари ва маҳалла банкирларини босқичма-босқич ўқитиш', 'Жами: 4 босқичли СИ ўқитиш | 1-босқич: Ҳоким ва ҳоким ўринбосарлари — СИ стратегия ва қарор қабул қилиш | 2-босқич: Банк филиал раҳбарлари — СИ скоринг ва риск таҳлили | 3-босқич: Маҳалла банкирлари — СИ платформа орқали мижоз хизмати | 4-босқич: МФЙ раислари — СИ маълумотлар таҳлили ва ҳисобот', TRUE, 'SQB', 'Раҳбарларни СИ га ўқитиш «юқоридан пастга» тамойилида амалга оширилади. Ҳар босқич 2–4 ҳафта давом этади. Кармана туманидаги 39 та МФЙ раиси ва 39 та маҳаллий банкирни қамраб олиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (834, 22, 23, 4, '4', 'Аҳолини СИ орқали тадбиркорликка ўқитиш', 'Фуқароларни СИ платформаси орқали касб танлаш, тадбиркорлик ва ишга жойлашишга тайёрлаш', '', FALSE, 'SQB', 'Маълумот SQB маҳаллий филиалидан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. СИ платформаси орқали ҳар бир фуқарони индивидуал баҳолаш — кўникмаси кучли бўлганлар ишга, тадбиркорлик қобилияти борлар бизнесга йўналтириш — Кармана туманида ҳам жорий этилиши керак. Инновациялар институти билан ҳамкорликда амалга ошириш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (835, 22, 24, 4, '4', '«SQB AI Advisor» — ақлли ёрдамчи платформа', 'Маҳалла банкирлари ва тадбиркорларга СИ ёрдами берувчи платформа', 'Жами: SQB AI Advisor функциялари | СИ маслаҳатчи чат-боти: тадбиркорлик, ҳуқуқий, молиявий саволларга жавоб | Бизнес-режа генератори: автоматик бизнес-режа тузиш | Кредит бўйича мос ечимлар: мижозга мос кредит маҳсулотини танлаш | Маҳалла агенти самарадорлиги: онлайн KPI мониторинг | Прогноз: даромадни ошириш тавсиялари, мавсумий хавфлар', TRUE, 'SQB', '«SQB AI Advisor» платформаси Кармана туманидаги маҳалла банкири ва тадбиркорларга кундалик ишларда СИ ёрдамини беради. 2026 йил якунигача барча 39 та МФЙда жорий этиш режалаштирилган.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (836, 22, 25, 4, '4', 'Маҳалла ихтисослашуви', 'Маҳаллаларнинг иқтисодий фаолият йўналишлари', 'Жами: 39 та маҳалла | Қишлоқ хўжалиги: 23 та МФЙ (59%) | Савдо ва хизмат: 10 та МФЙ (26%) | Чорвачилик: 5 та МФЙ (13%) | Анорчилик: 1 та МФЙ (3%)', TRUE, 'МФЙ агентлиги', 'Қишлоқ хўжалиги улуши юқори (59%) — қиймат занжирини кенгайтириш муҳим. Гўшт ва сабзавот қайта ишлаш даражаси паст (мос равишда ~15% ва ~18%) бўлгани учун қайта ишлаш кластерини ривожлантириш ва анорчилик маҳалласи бўйича брендлаш орқали қўшимча даромад яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (837, 22, 26, 4, '4', 'Маҳалла драйвер секторлари', 'Маҳалла даражасида ўсишни таъминловчи тармоқлар', 'Жами: 3 та драйвер сектор | 1-сектор: Қишлоқ хўжалиги | 2-сектор: Электротехника | 3-сектор: Қурилиш материаллари ишлаб чиқариш', TRUE, 'МФЙ агентлиги / SQB', 'Драйвер секторларни «ишлаб чиқариш + савдо + хизмат» занжирида боғлаш керак. «Навоий ЭИЗ» ҳудудида 22 лойиҳа ва 3 261 иш ўрни мавжудлиги, дон майдони (5 216 га) ҳамда қурилиш тошлари конлари (18 та) потенциалидан фойдаланиб, тайёр маҳсулотни бозорга чиқариш ва экспорт каналларини кенгайтириш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (838, 22, 27, 4, '4', 'Микролойиҳалар сони ва иш ўринлари', 'Йиллик кредит режа, иш ўринлари ва маҳалла тақсимоти', 'Жами: 1 560 та лойиҳа | Иш ўринлари: 3 250 та | Жами маҳаллалар: 39 та | Банк маблағи: 10,3 млрд сўм | 2026 йил режаси: Саноат — 26 та (1 741 млрд сўм, 1 035 иш ўрни), Хизмат — 51 та (264,2 млрд сўм, 361 иш ўрни)', TRUE, 'SQB / Туман ҳокимияти', '1 560 та микролойиҳа орқали 3 250 та иш ўрни яратилган. Банкирлар вазифалари: (1) лойиҳани танлаш ва скоринг; (2) кредит расмийлаштиришда ёрдам; (3) лойиҳа мониторинги; (4) молиявий маслаҳат. 2026 йил саноат лойиҳалари (1 741 млрд) SQB кредит режасининг (1 325 млрд) асосий устуни ҳисобланади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (839, 22, 28, 4, '4', 'Ишсизлик юқори маҳаллалар', 'Оғир тоифадаги маҳаллалар бўйича манзилли иш режаси', 'Жами: 2 та оғир тоифадаги маҳалла | 1-маҳалла: Кумушкон | 2-маҳалла: Кўҳна Қўрғон | Маҳалла типологияси: Оғир — 2 та, Ўрта — 7 та, Енгил — 8 та, Яхши — 22 та | Фокус: манзилли бандлик ва микролойиҳа дастурлари', TRUE, 'МФЙ агентлиги', 'Оғир тоифали 2 та маҳаллада «бир маҳалла — бир драйвер йўналиш» тамойили асосида тезкор бандлик режаси ишга туширилиши керак. Маҳалла кам бўлгани сабабли индивидуал лойиҳа портфели шакллантириш ва ҳар бир оила учун микрокредит ёки оилавий тадбиркорлик кредитини ажратиш амалий мумкин. 22 та «Яхши» тоифадаги маҳалла — туман инфратузилмасининг кучли таркибий қисми.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (840, 22, 29, 4, '4', 'SQB рақамли хизматлари', 'SQB банкнинг рақамли ва мобил молиявий хизматлар экотизими', 'Жами: 3 та рақамли платформа | SQB Mobile: жисмоний шахслар учун мобил банк — тўловлар, ўтказмалар, онлайн кредит | SQB Business: юридик шахслар учун онлайн бухгалтерия, тўлов, ҳисоб-китоб | SQB AI Advisor: сунъий интеллект асосидаги молиявий маслаҳатчи — кредит скоринг, инвестиция таҳлили | Банк инфратузилмаси: Жами банклар — 4 та | Банкоматлар: 80 та | Маҳалла банкирлари: 39 та (8 аёл, 31 эркак)', TRUE, 'SQB / Марказий банк', 'Маҳалла банкирлари сони (39 та) маҳаллалар сонига (39 та) тенг — бир маҳаллага бир банкир тамойили бажарилган. Аёл банкирлар улуши 21% (8/39) — бу кўрсаткични 30–40% га ошириш ва аёллар тадбиркорлигини қўллаб-қувватлаш тавсия этилади. 80 та банкомат — қулай рақамли инфратузилма.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (841, 22, 30, 4, '4', '«Ҳар бир оила — тадбиркор» дастури', 'Оилавий тадбиркорлик учун имтиёзли кредит', 'Жами: Оилавий тадбиркорлик дастури | Иштирокчи банклар: Халқ банки, Микрокредит банк | Фоиз ставкаси: 18% | Максимал сумма: 300 млн сўм | Муддат: 3 йилгача | Имтиёзли давр: 3–6 ой | Кармана: 279,3 млрд сўм кредит ҳажми (NPL — 6,2%)', TRUE, 'Марказий банк', 'Кармана туманида оилавий тадбиркорлик кредитлари ҳажми 279,3 млрд сўмни ташкил этади (NPL — 6,2%). NPL ни камайтириш учун SQB AI Advisor платформаси орқали кредит скоринг ва бизнес-режа тузишни автоматлаштириш тавсия этилади. Маҳалла банкирлари 1 265 та камбағал ва 1 265 та кам таъминланган оилани платформага йўналтириши керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (842, 22, 31, 4, '4', '«HAMROH» хотин-қизлар тадбиркорлиги', 'Хотин-қизлар учун махсус молиявий дастур', 'Жами: Хотин-қизлар учун махсус молиявий дастур | Иштирокчи банклар: SQB, Халқ банки, Микрокредит банк, Агро банк | Гаровсиз кредит: 100 млн сўмгача | Компания кафиллиги: 70%', TRUE, 'Марказий банк', 'HAMROH — хотин-қизлар тадбиркорлигини қўллаб-қувватлашнинг энг катта давлат дастури. Кармана туманида аёллар ишсизлиги (1 170 киши, умумий ишсизликнинг 54%) юқорилигини инобатга олиб, маҳалладаги 8 та аёл банкир орқали аёлларни фаол жалб қилиш ва бизнес тренинглар ташкил этиш зарур.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (843, 22, 32, 4, '4', 'Ишсизлик юқори маҳаллаларни ҳоли ҳудудга айлантириш режаси', '2 та оғир маҳаллада ишсизликни камайтириш режаси', 'Жами: 2 та маҳалла, оғир тоифа — Кумушкон, Кўҳна Қўрғон | Ишсизлар (2025): 2 157 киши | Ёшлар (16–30): 410 киши (2021) | Аёллар: 1 170 киши (2021) | Кредит маҳсулотлари: 1) Микрокредит (946,3 млрд сўм), 2) Оилавий тадбиркорлик (33 млрд сўм), 3) Давлат бюджети (245,6 млрд сўм) | Мақсад: 2027 йилгача 3,5% га тушириш', TRUE, 'SQB / МФЙ агентлиги', '2 та оғир тоифали маҳаллада аёллар ишсизлиги (54%) ва ёшлар ишсизлиги (19%) устунлик қилади. «Бир маҳалла — бир драйвер йўналиш» модели жорий қилиниши мақсадга мувофиқ — Кумушкон ва Кўҳна Қўрғон учун тегишли қ/х ёки қурилиш материаллари йўналишини танлаш ва 2–3 ойлик тезкор цикл орқали микролойиҳаларга жалб қилиш тавсия этилади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (844, 22, 33, 5, '5', 'Навоий ЭИЗ — туман саноат локомотиви', 'Эркин иқтисодий зона ҳудудида ишлаётган корхоналар ва иш ўринлари', 'Жами: 22 та лойиҳа Навоий ЭИЗ ҳудудида | Иш ўринлари: 3 261 та | Саноат ишлаб чиқариш (2025): 13 580 млрд сўм | Тармоқлар улуши: Саноат — 84,1% (туман иқтисодиётининг асоси) | Инвестиция (2025): $735 млн (2021 — $300 млн дан 2,4 баравар ўсди)', TRUE, 'Хокимият / Навоий ЭИЗ', 'Кармана тумани иқтисодиёти амалда саноатга боғланган (84,1%) — бу деярли моноструктура. Навоий ЭИЗ кучли ютуқ, аммо хавфли қарамлик ҳам. Тавсия: ЭИЗ ҳудудидаги 22 та амалдаги лойиҳа атрофида юқори қўшимча қийматли «спутник-кластерлар» (қадоқлаш, лаборатория, R&D, метрология, юк-логистика хизматлари) яратиш. 2027 йилгача яна 10–12 та хорижий резидентни киёфаланган тармоқлар (кимё, металлургия, қурилиш материаллари) бўйича жалб қилиб, ягона корхонадан ҳосил бўлган риск-концентрациясини юмшатиш керак.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (845, 22, 34, 5, '5', 'Қурилиш материаллари кластери', 'Туман ҳудудидаги фойдали қазилма конлари ва ҳомашё захиралари', 'Жами: 28 та фойдали қазилма кони (5 турдаги) | Цемент конлари: 5 та (захира 375 598 минг тонна) | Қурилиш тошлари: 18 та кон (39 040 минг м³) | Оҳак захираси: 2 та кон (1 691 минг м³) | Қум-шағал ва пардозбоп тош: 2 + 1 та кон', TRUE, 'Геология қўмитаси / Хокимият', 'Кармана — Ўзбекистоннинг қурилиш материаллари бўйича энг бой туманларидан бири, аммо ҳозирда тайёр маҳсулот ишлаб чиқариш кластери шаклланмаган («-» деб қайд этилган). 2026–2028 йилларга 3–5 та йирик ишлаб чиқарувчи (цемент, оҳак, керамика плиталар, пардоз тоши кесиш) учун «Карманабудстрой» кластерини ташкил этиш керак. М-37 йўли ва Навоий темир йўли орқали Қозоғистон, Россия, Қирғизистон бозорларига экспортга йўналтирилган йирик ишлаб чиқариш базаси яратиш мумкин — ҳозирги $143 млн импортни 25–30% га камайтириш реал.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (846, 22, 35, 5, '5', 'М-37 халқаро йўли — туман логистика ҳаби', 'Стратегик транспорт жойлашуви ва транзит салоҳияти', 'Жами: Логистика инфратузилмаси | Навоий шаҳригача: 6 км (вилоят маркази) | Темир йўлгача масофа: 8 км | Йўлларнинг умумий узунлиги: 1 058 км | Асфальтланган қисми: 68,4% | Юк ташиш ҳажми (2025): 93 424 минг тонна', TRUE, 'Хокимият / Йўл хўжалиги', 'Кармана — Тошкент-Бухоро-Хоразм ва Қозоғистон йўналишидаги М-37 халқаро магистрали тугуни. Навоий халқаро аэропортига яқинлиги (TIS логистика хаби) ва темир йўл оралиғи 8 км — бу «Сухой порт» (Dry Port) учун идеал параметр. 2026–2027 йилларда М-37 йўли бўйидаги хизмат кўрсатиш зонаси (юк терминали, ягона божхона тери, ёқилғи ва дам олиш мажмуаси) лойиҳасини ишга тушириш зарур. Юк айланмаси 93 млн тоннага етгани туфайли қўшимча 350–400 янги иш ўрнини яратиш мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (847, 22, 36, 5, '5', 'Кичик бизнес портлаши', 'Кичик тадбиркорлик субъектларининг устуворлиги', 'Жами: 18 560 млрд сўм — кичик бизнес ишлаб чиқариши (2025) | Йирик корхоналар: 9 728 млрд сўм (кичик бизнес 1,9 баравар олдинда) | 2025 йилда очилган корхоналар: 408 та (ёпилган: 209 та) | Микролойиҳалар: 1 560 та / 3 250 иш ўрни / 10,3 млрд банк маблағи | КЎК → Йирик ўтиш: 17 та корхона тоифа кўтариш жараёнида', TRUE, 'Шаҳар статистика бўлими / SQB', 'Туманнинг энг катта яширин салоҳияти — кичик бизнес йирик корхоналардан 1,9 баравар катта ҳажмга етган. Бу муҳим бурилиш нуқтаси: 17 та КЎК ўтиш жараёнидаги корхона учун «Кармана-Скейл» дастури ишлаб чиқариш керак — солиқ имтиёзлари (3–5 йил), банк-фабрика ёрдами, экспорт сертификатлаштириш ва малакали кадрлар тайёрлаш блокли қилиб бирлаштирилади. Мақсад — 2027 йилгача яна 30–40 та КЎК ни ўрта бизнесга кўтариш ва кичик бизнесни 25 трлн сўмга етказиш.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (848, 22, 37, 5, '5', 'Чорвачилик ва яйлов салоҳияти', 'Кенг яйлов фонди ва қишлоқ хўжалиги ресурслари', 'Жами: 62 250 гектар яйлов (туман ер фондининг 65%) | Қ/х маҳсулоти (2025): 3 003 млрд сўм (2021 — 1 916 дан +57%) | Қишлоқ хўжалик ерлари: 24 390 гектар | Ўрмон фонди: 8 560 гектар | Гўшт қайта ишлаш улуши: ~15% (паст — салоҳият катта)', TRUE, 'Қ/х бўлими / Ер қўмитаси', '62 250 гектар яйлов — туманнинг ишлатилмаган капитали. Ҳозирги фермер кластери атиги 1 та, гўшт қайта ишлаш 15% — бу маҳсулотни хом шаклда сотишни англатади. 2026–2028 учун «Кармана Мит» кластери (3–4 та қайта ишлаш корхонаси, ҳалол сертификатли экспортга йўналтирилган) ва қўйчилик-эчкичилик мажмуалари ташкил этилиши керак. Дефицит товарлар рўйхатида гўшт ва сут #1 ва #2 ўринда. Натижада йилига 700–800 янги иш ўрни ва $20–30 млн экспорт реал.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (849, 22, 38, 5, '5', 'Инвестиция ва лойиҳа фабрикаси', 'Жалб қилинган ва режалаштирилган инвестициялар динамикаси', 'Жами: $735 → $1 000 млн инвестиция режаси (2025 → 2031) | 2025 йил факт: $735 млн (2021 — $300 млн дан +145%) | 2026 саноат лойиҳалари: 26 та / 1 741 млрд сўм / 1 035 иш ўрни | 2026 хизмат лойиҳалари: 51 та / 264,2 млрд сўм / 361 иш ўрни | Жами лойиҳа портфели: 95 та лойиҳа / 2 167,1 млрд сўм / 1 533 иш ўрни', TRUE, 'Шаҳар ҳокимияти / SQB', 'Кармана инвестиция нуқтаи назаридан кучли ҳолатда — 4 йил ичида $300 → $735 млн. Аммо ТТИ (тўғридан-тўғри хорижий инвестиция) фақат $730 минг даражасида — деярли йўқ. Тавсия: «Investment Pack Karmana» — 26 та саноат лойиҳаси орасидан 5–7 та энг катта (350+ иш ўрни ёки 100+ млрд сўм) лойиҳани халқаро инвестор-консорциумларга очиб қўйиш, ЭБРР, АБР ва Хитой фондлари билан меморандум тузиш. ТТИ ни 2027 йилгача $30 млн га етказиш реалистик мақсад.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (850, 22, 39, 5, '5', 'Туризм ва тарихий мерос ҳаби', '3 та туризм маршрут ва транзит оқим', 'Жами: 3 та туризм маршрути (2027–2028 режа) | Давлат инвестицияси: 16 млрд сўм (маҳаллалар туризм инфратузилмасига) | Стратегик жойлашув: Навоий шаҳригача 6 км — транзит оқим | Тарихий обидалар: Работи Малик карвонсаройи, Мир Сайид Бахром мақбараси | Туризмда иш ўрни режаси: 2026 — 78 та / 2027 — 85 та', TRUE, 'Хокимият / Туризм бўлими', 'Туризм ҳозирда туман иқтисодиётида учинчи устувор тармоқ, бироқ инвестиция (16 млрд сўм) Қўқон (42 млрд) ёки Бухоро туманларига қараганда 2,5–3 баравар камроқ. Иш ўрни режаси (78–85) ҳам жуда оз. Тавсия: туризмни мустақил эмас, балки СаноаTouR концепцияси орқали «индустриал-туризм» (Навоий ЭИЗ ва Кармана конлари экскурсияси) + Бухорога кетаётган сайёҳлар учун транзит хизматлари (М-37 йўли бўйида ресторан-чойхона + 100 ўринлик мини-меҳмонхона тармоғи) сифатида ривожлантириш. Бу 2027 йилгача 200+ иш ўрни ва 80–90 млрд сўм даромад беради.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (851, 22, 40, 5, '5', 'Туризм инфратузилмасига давлат инвестицияси (батафсил)', 'Маҳаллалар туризм инфратузилмасини ривожлантириш батафсил режаси', '', FALSE, 'Хокимият', 'Маълумот Ҳокимиятдан сўралмоқда. Тўлдирилгандан сўнг таҳлил берилади. Кармана туманида туризм инфратузилмасига давлат инвестицияси (16 млрд сўм) аниқ маҳаллалар бўйича батафсил тақсимоти ва амалга ошириш муддатлари сўралмоқда — бу маълумот халқаро инвесторларни жалб қилишда муҳим.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (852, 22, 41, 6, '6', 'Стратегик устунликлар (4 та)', 'Кармана тумани иқтисодиётининг пойдеворли кучли томонлари', 'Жами: 4 та стратегик устунлик | 1-устунлик: Стратегик транспорт жойлашуви (Навоий 6 км, темир йўл 8 км, М-37) | 2-устунлик: Саноат ишлаб чиқариш салоҳияти юқори (84,1% улуш) | 3-устунлик: Савдо ва хизмат кўрсатиш соҳаси юқори фаол | 4-устунлик: Меҳнат ресурслари ва ёш аҳоли улуши катта (63 минг меҳнат ресурси)', TRUE, 'Хокимият / SQB', 'Тўрт устунликни алоҳида эмас, ягона занжир сифатида қараш керак: Навоий ЭИЗ + М-37 транспорти + кичик бизнес ўсиши + ёш кадрлар = «Кармана-2030» индустриал-логистика хабининг тайёр компонентлари. 2026 йилда 1-чоракда «Stratejik Council» (Хокимият + SQB + ЭИЗ + Бизнес палата) тузилиб, тўрт устунликни боғловчи 5 та флагман лойиҳани (қурилиш кластери, гўшт-сут қайта ишлаш, логистика парки, КЎК-ўтиш дастури, IT-серф зона) бир дастурга бирлаштириш мақсадга мувофиқ.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (853, 22, 42, 6, '6', '2026 йил лойиҳа портфели', 'Йил давомида амалга ошириладиган лойиҳалар умумий ҳажми', 'Жами: 95 та лойиҳа (2 167,1 млрд сўм, 1 533 иш ўрни) | Саноат лойиҳалари: 26 та — 1 741 млрд сўм — 1 035 иш ўрни | Хизмат кўрсатиш лойиҳалари: 51 та — 264,2 млрд сўм — 361 иш ўрни | Лойиҳа офиси: 45 та лойиҳа SQB бошқарувида | Расмийлаштириш орқали: 2026 йилда қўшимча 2 450 иш ўрни (норасмий → расмий)', TRUE, 'SQB / Шаҳар ҳокимияти', 'Лойиҳа портфелининг 80% маблағи (1 741 / 2 167 млрд) саноатга қаратилган — бу мутаносиблик яхши, лекин риск концентрацияси юқори. Тавсия: 26 та саноат лойиҳасини 3 категорияга ажратиш — «Anchor» (200+ иш ўрни), «Growth» (50–200), «Pilot» (50 гача). Энг йирик 5 та Anchor лойиҳа учун ЭБРР/АБР ҳамкорлигида $30–50 млн ташқи маблағ қидириш керак, шунда давлат бюджетини «Pilot» ва инфратузилмага қайта йўналтириш мумкин. Лойиҳа фабрикаси циклини (ғоя → баҳолаш → бизнес-режа → молиялаштириш) ўртача 90 кунгача қисқартириш — мақсадли KPI.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (854, 22, 43, 6, '6', 'Узоқ муддатли инвестиция режаси (2026–2031)', '6 йиллик инвестиция жалб қилиш динамикаси', 'Жами: 5 145 млрд сўм — 6 йиллик жами инвестиция режаси | 2026: 735 млрд сўм | 2027: ~780 млрд сўм | 2028: ~815 млрд сўм | 2029: 890 млрд сўм | 2030: 925 млрд сўм | 2031: 1 000 млрд сўм', TRUE, 'Хокимият', 'Йиллик ўсиш ўртачаси +6,3% — анча конкретив, аммо ҳозирги ТТИ ($730 минг) ёрдамида бу рақамга етиш қийин. Тавсия: 2026–2027 учун 3 та халқаро инвестиция конференцияси (Шанхай, Истанбул, Дубай) ва Навоий ЭИЗ резидентлари орасидан «амбассадор-инвесторлар» дастури ишга туширилсин. Маҳаллий облигация (бугунги ҳолатда мавжуд эмас) — 2027 йилда тажриба тариқасида 50 млрд сўмлик инфратузилма облигациясини чиқариш имконияти ўрганилсин. Шу йўл билан 2031 йилгача $1 млрд га эришиш реалистик бўлади.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
INSERT INTO indicators (indicator_id, district_id, no, slide, slide_no, name, description, value, found, source_org, ai_insight, kpi_count, kpi_pct, load_no, final_flag, date_modify) VALUES (855, 22, 44, 6, '6', 'Ер фонди ва табиий ресурслар', 'Туман ҳудудининг иқтисодий салоҳияти', 'Жами: 95 200 гектар — туман умумий майдони | Яйловлар: 62 250 га (65% — катта чорвачилик ресурси) | Қишлоқ хўжалик ерлари: 24 390 га | Ўрмон фонди: 8 560 га | Суғориладиган ер: 560 га (фақат 0,6% — асосий камчилик)', TRUE, 'Ер қўмитаси / Қ/х бўлими', 'Ер фонди тузилмаси ўзига хос: 65% яйлов (чорвачилик капитали), 25% деҳқончилик ерлари, бироқ суғорилган қисми атиги 560 га — бу муаммо. Сув танқислиги SWOT-таҳдид сифатида қайд этилган. 2026–2028 йиллар учун: (1) суғориш каналларини бетонлаш улушини 35% дан 65% га ошириш, (2) томчилатиб суғориш системасини 2 000 га гача кенгайтириш, (3) яйловларнинг 5 000 га ҳудудида интенсив чорвачилик мажмуалари (минг бошли қўйчилик-эчкичилик) яратиш. Бу 3 та чора билан Қ/х маҳсулоти 3 000 → 5 000 млрд сўмга етиши мумкин.', NULL, NULL, 1, TRUE, '2026-04-28 12:00:00+05'::TIMESTAMPTZ);
